window.SIDDUR_EXTRAS = {"items":[{"id":"birkat_hamazon","title":"ברכת המזון","category":"ברכות הנהנין","nusachim":{"ashkenaz":[{"kind":"instruction","text":"[][]","cond":[]},{"kind":"header","text":"מזמור פתיחה","cond":["shacharitTachanun"]},{"kind":"text","text":"עַל נַהֲרוֹת בָּבֶל, שָׁם יָשַׁבְנוּ גַּם בָּכִינוּ בְּזָכְרֵנוּ אֶת צִיּוֹן: עַל עֲרָבִים בְּתוֹכָהּ תָּלִינוּ כִּנֹּרוֹתֵינוּ: כִּי שָׁם שְׁאֵלוּנוּ שׁוֹבֵינוּ דִּבְרֵי שִׁיר וְתוֹלָלֵינוּ שִׂמְחָה, שִׁירוּ לָנוּ מִשִּׁיר צִיּוֹן: אֵיךְ נָשִׁיר אֶת שִׁיר יהוה עַל אַדְמַת נֵכָר: אִם אֶשְׁכָּחֵךְ יְרוּשָׁלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָׁלַיִם עַל רֹאשׁ שִׂמְחָתִי: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאֹמְרִים עָרוּ עָרוּ עַד הַיְסוֹד בָּהּ: בַּת בָּבֶל הַשְּׁדוּדָה, אַשְׁרֵי שֶׁיְשַׁלֶּם לָךְ אֶת גְּמוּלֵךְ שֶׁגָּמַלְתְּ לָנוּ: אַשְׁרֵי שֶׁיֹּאחֵז וְנִפֵּץ אֶת עֹלָלַיִךְ אֶל הַסָּלַע:","cond":["shacharitTachanun"]},{"kind":"header","text":"מזמור פתיחה","cond":["noShacharitTachanun"]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":["noShacharitTachanun"]},{"kind":"header","text":"זימון","cond":[]},{"kind":"instruction","text":"שלשה שאכלו יחדיו חייבים בזימון:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nומי שלא אכל עונה: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) וּמְבֹרָךְ שְׁמוֹ תָּמֵיד לְעוֹלָם וָעֵד.","cond":[]},{"kind":"header","text":"ברכת הזן","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ, בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל, וּמֵטִיב לַכֹּל, וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא. בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"header","text":"ברכת הארץ","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ, יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל, יהוה אֱלֹהֵינוּ, אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד, כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"header","text":"בונה ירושלים","cond":[]},{"kind":"text","text":"רַחֶם (נָא) יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ, זוּנֵנוּ, פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ, יהוה אֱלֹהֵינוּ, לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"header","text":"יעלה ויבוא","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"header","text":"יעלה ויבוא","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"header","text":"יעלה ויבוא","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"header","text":"הטוב והמטיב","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"header","text":"הרחמן","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]}],"sfard":[{"kind":"instruction","text":"[][]","cond":[]},{"kind":"header","text":"מזמור פתיחה","cond":["shacharitTachanun"]},{"kind":"text","text":"עַל נַהֲרוֹת בָּבֶל, שָׁם יָשַׁבְנוּ גַּם בָּכִינוּ בְּזָכְרֵנוּ אֶת צִיּוֹן: עַל עֲרָבִים בְּתוֹכָהּ תָּלִינוּ כִּנֹּרוֹתֵינוּ: כִּי שָׁם שְׁאֵלוּנוּ שׁוֹבֵינוּ דִּבְרֵי שִׁיר וְתוֹלָלֵינוּ שִׂמְחָה, שִׁירוּ לָנוּ מִשִּׁיר צִיּוֹן: אֵיךְ נָשִׁיר אֶת שִׁיר יהוה עַל אַדְמַת נֵכָר: אִם אֶשְׁכָּחֵךְ יְרוּשָׁלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָׁלַיִם עַל רֹאשׁ שִׂמְחָתִי: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאֹמְרִים עָרוּ עָרוּ עַד הַיְסוֹד בָּהּ: בַּת בָּבֶל הַשְּׁדוּדָה, אַשְׁרֵי שֶׁיְשַׁלֶּם לָךְ אֶת גְּמוּלֵךְ שֶׁגָּמַלְתְּ לָנוּ: אַשְׁרֵי שֶׁיֹּאחֵז וְנִפֵּץ אֶת עֹלָלַיִךְ אֶל הַסָּלַע:","cond":["shacharitTachanun"]},{"kind":"header","text":"מזמור פתיחה","cond":["noShacharitTachanun"]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":["noShacharitTachanun"]},{"kind":"header","text":"זימון","cond":[]},{"kind":"instruction","text":"שלשה שאכלו יחדיו חייבים בזימון:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nומי שלא אכל עונה: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) וּמְבֹרָךְ שְׁמוֹ תָּמֵיד לְעוֹלָם וָעֵד.","cond":[]},{"kind":"header","text":"ברכת הזן","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ, בְּטוּבוֹ בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וּמֵטִיב לַכֹּל וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא, כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"header","text":"ברכת הארץ","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד. כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"header","text":"בונה ירושלים","cond":[]},{"kind":"text","text":"רַחֶם נָא יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ זוּנֵנוּ פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"header","text":"הטוב והמטיב","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"header","text":"הרחמן","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]}],"edot_mizrach":[{"kind":"instruction","text":"[][]","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אֲנַחְנוּ בָּאִים לְקַיֵּם מִצְוַת עֲשֵׂה דְאוֹרַיְתָא לְבָרֵךְ בִּרְכַּת הַמָּזוֹן, כַּכָּתוּב בַּתּוֹרָה: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ, לְתַקֵּן שֹׁרֶשׁ מִצְוָה זוֹ בְּמָקוֹם עֶלְיוֹן. וִיהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּהְיֶה חֲשׁוּבָה וּמְקֻבֶּלֶת וּרְצוּיָה לְפָנֶיךָ בְּרָכָה רִאשׁוֹנָה וּבְרָכָה שְׁנִיָּה וּבְרָכָה שְׁלִישִׁית אֲשֶׁר נְבָרֵךְ עַתָּה עַל הַמָּזוֹן. וְתִתֵּן לָנוּ כֹּח וִיכֹלֶת וְעֵזֶר וְסִיּוּעַ לְהַעֲלות מַיִּין נֻקְבִּין וּלְהַמְשִׁיךְ אַרְבַּעַת הַמֹּחִין לְיִשְׂרָאֵל וְרָחֵל [הַגְּדוֹלָה]. וְגַם תִּהְיֶה חֲשׁוּבָה וּמְקֻבֶּלֶת וּרְצוּיָה לְפָנֶיךָ בְּרָכָה רְבִיעִית אֲשֶׁר נְבָרֵךְ עַתָּה. וְתִתֵּן לָנוּ כֹּח וִיכֹלֶת וְעֵזֶר וְסִיּוּעַ לְהַעֲלות מַיִּין נֻקְבִּין, וּלְהַמְשִׁיךְ אַרְבַּעַת הַמּוֹחִין לְיַעֲקֹב וְרָחֵל. וְיַעֲלֶה לְפָנֶיךָ כְּאִלּוּ כִוַּנּוּ בְּכָל הַכַּוָּנוֹת הָרְאוּיוֹת לְכַוֵּן בְּאַרְבַּע בְּרָכוֹת אֵלּוּ שֶׁל הַמָּזוֹן. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":[]},{"kind":"header","text":"למנצח","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"אֲבָרְכָה אֶת-יהוה בְּכָל-עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: סוֹף דָּבָר הַכֹּל נִשְׁמָע, אֶת-הָאֱלֹהִים יְרָא וְאֶת-מִצְוׂתָיו שְׁמוֹר, כִּי-זֶה כָּל-הָאָדָם: תְּהִלַּת יהוה יְדַבֶּר פִּי, וִיבָרֵךְ כָּל-בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד-עוֹלָם, הַלְלוּיָהּ: וַיְדַבֵּר אֵלַי, זֶה הַשֻּׁלְחָן אֲשֶׁר לִפְנֵי יהוה:","cond":[]},{"kind":"header","text":"זימון","cond":[]},{"kind":"instruction","text":"שלשה שאכלו יחדיו חייבים בזימון:","cond":[]},{"kind":"text","text":"המזמן אומר: הַב לָן וְנִבְרִיךְ לְמַלְכָּא עִלָּאָה קַדִּישָׁא.\nהמסובים עונים: שָמַיִם.\nהמברך אומר: בִּרְשׁוּת מַלְכָּא עִלָּאָה קַדִּישָׁא,","cond":[]},{"kind":"special","text":"וּבִרְשׁוּת שִׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין","cond":["sucot"]},{"kind":"text","text":"וּבִרְשׁוּת מוֹרַי וְרַבּוֹתַי, וּבִרְשׁוּתְכֶם, נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.","cond":[]},{"kind":"header","text":"ברכת הזן","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל הַזָּן אוֹתָנוּ וְאֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ בְּחֵן בְּחֶסֶד בְּרֶוַח וּבְרַחֲמִים רַבִּים, נֹתֵן לֶחֶם לְכָל-בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן תָּמִיד לְעוֹלָם וָעֶד, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וְשֻׁלְחָנוֹ עָרוּךְ לַכֹּל וְהִתְקִין מִחְיָה וּמָזוֹן לְכָל-בְּרִיּוֹתָיו אֲשֶׁר בָּרָא בְרַחֲמָיו וּבְרוֹב חֲסָדָיו כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ, וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"header","text":"ברכת הארץ","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה בְּרִית וְתוֹרָה חַיִּים וּמָזוֹן, עַל שֶׁהוֹצֵאתָנוּ מֵאֶרֶץ מִצְרַיִם וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֵּי רְצוֹנָךְ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים וּמָזוֹן שֶׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אֶת שְׁמָךְ כָּאָמוּר: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת-יהוה אֱלֹהֶיךָ עַל-הָאָרֶץ הַטּוֹבָה אֲשֶׁר נָתַן-לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"header","text":"בונה ירושלים","cond":[]},{"kind":"text","text":"רַחֵם יהוה אֱלֹהֵינוּ עָלֵינוּ וְעַל יִשְׂרָאֵל עַמָּךְ, וְעַל יְרוּשָׁלַיִם עִירָךְ, וְעַל הַר צִיּוֹן מִשְׁכַּן כְּבוֹדָךְ, וְעַל הֵיכָלָךְ, וְעַל מְעוֹנָךְ, וְעַל דְּבִירָךְ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, אָבִינוּ רְעֵנוּ זוּנֵנוּ, פַּרְנְסֵנוּ, כַּלְכְּלֵנוּ, הַרְוִיחֵנוּ הַרְוַח לָנוּ מְהֵרָה מִכָּל-צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לִידֵי מַתְּנוֹת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, אֶלָּא לְיָדְךָ הַמְּלֵאָה וְהָרְחָבָה, הָעֲשִׁירָה וְהַפְּתוּחָה. יְהִי רָצוֹן שֶׁלֹּא נֵבוֹשׁ בָּעוֹלָם הַזֶּה, וְלֹא נִכָּלֵם לְעוֹלָם הַבָּא, וּמַלְכוּת בֵּית דָּוִד מְשִׁיחָךְ תַּחֲזִירֶנָּה לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"header","text":"יעלה ויבוא","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"header","text":"יעלה ויבוא","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"header","text":"יעלה ויבוא","cond":["sucot"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וְתִבְנֶה יְרוּשָׁלַיִם עִירָךְ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם. (ואומר בלחש: אָמֵן).","cond":[]},{"kind":"header","text":"הטוב והמטיב","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, לָעַד הָאֵל אָבִינוּ מַלְכֵּנוּ אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, קְדוֹשֵׁנוּ, קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל-יוֹם וָיוֹם הוּא הֵטִיב לָנוּ, הוּא מֵטִיב לָנוּ, הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ, הוּא גוֹמְלֵנוּ, הוּא יִגְמְלֵנוּ לָעַד חֵן וָחֶסֶד וְרַחֲמִים וְרֵיוַח וְהַצָּלָה וְכָל-טוֹב.","cond":[]},{"kind":"header","text":"הרחמן","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִשְׁתַּבַּח עַל כִּסֵּא כְבוֹדוֹ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בָּנוּ לְדוֹר דּוֹרִים.\nהָרַחֲמָן הוּא קֶרֶן לְעַמּוֹ יָרִים.\nהָרַחֲמָן הוּא יִתְפָּאַר בָּנוּ לָנֶצַח נְצָחִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד וְלֹא בְבִזּוּי, בְּהֶתֵּר וְלֹא בְאִסּוּר, בְּנַחַת וְלֹא בְצָעַר.\nהָרַחֲמָן הוּא יִתֵּן שָׁלוֹם בֵּינֵינוּ.\nהָרַחֲמָן הוּא יִשְׁלַח בְּרָכָה רְוָחָה וְהַצְלָחָה בְּכָל-מַעֲשֵׂה יָדֵינוּ.\nהָרַחֲמָן הוּא יַצְלִיחַ אֶת דְּרָכֵינוּ.\nהָרַחֲמָן הוּא יִשְׁבּוֹר עוֹל גָּלוּת מְהֵרָה מֵעַל צַוָּארֵנוּ.\nהָרַחֲמָן הוּא יוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת בְּאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִרְפָּאֵנוּ רְפוּאָה שְׁלֵמָה רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף.\nהָרַחֲמָן הוּא יִפְתַּח לָנוּ אֶת יָדוֹ הָרְחָבָה.\nהָרַחֲמָן הוּא יְבָרֵךְ כָּל אֶחָד וְאֶחָד מִמֶּנּוּ בִּשְׁמוֹ הַגָּדוֹל כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ יַחַד בְּרָכָה שְׁלֵמָה, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן.\nהָרַחֲמָן הוּא יִפְרוֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמוֹ.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לֵישֵׁב בְּסֻכַּת עוֹרוֹ שֶׁל לִוְיָתָן.\nהָרַחֲמָן הוּא יַשְׁפִּיעַ עָלֵינוּ שֶׁפַע קְדֻשָּׁה וְטָהֳרָה מִשִּׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין, זְכוּתָם תְּהֵא מָגֵן וְצִנָּה עָלֵינוּ.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["pesach"]},{"kind":"text","text":"הָרַחֲמָן הוּא יִטַּע תּוֹרָתוֹ וְאַהֲבָתוֹ בְּלִבֵּנוּ וְתִהְיֶה יִרְאָתוֹ עַל פָּנֵינוּ לְבִלְתִּי נֶחֱטָא, וְיִהְיוּ כָל-מַעֲשֵׂינוּ לְשֵׁם שָׁמָיִם.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת הַשֻּׁלְחָן הַזֶּה שֶׁאָכַלְנוּ עָלָיו וִיסַדֵּר בּוֹ כָּל מַעֲדַנֵּי עוֹלָם וְיִהְיֶה כְּשֻׁלְחָנוֹ שֶׁל אַבְרָהָם אָבִינוּ (עָלָיו הַשָּׁלוֹם), כָּל רָעֵב מִמֶּנּוּ יֹאכַל, וְכָל צָמֵא מִמֶּנּוּ יִשְׁתֶּה, וְאַל יֶחְסַר מִמֶּנּוּ כָּל טוּב לָעַד וּלְעוֹלְמֵי עוֹלָמִים. הָרַחֲמָן הוּא יְבָרֵךְ אֶת בַּעַל הַבַּיִת הַזֶּה וּבַעַל הַסְּעֻדָּה הַזּאת, הוּא וּבָנָיו וְאִשְׁתּוֹ וְכָל אֲשֶׁר לוֹ, בְּבָנִים שֶׁיִּחְיוּ, וּבִנְכָסִים שֶׁיִּרְבּוּ, בָּרֵךְ יהוה חֵילוֹ וּפֹעַל יָדָיו תִּרְצֶה, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִזְדַּקֵּק לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר חֵטְא וְהִרְהוּר עָוׂן. שָׂשׂ וְשָׂמֵחַ כָּל הַיָּמִים בְּעֹשֶׁר וְכָבוֹד מֵעַתָּה וְעַד עוֹלָם, לֹא יֵבוֹשׁ בָּעוֹלָם הַזֶּה וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, אָמֵן כֵּן יְהִי רָצוֹן.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְחַיֵּינוּ וִיזַכֵּנוּ וִיקָרְבֵנוּ לִימוֹת הַמָּשִׁיחַ וּלְבִנְיַן בֵּית הַמִּקְדָּשׁ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדרְשֵׁי יהוה לֹא-יַחְסְרוּ כָל-טוֹב: נַעַר הָיִיתִי גַּם-זָקַנְתִּי וְלֹא-רָאִיתִי צַדִּיק נֶעֱזָב, וְזַרְעוֹ מְבַקֶּשׁ-לָחֶם: כָּל-הַיּוֹם חוֹנֵן וּמַלְוֶה, וְזַרְעוֹ לִבְרָכָה: מַה שֶּׁאָכַלְנוּ יִהְיֶה לְשָׂבְעָה, וּמַה שֶּׁשָּׁתִינוּ יִהְיֶה לִרְפוּאָה, וּמַה שֶּׁהוֹתַרְנוּ יִהְיֶה לִבְרָכָה, כְּדִכְתִיב: וַיִּתֵּן לִפְנֵיהֶם וַיֹּאכְלוּ וַיּוֹתִירוּ כִּדְבַר יהוה: בְּרוּכִים אַתֶּם לַיהוה, עוֹשֵׂה שָׁמַיִם וָאָרֶץ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטָחוֹ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת-עַמּוֹ בַשָּׁלוֹם:","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]}]}},{"id":"meein_shalosh","title":"ברכה מעין שלוש (על המחיה)","category":"ברכות הנהנין","nusachim":{"ashkenaz":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם,","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"עַל הַמִחְיָה וְעַל הַכַּלְכָּלָה","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"עַל הַגֶּפֶן וְעַל פְּרִי הַגֶּפֶן","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"עַל הָעֵץ וְעַל פְּרִי הָעֵץ\n\nוְעַל תְּנוּבַת הַשָּׂדֶה וְעַל אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה שֶׁרָצִיתָ וְהִנְחַלְתָּ לַאֲבוֹתֵינוּ לֶאֱכֹל מִפִּרְיָהּ וְלִשְׂבּוֹעַ מִטּוּבָהּ. רַחֵם (נָא) יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מִזְבְּחֶךָ וְעַל הֵיכָלֶךָ, וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְּיָמֵינוּ וְהַעֲלֵנוּ לְתוֹכָהּ וְשַׂמְּחֵנוּ בְּבִנְיָנָהּ וְנֹאכַל מִפִּרְיָּהּ וְנִשְׂבַּע מִטּוּבָהּ וּנְבָרֶכְךָ עָלֶיהָ בִּקְדֻשָּׁה וּבְטָהֳרָה.","cond":[]},{"kind":"special","text":"וְזָכְרֵנוּ לְטוֹבָה בְּיוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְּיוֹם חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְּיוֹם חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"text","text":"כִּי אַתָּה יהוה טוֹב וּמֵטִיב לַכֹּל, וְנוֹדֶה לְךָ עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל הַמִחְיָה.","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פְּרִי גַפְנָהּ (על יין חו\"ל אומר: וְעַל פְּרִי הַגֶּפֶן).","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת).\n\nבָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל הַמִחְיָה.","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פְּרִי גַפְנָהּ (על יין חו\"ל אומר: פְּרִי הַגֶּפֶן).","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת).","cond":[]}],"sfard":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם,","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"עַל הַמִחְיָה וְעַל הַכַּלְכָּלָה","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"עַל הַגֶּפֶן וְעַל פְּרִי הַגֶּפֶן","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"עַל הָעֵץ וְעַל פְּרִי הָעֵץ\n\nוְעַל תְּנוּבַת הַשָּׂדֶה וְעַל אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה שֶׁרָצִיתָ וְהִנְחַלְתָּ לַאֲבוֹתֵינוּ לֶאֱכֹל מִפִּרְיָהּ וְלִשְׂבּוֹעַ מִטּוּבָהּ. רַחֵם (נָא) יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מִזְבְּחֶךָ וְעַל הֵיכָלֶךָ, וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְּיָמֵינוּ וְהַעֲלֵנוּ לְתוֹכָהּ וְשַׂמְּחֵנוּ בְּבִנְיָנָהּ וְנֹאכַל מִפִּרְיָּהּ וְנִשְׂבַּע מִטּוּבָהּ וּנְבָרֶכְךָ עָלֶיהָ בִּקְדֻשָּׁה וּבְטָהֳרָה.","cond":[]},{"kind":"special","text":"וְזָכְרֵנוּ לְטוֹבָה בְּיוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְּיוֹם חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְּיוֹם חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"text","text":"כִּי אַתָּה יהוה טוֹב וּמֵטִיב לַכֹּל, וְנוֹדֶה לְךָ עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל הַמִחְיָה.","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פְּרִי גַפְנָהּ (על יין חו\"ל אומר: וְעַל פְּרִי הַגֶּפֶן).","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת).\n\nבָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל הַמִחְיָה וְעַל הַכַּלְכָּלָה","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פְּרִי גַפְנָהּ (על יין חו\"ל אומר: פְּרִי הַגֶּפֶן).","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת).","cond":[]}],"edot_mizrach":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם,","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"עַל הַמִּחְיָה ועַל הַכַּלְכָּלָה","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"עַל הַגֶּפֶן ועַל פְּרִי הַגֶּפֶן","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"עַל הָעֵץ ועַל פּרִי הָעֵץ\n\nוְעַל תְּנוּבַת הַשָּׂדֶה, וְעַל אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה שֶׁרָצִיתָ וְהִנְחַלְתָּ לַאֲבוֹתֵינוּ, לֶאֱכֹל מִפִּרְיָהּ, וְלִשְׂבֹּעַ מִטּוּבָהּ. רַחֵם יהוה אֱלֹהֵינוּ עָלֵינוּ, וְעַל יִשְׂרָאֵל עַמָּךְ, וְעַל יְרוּשָׁלַיִם עִירָךְ, וְעַל הַר צִיּוֹן מִשְׁכַּן כְּבוֹדָךְ, וְעַל מִזְבָּחָךְ וְעַל הֵיכָלָךְ, וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ, בִּמְהֵרָה בְיָמֵינוּ, וְהַעֲלֵנוּ לְתוֹכָהּ, וְשַׂמְּחֵנוּ בְּבִנְיָנָהּ, וּנְבָרְכָךְ עָלֶיהָ בִּקְדֻשָּׁה וּבְטָהֳרָה.","cond":[]},{"kind":"special","text":"וְזָכְרֵנוּ לְטוֹבָה בְּיוֹם רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְיוֹם חַג הַסֻּכּוֹת הַזֶּה בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"וְשַׂמְּחֵנוּ בְיוֹם חַג הַמַּצּוֹת הַזֶּה בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה.","cond":["pesach"]},{"kind":"text","text":"כִּי אַתָּה טוֹב וּמֵטִיב לַכֹּל, וְנוֹדֶה לְךָ (יהוה אֱלֹהֵינוּ) עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל מִחְיָתָהּ וְעַל כַּלְכָּלָתָהּ (על תבואת חו\"ל אומר: וְעַל הַמִּחְיָה וְעַל הַכַּלְכָּלָה)","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פּרִי גַפְנָהּ (על יין חו\"ל אומר: וְעַל פְּרִי הַגֶּפֶן)","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת)\n\nבָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ","cond":[]},{"kind":"instruction","text":"על חמשת מיני דגן","cond":[]},{"kind":"text","text":"וְעַל מִחְיָתָהּ (על תבואת חו\"ל אומר: וְעַל הַמִּחְיָה).","cond":[]},{"kind":"instruction","text":"על היין","cond":[]},{"kind":"text","text":"וְעַל פְּרִי גַפְנָהּ (על יין חו\"ל אומר: וְעַל פְּרִי הַגֶּפֶן).","cond":[]},{"kind":"instruction","text":"על פירות משבעת המינים","cond":[]},{"kind":"text","text":"וְעַל פֵּרוֹתֶיהָ (על פירות חו\"ל אומר: וְעַל הַפֵּרוֹת).","cond":[]}]}},{"id":"borei_nefashot","title":"בורא נפשות","category":"ברכות הנהנין","nusachim":{"ashkenaz":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא נְפָשׁוֹת רַבּוֹת וְחֶסְרוֹנָן עַל כָּל מַה שֶּׁבָּרָאתָ לְהַחֲיוֹת בָּהֶם נֶפֶשׁ כָּל חָי. בָּרוּךְ חֵי הָעוֹלָמִים.","cond":[]}],"sfard":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא נְפָשׁוֹת רַבּוֹת וְחֶסְרוֹנָן עַל כָּל מַה שֶּׁבָּרָאתָ לְהַחֲיוֹת בָּהֶם נֶפֶשׁ כָּל חָי. בָּרוּךְ חֵי הָעוֹלָמִים.","cond":[]}],"edot_mizrach":[{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא נְפָשׁוֹת רַבּוֹת וְחֶסְרוֹנָן עַל כָּל מַה שֶּׁבָּרָאתָ לְהַחֲיוֹת בָּהֶם נֶפֶשׁ כָּל חָי. בָּרוּךְ חֵי הָעוֹלָמִים.","cond":[]}]}},{"id":"asher_yatzar","title":"אשר יצר","category":"ברכות הנהנין","nusachim":{"ashkenaz":[{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה וּבָֽרָא בוֹ נְקָבִים נְקָבִים חֲלוּלִים חֲלוּלִים גָּלוּי וְיָדֽוּעַ לִפְנֵי כִסֵּא כְבוֹדֶֽךָ שֶׁאִם יִפָּתֵֽחַ אֶחָד מֵהֶם אוֹ יִסָּתֵם אֶחָד מֵהֶם אִי אֶפְשַׁר לְהִתְקַיֵּם וְלַעֲמֹד לְפָנֶֽיךָ. בָּרוּךְ אַתָּה יְהֹוָה רוֹפֵא כָל בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת:","cond":[]}],"sfard":[{"kind":"text","text":"בָּרוּךְ אַתָּה יְהֹוָה אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה וּבָֽרָא בוֹ נְקָבִים נְקָבִים חֲלוּלִים חֲלוּלִים גָּלוּי וְיָדֽוּעַ לִפְנֵי כִסֵּא כְבוֹדֶֽךָ שֶׁאִם יִפָּתֵֽחַ אֶחָד מֵהֶם אוֹ יִסָּתֵם אֶחָד מֵהֶם אִי אֶפְשַׁר לְהִתְקַיֵּם וְלַעֲמֹד לְפָנֶֽיךָ אֲפִילוּ שָׁעָה אֶחָת. בָּרוּךְ אַתָּה יְהֹוָה רוֹפֵא כָל בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת:","cond":[]}],"edot_mizrach":[{"kind":"text","text":"בָּרוּךְ אַתָּה יְהוָֹה, אֱלֹהֵֽינוּ מֶֽלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּחָכְמָה, וּבָרָא בוֹ נְקָבִים נְקָבִים, חֲלוּלִים חֲלוּלִים, גָּלוּי וְיָדוּעַ לִפְנֵי כִסֵּא כְבוֹדֶךָ, שֶׁאִם יִסָּתֵם אֶחָד מֵהֶם, אוֹ אִם יִפָּתֵח אֶחָד מֵהֶם, אֵי אֶפְשָׁר לְהִתְקַיֵּם אַפִלּוּ שָׁעָה אֶחָת. בָּרוּךְ אַתָּה יְהֹוָה, רוֹפֵא כָל־בָּשָׂר וּמַפְלִיא לַעֲשׂוֹת:","cond":[]}]}},{"id":"tefilat_haderech","title":"תפילת הדרך","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתּוֹלִיכֵנוּ לְשָׁלוֹם, וְתַצְעִידֵנוּ לְשָׁלוֹם, וְתַדְרִיכֵנוּ לְשָׁלוֹם, וְתַגִּיעֵנוּ לִמְחוֹז חֶפְצֵנוּ לְחַיִּים וּלְשִׂמְחָה וּלְשָׁלוֹם, (וְתַחֲזִירֵנוּ לְבֵיתֵנוּ לְשָׁלוֹם,) וְתַצִּילֵנוּ מִכַּף כָּל אוֹיֵב וְאוֹרֵב בַּדֶּרֶךְ וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת הַמִּתְרַגְּשׁוֹת לָבוֹא לָעוֹלָם, וְתִשְׁלַח בְּרָכָה בְּמַעֲשֵׂה יָדֵינוּ, וְתִתְּנֵנוּ לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רוֹאֵינוּ, וְתִשְׁמַע קוֹל תַחֲנוּנֵינוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלָּה וְתַחֲנוּן אָתָּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵע תְּפִלָּה.","cond":[]}],"sfard":[{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתּוֹלִיכֵנוּ לְשָׁלוֹם, וְתַצְעִידֵנוּ לְשָׁלוֹם, וְתִסְמְכֵנוּ לְשָׁלוֹם, וְתַנְחֵנוּ אֶל מְחוֹז חֶפְצֵנוּ לְחַיִּים וּלְשִׂמְחָה וּלְשָׁלוֹם, (וְתַחֲזִירֵנוּ לְבֵיתֵנוּ לְשָׁלוֹם,) וְתַצִּילֵנוּ מִכַּף כָּל אוֹיֵב וְאוֹרֵב בַּדֶּרֶךְ וּמִכָּל מִינֵי פֻּרְעָנֻיּוֹת הַמִּתְרַגְּשׁוֹת לָבוֹא לָעוֹלָם, וְתִשְׁלַח בְּרָכָה בְּמַעֲשֵׂה יָדֵינוּ, וְתִתְּנֵנוּ לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל רוֹאֵינוּ, וְתִשְׁמַע קוֹל תַחֲנוּנֵינוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלָּה וְתַחֲנוּן אָתָּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵע תְּפִלָּה.","cond":[]}],"edot_mizrach":[{"kind":"text","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתּוֹלִיכֵנוּ לְשָׁלוֹם, וְתַצְעִידֵנוּ לְשָׁלוֹם, וְתַדְרִיכֵנוּ לְשָׁלוֹם, וְתַגִּיעֵנוּ לִמְחוֹז חֶפְצֵנוּ לְחַיִּים טוֹבִים וּלְשִׂמְחָה וּלְשָׁלוֹם, (אם חוזר בו ביום מוסיף: וְתַחֲזִירֵנוּ לשָׁלוֹם,) וְתַצִּילֵנוּ מִכַּף כָּל-אוֹיֵב וְאוֹרֵב בַּדֶּרֶךְ, וּמִתּאוּנוֹת דְּרָכִים, וּמִסַּכָּנַת מְחַבְּלִים, וּמִכָל מִינֵי פֻרְעָנֻיּוֹת הַמִּתְרַגְּשׁוֹת וּבָאוֹת לָעוֹלָם, וְתִשְׁלַח בְּרָכָה בְּכָל-מַעֲשֵׂה יָדֵינוּ, וְתִתְּנֵנוּ לְחֵן וּלְחֶסֶד וּלְרַחֲמִים בְּעֵינֶיךָ וּבְעֵינֵי כָל-רוֹאֵינוּ, וְתִשְׁמַע קוֹל תַּחֲנוּנֵינוּ, כִּי אֵל שׁוֹמֵעַ תְּפִלָּה וְתַחֲנוּן אָתָּה. בָּרוּךְ אַתָּה יהוה, שׁוֹמֵעַ תְּפִלָּה.\n\nוְיַעֲקֹב הָלַך לְדַרְכּוֹ וַיִּפְגְּעוּ בוֹ מַלְאֲכֵי אֱלֹהִים: וַיֹּאמֶר יַעֲקֹב כַּאֲשֶׁר רָאָם, מַחֲנֶה אֱלֹהִים זֶה, וַיִּקְרָא שֵׁם הַמָּקוֹם הָהוּא מַחֲנָיִם:\nוְיַעֲקֹב הָלַך לְדַרְכּוֹ וַיִּפְגְּעוּ בוֹ מַלְאֲכֵי אֱלֹהִים: וַיֹּאמֶר יַעֲקֹב כַּאֲשֶׁר רָאָם, מַחֲנֶה אֱלֹהִים זֶה, וַיִּקְרָא שֵׁם הַמָּקוֹם הָהוּא מַחֲנָיִם:\nוְיַעֲקֹב הָלַך לְדַרְכּוֹ וַיִּפְגְּעוּ בוֹ מַלְאֲכֵי אֱלֹהִים: וַיֹּאמֶר יַעֲקֹב כַּאֲשֶׁר רָאָם, מַחֲנֶה אֱלֹהִים זֶה, וַיִּקְרָא שֵׁם הַמָּקוֹם הָהוּא מַחֲנָיִם:\n\nוַיִּסָּעוּ, וַיְהִי חִתַּת אֱלֹהִים עַל הֶעָרִים אֲשֶׁר סְבִיבוֹתֵיהֶם, וְלֹא רָדְפוּ אַחֲרֵי בְּנֵי יַעֲקֹב:\nוַיִּסָּעוּ, וַיְהִי חִתַּת אֱלֹהִים עַל הֶעָרִים אֲשֶׁר סְבִיבוֹתֵיהֶם, וְלֹא רָדְפוּ אַחֲרֵי בְּנֵי יַעֲקֹב:\nוַיִּסָּעוּ, וַיְהִי חִתַּת אֱלֹהִים עַל הֶעָרִים אֲשֶׁר סְבִיבוֹתֵיהֶם, וְלֹא רָדְפוּ אַחֲרֵי בְּנֵי יַעֲקֹב:","cond":[]}]}},{"id":"kriat_shema_al_hamita","title":"קריאת שמע שעל המיטה","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"text","text":"הֲרֵינִי מוֹחֵל לְכָל מִי שֶׁהִכְעִיס וְהִקְנִיט אוֹתִי, אוֹ שֶׁחָטָא כְּנֶגְדִּי בֵּין בְּגוּפִי בֵּין בְּמָמוֹנִי בֵּין בִּכְבוֹדִי בֵּין בְּכָל אֲשֶׁר לִי, בֵּין בְּאֹנֶס, בֵּין בְּרָצוֹן, בֵּין בְּשׁוֹגֵג, בֵּין בְּמֵזִיד, בֵּין בְּדִבּוּר בֵּין בְּמַעֲשֶׂה, וְלֹא יֵעָנֵשׁ שׁוּם אָדָם בְּסִבָּתִי.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יֹשֵׁב בְּסֵתֶר עֶלְיוֹן בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שַׂמְתָּ מְעוֹנֶךָ: לֹא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לֹא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגֹּף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרֹךְ, תִּרְמֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:\n\nיהוה, מָה רַבּוּ צָרָי, רַבִּים קָמִים עָלָי: רַבִּים אֹמְרִים לְנַפְשִׁי אֵין יְשׁוּעָתָה לּוֹ בֵאלֹהִים סֶלָה: וְאַתָּה יהוה מָגֵן בַּעֲדִי, כְּבוֹדִי וּמֵרִים רֹאשִׁי: קוֹלִי אֶל יהוה אֶקְרָא, וַיַּעֲנֵנִי מֵהַר קָדְשׁוֹ סֶלָה: אֲנִי שָׁכַבְתִּי וָאִישָׁנָה, הֱקִיצוֹתִי כִּי יהוה יִסְמְכֵנִי: לֹא אִירָא מֵרִבְבוֹת עָם, אֲשֶׁר סָבִיב שָׁתוּ עָלָי: קוּמָה יהוה הוֹשִׁיעֵנִי אֱלֹהַי, כִּי הִכִּיתָ אֶת כָּל אֹיְבַי לֶחִי, שִׁנֵּי רְשָׁעִים שִׁבַּרְתָּ: לַיהוה הַיְשׁוּעָה עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה:\n\nהַשְׁכִּיבֵנוּ יהוה אֱלֹהֵינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ לְמַעַן שְׁמֶךָ. וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ אוֹיֵב, דֶּבֶר וְחֶרֶב וְרָעָב וְיָגוֹן. וְהָסֵר שָׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ, כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אָתָּה, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּשְׁמוֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם.\n\nבָּרוּךְ יהוה בַּיּוֹם. בָּרוּךְ יהוה בַּלָּיְלָה. בָּרוּךְ יהוה בְּשָׁכְבֵנוּ. בָּרוּךְ יהוה בְּקוּמֵנוּ. כִּי בְיָדְךָ נַפְשׁוֹת הַחַיִּים וְהַמֵּתִים. אֲשֶׁר בְּיָדוֹ נֶפֶשׁ כָּל חָי וְרוּחַ כָּל בְּשָׂר אִישׁ: בְּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת: אֱלֹהֵינוּ שֶׁבַּשָּׁמַיִם, יַחֵד שִׁמְךָ וְקַיֵּם מַלְכוּתְךָ תָּמִיד, וּמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\n\nיִרְאוּ עֵינֵינוּ וְיִשְׂמַח לִבֵּנוּ וְתָגֵל נַפְשֵׁנוּ בִּישׁוּעָתְךָ בֶּאֱמֶת בֶּאֱמֹר לְצִיּוֹן מָלַךְ אֱלֹהָיִךְ. יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלךְ בְּכָבוֹד, כִּי אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\n\nהַמַּלְאָךְ הַגֹּאֵל אֹתִי מִכָּל רָע יְבָרֵךְ אֶת הַנְּעָרִים, וְיִקָּרֵא בָהֶם שְׁמִי וְשֵׁם אֲבֹתַי, אַבְרָהָם וְיִצְחָק, וְיִדְגּוּ לָרֹב בְּקֶרֶב הָאָרֶץ:\n\nוַיֹּאמֶר אִם שָׁמוֹעַ תִּשְׁמַע לְקוֹל יהוה אֱלֹהֶיךָ וְהַיָּשָׁר בְּעֵינָיו תַּעֲשֶׂה, וְהַאֲזַנְתָּ לְמִצְוׂתָיו וְשָׁמַרְתָּ כָּל חֻקָּיו, כָּל הַמַּחֲלָה אֲשֶׁר שַׂמְתִּי בְמִצְרַיִם לֹא אָשִׂים עָלֶיךָ, כִּי אֲנִי יהוה רֹפְאֶךָ: וַיֹּאמֶר יהוה אֶל הַשָּׂטָן, יִגְעַר יהוה בְּךָ הַשָּׂטָן, וְיִגְעַר יהוה בְּךָ הַבֹּחֵר בִּירוּשָׁלַיִם, הֲלוֹא זֶה אוּד מֻצָּל מֵאֵשׁ: הִנֵּה מִטָּתוֹ שֶׁלִּשְׁלֹמֹה, שִׁשִּׁים גִּבֹּרִים סָבִיב לָהּ, מִגִּבֹּרֵי יִשְׂרָאֵל: כֻּלָּם אֲחֻזֵי חֶרֶב, מְלֻמְּדֵי מִלְחָמָה, אִישׁ חַרְבּוֹ עַל יְרֵכוֹ מִפַּחַד בַּלֵּילוֹת:\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\n\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\n\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\n\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\n\n\nשִׁיר הַמַּעֲלוֹת, אַשְׁרֵי כָּל יְרֵא יהוה, הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל, אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פּוֹרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִילֵי זֵיתִים סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִּי כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן, וּרְאֵה בְּטוּב יְרוּשָׁלַיִם כֹּל יְמֵי חַיֶּיךָ: וּרְאֵה בָנִים לְבָנֶיךָ, שָׁלוֹם עַל יִשְׂרָאֵל:\n\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:","cond":[]},{"kind":"header","text":"המפיל","cond":[]},{"kind":"instruction","text":"ברכת המפיל","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּפִּיל חֶבְלֵי שֵׁנָה עַל עֵינָי וּתְנוּמָה עַל עַפְעַפָּי. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּשְׁכִּיבֵנִי לְשָׁלוֹם וְתַעֲמִידֵנִי לְשָׁלוֹם, וְאַל יְבַהֲלוּנִי רַעֲיוֹנַי וַחֲלוֹמוֹת רָעִים וְהִרְהוּרִים רָעִים, וּתְהֵא מִטָּתִי שְׁלֵמָה לְפָנֶיךָ, וְהָאֵר עֵינַי פֶּן אִישַׁן הַמָּוֶת, כִּי אַתָּה הַמֵּאִיר לְאִישׁוֹן בַּת עַיִן. בָּרוּךְ אַתָּה יהוה, הַמֵּאִיר לָעוֹלָם כֻּלוֹ בִּכְבוֹדוֹ.","cond":[]}],"sfard":[{"kind":"text","text":"הֲרֵינִי מוֹחֵל לְכָל מִי שֶׁהִכְעִיס וְהִקְנִיט אוֹתִי, אוֹ שֶׁחָטָא כְּנֶגְדִּי בֵּין בְּגוּפִי בֵּין בְּמָמוֹנִי בֵּין בִּכְבוֹדִי בֵּין בְּכָל אֲשֶׁר לִי, בֵּין בְּאֹנֶס, בֵּין בְּרָצוֹן, בֵּין בְּשׁוֹגֵג, בֵּין בְּמֵזִיד, בֵּין בְּדִבּוּר בֵּין בְּמַעֲשֶׂה, וְלֹא יֵעָנֵשׁ שׁוּם אָדָם בְּסִבָּתִי..","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"header","text":"ויהי נעם","cond":[]},{"kind":"text","text":"וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: יֹשֵׁב בְּסֵתֶר עֶלְיוֹן בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי, עֶלְיוֹן שַׂמְתָּ מְעוֹנֶךָ: לֹא תְאֻנֶּה אֵלֶיךָ רָעָה, וְנֶגַע לֹא יִקְרַב בְּאָהֳלֶךָ: כִּי מַלְאָכָיו יְצַוֶּה לָּךְ, לִשְׁמָרְךָ בְּכָל דְּרָכֶיךָ: עַל כַּפַּיִם יִשָּׂאוּנְךָ, פֶּן תִּגֹּף בָּאֶבֶן רַגְלֶךָ: עַל שַׁחַל וָפֶתֶן תִּדְרֹךְ, תִּרְמֹס כְּפִיר וְתַנִּין: כִּי בִי חָשַׁק וַאֲפַלְּטֵהוּ, אֲשַׂגְּבֵהוּ כִּי יָדַע שְׁמִי: יִקְרָאֵנִי וְאֶעֱנֵהוּ, עִמּוֹ אָנֹכִי בְצָרָה, אֲחַלְּצֵהוּ וַאֲכַבְּדֵהוּ: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי: אֹרֶךְ יָמִים אַשְׂבִּיעֵהוּ, וְאַרְאֵהוּ בִּישׁוּעָתִי:","cond":[]},{"kind":"text","text":"יהוה, מָה רַבּוּ צָרָי, רַבִּים קָמִים עָלָי: רַבִּים אֹמְרִים לְנַפְשִׁי אֵין יְשׁוּעָתָה לּוֹ בֵאלֹהִים סֶלָה: וְאַתָּה יהוה מָגֵן בַּעֲדִי, כְּבוֹדִי וּמֵרִים רֹאשִׁי: קוֹלִי אֶל יהוה אֶקְרָא, וַיַּעֲנֵנִי מֵהַר קָדְשׁוֹ סֶלָה: אֲנִי שָׁכַבְתִּי וָאִישָׁנָה, הֱקִיצוֹתִי כִּי יהוה יִסְמְכֵנִי: לֹא אִירָא מֵרִבְבוֹת עָם, אֲשֶׁר סָבִיב שָׁתוּ עָלָי: קוּמָה יהוה הוֹשִׁיעֵנִי אֱלֹהַי, כִּי הִכִּיתָ אֶת כָּל אֹיְבַי לֶחִי, שִׁנֵּי רְשָׁעִים שִׁבַּרְתָּ: לַיהוה הַיְשׁוּעָה עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה:\n\nהַשְׁכִּיבֵנוּ יהוה אֱלֹהֵינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ מְהֵרָה לְמַעַן שְׁמֶךָ. וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ אוֹיֵב, דֶּבֶר וְחֶרֶב וְרָעָב וְיָגוֹן. וְהָסֵר שָׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ, כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אָתָּה, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה. וּשְׁמוֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם.\n\nבָּרוּךְ יהוה בַּיּוֹם. בָּרוּךְ יהוה בַּלָּיְלָה. בָּרוּךְ יהוה בְּשָׁכְבֵנוּ. בָּרוּךְ יהוה בְּקוּמֵנוּ. כִּי בְיָדְךָ נַפְשׁוֹת הַחַיִּים וְהַמֵּתִים. אֲשֶׁר בְּיָדוֹ נֶפֶשׁ כָּל חָי וְרוּחַ כָּל בְּשָׂר אִישׁ: בְּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת: אֱלֹהֵינוּ שֶׁבַּשָּׁמַיִם, יַחֵד שִׁמְךָ וְקַיֵּם מַלְכוּתְךָ תָּמִיד, וּמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\n\nיִרְאוּ עֵינֵינוּ וְיִשְׂמַח לִבֵּנוּ וְתָגֵל נַפְשֵׁנוּ בִּישׁוּעָתְךָ בֶּאֱמֶת בֶּאֱמֹר לְצִיּוֹן מָלַךְ אֱלֹהָיִךְ. יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלךְ בְּכָבוֹד, כִּי אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\n\nהַמַּלְאָךְ הַגֹּאֵל אֹתִי מִכָּל רָע יְבָרֵךְ אֶת הַנְּעָרִים, וְיִקָּרֵא בָהֶם שְׁמִי וְשֵׁם אֲבֹתַי, אַבְרָהָם וְיִצְחָק, וְיִדְגּוּ לָרֹב בְּקֶרֶב הָאָרֶץ:\n\nוַיֹּאמֶר אִם שָׁמוֹעַ תִּשְׁמַע לְקוֹל יהוה אֱלֹהֶיךָ וְהַיָּשָׁר בְּעֵינָיו תַּעֲשֶׂה, וְהַאֲזַנְתָּ לְמִצְוׂתָיו וְשָׁמַרְתָּ כָּל חֻקָּיו, כָּל הַמַּחֲלָה אֲשֶׁר שַׂמְתִּי בְמִצְרַיִם לֹא אָשִׂים עָלֶיךָ, כִּי אֲנִי יהוה רֹפְאֶךָ: וַיֹּאמֶר יהוה אֶל הַשָּׂטָן, יִגְעַר יהוה בְּךָ הַשָּׂטָן, וְיִגְעַר יהוה בְּךָ הַבֹּחֵר בִּירוּשָׁלַיִם, הֲלוֹא זֶה אוּד מֻצָּל מֵאֵשׁ: הִנֵּה מִטָּתוֹ שֶׁלִּשְׁלֹמֹה, שִׁשִּׁים גִּבֹּרִים סָבִיב לָהּ, מִגִּבֹּרֵי יִשְׂרָאֵל: כֻּלָּם אֲחֻזֵי חֶרֶב, מְלֻמְּדֵי מִלְחָמָה, אִישׁ חַרְבּוֹ עַל יְרֵכוֹ מִפַּחַד בַּלֵּילוֹת:\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ, וְיָשֵׂם לְךָ שָׁלוֹם:\n\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\nהִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשׂרָאֵל:\n\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: קִוִּיתִי יהוה לִישׁוּעָתְךָ. יהוה לִישׁוּעָתְךָ קִוִּיתִי.\n\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\nבְּשֵׁם יהוה אֱלֹהֵי יִשְׂרָאֵל, מִימִינִי מִיכָאֵל, וּמִשְּׂמֹאלִי גַּבְרִיאֵל, וּמִלְּפָנַי אוּרִיאֵל, וּמֵאֲחוֹרַי רְפָאֵל, וְעַל רֹאשִׁי שְׁכִינַת אֵל.\n\n\nשִׁיר הַמַּעֲלוֹת, אַשְׁרֵי כָּל יְרֵא יהוה, הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל, אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פּוֹרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִילֵי זֵיתִים סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִּי כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן, וּרְאֵה בְּטוּב יְרוּשָׁלַיִם כֹּל יְמֵי חַיֶּיךָ: וּרְאֵה בָנִים לְבָנֶיךָ, שָׁלוֹם עַל יִשְׂרָאֵל:\n\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:\nרִגְזוּ וְאַל תֶּחֱטָאוּ, אִמְרוּ בִלְבַבְכֶם עַל מִשְׁכַּבְכֶם וְדֹמּוּ סֶלָה:","cond":[]},{"kind":"header","text":"המפיל","cond":[]},{"kind":"instruction","text":"ברכת המפיל","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּפִּיל חֶבְלֵי שֵׁנָה עַל עֵינָי וּתְנוּמָה עַל עַפְעַפָּי וּמֵּאִיר לְאִישׁוֹן בַּת עַיִן. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּשְׁכִּיבֵנִי לְשָׁלוֹם וְתַעֲמִידֵנִי לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וְאַל יְבַהֲלוּנִי רַעֲיוֹנַי וַחֲלוֹמוֹת רָעִים וְהִרְהוּרִים רָעִים, וּתְהֵא מִטָּתִי שְׁלֵמָה לְפָנֶיךָ, וְהָאֵר עֵינַי פֶּן אִישַׁן הַמָּוֶת. בָּרוּךְ אַתָּה יהוה, הַמֵּאִיר לָעוֹלָם כֻּלוֹ בִּכְבוֹדוֹ.","cond":[]}],"edot_mizrach":[{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מְקַבֵּל עָלַי אֱלָהוּתוּ יִתְבָּרַךְ וְאַהֲבָתוֹ וְיִרְאָתוֹ, וְהֲרֵינִי יָרֵא מִמֶנּוּ, בְּגִין דְּאִיהוּ רַב וְשַׁלִּיט עַל כֹּלָא, וְכֹלָּא קַמֵּהּ כְּלָא. וַהֲרֵינִי מַמְלִיכוֹ עַל כָּל אֵבֶר וְאֵבֶר וְגִיד וְגִיד מֵרַמַ\"ח אֵבָרִים וּשְׁסָ\"ה גִידִים שֶׁל גּוּפִי וְנַפְשִׁי רוּחִי וְנִשְׁמָתִי, מַלְכוּת גְּמוּרָה וּשְׁלֵמָה. וַהֲרֵינִי עֶבֶד לַשֵּׁם יִתְבָּרַךְ, וְהוּא בְרַחֲמָיו יְזַכֵּנִי לְעָבְדוֹ בְלֵב שָׁלֵם וְנֶפֶשׁ חֲפֵצָה. אָמֵן כֵּן יְהִי רָצוֹן.\n\nרִבּוֹנוֹ שֶׁל עוֹלָם, הֲרֵינִי מוֹחֵל וְסוֹלֵחַ לְכָל מִי שֶׁהִכְעִיס וְהִקְנִיט אוֹתִי, אוֹ שֶׁחָטָא כְּנֶגְדִּי, בֵּין בְּגוּפִי, בֵּין בְּמָמוֹנִי, בֵּין בִּכְבוֹדִי, בֵּין בְּכָל אֲשֶׁר לִי, בֵּין בְּאֹנֶס בֵּין בְּרָצוֹן, בֵּין בְּשׁוֹגֵג בֵּין בְּמֵזִיד, בֵּין בְּדִבּוּר בֵּין בְּמַעֲשֶׂה, בֵּין בְּגִלְגּוּל זֶה בֵּין בְּגִלְגּוּל אַחֵר, לְכָל בַּר יִשְׂרָאֵל, וְלֹא יֵעָנֵשׁ שׁוּם אָדָם בְּסִבָּתִי. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁלֹּא אֶחֱטָא עוֹד, וּמַה שֶּׁחָטָאתִי לְפָנֶיךָ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים, אֲבָל לֹא עַל יְדֵי יִסּוּרִין וָחֳלָאִים רָעִים. יִהְיוּ לְרָצוֹן אִמְרֵי פִי וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגֹאֲלִי:","cond":[]},{"kind":"instruction","text":"אם ישן אחר חצות לילה, יאמר ברכת \"המפיל\" ללא שם ומלכות, ויהרהר שם ומלכות בלבו:","cond":[]},{"kind":"header","text":"המפיל","cond":[]},{"kind":"text","text":"בָּרוּךְ [אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם,] הַמַּפִּיל חֶבְלֵי שֵׁנָה עַל עֵינַי, וּתְנוּמָה עַל עַפְעַפַּי, וּמֵאִיר לְאִישׁוֹן בַּת עָיִן. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתַּשְׁכִּיבֵנִי לְשָׁלוֹם, וְתַעֲמִידֵנִי לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וְתֵן חֶלְקִי בְּתוֹרָתֶךָ, וְתַרְגִּילֵנִי לִדְבַר מִצְוָה, וְאַל תַּרְגִּילֵנִי לִדְבַר עֲבֵרָה, וְאַל תְּבִיאֵנִי לִידֵי חֵטְא, וְלֹא לִידֵי נִסָּיוֹן, וְלֹא לִידֵי בִזָּיוֹן, וְיִשְׁלֹט בִּי יֵצֶר הַטּוֹב, וְאַל יִשְׁלֹט בִּי יֵצֶר הָרָע, וְתַצִּילֵנִי מִיֵּצֶר הָרָע וּמֵחֳלָאִים רָעִים, וְאַל יַבְהִילוּנִי חֲלוֹמוֹת רָעִים וְהִרְהוּרִים רָעִים, וּתְהֵא מִטָּתִי שְׁלֵמָה לְפָנֶיךָ, וְהָאֵר עֵינַי פֶּן אִישַׁן הַמָּוֶת. בָּרוּךְ [אַתָּה יהוה,] הַמֵּאִיר לָעוֹלָם כֻּלּוֹ בִּכְבוֹדוֹ.","cond":[]},{"kind":"instruction","text":"יש אומרים:\n\nהַשְׁכִּיבֵנוּ אָבִינוּ לְשָׁלוֹם, וְהַעֲמִידֵנוּ מַלְכֵּנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם, וּפְרֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמֶךָ, וְתַקְּנֵנוּ מַלְכֵּנוּ בְּעֵצָה טוֹבָה מִלְּפָנֶיךָ, וְהוֹשִׁיעֵנוּ מְהֵרָה לְמַעַן שְׁמְךָ, וְהָגֵן בַּעֲדֵנוּ, וְהָסֵר מֵעָלֵינוּ מַכַּת אוֹיֵב, דֶּבֶר, חֶרֶב, חֹלִי, צָרָה, רָעָה, רָעָב, וְיָגוֹן וּמַשְׁחִית וּמַגֵּפָה. שְׁבֹר וְהָסֵר הַשָּׂטָן מִלְּפָנֵינוּ וּמֵאַחֲרֵינוּ, וּבְצֵל כְּנָפֶיךָ תַּסְתִּירֵנוּ, וּשְׁמֹר צֵאתֵנוּ וּבוֹאֵנוּ לְחַיִּים טוֹבִים וּלְשָׁלוֹם מֵעַתָּה וְעַד עוֹלָם. כִּי אֵל שׁוֹמְרֵנוּ וּמַצִּילֵנוּ אַתָּה מִכָּל דָּבָר רָע וּמִפַּחַד לָיְלָה. בָּרוּךְ שׁוֹמֵר אֶת עַמּוֹ יִשְׂרָאֵל לָעַד.","cond":[]},{"kind":"header","text":"קריאת שמע","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\nוְאָהַבְתָּ אֵת יהוה אֱלֹהֶיךָ, בְּכָל לְבָבְךָ וּבְכָל נַפְשְׁךָ וּבְכָל מְאֹדֶךָ: וְהָיוּ הַדְּבָרִים הָאֵלֶּה אֲשֶׁר אָנֹכִי מְצַוְּךָ הַיּוֹם, עַל לְבָבֶךָ: וְשִׁנַּנְתָּם לְבָנֶיךָ וְדִבַּרְתָּ בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּקְשַׁרְתָּם לְאוֹת עַל יָדֶךָ, וְהָיוּ לְטֹטָפֹת בֵּין עֵינֶיךָ: וּכְתַבְתָּם עַל מְזֻזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ:","cond":[]},{"kind":"text","text":"וְהָיָה אִם שָׁמֹעַ תִּשְׁמְעוּ אֶל מִצְוׂתַי, אֲשֶׁר אָנֹכִי מְצַוֶּה אֶתְכֶם הַיּוֹם, לְאַהֲבָה אֶת יהוה אֱלֹהֵיכֶם וּלְעָבְדוֹ, בְּכָל לְבַבְכֶם וּבְכָל נַפְשְׁכֶם: וְנָתַתִּי מְטַר אַרְצְכֶם בְּעִתּוֹ, יוֹרֶה וּמַלְקוֹשׁ, וְאָסַפְתָּ דְגָנֶךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ: וְנָתַתִּי עֵשֶׂב בְּשָׂדְךָ לִבְהֶמְתֶּךָ, וְאָכַלְתָּ וְשָׂבָעְתָּ: הִשָּׁמְרוּ לָכֶם פֶּן יִפְתֶּה לְבַבְכֶם, וְסַרְתֶּם וַעֲבַדְתֶּם אֱלֹהִים אֲחֵרִים וְהִשְׁתַּחֲוִיתֶם לָהֶם: וְחָרָה אַף יהוה בָּכֶם, וְעָצַר אֶת הַשָּׁמַיִם וְלֹא יִהְיֶה מָטָר, וְהָאֲדָמָה לֹא תִתֵּן אֶת יְבוּלָהּ, וַאֲבַדְתֶּם מְהֵרָה מֵעַל הָאָרֶץ הַטֹּבָה אֲשֶׁר יהוה נֹתֵן לָכֶם: וְשַׂמְתֶּם אֶת דְּבָרַי אֵלֶּה עַל לְבַבְכֶם וְעַל נַפְשְׁכֶם, וּקְשַׁרְתֶּם אֹתָם לְאוֹת עַל יֶדְכֶם וְהָיוּ לְטוֹטָפֹת בֵּין עֵינֵיכֶם: וְלִמַּדְתֶּם אֹתָם אֶת בְּנֵיכֶם לְדַבֵּר בָּם, בְּשִׁבְתְּךָ בְּבֵיתֶךָ וּבְלֶכְתְּךָ בַדֶּרֶךְ וּבְשָׁכְבְּךָ וּבְקוּמֶךָ: וּכְתַבְתָּם עַל מְזוּזוֹת בֵּיתֶךָ וּבִשְׁעָרֶיךָ: לְמַעַן יִרְבּוּ יְמֵיכֶם וִימֵי בְנֵיכֶם עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע יהוה לַאֲבֹתֵיכֶם לָתֵת לָהֶם, כִּימֵי הַשָּׁמַיִם עַל הָאָרֶץ:","cond":[]},{"kind":"text","text":"וַיֹּאמֶר יהוה אֶל מֹשֶׁה לֵּאמֹר: דַּבֵּר אֶל בְּנֵי יִשְׂרָאֵל וְאָמַרְתָּ אֲלֵהֶם, וְעָשׂוּ לָהֶם צִיצִת עַל כַּנְפֵי בִגְדֵיהֶם לְדֹרֹתָם, וְנָתְנוּ עַל צִיצִת הַכָּנָף פְּתִיל תְּכֵלֶת: וְהָיָה לָכֶם לְצִיצִת, וּרְאִיתֶם אֹתוֹ, וּזְכַרְתֶּם אֶת כָּל מִצְוׂת יהוה וַעֲשִׂיתֶם אֹתָם, וְלֹא תָתֻרוּ אַחֲרֵי לְבַבְכֶם וְאַחֲרֵי עֵינֵיכֶם אֲשֶׁר אַתֶּם זֹנִים אַחֲרֵיהֶם: לְמַעַן תִּזְכְּרוּ וַעֲשִׂיתֶם אֶת כָּל מִצְוׂתָי, וִהְיִיתֶם קְדֹשִׁים לֵאלֹהֵיכֶם: אֲנִי יהוה אֱלֹהֵיכֶם אֲשֶׁר הוֹצֵאתִי אֶתְכֶם מֵאֶרֶץ מִצְרַיִם, לִהְיוֹת לָכֶם לֵאלֹהִים, אֲנִי יהוה אֱלֹהֵיכֶם:","cond":[]},{"kind":"text","text":"יהוה אֱלֹהֵיכֶם: אֱמֶת.\n\nיַעְלְזוּ חֲסִידִים בְּכָבוֹד, יְרַנְּנוּ עַל מִשְׁכְּבוֹתָם: רוֹמְמוֹת אֵל בִּגְרוֹנָם, וְחֶרֶב פִּיפִיּוֹת בְּיָדָם:\n\nהִנֵּה מִטָּתוֹ שֶׁלִּשְׁלֹמֹה שִׁשִּׁים גִּבֹּרִים סָבִיב לָהּ, מִגִּבֹּרֵי יִשְׂרָאֵל: כֻּלָּם אֲחֻזֵי חֶרֶב מְלֻמְּדֵי מִלְחָמָה, אִישׁ חַרְבּוֹ עַל יְרֵכוֹ מִפַּחַד בַּלֵּילוֹת:\nהִנֵּה מִטָּתוֹ שֶׁלִּשְׁלֹמֹה שִׁשִּׁים גִּבֹּרִים סָבִיב לָהּ, מִגִּבֹּרֵי יִשְׂרָאֵל: כֻּלָּם אֲחֻזֵי חֶרֶב מְלֻמְּדֵי מִלְחָמָה, אִישׁ חַרְבּוֹ עַל יְרֵכוֹ מִפַּחַד בַּלֵּילוֹת:\nהִנֵּה מִטָּתוֹ שֶׁלִּשְׁלֹמֹה שִׁשִּׁים גִּבֹּרִים סָבִיב לָהּ, מִגִּבֹּרֵי יִשְׂרָאֵל: כֻּלָּם אֲחֻזֵי חֶרֶב מְלֻמְּדֵי מִלְחָמָה, אִישׁ חַרְבּוֹ עַל יְרֵכוֹ מִפַּחַד בַּלֵּילוֹת:\n\nיְבָרֶכְךָ יהוה וְיִשְׁמְרֶךָ: יָאֵר יהוה פָּנָיו אֵלֶיךָ וִיחֻנֶּךָּ: יִשָׂא יהוה פָּנָיו אֵלֶיךָ וְיָשֵׂם לְךָ שָׁלוֹם:\n\nאִם תִּשְׁכַּב לֹא תִפְחָד וְשָׁכַבְתָּ וְעָרְבָה שְׁנָתֶךָ: שָׁמְרֵנִי כְּאִישׁוֹן בַּת עָיִן בְּצֵל כְּנָפֶיךָ תַּסְתִּירֵנִי: אֲנִי שָׁכַבְתִּי וָאִישָׁנָה, הֱקִיצוֹתִי כִּי יהוה יִסְמְכֵנִי: בְּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת:\n\nיֹשֵׁב בְּסֵתֶר עֶלְיוֹן, בְּצֵל שַׁדַּי יִתְלוֹנָן: אֹמַר לַיהוה מַחְסִי וּמְצוּדָתִי, אֱלֹהַי אֶבְטַח בּוֹ: כִּי הוּא יַצִּילְךָ מִפַּח יָקוּשׁ, מִדֶּבֶר הַוּוֹת: בְּאֶבְרָתוֹ יָסֶךְ לָךְ, וְתַחַת כְּנָפָיו תֶּחְסֶה, צִנָּה וְסֹחֵרָה אֲמִתּוֹ: לֹא תִירָא מִפַּחַד לָיְלָה, מֵחֵץ יָעוּף יוֹמָם: מִדֶּבֶר בָּאֹפֶל יַהֲלֹךְ, מִקֶּטֶב יָשׁוּד צָהֳרָיִם: יִפֹּל מִצִּדְּךָ אֶלֶף, וּרְבָבָה מִימִינֶךָ, אֵלֶיךָ לֹא יִגָּשׁ: רַק בְּעֵינֶיךָ תַבִּיט, וְשִׁלֻּמַת רְשָׁעִים תִּרְאֶה: כִּי אַתָּה יהוה מַחְסִי.","cond":[]},{"kind":"instruction","text":"יעמוד ויאמר ודוי, ואם עשה איזה עון באותו היום יתחרט ויתודה עליו בלב נשבר ובדמעה ויקבל עליו שלא יעשהו עוד, ואם ככה הוא עושה אשריו ואשרי חלקו. וביום שאין אומרים בו תחנון לא יאמר וידוי, וגם לא בלילה שלאחריו עד חצות הלילה:","cond":["shacharitTachanun"]},{"kind":"header","text":"וידוי","cond":["shacharitTachanun"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:","cond":["shacharitTachanun"]},{"kind":"header","text":"אנא בכח","cond":[]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":[]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":[]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":[]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":[]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":[]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":[]},{"kind":"text","text":"שַׁוְעָתֵנוּ קַבֵּל, וּשְׁמַע צַעֲקָתֵנוּ, יוֹדֵעַ תַּעֲלוּמוֹת (שק\"ו צי\"ת).","cond":[]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["sun"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["mon"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["tue"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["wed"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["thu"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["fri"]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["sun"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["mon"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["tue"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["wed"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["thu"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["fri"]},{"kind":"text","text":"אָנָּא, בְּכֹחַ גְּדֻלַּת יְמִינְךָ, תַּתִּיר צְרוּרָה (אב\"ג ית\"ץ).","cond":["sun"]},{"kind":"text","text":"קַבֵּל רִנַּת עַמְּךָ, שַׂגְּבֵנוּ, טַהֲרֵנוּ, נוֹרָא (קר\"ע שט\"ן).","cond":["mon"]},{"kind":"text","text":"נָא גִּבּוֹר, דּוֹרְשֵׁי יִחוּדֶךָ, כְּבָבַת שָׁמְרֵם (נג\"ד יכ\"ש).","cond":["tue"]},{"kind":"text","text":"בָּרְכֵם, טַהֲרֵם, רַחֲמֵי צִדְקָתְךָ תָּמִיד גָּמְלֵם (בט\"ר צת\"ג).","cond":["wed"]},{"kind":"text","text":"חָסִין קָדוֹשׁ, בְּרֹב טוּבְךָ נַהֵל עֲדָתֶךָ (חק\"ב טנ\"ע).","cond":["thu"]},{"kind":"text","text":"יָחִיד גֵּאֶה, לְעַמְּךָ פְנֵה, זוֹכְרֵי קְדֻשָּׁתֶךָ (יג\"ל פז\"ק).","cond":["fri"]},{"kind":"instruction","text":"בלחש:","cond":[]},{"kind":"text","text":"בָּרוּךְ שֵׁם כְּבוֹד מַלְכוּתוֹ לְעוֹלָם וָעֶד.\n\n\nאַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ, כִּי בָא מוֹעֵד: בּיָדְךָ אַפְקִיד רוּחִי, פָּדִיתָה אוֹתִי יהוה אֵל אֱמֶת: בְּטוֹב אָלִין וְאָקִיץ בְּרַחֲמִים:","cond":[]},{"kind":"instruction","text":"ויאמר פסוק זה ויחזור עליו עד שיירדם:","cond":[]},{"kind":"text","text":"תּוֹרָה צִוָּה לָנוּ מֹשֶׁה, מוֹרָשָׁה קְהִלַּת יַעֲקֹב:","cond":[]}]}},{"id":"kiddush_levana","title":"קידוש לבנה","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"instruction","text":"קידוש לבנה לאשכנזים משלשה ימים מעת לעת מזמן המולד ועד יום ט\"ו בחודש.","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם, וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהוה כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר:","cond":[]},{"kind":"instruction","text":"ישים פניו למזרח ויישר רגליו ויראה ראיה אחת בפני הלבנה קודם שיתחיל לברך ואח\"כ לא יביט בה כלל:","cond":[]},{"kind":"header","text":"ברכת הלבנה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בְּמַאֲמָרוֹ בָּרָא שְׁחָקִים, וּבְרוּחַ פִּיו כָּל צְבָאָם, חֹק וּזְמַן נָתַן לָהֶם שֶׁלּא יְשַׁנּוּ אֶת תַּפְקִידָם, שָׂשִׂים וּשְׂמֵחִים לַעֲשׂוֹת רְצוֹן קוֹנָם, פּוֹעֵל אֱמֶת שֶׁפְּעֻלָּתוֹ אֱמֶת, וְלַלְּבָנָה אָמַר שֶׁתִּתְחַדֵּשׁ, עֲטֶרֶת תִּפְאֶרֶת לַעֲמוּסֵי בָטֶן שֶׁהֵם עֲתִידִים לְהִתְחַדֵּשׁ כְּמוֹתָהּ, וּלְפָאֵר לְיוֹצְרָם עַל שֵׁם כְּבוֹד מַלְכוּתו. בָּרוּךְ אַתָּה יהוה, מְחַדֵּשׁ חֳדָשִׁים.\n\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.\n\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\n\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\n\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.","cond":[]},{"kind":"instruction","text":"ואומר לחבירו ג\"פ:","cond":[]},{"kind":"text","text":"שָׁלוֹם עֲלֵיכֶם.","cond":[]},{"kind":"instruction","text":"וחבירו משיבו ג\"פ:","cond":[]},{"kind":"text","text":"עֲלֵיכֶם שָׁלוֹם.\n\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\n\nקוֹל דּוֹדִי הִנֵּה זֶה בָּא, מְדַלֵּג עַל הֶהָרִים, מְקַפֵּץ עַל הַגְּבָעוֹת: דּוֹמֶה דוֹדִי לִצְבִי אוֹ לְעֹפֶר הָאַיָּלִים, הִנֵּה זֶה עוֹמֵד אַחַר כָּתְלֵנוּ, מַשְׁגִּיחַ מִן הַחַלּוֹנוֹת, מֵצִיץ מִן הַחֲרַכִּים:\n\nשִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה, וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:\n\nהַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:\n\nתָּנָא דְבֵי רַבִּי יִשְׁמָעֵאל: אִלְמָלֵי לֹא זָכוּ יִשְׂרָאֵל אֶלָּא לְהַקְבִּיל פְּנֵי אֲבִיהֶם שֶׁבַּשָׁמַיִם פַּעַם אַחַת בַּחֹדֶשׁ דַּיָם. אָמַר אַבַּיֵי: הִלְכָּךְ צָרִיךְ לְמֵימְרָא מְעוּמָד. מִי זֹאת עולָה מִן הַמִּדְבָּר מִתְרַפֶּקֶת עַל דּוֹדָהּ. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, לְמַלֹּאת פְּגִימַת הַלְּבָנָה וְלֹא יִהְיֶה בָּהּ שׁוּם מִעוּט, וִיהִי אוֹר הַלְּבָנָה כְּאוֹר הַחַמָּה וּכְאוֹר שִׁבְעַת יְמֵי בְרֵאשִׁית, כְּמו שֶׁהָיְתָה קוֹדֶם מִעוּטָהּ, שֶׁנֶּאֱמַר: אֶת שְׁנֵי הַמְּאֹרוֹת הַגְּדוֹלִים, וְיִתְקַיֶם בָּנוּ מִקְרָא שֶׁכָּתוּב: וּבִקְשׁוּ אֶת יהוה אֱלֹהֵיהֶם וְאֵת דָּוִד מַלְכָּם. אָמֵן.\n\nלַמְנַצֵּח בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי תִשְׁפֹּט עַמִּים מִישׁוֹר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אֹתוֹ כָּל אַפְסֵי אָרֶץ:","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ, כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"יש מזמרים:","cond":[]},{"kind":"text","text":"טוֹבִים מְאוֹרוֹת שֶׁבְּרָא אֱלֹהֵינוּ, יְצָרָם בְּדַעַת בְּבִינָה וּבְהַשְׂכֵּל.\nכֹּחַ וּגְבוּרָה נָתַן בָּהֶם, לִהְיוֹת מוֹשְׁלִים בְּקֶרֶב תֵּבֵל.\n\nמְלֵאִים זִיו וּמְפִיקִים נֹגַהּ, נָאֶה זִיוָם בְּכָל הָעוֹלָם.\nשְׂמֵחִים בְּצֵאתָם וְשָׂשִׂים בְּבֹאָם, עוֹשִׂים בְּאֵימָה רְצוֹן קוֹנָם.\n\nפְּאֵר וְכָבוֹד נוֹתְנִים לִשְׁמוֹ, צָהֳלָה וְרִנָּה לְזֵכֶר מַלְכוּתוֹ.\nקָרָא לַשֶּׁמֶשׁ וַיִּזְרַח אוֹר, רָאָה וְהִתְקִין צוּרַת הַלְּבָנָה.","cond":[]}],"sfard":[{"kind":"instruction","text":"קידוש לבנה לאשכנזים משלשה ימים מעת לעת מזמן המולד ועד יום ט\"ו בחודש.","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם, וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהוה כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר:\n\nהריני מוכן ומזומן לקים המצוה לקדש הלבנה. לשם יחוד קודשא בריך הוא ושכינתיה על ידי ההוא טמיר ונעלם בשם כל ישראל:","cond":[]},{"kind":"instruction","text":"ישים פניו למזרח ויישר רגליו ויראה ראיה אחת בפני הלבנה קודם שיתחיל לברך ואח\"כ לא יביט בה כלל:","cond":[]},{"kind":"header","text":"ברכת הלבנה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בְּמַאֲמָרוֹ בָּרָא שְׁחָקִים, וּבְרוּחַ פִּיו כָּל צְבָאָם, חֹק וּזְמַן נָתַן לָהֶם שֶׁלּא יְשַׁנּוּ אֶת תַּפְקִידָם, שָׂשִׂים וּשְׂמֵחִים לַעֲשׂוֹת רְצוֹן קוֹנָם, פּוֹעֵל אֱמֶת שֶׁפְּעֻלָּתוֹ אֱמֶת, וְלַלְּבָנָה אָמַר שֶׁתִּתְחַדֵּשׁ, עֲטֶרֶת תִּפְאֶרֶת לַעֲמוּסֵי בָטֶן שֶׁהֵם עֲתִידִים לְהִתְחַדֵּשׁ כְּמוֹתָהּ, וּלְפָאֵר לְיוֹצְרָם עַל שֵׁם כְּבוֹד מַלְכוּתו. בָּרוּךְ אַתָּה יהוה, מְחַדֵּשׁ חֳדָשִׁים.\n\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.\nבָּרוּךְ יוצְרֵךְ בָּרוּךְ עוֹשֵׂךְ בָּרוּךְ קוֹנֵךְ בָּרוּךְ בּוֹרְאֵךְ.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.","cond":[]},{"kind":"instruction","text":"רוקד ואומר","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁאֲנִי רוֹקֵד כְּנֶגְדֵּךְ וְאֵינִי יָכוֹל לִנְגוֹעַ בָּךְ כַּךְ לֹא יוּכְלוּ כָּל אוֹיְבַי לִנְגוֹעַ בִּי לְרָעָה.\n\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\nתִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן.\n\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\nכָּאָבֶן יִדְּמוּ זְרוֹעֲךָ בִּגְדֹל וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\n\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.","cond":[]},{"kind":"instruction","text":"ואומר לחבירו ג\"פ:","cond":[]},{"kind":"text","text":"שָׁלוֹם עֲלֵיכֶם.","cond":[]},{"kind":"instruction","text":"וחבירו משיבו ג\"פ:","cond":[]},{"kind":"text","text":"עֲלֵיכֶם שָׁלוֹם.\n\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\nסִמָּן טוֹב וּמַזָּל טוֹב יְהֵא לָנוּ וּלְכָל יִשְׂרָאֵל אָמֵן.\n\nקוֹל דּוֹדִי הִנֵּה זֶה בָּא, מְדַלֵּג עַל הֶהָרִים, מְקַפֵּץ עַל הַגְּבָעוֹת: דּוֹמֶה דוֹדִי לִצְבִי אוֹ לְעֹפֶר הָאַיָּלִים, הִנֵּה זֶה עוֹמֵד אַחַר כָּתְלֵנוּ, מַשְׁגִּיחַ מִן הַחַלּוֹנוֹת, מֵצִיץ מִן הַחֲרַכִּים:\n\nשִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה, וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:\n\nהַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:\n\nתָּנָא דְבֵי רַבִּי יִשְׁמָעֵאל: אִלְמָלֵי לֹא זָכוּ יִשְׂרָאֵל אֶלָּא לְהַקְבִּיל פְּנֵי אֲבִיהֶם שֶׁבַּשָׁמַיִם פַּעַם אַחַת בַּחֹדֶשׁ דַּיָם. אָמַר אַבַּיֵי: הִלְכָּךְ צָרִיךְ לְמֵימְרָא מְעוּמָד. מִי זֹאת עולָה מִן הַמִּדְבָּר מִתְרַפֶּקֶת עַל דּוֹדָהּ. וִיהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, לְמַלֹּאת פְּגִימַת הַלְּבָנָה וְלֹא יִהְיֶה בָּהּ שׁוּם מִעוּט, וִיהִי אוֹר הַלְּבָנָה כְּאוֹר הַחַמָּה וּכְאוֹר שִׁבְעַת יְמֵי בְרֵאשִׁית, כְּמו שֶׁהָיְתָה קוֹדֶם מִעוּטָהּ, שֶׁנֶּאֱמַר: אֶת שְׁנֵי הַמְּאֹרוֹת הַגְּדוֹלִים, וְיִתְקַיֶם בָּנוּ מִקְרָא שֶׁכָּתוּב: וּבִקְשׁוּ אֶת יהוה אֱלֹהֵיהֶם וְאֵת דָּוִד מַלְכָּם. אָמֵן.\n\nלַמְנַצֵּח בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי תִשְׁפֹּט עַמִּים מִישׁוֹר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אֹתוֹ כָּל אַפְסֵי אָרֶץ:","cond":[]},{"kind":"instruction","text":"וינער שולי הציצית.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם[, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ]. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ. כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"וְעַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"יש מזמרים:","cond":[]},{"kind":"text","text":"טוֹבִים מְאוֹרוֹת שֶׁבְּרָא אֱלֹהֵינוּ, יְצָרָם בְּדַעַת בְּבִינָה וּבְהַשְׂכֵּל.\nכֹּחַ וּגְבוּרָה נָתַן בָּהֶם, לִהְיוֹת מוֹשְׁלִים בְּקֶרֶב תֵּבֵל.\n\nמְלֵאִים זִיו וּמְפִיקִים נֹגַהּ, נָאֶה זִיוָם בְּכָל הָעוֹלָם.\nשְׂמֵחִים בְּצֵאתָם וְשָׂשִׂים בְּבֹאָם, עוֹשִׂים בְּאֵימָה רְצוֹן קוֹנָם.\n\nפְּאֵר וְכָבוֹד נוֹתְנִים לִשְׁמוֹ, צָהֳלָה וְרִנָּה לְזֵכֶר מַלְכוּתוֹ.\nקָרָא לַשֶּׁמֶשׁ וַיִּזְרַח אוֹר, רָאָה וְהִתְקִין צוּרַת הַלְּבָנָה.","cond":[]}],"edot_mizrach":[{"kind":"instruction","text":"זמן ברכת הלבנה בכל חודש מתחיל משעה שנגמרו שבעה ימים מעת לעת מהמולד, ונמשך עד חצי הזמן של חודש הלבנה, דהיינו חצי מכ\"ט ימים, י\"ב שעות ותשצ\"ג חלקים. כלומר עד שיעברו ארבעה עשר ימים, ושמונה עשרה שעות ועשרים ושתיים דקות מזמן המולד. אסור לברך אם הלבנה מכוסה אפילו בענן דק. טוב להקפיד לברך דוקא במוצאי שבת.\n\nלפני הברכה נוהגים לומר:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: הַשָּׁמַיִם מְסַפְּרִים כְּבוֹד אֵל, וּמַעֲשֵׂה יָדָיו מַגִּיד הָרָקִיעַ: יוֹם לְיוֹם יַבִּיעַ אֹמֶר, וְלַיְלָה לְּלַיְלָה יְחַוֶּה דָּעַת: אֵין אֹמֶר וְאֵין דְּבָרִים בְּלִי נִשְׁמָע קוֹלָם: בְּכָל הָאָרֶץ יָצָא קַוָּם, וּבִקְצֵה תֵבֵל מִלֵּיהֶם, לַשֶּׁמֶשׁ שָׂם אֹהֶל בָּהֶם: וְהוּא כְּחָתָן יֹצֵא מֵחֻפָּתוֹ, יָשִׂישׂ כְּגִבּוֹר לָרוּץ אֹרַח: מִקְצֵה הַשָּׁמַיִם מוֹצָאוֹ, וּתְקוּפָתוֹ עַל קְצוֹתָם, וְאֵין נִסְתָּר מֵחַמָּתוֹ: תּוֹרַת יהוה תְּמִימָה מְשִׁיבַת נָפֶשׁ, עֵדוּת יהוה נֶאֱמָנָה מַחְכִּימַת פֶּתִי: פִּקּוּדֵי יהוה יְשָׁרִים מְשַׂמְּחֵי לֵב, מִצְוַת יהוה בָּרָה מְאִירַת עֵינָיִם: יִרְאַת יהוה טְהוֹרָה עוֹמֶדֶת לָעַד, מִשְׁפְּטֵי יהוה אֱמֶת, צָדְקוּ יַחְדָּו: הַנֶּחֱמָדִים מִזָּהָב וּמִפַּז רָב, וּמְתוּקִים מִדְּבַשׁ וְנֹפֶת צוּפִים: גַּם עַבְדְּךָ נִזְהָר בָּהֶם בְּשָׁמְרָם עֵקֶב רָב: שְׁגִיאוֹת מִי יָבִין, מִנִּסְתָּרוֹת נַקֵּנִי: גַּם מִזֵּדִים חֲשֹׂךְ עַבְדֶּךָ, אַל יִמְשְׁלוּ בִי, אָז אֵיתָם וְנִקֵּיתִי מִפֶּשַׁע רָב: יִהְיוּ לְרָצוֹן אִמְרֵי פִי, וְהֶגְיוֹן לִבִּי לְפָנֶיךָ, יהוה צוּרִי וְגֹאֲלִי: צוּרִי בָּעוֹלָם הַזֶּה וגוֹאֲלִי לָעוֹלָם הַבָּא. וְכָל קַרְנֵי רְשָׁעִים אֲגַדֵּעַ, תְּרוֹמַמְנָה קַרְנוֹת צַדִּיק:\n\nהַלְלוּיָהּ, הַלְלוּ אֶת יהוה מִן הַשָּׁמַיִם, הַלְלוּהוּ בַּמְּרוֹמִים: הַלְלוּהוּ כָל מַלְאָכָיו, הַלְלוּהוּ כָּל צְבָאָיו: הַלְלוּהוּ שֶׁמֶשׁ וְיָרֵחַ, הַלְלוּהוּ כָּל כּוֹכְבֵי אוֹר: הַלְלוּהוּ שְׁמֵי הַשָּׁמָיִם, וְהַמַּיִם אֲשֶׁר מֵעַל הַשָּׁמָיִם: יְהַלְלוּ אֶת שֵׁם יהֹוה, כִּי הוּא צִוָּה וְנִבְרָאוּ: וַיַּעֲמִידֵם לָעַד לְעוֹלָם, חָק נָתַן וְלֹא יַעֲבוֹר: כִּי אֶרְאֶה שָׁמֶיךָ מַעֲשֵׂה אֶצְבְּעוֹתֶיךָ, יָרֵח וְכוֹכָבִים אֲשֶׁר כּוֹנָנְתָּ: יהוה אֲדֹנֵינוּ, מָה אַדִּיר שִׁמְךָ בְּכָל הָאָרֶץ:","cond":[]},{"kind":"instruction","text":"לפני הברכה יאמר:","cond":[]},{"kind":"header","text":"ברכת הלבנה","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ וּרְחִימוּ וּדְחִילוּ, ליַחֲדָא שֵׁם אוֹת י' וְאוֹת הֵ' בּשֵם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אֲנַחְנוּ בָּאִים לְבָרֵךְ בִּרְכַּת הַלְּבָנָה, כְּמוֹ שֶׁתִּקְּנוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה, עִם כָּל הַמִּצְוׂת הַכְּלוּלוֹת בָּהּ, לְתַקֵּן אֶת שָׁרְשָׁהּ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ, וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בְּמַאֲמָרוֹ בָּרָא שְׁחָקִים וּבְרוּחַ פִּיו כָּל צְבָאָם, חֹק וּזְמַן נָתַן לָהֶם שֶׁלֹּא יְשַׁנוּ אֶת תַּפְקִידָם, שָׂשִׂים וּשְׂמֵחִים לַעֲשׂוֹת רְצוֹן קוֹנֵיהֶם, פּוֹעֵל אֱמֶת שֶׁפְּעֻלָּתוֹ אֱמֶת, וְלַלְּבָנָה אָמַר שֶׁתִּתְחַדֵּשׁ, עֲטֶרֶת תִּפְאֶרֶת לַעֲמוּסֵי בָטֶן, שֶׁגַּם הֵם עֲתִידִים לְהִתְחַדֵּשׁ כְּמוֹתָהּ וּלְפָאֵר לְיוֹצְרָם עַל שֵׁם כְּבוֹד מַלְכוּתוֹ. בָּרוּךְ אַתָּה יהוה, מְחַדֵּשׁ חֳדָשִׁים.\n\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבָּרוּךְ יוֹצְרֵךְ, בָּרוּךְ עוֹשֵׂךְ, בָּרוּךְ קוֹנֵךְ, בָּרוּךְ בּוֹראֵךְ. כְּשֵׁם שֶׁאֲנַחְנוּ מרַקְּדִים כְּנֶגְדֵּךְ, וְאֵין אֲנַחְנוּ יְכוֹלִים לִגַּע בָּךְ, כָּךְ אִם יְרַקְּדוּ אֲחֵרִים כְּנֶגְדֵּנוּ לְהַזִּיקֵנוּ, לֹא יוּכְלוּ לִגַּע בָּנוּ, וְלֹא יִשְׁלְטוּ בָנוּ, וְלֹא יַעֲשׂוּ בָנוּ שׁוּם רֹשֶׁם כְּלָל ועִקָר. תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן: כָּאָבֶן יִדְּמוּ, זְרוֹעֲךָ בִּגְדֹל, וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\n\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבָּרוּךְ יוֹצְרֵךְ, בָּרוּךְ עוֹשֵׂךְ, בָּרוּךְ קוֹנֵךְ, בָּרוּךְ בּוֹראֵךְ. כְּשֵׁם שֶׁאֲנַחְנוּ מרַקְּדִים כְּנֶגְדֵּךְ, וְאֵין אֲנַחְנוּ יְכוֹלִים לִגַּע בָּךְ, כָּךְ אִם יְרַקְּדוּ אֲחֵרִים כְּנֶגְדֵּנוּ לְהַזִּיקֵנוּ, לֹא יוּכְלוּ לִגַּע בָּנוּ, וְלֹא יִשְׁלְטוּ בָנוּ, וְלֹא יַעֲשׂוּ בָנוּ שׁוּם רֹשֶׁם כְּלָל ועִקָר. תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן: כָּאָבֶן יִדְּמוּ, זְרוֹעֲךָ בִּגְדֹל, וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\n\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבְּסִמָּן טוֹב תְּהִי לָנוּ וּלְכָל יִשְׂרָאֵל.\nבָּרוּךְ יוֹצְרֵךְ, בָּרוּךְ עוֹשֵׂךְ, בָּרוּךְ קוֹנֵךְ, בָּרוּךְ בּוֹראֵךְ. כְּשֵׁם שֶׁאֲנַחְנוּ מרַקְּדִים כְּנֶגְדֵּךְ, וְאֵין אֲנַחְנוּ יְכוֹלִים לִגַּע בָּךְ, כָּךְ אִם יְרַקְּדוּ אֲחֵרִים כְּנֶגְדֵּנוּ לְהַזִּיקֵנוּ, לֹא יוּכְלוּ לִגַּע בָּנוּ, וְלֹא יִשְׁלְטוּ בָנוּ, וְלֹא יַעֲשׂוּ בָנוּ שׁוּם רֹשֶׁם כְּלָל ועִקָר. תִּפֹּל עֲלֵיהֶם אֵימָתָה וָפַחַד, בִּגְדֹל זְרוֹעֲךָ יִדְּמוּ כָּאָבֶן: כָּאָבֶן יִדְּמוּ, זְרוֹעֲךָ בִּגְדֹל, וָפַחַד אֵימָתָה עֲלֵיהֶם תִּפֹּל.\n\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\nדָּוִד מֶלֶךְ יִשְׂרָאֵל חַי וְקַיָּם.\n\nאָמֵן אָמֵן אָמֵן.\nנֶצַח נֶצַח נֶצַח.\nסֶלָה סֶלָה סֶלָה.\nוָעֶד וָעֶד וָעֶד.\n\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\nלֵב טָהוֹר בְּרָא לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי:\n\nשִׁיר לַמַּעֲלוֹת, אֶשָּׂא עֵינַי אֶל הֶהָרִים, מֵאַיִן יָבֹא עֶזְרִי: עֶזְרִי מֵעִם יהוה, עֹשֵׂה שָׁמַיִם וָאָרֶץ: אַל יִתֵּן לַמּוֹט רַגְלֶךָ, אַל יָנוּם שֹׁמְרֶךָ: הִנֵּה לֹא יָנוּם וְלֹא יִישָׁן, שׁוֹמֵר יִשְׂרָאֵל: יהוה שֹׁמְרֶךָ, יהוה צִלְּךָ עַל יַד יְמִינֶךָ: יוֹמָם הַשֶּׁמֶשׁ לֹא יַכֶּכָּה וְיָרֵחַ בַּלָּיְלָה: יהוה יִשְׁמָרְךָ מִכָּל רָע, יִשְׁמֹר אֶת נַפְשֶׁךָ: יהוה יִשְׁמָר צֵאתְךָ וּבוֹאֶךָ, מֵעַתָּה וְעַד עוֹלָם:\n\nהַלְלוּיָהּ, הַלְלוּ אֵל בְּקָדְשׁוֹ, הַלְלוּהוּ בִּרְקִיעַ עֻזּוֹ: הַלְלוּהוּ בִגְבוּרֹתָיו, הַלְלוּהוּ כְּרֹב גֻּדְלוֹ: הַלְלוּהוּ בְּתֵקַע שׁוֹפָר, הַלְלוּהוּ בְּנֵבֶל וְכִנּוֹר: הַלְלוּהוּ בְתֹף וּמָחוֹל, הַלְלוּהוּ בְּמִנִּים וְעוּגָב: הַלְלוּהוּ בְצִלְצְלֵי שָׁמַע, הַלְלוּהוּ בְּצִלְצְלֵי תְרוּעָה: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ: כֹּל הַנְּשָׁמָה תְּהַלֵּל יָהּ, הַלְלוּיָהּ:\n\nתָּנָא דְבֵי רִבִּי יִשְׁמָעֵאל: אִלְמָלֵי לֹא זָכוּ בְּנֵי יִשְׂרָאֵל אֶלָּא לְהַקְבִּיל פְּנֵי אֲבִיהֶם שֶׁבַּשָּׁמַיִם פַּעַם אַחַת בַּחֹדֶשׁ, דַּיָּם. אָמַר אַבַּיֵּי: הֵלְכָךְ נִמְרִינְהוּ מֵעֹמֶד.","cond":[]},{"kind":"instruction","text":"קדיש על ישראל","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nעַל יִשְׂרָאֵל וְעַל רַבָּנָן וְעַל תַּלְמִידֵיהוֹן וְעַל כָּל תַּלְמִידֵי תַלְמִידֵיהוֹן, דְּעָסְקִין בְּאוֹרַיְתָא קַדִּישְׁתָּא, דִּי בְאַתְרָא הָדֵין וְדִי בְכָל אֲתַר וַאֲתַר, יְהֵא לָנָא וּלְכוֹן וּלְהוֹן, חִנָּא וְחִסְדָּא וְרַחֲמֵי, מִן קֳדָם אֱלָהָא מָארֵי שְׁמַיָּא וְאַרְעָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"וְהָיָה אוֹר הַלְּבָנָה כְּאוֹר הַחַמָּה, וְאוֹר הַחַמָּה יִהְיֶה שִׁבְעָתַיִם, כְּאוֹר שִׁבְעַת הַיָּמִים, בְּיוֹם חֲבֹשׁ יהוה אֶת שֶׁבֶר עַמּוֹ, וּמַחַץ מַכָּתוֹ יִרְפָּא: וַתַּעְדִּי זָהָב וָכֶסֶף, וּמַלְבּוּשֵׁךְ שֵׁשׁ וָמֶשִׁי וְרִקְמָה, סֹלֶת וּדְבַשׁ וָשֶׁמֶן אָכָלְתְּ, וַתִּיפִי בִּמְאֹד מאֹד, וַתִּצְלחִי לִמְלוּכָה:\n\nשָׁלוֹם עֲלֵיכֶם.\nשָׁלוֹם עֲלֵיכֶם.\nשָׁלוֹם עֲלֵיכֶם.","cond":[]}]}},{"id":"tikkun_chatzot","title":"תיקון חצות","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"instruction","text":"סדר תיקון חצות","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִּקּוּן רָחֵל וְתִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשָׁם בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["rachel"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשׁוֹ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["noRachel"]},{"kind":"header","text":"תיקון רחל","cond":["rachel"]},{"kind":"instruction","text":"תיקון רחל","cond":["rachel"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:\n\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ. אַתָּה יוֹדֵעַ רָזֵי עוֹלָם. וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חֹפֵשׂ כָּל חַדְרֵי בָטֶן, רוֹאֶה כְלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ.","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על חורבן בית המקדש, יישב על הארץ כאבל ויאמר:","cond":["rachel"]},{"kind":"text","text":"עַל נַהֲרוֹת בָּבֶל, שָׁם יָשַׁבְנוּ גַּם בָּכִינוּ בְּזָכְרֵנוּ אֶת צִיּוֹן: עַל עֲרָבִים בְּתוֹכָהּ תָּלִינוּ כִּנֹּרוֹתֵינוּ: כִּי שָׁם שְׁאֵלוּנוּ שׁוֹבֵינוּ דִּבְרֵי שִׁיר וְתוֹלָלֵינוּ שִׂמְחָה, שִׁירוּ לָנוּ מִשִּׁיר צִיּוֹן: אֵיךְ נָשִׁיר אֶת שִׁיר יהוה עַל אַדְמַת נֵכָר: אִם אֶשְׁכָּחֵךְ יְרוּשָׁלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָׁלַיִם עַל רֹאשׁ שִׂמְחָתִי: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאֹמְרִים עָרוּ עָרוּ עַד הַיְסוֹד בָּהּ: בַּת בָּבֶל הַשְּׁדוּדָה, אַשְׁרֵי שֶׁיְשַׁלֶּם לָךְ אֶת גְּמוּלֵךְ שֶׁגָּמַלְתְּ לָנוּ: אַשְׁרֵי שֶׁיֹּאחֵז וְנִפֵּץ אֶת עֹלָלַיִךְ אֶל הַסָּלַע:","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על הרג צדיקים","cond":["rachel"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["rachel"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:\n\nהַבֵּט מִשָּׁמַיִם וּרְאֵה מִזְּבֻל קָדְשְׁךָ וְתִפְאַרְתֶּךָ, אַיֵּה קִנְאָתְךָ וּגְבוּרֹתֶךָ, הֲמוֹן מֵעֶיךָ וְרַחֲמֶיךָ אֵלַי הִתְאַפָּקוּ: כִּי אַתָּה אָבִינוּ, כִּי אַבְרָהָם לֹא יְדָעָנוּ וְיִשְׂרָאֵל לֹא יַכִּירָנוּ, אַתָּה יהוה אָבִינוּ, גֹּאֲלֵנוּ מֵעוֹלָם שְׁמֶךָ: לָמָּה תַתְעֵנוּ יהוה מִדְּרָכֶיךָ, תַּקְשִׁיחַ לִבֵּנוּ מִיִּרְאָתֶךָ, שׁוּב לְמַעַן עֲבָדֶיךָ שִׁבְטֵי נַחֲלָתֶךָ: לַמִּצְעָר יָרְשׁוּ עַם קָדְשֶׁךָ, צָרֵינוּ בּוֹסְסוּ מִקְדָּשֶׁךָ:\n\nוְעַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ, וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אַל תִּקְצֹף יהוה עַד מְאֹד וְאַל לָעַד תִּזְכֹּר עָוׂן, הֵן הַבֶּט נָא עַמְּךָ כֻלָּנוּ: עָרֵי קָדְשְׁךָ הָיוּ מִדְבָּר, צִיּוֹן מִדְבָּר הָיָתָה, יְרוּשָׁלִַם שְׁמָמָה: בֵּית קָדְשֵׁנוּ וְתִפְאַרְתֵּנוּ אֲשֶׁר הִלְלוּךָ אֲבֹתֵינוּ הָיָה לִשְׂרֵפַת אֵשׁ, וְכָל מַחֲמַדֵּינוּ הָיָה לְחָרְבָּה: הַעַל אֵלֶּה תִתְאַפַּק יהוה, תֶּחֱשֶׁה וּתְעַנֵּנוּ עַד מְאֹד:","cond":["rachel"]},{"kind":"instruction","text":"בימי בין המצרים מוסיפים:","cond":["rachel","threeWeeks"]},{"kind":"text","text":"הֲמָאֹס מָאַסְתָּ אֶת יְהוּדָה, אִם בְּצִיּוֹן גָּעֲלָה נַפְשֶׁךָ, מַדּוּעַ הִכִּיתָנוּ וְאֵין לָנוּ מַרְפֵּא, קַוֵּה לְשָׁלוֹם וְאֵין טוֹב, וּלְעֵת מַרְפֵּא וְהִנֵּה בְעָתָה: יָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ, עֲוׂן אֲבוֹתֵינוּ, כִּי חָטָאנוּ לָךְ: אַל תִּנְאַץ לְמַעַן שִׁמְךָ, אַל תְּנַבֵּל כִּסֵּא כְבוֹדֶךָ, זְכֹר, אַל תָּפֵר בְּרִיתְךָ אִתָּנוּ:\n\nכֹּה אָמַר אֲדֹנָי, קוֹל בְּרָמָה נִשְׁמָע, נְהִי בְּכִי תַמְרוּרִים, רָחֵל מְבַכָּה עַל בָּנֶיהָ, מֵאֲנָה לְהִנָּחֵם עַל בָּנֶיהָ כִּי אֵינֶנּוּ: אֲדֹנָי מִמָּרוֹם יִשְׁאָג וּמִמְּעוֹן קָדְשׁוֹ יִתֵּן קוֹלוֹ, שָׁאֹג יִשְׁאַג עַל נָוֵהוּ: וַיִּקְרָא אֲדֹנָי אֱלֹהִים צְבָאוֹת בַּיּוֹם הַהוּא לִבְכִי וּלְמִסְפֵּד וּלְקָרְחָה וְלַחֲגֹר שָׂק: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: הֵן אֶרְאֶלָּם צָעֲקוּ חֻצָה, מַלְאֲכֵי שָׁלוֹם מַר יִבְכָּיוּן:\n\n\nהִקָּבְצוּ וְשִׁמְעוּ בְּנֵי יַעֲקֹב כֻּלְּכֶם, קִרְעוּ לְבַבְכֶם וְאַל בִּגְדֵיכֶם, כִּי בְפִשְׁעֵיכֶם שֻׁלְּחָה אִמְּכֶם, וּתְנוּ כָבוֹד לַאֲדֹנָי אֱלֹהֵיכֶם.\n\nמִי הָאִישׁ הֶחָפֵץ חַיִּים וְחֵךְ אֹכֶל יִטְעַם לוֹ, אוֹהֵב יָמִים לִרְאוֹת טוֹב וּלְבַקֵּר בְּהֵיכָלוֹ, וְהָאֱלֹהִים יִרְאֶה לוֹ לִשְׁכֹּן בְּאָהֳלוֹ מִבְּלִי לוֹ, אֲשֶׁר לֹא עָמַל בּוֹ וְלֹא גִדְּלוֹ.\n\nאָנָה הָלַךְ דּוֹדֵךְ תַּרְקִיעַ עִמּוֹ לִשְׁחָקִים, אָנֹכִי חָטָאתִי וְהוּא אָסוּר בָּזִקִּים, וְעַל זֹאת סִפְדוּ וְהֵילִילוּ בֹּאוּ וְלִינוּ בַשַּׂקִּים, בָּרְחוֹבוֹת וּבַשְּׁוָקִים.\n\nשְׁכִינָה מָה אוֹמֶרֶת קַלַּנִי מֵרֹאשִׁי, הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת עָבְרוּ רֹאשִׁי, וְהַנֵּצַח וְהַהוֹד אֵין דּוֹרֵשׁ לְנַפְשִׁי, וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי.\n\nעַל זֹאת אֶסְפְּדָה וְאֵילִילָה, אֲסַלְּדָה בְחִילָה, קוֹלִי כַּחוֹלָה, מֵעַי מֵעַי אוֹחִילָה, לְמַעַנְכֶם שֻׁלַּחְתִּי בָּבֶלָה, וַאֲנִי בְּתוֹךְ הַגּוֹלָה.\n\nעֲוׂנוֹתֵיכֶם הִטּוּ אֵלֶּה וְחַטֹּאתֵיכֶם, הִגְלֵיתִי אֶתְכֶם לְיַסְּרָה אֶתְכֶם, וַיִּתְעַבֵּר אֲדֹנָי בִּי לְמַעַנְכֶם, וַיִּשְׁלָחֵנִי אֱלֹהִים לִפְנֵיכֶם.\n\nבְּבֵית יִשְׂרָאֵל רָאִיתִי שַׁעֲרוּרִיָּה, אֵין אִישׁ שָׂם עַל לֵב שַׁלָּמָּה אֶהְיֶה כְּעוֹטְיָה, כְּקִיר נָטוּי וּכְגָדֵר הַדְּחוּיָה, הֲמִדְבָּר הָיִיתִי לְיִשְׂרָאֵל אִם אֶרֶץ מַאְפֵּלְיָה.\n\nיָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ וַעֲוׂן אֲבוֹתֵינוּ, הִנְנוּ אָתָאנוּ לְךָ אֲדֹנָי אֱלֹהֵינוּ, שׁוּב לְמַעַן עֲבָדֶיךָ וְסָלַחְתָּ לַעֲוׂנֵנוּ, תָּשׁוּב תְּרַחֲמֵנוּ וְתִכְבֹּשׁ עֲוׂנוֹתֵינוּ.\n\nוַיֹּאמֶר אֲדֹנָי אָהַבְתִּי אֶתְכֶם, כָּל יִשְׁעִי וְכָל חֶפְצִי אָשׁוּב לְרַחֶמְכֶם, שׁוּבוּ אֵלַי וְאָשׁוּבָה אֲלֵיכֶם, אָנֹכִי אָנֹכִי הוּא מְנַחֶמְכֶם.\n\nאִמְרוּ לְבַת צִיּוֹן כֹּה אָמַר אֲדוֹנָיִךְ, תַּחַת הֱיוֹתֵךְ עֲזוּבָה יִבְעָלוּךְ בָּנָיִךְ, וְכִמְשׂוֹשׂ חָתָן עַל כַּלָּה יָשִׂישׂ עָלַיִךְ אֱלֹהָיִךְ, וְהָיִית עֲטֶרֶת תִּפְאֶרֶת בְּיַד אֲדֹנָי, וּצְנִיף מְלוּכָה בְּכַף אֱלֹהָיִךְ.\n\n\nקוֹל בְּרָמָה נִשְׁמָע בִּילָלָה, קוֹל נְהִי מִצִּיּוֹן הַמְהֻלָּלָה.\n\nחִשַּׁבְתִּי יָמִים הָיִיתִי גְבֶרֶת, בְּיַד אֲדֹנָי עֲטֶרֶת תִּפְאֶרֶת, וְעַתָּה אֲנִי שְׁחַרְחֹרֶת, טָבַעְתִּי בַבּוֹר בִּיוֵן מְצוּלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיְחִידָה רַעְיָה אֲזַי הָיִיתִי, וּכְבוֹד עֶלְיוֹן אֲנִי נִקְרֵאתִי, וְעַתָּה לְתַחְתִּיּוֹת יָרַדְתִּי, וְדוֹדִי וְרֵעִי לָרוּם עָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיַחַד יוֹדְעַי בְּתוּלוֹתַי וְרַעְיוֹתַי, בְּכוּ נָא עִמִּי כִּי רַבּוֹת אַנְחוֹתַי, אֵין נוֹטֶה עוֹד אָהֳלִי וּמֵקִים יְרִיעוֹתַי, כִּי דוֹדִי מֶנִּי נָסַע וְנִגְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nמִמָּרוֹם הֻשְׁלַכְתִּי בְּרֹב מְגִנָּה, שָׁלַח אֵשׁ בְּעַצְמוֹתַי וַיִּרְדֶּנָּה, וְיָצָאתִי בַגּוֹלָה בָּדָד כְּאַלְמָנָה, הָגְלָה יְהוּדָה הָגְלַת שְׁלוֹמִים כֻּלָּהּ. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהָיִיתִי כְכַלָּה בְּתוֹךְ אַפִּרְיוֹן, וַעֲנַן יוֹמָם עַל מְכוֹן הַר צִיּוֹן, הֻשְׁלַכְתִּי לַחוּץ כְּעָנִי וְאֶבְיוֹן, בְּגָדַי לָקַח צָר וַאֲנִי אֻמְלָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nכֹּהֲנַי וּזְקֵנַי טָבְחוּ אוֹיְבַי, מַחֲזִיקִים בִּבְרִיתִי זֶרַע אוֹהֲבַי, בָּנַי הַיְקָרִים וּבַחוּרַי, הָלְכוּ בַשֶּׁבִי וְעוֹלָלַי בַּגּוֹלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהֵן כָּל אֵלֶּה אֵין דּוֹרֵשׁ לְנַפְשִׁי, אִמָּלְאָה הָחֳרָבָה וְאֶל עַמִּים אָרִים רֹאשִׁי, וְאוֹיְבִי אָמַר לֹא תִקְרְאִי עוֹד אִישִׁי, כִּי נָפַלְתִּי לִפְנֵי בְנֵי עַוְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nנָא אָב הָרַחֲמָן תָּשׁוּב לְצִיּוֹן, עַיִן בְּעַיִן נִרְאֶה בְּבִנְיַן אַפִּרְיוֹן, וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן, וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה. וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן. וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה.\n\n\nעַד מָתַי אֲדֹנָי בְּיוֹם זֶה לְעֻמָּתֶךָ, בְּמַר תְּיַלֵּל עֲדָתֶךָ, עַל בֵּית תְּפִלָּתֶךָ, אֲשֶׁר שָׂרְפוּ צָרֶיךָ, וְהָרְגוּ בְּנֵי בְרִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי תִּשְׁכַּח שְׁאוֹן קָמֶיךָ, וְשׁוֹמְמוֹת הֵיכָלֶךָ, וּנְפוּצוֹת לְאֻמֶּךָ, הַלְּחוּצִים עָלֶיךָ.\nהַהֲרוּגִים עַל שְׁמֶךָ.\n\nעַד מָתַי עָשַׁנְתָּ בִּתְפִלַּת עַמֶּךָ, אֲשֶׁר יֶהֱגוּ לְפָנֶיךָ, עַל חֻרְבַּן בֵּיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי אֶשְׁכְּבָה בֵּין שְׁפַתָּיִם, וּבֵין תַּנּוּר וְכִירָיִם, יִכְהוּ לִי עֵינָיִם.\nלוֹהֲטִים לִי יִשְׁאֲפוּ עֶרֶב וָבֹקֶר וְצָהֳרָיִם.\n\nעַד מָתַי אֶשְׁתּוֹמֵם עַל חֻרְבַּן פַּעֲמַיִם, עַד מָתַי לֹא תְרַחֵם אֶת יְרוּשָׁלַיִם, עַד מָתַי יֶהֱגוּ בַּצַר שְׁאֵרִית צֹאן מַרְעִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי עַכּוּ\"ם יַעֲלֹזוּ, אֲשֶׁר אָכַל אֶת יַעֲקֹב וּבְכָל עֵת יָבוֹזּוּ, אֲנִי אֶדְרשׁ אֶת שְׁלוֹמָם וְהֵם יִמְרֹטוּ וְיָגֹזּוּ.\nבְּחֶרְפָּה הִכּוּ לְחָיַי וּבְשִׂפְתֵי שָׁוְא נָלוֹזוּ.\n\nעַד מָתַי אֲדֹנָי רְשָׁעִים יַעֲלֹזוּ, עַד אָן יִצְעַק בַּשְּׁבִי (פלוני בן פלונית) אֲמָתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\n\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת. הִנֵּה זֹאת תּוֹרַת הַבָּיִת.\n\nאֵיכָה נֶחֱרַב הָאוּלָם, וְנֶהֱרַס יְסוֹד הָעוֹלָם, וְחִלּוּ כּוֹכָבִים וְהִלָּם, וּבָא אֲשֶׁר לוֹ הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nדִּירַת קֹדֶשׁ אֲשֶׁר בָּנִיתָ, לְהַנְחִיל לְעַם זוּ קָנִיתָ, אוֹי כִּי הָאוֹיְבִים צִוִּיתָ, יָבֹאוּ וּפִנּוּ אֶת הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nנֶחְשְׁכוּ כָּל מְאוֹרֶיהָ, סֻגָּרוּ כָּל שְׁעָרֶיהָ, עַד כִּי אָמְרוּ כָּל רוֹאֶיהָ, כְּנֶגַע נִרְאָה לִי בַּבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nאֲדֹנָי שׁוּב מֵחֲרוֹן אַפְּךָ וַחֲמָתֶךָ, וּזְכֹר דְּבַר נְבוּאָתֶךָ, לְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\nלְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\n\n\nאוֹי לִי עַל גָּלוּת הַשְּׁכִינָה.\nאוֹי לִי עַל חֻרְבָּן בֵּית הַמִּקְדָּשׁ.\nאוֹי לִי עַל שְׂרֵפַת הַתּוֹרָה.\nאוֹי לִי עַל הֲרִיגַת הַצַּדִּיקִים.\nאוֹי לִי עַל חִלּוּל שְׁמוֹ הַגָּדוֹל וְתוֹרָתוֹ הַקְּדוֹשָׁה.\nאוֹי לִי עַל כִּי גָבַר אוֹיֵב.\nאוֹי לִי עַל תִּנּוֹקוֹת שֶׁל בֵּית רַבָּן שֶׁבָּטֵלוּ.\nאוֹי לִי עַל צַעַר כָּל הָעוֹלָמוֹת.\nאוֹי לִי עַל צער הָאָבוֹת הַקְּדוֹשִׁים וְהָאִמָּהוֹת הַקְּדוֹשׁוֹת.\nאוֹי לִי עַל צער הַנְּבִיאִים וְהַחֲסִידִים וְהַצַּדִּיקִים אֲשֶׁר בְּגַן עֵדֶן.\nאוֹי לִי עַל צַעֲרוֹ שֶׁל מָשִיחַ.\nעֲוׂנוֹתֵינוּ הִטּוּ אֵלֶּה וּפְשָׁעֵינוּ הֶאֱרִיכוּ קִצֵּנוּ וְחַטֹּאתֵינוּ מָנְעוּ הַטּוֹב מִמֶּנּוּ.\nאוֹי לָהֶם לְבָנִים שֶׁגָּלוּ מֵעַל שֻׁלְחַן אֲבִיהֶם זֶה כַּמָּה אֹרֶך יָמִים וְשָׁנִים רַבִּים וְרָעִים.\nוְכָל דוֹר שֶׁלֹּא נִבְנָה בֵּית הַמִּקְדָּשׁ בְּיָמָיו כְּאִלּוּ נֶחְרַב בְּיָמָיו.\n\n\nעַל הֵיכָלִי אֶבְכֶּה יוֹמָם וָלָיְלָה. וּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\nבְּכִי תָמִיד עַל הַחֻרְבָּן פַּעֲמָיִם.\nאֶרֶץ צְבִי וִירוּשָׁלָיִם.\nוְעַל עַמָּהּ אֲשֶׁר הָלְכוּ בַגּוֹלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nבֵּית תִּפְאַרְתִּי שָׂם אוֹיֵב לְשַׁמָּה.\nהוֹשִׁיבַנִי בִּידֵי נְבָיוֹת וְשַׁמָּה.\nעַל זֹאת אֶבְכֶּה תָמִיד בְּקוֹל יְלָלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nסִפְדִי תּוֹרָה כִּי חֻלְלָה תִּפְאַרְתֵּךְ.\nנָפְלָה נִזְרֵךְ מִיּוֹם שֶׁחָרַב בֵּיתֵךְ.\nעַל זֹאת אֶשָּׂא קִינָה עַל אָהֳלִיבָה וְאָהֳלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nחִזְקִי עַמִּי מַהֵר אֶבְנֶה דְבִירְכֶם.\nנָקָם אַלְבִּישׁ וְאָשִׁיב אֶת שְׁבוּתְכֶם.\nתּוֹךְ הֵיכָלִי אֶשְׁכֹּן כְּבַתְּחִלָּה.\nכִּי מִצִּיּוֹן תֵּצֵא תוֹרָה וּתְהִלָּה.\nכְּדִכְתִיב: כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה, וּדְבַר אֲדֹנָי מִירוּשָׁלָיִם:\n\n\nעוּרָה נָּא יְמִינְךָ רָמָה.\nוְלִזְעוּמָה קְרָא נֻחָמָה.\nוְיֵאָמֵר לְעַם דַּלָּה וַעֲגוּמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא חֲשׂוֹף זְרוֹעֲךָ.\nוְיִגָּלֶה קֵץ יִשְׁעֲךָ.\nוְיֵאָמֵר לְשֶׂה נֶאֱלָמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא יְמִינְךָ הָאֵל.\nוּפְדֵה בְּרַחֲמֶיךָ יִשְׂרָאֵל.\nוְיֵאָמֵר לְעַם דַּל הַשּׁוֹאֵל.\nוּבָא לְצִיּוֹן גּוֹאֵל.\n\nעוּרָה נָּא יְמִינְךָ עֶלְיוֹן.\nוּבְנֵה בְּרַחֲמֶיךָ אֶת צִיּוֹן.\nוְיֵאָמֵר לְעַם דַּל וְאֶבְיוֹן.\nכִּי נִחַם אֲדֹנָי צִיּוֹן.\nכְּדִכְתִיב: כִּי נִחַם אֲדֹנָי צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן אֲדֹנָי, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה.\n\n\nהִתְנַעֲרִי מֵעָפָר, קוּמִי שְּׁבִי יְרוּשָׁלִָם, הִתְפַּתְּחִי מוֹסְרֵי צַוָּארֵךְ שְׁבִיָּה בַּת צִיּוֹן:","cond":["rachel","threeWeeks"]},{"kind":"instruction","text":"עד כאן לימי בין המצרים","cond":["rachel","threeWeeks"]},{"kind":"text","text":"עַל חוֹמֹתַיִךְ יְרוּשָׁלִַם הִפְקַדְתִּי שֹׁמְרִים, כָּל הַיּוֹם וְכָל הַלַּיְלָה תָּמִיד לֹא יֶחֱשׁוּ, הַמַּזְכִּרִים אֶת יהוה אַל דֳּמִי לָכֶם: וְאַל תִּתְּנוּ דֳמִי לוֹ, עַד יְכוֹנֵן וְעַד יָשִׂים אֶת יְרוּשָׁלַיִם תְּהִלָּה בָּאָרֶץ: נִשְׁבַּע יהוה בִּימִינוֹ וּבִזְרוֹעַ עֻזּוֹ, אִם אֶתֵּן אֶת דְּגָנֵךְ עוֹד מַאֲכָל לְאֹיְבַיִךְ וְאִם יִשְׁתּוּ בְנֵי נֵכָר תִּירוֹשֵׁךְ אֲשֶׁר יָגַעַתְּ בּוֹ: כִּי מְאַסְפָיו יֹאכְלֻהוּ וְהִלְלוּ אֶת יהוה, וּמְקַבְּצָיו יִשְׁתֻּהוּ בְּחַצְרוֹת קָדְשִׁי:\n\nאַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ כִּי בָא מוֹעֵד: כִּי רָצוּ עֲבָדֶיךָ אֶת אֲבָנֶיהָ וְאֶת עֲפָרָהּ יְחֹנֵנוּ: בּוֹנֵה יְרוּשָׁלִַם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס:","cond":["rachel"]},{"kind":"header","text":"תיקון לאה","cond":[]},{"kind":"instruction","text":"תיקון לאה","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מַשְׂכִּיל לִבְנֵי-קֹרַח: כְּאַיָּל תַּעֲרֹג עַל-אֲפִיקֵי-מָיִם, כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים: צָמְאָה נַפְשִׁי לֵאלֹהִים, לְאֵל חָי, מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים: הָיְתָה-לִּי דִמְעָתִי לֶחֶם יוֹמָם וָלָיְלָה, בֶּאֱמֹר אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: אֵלֶּה אֶזְכְּרָה וְאֶשְׁפְּכָה עָלַי נַפְשִׁי, כִּי אֶעֱבֹר בַּסָּךְ אֶדַּדֵּם עַד-בֵּית אֱלֹהִים, בְּקוֹל-רִנָּה וְתוֹדָה, הָמוֹן חוֹגֵג: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וַתֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעוֹת פָּנָיו: אֱלֹהַי, עָלַי נַפְשִׁי תִשְׁתּוֹחָח, עַל-כֵּן אֶזְכָּרְךָ מֵאֶרֶץ יַרְדֵּן, וְחֶרְמוֹנִים מֵהַר מִצְעָר: תְּהוֹם-אֶל-תְּהוֹם קוֹרֵא לְקוֹל צִנּוֹרֶיךָ, כָּל-מִשְׁבָּרֶיךָ וְגַלֶּיךָ עָלַי עָבָרוּ: יוֹמָם יְצַוֶּה יהוה חַסְדּוֹ, וּבַלַּיְלָה שִׁירֹה עִמִּי, תְּפִלָּה לְאֵל חַיָּי: אוֹמְרָה לְאֵל סַלְעִי, לָמָה שְׁכַחְתָּנִי, לָמָּה-קֹדֵר אֵלֵךְ, בְּלַחַץ אוֹיֵב: בְּרֶצַח בְּעַצְמוֹתַי, חֵרְפוּנִי צוֹרְרָי, בְּאָמְרָם אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"שָׁפְטֵנִי אֱלֹהִים וְרִיבָה רִיבִי, מִגּוֹי לֹא חָסִיד, מֵאִישׁ מִרְמָה וְעַוְלָה תְפַלְּטֵנִי: כִּי-אַתָּה אֱלֹהֵי מָעוּזִּי, לָמָה זְנַחְתָּנִי, לָמָּה-קֹדֵר אֶתְהַלֵּךְ בְּלַחַץ אוֹיֵב: שְׁלַח-אוֹרְךָ וַאֲמִתְּךָ הֵמָּה יַנְחוּנִי, יְבִיאוּנִי אֶל-הַר-קָדְשְׁךָ וְאֶל-מִשְׁכְּנוֹתֶיךָ: וְאָבוֹאָה אֶל-מִזְבַּח אֱלֹהִים, אֶל-אֵל שִׂמְחַת גִּילִי, וְאוֹדְךָ בְכִנּוֹר, אֱלֹהִים אֱלֹהָי: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, אוֹדֶה יהוה בְּכָל לֵבָב, בְּסוֹד יְשָׁרִים וְעֵדָה: גְּדֹלִים מַעֲשֵׂי יהוה, דְּרוּשִׁים לְכָל חֶפְצֵיהֶם: הוֹד וְהָדָר פָּעֳלוֹ, וְצִדְקָתוֹ עֹמֶדֶת לָעַד: זֵכֶר עָשָׂה לְנִפְלְאֹתָיו, חַנּוּן וְרַחוּם יהוה: טֶרֶף נָתַן לִירֵאָיו, יִזְכֹּר לְעוֹלָם בְּרִיתוֹ: כֹּחַ מַעֲשָׂיו הִגִּיד לְעַמּוֹ, לָתֵת לָהֶם נַחֲלַת גּוֹיִם: מַעֲשֵׂי יָדָיו אֱמֶת וּמִשְׁפָּט, נֶאֱמָנִים כָּל פִּקּוּדָיו: סְמוּכִים לָעַד לְעוֹלָם, עֲשׂוּיִם בֶּאֱמֶת וְיָשָׁר: פְּדוּת שָׁלַח לְעַמּוֹ, צִוָּה לְעוֹלָם בְּרִיתוֹ, קָדוֹשׁ וְנוֹרָא שְׁמוֹ: רֵאשִׁית חָכְמָה יִרְאַת יהוה, שֵׂכֶל טוֹב לְכָל עֹשֵׂיהֶם, תְּהִלָּתוֹ עֹמֶדֶת לָעַד:\n\nלַמְנַצֵּחַ מִזְמוֹר לְדָוִד: בְּבוֹא אֵלָיו נָתָן הַנָּבִיא, כַּאֲשֶׁר-בָּא אֶל-בַּת-שָׁבַע: חָנֵּנִי אֱלֹהִים כְּחַסְדֶּךָ, כְּרֹב רַחֲמֶיךָ מְחֵה פְשָׁעָי: הֶרֶב כַּבְּסֵנִי מֵעֲוׂנִי, וּמֵחַטָּאתִי טַהֲרֵנִי: כִּי-פְשָׁעַי אֲנִי אֵדָע, וְחַטָּאתִי נֶגְדִּי תָמִיד: לְךָ לְבַדְּךָ חָטָאתִי, וְהָרַע בְּעֵינֶיךָ עָשִׂיתִי, לְמַעַן-תִּצְדַּק בְּדָבְרֶךָ, תִּזְכֶּה בְשָׁפְטֶךָ: הֵן-בְּעָווֹן חוֹלָלְתִּי, וּבְחֵטְא יֶחֱמַתְנִי אִמִּי: הֵן אֱמֶת חָפַצְתָּ בַטֻּחוֹת, וּבְסָתֻם חָכְמָה תוֹדִיעֵנִי: תְּחַטְּאֵנִי בְאֵזוֹב וְאֶטְהָר, תְּכַבְּסֵנִי וּמִשֶּׁלֶג אַלְבִּין: תַּשְׁמִיעֵנִי שָׂשׂוֹן וְשִׂמְחָה, תָּגֵלְנָה עֲצָמוֹת דִּכִּיתָ: הַסְתֵּר פָּנֶיךָ מֵחֲטָאָי, וְכָל-עֲוׂנתַי מְחֵה: לֵב טָהוֹר בְּרָא-לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי: אַל-תַּשְׁלִיכֵנִי מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל-תִּקַּח מִמֶּנִּי: הָשִׁיבָה לִּי שְׂשׂוֹן יִשְׁעֶךָ, וְרוּחַ נְדִיבָה תִסְמְכֵנִי: אֲלַמְּדָה פֹשְׁעִים דְּרָכֶיךָ, וְחַטָּאִים אֵלֶיךָ יָשׁוּבוּ: הַצִּילֵנִי מִדָּמִים אֱלֹהִים אֱלֹהֵי תְשׁוּעָתִי, תְּרַנֵּן לְשׁוֹנִי צִדְקָתֶךָ: אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ: כִּי לֹא-תַחְפֹּץ זֶבַח וְאֶתֵּנָה, עוֹלָה לֹא תִרְצֶה: זִבְחֵי אֱלֹהִים רוּחַ נִשְׁבָּרָה, לֵב-נִשְׁבָּר וְנִדְכֶּה אֱלֹהִים לֹא תִבְזֶה: הֵיטִיבָה בִרְצוֹנְךָ אֶת-צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם: אָז תַּחְפֹּץ זִבְחֵי-צֶדֶק, עוֹלָה וְכָלִיל, אָז יַעֲלוּ עַל-מִזְבַּחֲךָ פָרִים:","cond":[]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם.","cond":["rachel"]},{"kind":"text","text":"תָקוּם תְּרַחֵם צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר או\"א ומזמור בשוב ה' כדי לפסוק בנחמה (בא\"ח וישלח)","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כּבַתְּחִלָּה, כּוֹנֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם, וּלְוִיִּים לְדוּכָנָם, לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְּשִׂמְחָה לְאַרְצֵנוּ, וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשֵׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חֹבֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם.\n\nשִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]}],"sfard":[{"kind":"instruction","text":"סדר תיקון חצות","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִּקּוּן רָחֵל וְתִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשָׁם בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["rachel"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשׁוֹ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["noRachel"]},{"kind":"header","text":"תיקון רחל","cond":["rachel"]},{"kind":"instruction","text":"תיקון רחל","cond":["rachel"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:\n\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ. אַתָּה יוֹדֵעַ רָזֵי עוֹלָם. וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חֹפֵשׂ כָּל חַדְרֵי בָטֶן, רוֹאֶה כְלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ.","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על חורבן בית המקדש, יישב על הארץ כאבל ויאמר:","cond":["rachel"]},{"kind":"text","text":"עַל נַהֲרוֹת בָּבֶל, שָׁם יָשַׁבְנוּ גַּם בָּכִינוּ בְּזָכְרֵנוּ אֶת צִיּוֹן: עַל עֲרָבִים בְּתוֹכָהּ תָּלִינוּ כִּנֹּרוֹתֵינוּ: כִּי שָׁם שְׁאֵלוּנוּ שׁוֹבֵינוּ דִּבְרֵי שִׁיר וְתוֹלָלֵינוּ שִׂמְחָה, שִׁירוּ לָנוּ מִשִּׁיר צִיּוֹן: אֵיךְ נָשִׁיר אֶת שִׁיר יהוה עַל אַדְמַת נֵכָר: אִם אֶשְׁכָּחֵךְ יְרוּשָׁלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָׁלַיִם עַל רֹאשׁ שִׂמְחָתִי: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאֹמְרִים עָרוּ עָרוּ עַד הַיְסוֹד בָּהּ: בַּת בָּבֶל הַשְּׁדוּדָה, אַשְׁרֵי שֶׁיְשַׁלֶּם לָךְ אֶת גְּמוּלֵךְ שֶׁגָּמַלְתְּ לָנוּ: אַשְׁרֵי שֶׁיֹּאחֵז וְנִפֵּץ אֶת עֹלָלַיִךְ אֶל הַסָּלַע:","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על הרג צדיקים","cond":["rachel"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["rachel"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:\n\nהַבֵּט מִשָּׁמַיִם וּרְאֵה מִזְּבֻל קָדְשְׁךָ וְתִפְאַרְתֶּךָ, אַיֵּה קִנְאָתְךָ וּגְבוּרֹתֶךָ, הֲמוֹן מֵעֶיךָ וְרַחֲמֶיךָ אֵלַי הִתְאַפָּקוּ: כִּי אַתָּה אָבִינוּ, כִּי אַבְרָהָם לֹא יְדָעָנוּ וְיִשְׂרָאֵל לֹא יַכִּירָנוּ, אַתָּה יהוה אָבִינוּ, גֹּאֲלֵנוּ מֵעוֹלָם שְׁמֶךָ: לָמָּה תַתְעֵנוּ יהוה מִדְּרָכֶיךָ, תַּקְשִׁיחַ לִבֵּנוּ מִיִּרְאָתֶךָ, שׁוּב לְמַעַן עֲבָדֶיךָ שִׁבְטֵי נַחֲלָתֶךָ: לַמִּצְעָר יָרְשׁוּ עַם קָדְשֶׁךָ, צָרֵינוּ בּוֹסְסוּ מִקְדָּשֶׁךָ:\n\nוְעַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ, וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אַל תִּקְצֹף יהוה עַד מְאֹד וְאַל לָעַד תִּזְכֹּר עָוׂן, הֵן הַבֶּט נָא עַמְּךָ כֻלָּנוּ: עָרֵי קָדְשְׁךָ הָיוּ מִדְבָּר, צִיּוֹן מִדְבָּר הָיָתָה, יְרוּשָׁלִַם שְׁמָמָה: בֵּית קָדְשֵׁנוּ וְתִפְאַרְתֵּנוּ אֲשֶׁר הִלְלוּךָ אֲבֹתֵינוּ הָיָה לִשְׂרֵפַת אֵשׁ, וְכָל מַחֲמַדֵּינוּ הָיָה לְחָרְבָּה: הַעַל אֵלֶּה תִתְאַפַּק יהוה, תֶּחֱשֶׁה וּתְעַנֵּנוּ עַד מְאֹד:","cond":["rachel"]},{"kind":"instruction","text":"בימי בין המצרים מוסיפים:","cond":["rachel","threeWeeks"]},{"kind":"text","text":"הֲמָאֹס מָאַסְתָּ אֶת יְהוּדָה, אִם בְּצִיּוֹן גָּעֲלָה נַפְשֶׁךָ, מַדּוּעַ הִכִּיתָנוּ וְאֵין לָנוּ מַרְפֵּא, קַוֵּה לְשָׁלוֹם וְאֵין טוֹב, וּלְעֵת מַרְפֵּא וְהִנֵּה בְעָתָה: יָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ, עֲוׂן אֲבוֹתֵינוּ, כִּי חָטָאנוּ לָךְ: אַל תִּנְאַץ לְמַעַן שִׁמְךָ, אַל תְּנַבֵּל כִּסֵּא כְבוֹדֶךָ, זְכֹר, אַל תָּפֵר בְּרִיתְךָ אִתָּנוּ:\n\nכֹּה אָמַר אֲדֹנָי, קוֹל בְּרָמָה נִשְׁמָע, נְהִי בְּכִי תַמְרוּרִים, רָחֵל מְבַכָּה עַל בָּנֶיהָ, מֵאֲנָה לְהִנָּחֵם עַל בָּנֶיהָ כִּי אֵינֶנּוּ: אֲדֹנָי מִמָּרוֹם יִשְׁאָג וּמִמְּעוֹן קָדְשׁוֹ יִתֵּן קוֹלוֹ, שָׁאֹג יִשְׁאַג עַל נָוֵהוּ: וַיִּקְרָא אֲדֹנָי אֱלֹהִים צְבָאוֹת בַּיּוֹם הַהוּא לִבְכִי וּלְמִסְפֵּד וּלְקָרְחָה וְלַחֲגֹר שָׂק: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: הֵן אֶרְאֶלָּם צָעֲקוּ חֻצָה, מַלְאֲכֵי שָׁלוֹם מַר יִבְכָּיוּן:\n\n\nהִקָּבְצוּ וְשִׁמְעוּ בְּנֵי יַעֲקֹב כֻּלְּכֶם, קִרְעוּ לְבַבְכֶם וְאַל בִּגְדֵיכֶם, כִּי בְפִשְׁעֵיכֶם שֻׁלְּחָה אִמְּכֶם, וּתְנוּ כָבוֹד לַאֲדֹנָי אֱלֹהֵיכֶם.\n\nמִי הָאִישׁ הֶחָפֵץ חַיִּים וְחֵךְ אֹכֶל יִטְעַם לוֹ, אוֹהֵב יָמִים לִרְאוֹת טוֹב וּלְבַקֵּר בְּהֵיכָלוֹ, וְהָאֱלֹהִים יִרְאֶה לוֹ לִשְׁכֹּן בְּאָהֳלוֹ מִבְּלִי לוֹ, אֲשֶׁר לֹא עָמַל בּוֹ וְלֹא גִדְּלוֹ.\n\nאָנָה הָלַךְ דּוֹדֵךְ תַּרְקִיעַ עִמּוֹ לִשְׁחָקִים, אָנֹכִי חָטָאתִי וְהוּא אָסוּר בָּזִקִּים, וְעַל זֹאת סִפְדוּ וְהֵילִילוּ בֹּאוּ וְלִינוּ בַשַּׂקִּים, בָּרְחוֹבוֹת וּבַשְּׁוָקִים.\n\nשְׁכִינָה מָה אוֹמֶרֶת קַלַּנִי מֵרֹאשִׁי, הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת עָבְרוּ רֹאשִׁי, וְהַנֵּצַח וְהַהוֹד אֵין דּוֹרֵשׁ לְנַפְשִׁי, וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי.\n\nעַל זֹאת אֶסְפְּדָה וְאֵילִילָה, אֲסַלְּדָה בְחִילָה, קוֹלִי כַּחוֹלָה, מֵעַי מֵעַי אוֹחִילָה, לְמַעַנְכֶם שֻׁלַּחְתִּי בָּבֶלָה, וַאֲנִי בְּתוֹךְ הַגּוֹלָה.\n\nעֲוׂנוֹתֵיכֶם הִטּוּ אֵלֶּה וְחַטֹּאתֵיכֶם, הִגְלֵיתִי אֶתְכֶם לְיַסְּרָה אֶתְכֶם, וַיִּתְעַבֵּר אֲדֹנָי בִּי לְמַעַנְכֶם, וַיִּשְׁלָחֵנִי אֱלֹהִים לִפְנֵיכֶם.\n\nבְּבֵית יִשְׂרָאֵל רָאִיתִי שַׁעֲרוּרִיָּה, אֵין אִישׁ שָׂם עַל לֵב שַׁלָּמָּה אֶהְיֶה כְּעוֹטְיָה, כְּקִיר נָטוּי וּכְגָדֵר הַדְּחוּיָה, הֲמִדְבָּר הָיִיתִי לְיִשְׂרָאֵל אִם אֶרֶץ מַאְפֵּלְיָה.\n\nיָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ וַעֲוׂן אֲבוֹתֵינוּ, הִנְנוּ אָתָאנוּ לְךָ אֲדֹנָי אֱלֹהֵינוּ, שׁוּב לְמַעַן עֲבָדֶיךָ וְסָלַחְתָּ לַעֲוׂנֵנוּ, תָּשׁוּב תְּרַחֲמֵנוּ וְתִכְבֹּשׁ עֲוׂנוֹתֵינוּ.\n\nוַיֹּאמֶר אֲדֹנָי אָהַבְתִּי אֶתְכֶם, כָּל יִשְׁעִי וְכָל חֶפְצִי אָשׁוּב לְרַחֶמְכֶם, שׁוּבוּ אֵלַי וְאָשׁוּבָה אֲלֵיכֶם, אָנֹכִי אָנֹכִי הוּא מְנַחֶמְכֶם.\n\nאִמְרוּ לְבַת צִיּוֹן כֹּה אָמַר אֲדוֹנָיִךְ, תַּחַת הֱיוֹתֵךְ עֲזוּבָה יִבְעָלוּךְ בָּנָיִךְ, וְכִמְשׂוֹשׂ חָתָן עַל כַּלָּה יָשִׂישׂ עָלַיִךְ אֱלֹהָיִךְ, וְהָיִית עֲטֶרֶת תִּפְאֶרֶת בְּיַד אֲדֹנָי, וּצְנִיף מְלוּכָה בְּכַף אֱלֹהָיִךְ.\n\n\nקוֹל בְּרָמָה נִשְׁמָע בִּילָלָה, קוֹל נְהִי מִצִּיּוֹן הַמְהֻלָּלָה.\n\nחִשַּׁבְתִּי יָמִים הָיִיתִי גְבֶרֶת, בְּיַד אֲדֹנָי עֲטֶרֶת תִּפְאֶרֶת, וְעַתָּה אֲנִי שְׁחַרְחֹרֶת, טָבַעְתִּי בַבּוֹר בִּיוֵן מְצוּלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיְחִידָה רַעְיָה אֲזַי הָיִיתִי, וּכְבוֹד עֶלְיוֹן אֲנִי נִקְרֵאתִי, וְעַתָּה לְתַחְתִּיּוֹת יָרַדְתִּי, וְדוֹדִי וְרֵעִי לָרוּם עָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיַחַד יוֹדְעַי בְּתוּלוֹתַי וְרַעְיוֹתַי, בְּכוּ נָא עִמִּי כִּי רַבּוֹת אַנְחוֹתַי, אֵין נוֹטֶה עוֹד אָהֳלִי וּמֵקִים יְרִיעוֹתַי, כִּי דוֹדִי מֶנִּי נָסַע וְנִגְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nמִמָּרוֹם הֻשְׁלַכְתִּי בְּרֹב מְגִנָּה, שָׁלַח אֵשׁ בְּעַצְמוֹתַי וַיִּרְדֶּנָּה, וְיָצָאתִי בַגּוֹלָה בָּדָד כְּאַלְמָנָה, הָגְלָה יְהוּדָה הָגְלַת שְׁלוֹמִים כֻּלָּהּ. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהָיִיתִי כְכַלָּה בְּתוֹךְ אַפִּרְיוֹן, וַעֲנַן יוֹמָם עַל מְכוֹן הַר צִיּוֹן, הֻשְׁלַכְתִּי לַחוּץ כְּעָנִי וְאֶבְיוֹן, בְּגָדַי לָקַח צָר וַאֲנִי אֻמְלָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nכֹּהֲנַי וּזְקֵנַי טָבְחוּ אוֹיְבַי, מַחֲזִיקִים בִּבְרִיתִי זֶרַע אוֹהֲבַי, בָּנַי הַיְקָרִים וּבַחוּרַי, הָלְכוּ בַשֶּׁבִי וְעוֹלָלַי בַּגּוֹלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהֵן כָּל אֵלֶּה אֵין דּוֹרֵשׁ לְנַפְשִׁי, אִמָּלְאָה הָחֳרָבָה וְאֶל עַמִּים אָרִים רֹאשִׁי, וְאוֹיְבִי אָמַר לֹא תִקְרְאִי עוֹד אִישִׁי, כִּי נָפַלְתִּי לִפְנֵי בְנֵי עַוְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nנָא אָב הָרַחֲמָן תָּשׁוּב לְצִיּוֹן, עַיִן בְּעַיִן נִרְאֶה בְּבִנְיַן אַפִּרְיוֹן, וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן, וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה. וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן. וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה.\n\n\nעַד מָתַי אֲדֹנָי בְּיוֹם זֶה לְעֻמָּתֶךָ, בְּמַר תְּיַלֵּל עֲדָתֶךָ, עַל בֵּית תְּפִלָּתֶךָ, אֲשֶׁר שָׂרְפוּ צָרֶיךָ, וְהָרְגוּ בְּנֵי בְרִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי תִּשְׁכַּח שְׁאוֹן קָמֶיךָ, וְשׁוֹמְמוֹת הֵיכָלֶךָ, וּנְפוּצוֹת לְאֻמֶּךָ, הַלְּחוּצִים עָלֶיךָ.\nהַהֲרוּגִים עַל שְׁמֶךָ.\n\nעַד מָתַי עָשַׁנְתָּ בִּתְפִלַּת עַמֶּךָ, אֲשֶׁר יֶהֱגוּ לְפָנֶיךָ, עַל חֻרְבַּן בֵּיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי אֶשְׁכְּבָה בֵּין שְׁפַתָּיִם, וּבֵין תַּנּוּר וְכִירָיִם, יִכְהוּ לִי עֵינָיִם.\nלוֹהֲטִים לִי יִשְׁאֲפוּ עֶרֶב וָבֹקֶר וְצָהֳרָיִם.\n\nעַד מָתַי אֶשְׁתּוֹמֵם עַל חֻרְבַּן פַּעֲמַיִם, עַד מָתַי לֹא תְרַחֵם אֶת יְרוּשָׁלַיִם, עַד מָתַי יֶהֱגוּ בַּצַר שְׁאֵרִית צֹאן מַרְעִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי עַכּוּ\"ם יַעֲלֹזוּ, אֲשֶׁר אָכַל אֶת יַעֲקֹב וּבְכָל עֵת יָבוֹזּוּ, אֲנִי אֶדְרשׁ אֶת שְׁלוֹמָם וְהֵם יִמְרֹטוּ וְיָגֹזּוּ.\nבְּחֶרְפָּה הִכּוּ לְחָיַי וּבְשִׂפְתֵי שָׁוְא נָלוֹזוּ.\n\nעַד מָתַי אֲדֹנָי רְשָׁעִים יַעֲלֹזוּ, עַד אָן יִצְעַק בַּשְּׁבִי (פלוני בן פלונית) אֲמָתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\n\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת. הִנֵּה זֹאת תּוֹרַת הַבָּיִת.\n\nאֵיכָה נֶחֱרַב הָאוּלָם, וְנֶהֱרַס יְסוֹד הָעוֹלָם, וְחִלּוּ כּוֹכָבִים וְהִלָּם, וּבָא אֲשֶׁר לוֹ הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nדִּירַת קֹדֶשׁ אֲשֶׁר בָּנִיתָ, לְהַנְחִיל לְעַם זוּ קָנִיתָ, אוֹי כִּי הָאוֹיְבִים צִוִּיתָ, יָבֹאוּ וּפִנּוּ אֶת הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nנֶחְשְׁכוּ כָּל מְאוֹרֶיהָ, סֻגָּרוּ כָּל שְׁעָרֶיהָ, עַד כִּי אָמְרוּ כָּל רוֹאֶיהָ, כְּנֶגַע נִרְאָה לִי בַּבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nאֲדֹנָי שׁוּב מֵחֲרוֹן אַפְּךָ וַחֲמָתֶךָ, וּזְכֹר דְּבַר נְבוּאָתֶךָ, לְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\nלְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\n\n\nאוֹי לִי עַל גָּלוּת הַשְּׁכִינָה.\nאוֹי לִי עַל חֻרְבָּן בֵּית הַמִּקְדָּשׁ.\nאוֹי לִי עַל שְׂרֵפַת הַתּוֹרָה.\nאוֹי לִי עַל הֲרִיגַת הַצַּדִּיקִים.\nאוֹי לִי עַל חִלּוּל שְׁמוֹ הַגָּדוֹל וְתוֹרָתוֹ הַקְּדוֹשָׁה.\nאוֹי לִי עַל כִּי גָבַר אוֹיֵב.\nאוֹי לִי עַל תִּנּוֹקוֹת שֶׁל בֵּית רַבָּן שֶׁבָּטֵלוּ.\nאוֹי לִי עַל צַעַר כָּל הָעוֹלָמוֹת.\nאוֹי לִי עַל צער הָאָבוֹת הַקְּדוֹשִׁים וְהָאִמָּהוֹת הַקְּדוֹשׁוֹת.\nאוֹי לִי עַל צער הַנְּבִיאִים וְהַחֲסִידִים וְהַצַּדִּיקִים אֲשֶׁר בְּגַן עֵדֶן.\nאוֹי לִי עַל צַעֲרוֹ שֶׁל מָשִיחַ.\nעֲוׂנוֹתֵינוּ הִטּוּ אֵלֶּה וּפְשָׁעֵינוּ הֶאֱרִיכוּ קִצֵּנוּ וְחַטֹּאתֵינוּ מָנְעוּ הַטּוֹב מִמֶּנּוּ.\nאוֹי לָהֶם לְבָנִים שֶׁגָּלוּ מֵעַל שֻׁלְחַן אֲבִיהֶם זֶה כַּמָּה אֹרֶך יָמִים וְשָׁנִים רַבִּים וְרָעִים.\nוְכָל דוֹר שֶׁלֹּא נִבְנָה בֵּית הַמִּקְדָּשׁ בְּיָמָיו כְּאִלּוּ נֶחְרַב בְּיָמָיו.\n\n\nעַל הֵיכָלִי אֶבְכֶּה יוֹמָם וָלָיְלָה. וּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\nבְּכִי תָמִיד עַל הַחֻרְבָּן פַּעֲמָיִם.\nאֶרֶץ צְבִי וִירוּשָׁלָיִם.\nוְעַל עַמָּהּ אֲשֶׁר הָלְכוּ בַגּוֹלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nבֵּית תִּפְאַרְתִּי שָׂם אוֹיֵב לְשַׁמָּה.\nהוֹשִׁיבַנִי בִּידֵי נְבָיוֹת וְשַׁמָּה.\nעַל זֹאת אֶבְכֶּה תָמִיד בְּקוֹל יְלָלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nסִפְדִי תּוֹרָה כִּי חֻלְלָה תִּפְאַרְתֵּךְ.\nנָפְלָה נִזְרֵךְ מִיּוֹם שֶׁחָרַב בֵּיתֵךְ.\nעַל זֹאת אֶשָּׂא קִינָה עַל אָהֳלִיבָה וְאָהֳלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nחִזְקִי עַמִּי מַהֵר אֶבְנֶה דְבִירְכֶם.\nנָקָם אַלְבִּישׁ וְאָשִׁיב אֶת שְׁבוּתְכֶם.\nתּוֹךְ הֵיכָלִי אֶשְׁכֹּן כְּבַתְּחִלָּה.\nכִּי מִצִּיּוֹן תֵּצֵא תוֹרָה וּתְהִלָּה.\nכְּדִכְתִיב: כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה, וּדְבַר אֲדֹנָי מִירוּשָׁלָיִם:\n\n\nעוּרָה נָּא יְמִינְךָ רָמָה.\nוְלִזְעוּמָה קְרָא נֻחָמָה.\nוְיֵאָמֵר לְעַם דַּלָּה וַעֲגוּמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא חֲשׂוֹף זְרוֹעֲךָ.\nוְיִגָּלֶה קֵץ יִשְׁעֲךָ.\nוְיֵאָמֵר לְשֶׂה נֶאֱלָמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא יְמִינְךָ הָאֵל.\nוּפְדֵה בְּרַחֲמֶיךָ יִשְׂרָאֵל.\nוְיֵאָמֵר לְעַם דַּל הַשּׁוֹאֵל.\nוּבָא לְצִיּוֹן גּוֹאֵל.\n\nעוּרָה נָּא יְמִינְךָ עֶלְיוֹן.\nוּבְנֵה בְּרַחֲמֶיךָ אֶת צִיּוֹן.\nוְיֵאָמֵר לְעַם דַּל וְאֶבְיוֹן.\nכִּי נִחַם אֲדֹנָי צִיּוֹן.\nכְּדִכְתִיב: כִּי נִחַם אֲדֹנָי צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן אֲדֹנָי, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה.\n\n\nהִתְנַעֲרִי מֵעָפָר, קוּמִי שְּׁבִי יְרוּשָׁלִָם, הִתְפַּתְּחִי מוֹסְרֵי צַוָּארֵךְ שְׁבִיָּה בַּת צִיּוֹן:","cond":["rachel","threeWeeks"]},{"kind":"instruction","text":"עד כאן לימי בין המצרים","cond":["rachel","threeWeeks"]},{"kind":"text","text":"עַל חוֹמֹתַיִךְ יְרוּשָׁלִַם הִפְקַדְתִּי שֹׁמְרִים, כָּל הַיּוֹם וְכָל הַלַּיְלָה תָּמִיד לֹא יֶחֱשׁוּ, הַמַּזְכִּרִים אֶת יהוה אַל דֳּמִי לָכֶם: וְאַל תִּתְּנוּ דֳמִי לוֹ, עַד יְכוֹנֵן וְעַד יָשִׂים אֶת יְרוּשָׁלַיִם תְּהִלָּה בָּאָרֶץ: נִשְׁבַּע יהוה בִּימִינוֹ וּבִזְרוֹעַ עֻזּוֹ, אִם אֶתֵּן אֶת דְּגָנֵךְ עוֹד מַאֲכָל לְאֹיְבַיִךְ וְאִם יִשְׁתּוּ בְנֵי נֵכָר תִּירוֹשֵׁךְ אֲשֶׁר יָגַעַתְּ בּוֹ: כִּי מְאַסְפָיו יֹאכְלֻהוּ וְהִלְלוּ אֶת יהוה, וּמְקַבְּצָיו יִשְׁתֻּהוּ בְּחַצְרוֹת קָדְשִׁי:\n\nאַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ כִּי בָא מוֹעֵד: כִּי רָצוּ עֲבָדֶיךָ אֶת אֲבָנֶיהָ וְאֶת עֲפָרָהּ יְחֹנֵנוּ: בּוֹנֵה יְרוּשָׁלִַם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס:","cond":["rachel"]},{"kind":"header","text":"תיקון לאה","cond":[]},{"kind":"instruction","text":"תיקון לאה","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מַשְׂכִּיל לִבְנֵי-קֹרַח: כְּאַיָּל תַּעֲרֹג עַל-אֲפִיקֵי-מָיִם, כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים: צָמְאָה נַפְשִׁי לֵאלֹהִים, לְאֵל חָי, מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים: הָיְתָה-לִּי דִמְעָתִי לֶחֶם יוֹמָם וָלָיְלָה, בֶּאֱמֹר אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: אֵלֶּה אֶזְכְּרָה וְאֶשְׁפְּכָה עָלַי נַפְשִׁי, כִּי אֶעֱבֹר בַּסָּךְ אֶדַּדֵּם עַד-בֵּית אֱלֹהִים, בְּקוֹל-רִנָּה וְתוֹדָה, הָמוֹן חוֹגֵג: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וַתֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעוֹת פָּנָיו: אֱלֹהַי, עָלַי נַפְשִׁי תִשְׁתּוֹחָח, עַל-כֵּן אֶזְכָּרְךָ מֵאֶרֶץ יַרְדֵּן, וְחֶרְמוֹנִים מֵהַר מִצְעָר: תְּהוֹם-אֶל-תְּהוֹם קוֹרֵא לְקוֹל צִנּוֹרֶיךָ, כָּל-מִשְׁבָּרֶיךָ וְגַלֶּיךָ עָלַי עָבָרוּ: יוֹמָם יְצַוֶּה יהוה חַסְדּוֹ, וּבַלַּיְלָה שִׁירֹה עִמִּי, תְּפִלָּה לְאֵל חַיָּי: אוֹמְרָה לְאֵל סַלְעִי, לָמָה שְׁכַחְתָּנִי, לָמָּה-קֹדֵר אֵלֵךְ, בְּלַחַץ אוֹיֵב: בְּרֶצַח בְּעַצְמוֹתַי, חֵרְפוּנִי צוֹרְרָי, בְּאָמְרָם אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"שָׁפְטֵנִי אֱלֹהִים וְרִיבָה רִיבִי, מִגּוֹי לֹא חָסִיד, מֵאִישׁ מִרְמָה וְעַוְלָה תְפַלְּטֵנִי: כִּי-אַתָּה אֱלֹהֵי מָעוּזִּי, לָמָה זְנַחְתָּנִי, לָמָּה-קֹדֵר אֶתְהַלֵּךְ בְּלַחַץ אוֹיֵב: שְׁלַח-אוֹרְךָ וַאֲמִתְּךָ הֵמָּה יַנְחוּנִי, יְבִיאוּנִי אֶל-הַר-קָדְשְׁךָ וְאֶל-מִשְׁכְּנוֹתֶיךָ: וְאָבוֹאָה אֶל-מִזְבַּח אֱלֹהִים, אֶל-אֵל שִׂמְחַת גִּילִי, וְאוֹדְךָ בְכִנּוֹר, אֱלֹהִים אֱלֹהָי: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, אוֹדֶה יהוה בְּכָל לֵבָב, בְּסוֹד יְשָׁרִים וְעֵדָה: גְּדֹלִים מַעֲשֵׂי יהוה, דְּרוּשִׁים לְכָל חֶפְצֵיהֶם: הוֹד וְהָדָר פָּעֳלוֹ, וְצִדְקָתוֹ עֹמֶדֶת לָעַד: זֵכֶר עָשָׂה לְנִפְלְאֹתָיו, חַנּוּן וְרַחוּם יהוה: טֶרֶף נָתַן לִירֵאָיו, יִזְכֹּר לְעוֹלָם בְּרִיתוֹ: כֹּחַ מַעֲשָׂיו הִגִּיד לְעַמּוֹ, לָתֵת לָהֶם נַחֲלַת גּוֹיִם: מַעֲשֵׂי יָדָיו אֱמֶת וּמִשְׁפָּט, נֶאֱמָנִים כָּל פִּקּוּדָיו: סְמוּכִים לָעַד לְעוֹלָם, עֲשׂוּיִם בֶּאֱמֶת וְיָשָׁר: פְּדוּת שָׁלַח לְעַמּוֹ, צִוָּה לְעוֹלָם בְּרִיתוֹ, קָדוֹשׁ וְנוֹרָא שְׁמוֹ: רֵאשִׁית חָכְמָה יִרְאַת יהוה, שֵׂכֶל טוֹב לְכָל עֹשֵׂיהֶם, תְּהִלָּתוֹ עֹמֶדֶת לָעַד:\n\nלַמְנַצֵּחַ מִזְמוֹר לְדָוִד: בְּבוֹא אֵלָיו נָתָן הַנָּבִיא, כַּאֲשֶׁר-בָּא אֶל-בַּת-שָׁבַע: חָנֵּנִי אֱלֹהִים כְּחַסְדֶּךָ, כְּרֹב רַחֲמֶיךָ מְחֵה פְשָׁעָי: הֶרֶב כַּבְּסֵנִי מֵעֲוׂנִי, וּמֵחַטָּאתִי טַהֲרֵנִי: כִּי-פְשָׁעַי אֲנִי אֵדָע, וְחַטָּאתִי נֶגְדִּי תָמִיד: לְךָ לְבַדְּךָ חָטָאתִי, וְהָרַע בְּעֵינֶיךָ עָשִׂיתִי, לְמַעַן-תִּצְדַּק בְּדָבְרֶךָ, תִּזְכֶּה בְשָׁפְטֶךָ: הֵן-בְּעָווֹן חוֹלָלְתִּי, וּבְחֵטְא יֶחֱמַתְנִי אִמִּי: הֵן אֱמֶת חָפַצְתָּ בַטֻּחוֹת, וּבְסָתֻם חָכְמָה תוֹדִיעֵנִי: תְּחַטְּאֵנִי בְאֵזוֹב וְאֶטְהָר, תְּכַבְּסֵנִי וּמִשֶּׁלֶג אַלְבִּין: תַּשְׁמִיעֵנִי שָׂשׂוֹן וְשִׂמְחָה, תָּגֵלְנָה עֲצָמוֹת דִּכִּיתָ: הַסְתֵּר פָּנֶיךָ מֵחֲטָאָי, וְכָל-עֲוׂנתַי מְחֵה: לֵב טָהוֹר בְּרָא-לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי: אַל-תַּשְׁלִיכֵנִי מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל-תִּקַּח מִמֶּנִּי: הָשִׁיבָה לִּי שְׂשׂוֹן יִשְׁעֶךָ, וְרוּחַ נְדִיבָה תִסְמְכֵנִי: אֲלַמְּדָה פֹשְׁעִים דְּרָכֶיךָ, וְחַטָּאִים אֵלֶיךָ יָשׁוּבוּ: הַצִּילֵנִי מִדָּמִים אֱלֹהִים אֱלֹהֵי תְשׁוּעָתִי, תְּרַנֵּן לְשׁוֹנִי צִדְקָתֶךָ: אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ: כִּי לֹא-תַחְפֹּץ זֶבַח וְאֶתֵּנָה, עוֹלָה לֹא תִרְצֶה: זִבְחֵי אֱלֹהִים רוּחַ נִשְׁבָּרָה, לֵב-נִשְׁבָּר וְנִדְכֶּה אֱלֹהִים לֹא תִבְזֶה: הֵיטִיבָה בִרְצוֹנְךָ אֶת-צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם: אָז תַּחְפֹּץ זִבְחֵי-צֶדֶק, עוֹלָה וְכָלִיל, אָז יַעֲלוּ עַל-מִזְבַּחֲךָ פָרִים:","cond":[]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם.","cond":["rachel"]},{"kind":"text","text":"תָקוּם תְּרַחֵם צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר או\"א ומזמור בשוב ה' כדי לפסוק בנחמה (בא\"ח וישלח)","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כּבַתְּחִלָּה, כּוֹנֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם, וּלְוִיִּים לְדוּכָנָם, לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְּשִׂמְחָה לְאַרְצֵנוּ, וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשֵׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חֹבֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם.\n\nשִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]}],"edot_mizrach":[{"kind":"instruction","text":"סדר תיקון חצות","cond":[]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִּקּוּן רָחֵל וְתִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשָׁם בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["rachel"]},{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מֵעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הֲרֵינִי מוּכָן לוֹמַר תִקּוּן לֵאָה, כְּמוֹ שֶׁסִּדְּרוּ לָנוּ רַבּוֹתֵינוּ זִכְרוֹנָם לִבְרָכָה לְתַקֵּן אֶת שָׁרְשׁוֹ בְּמָקוֹם עֶלְיוֹן, לַעֲשׂוֹת נַחַת רוּחַ לְיוֹצְרֵנוּ וְלַעֲשׂוֹת רְצוֹן בּוֹרְאֵנוּ. וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ: וִיהִי נֹעַם אֲדֹנָי אֱלֹהֵינוּ עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנָה עָלֵינוּ, וּמַעֲשֵׂה יָדֵינוּ כּוֹנְנֵהוּ:","cond":["noRachel"]},{"kind":"header","text":"תיקון רחל","cond":["rachel"]},{"kind":"instruction","text":"תיקון רחל","cond":["rachel"]},{"kind":"text","text":"אָנָּא יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, תָּבֹא לְפָנֶיךָ תְּפִלָּתֵנוּ, וְאַל תִּתְעַלַּם מַלְכֵּנוּ מִתְּחִנָּתֵנוּ, שֶׁאֵין אֲנַחְנוּ עַזֵּי פָנִים וּקְשֵׁי עֹרֶף לוֹמַר לְפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ צַדִּיקִים אֲנַחְנוּ וְלֹא חָטָאנוּ, אֲבָל חָטָאנוּ, עָוִינוּ, פָּשַׁעְנוּ, אֲנַחְנוּ וַאֲבוֹתֵינוּ וְאַנְשֵׁי בֵיתֵנוּ:\n\nאָשַׁמְנוּ. בָּגַדְנוּ. גָּזַלְנוּ. דִּבַּרְנוּ דוֹפִי וְלָשׁון הָרָע. הֶעֱוִינוּ. וְהִרְשַׁעְנוּ. זַדְנוּ. חָמַסְנוּ. טָפַלְנוּ שֶׁקֶר וּמִרְמָה. יָעַצְנוּ עֵצוֹת רָעוֹת. כִּזַּבְנוּ. כָּעַסְנוּ. לַצְנוּ. מָרַדְנוּ. מָרִינוּ דְבָרֶיךָ. נִאַצְנוּ. נִאַפְנוּ. סָרַרְנוּ. עָוִינוּ. פָּשַׁעְנוּ. פָּגַמְנוּ. צָרַרְנוּ. צִעַרְנוּ אָב וָאֵם. קִשִּׁינוּ עֹרֶף. רָשַׁעְנוּ. שִׁחַתְנוּ. תִּעַבְנוּ. תָּעִינוּ וְתִעֲתַעְנוּ, וְסַרְנוּ מִמִּצְוׂתֶיךָ וּמִמִּשְׁפָּטֶיךָ הַטּוֹבִים וְלֹא שָׁוָה לָנוּ. וְאַתָּה צַדִּיק עַל כָּל הַבָּא עָלֵינוּ, כִּי אֱמֶת עָשִׂיתָ. ואֲנַחְנוּ הִרְשָׁעְנוּ:\n\nמַה נֹּאמַר לְפָנֶיךָ יוֹשֵׁב מָרוֹם, וּמַה נְּסַפֵּר לְפָנֶיךָ שׁוֹכֵן שְׁחָקִים, הֲלֹא הַנִּסְתָּרוֹת וְהַנִּגְלוֹת אַתָּה יוֹדֵעַ. אַתָּה יוֹדֵעַ רָזֵי עוֹלָם. וְתַעֲלוּמוֹת סִתְרֵי כָל חָי. אַתָּה חֹפֵשׂ כָּל חַדְרֵי בָטֶן, רוֹאֶה כְלָיוֹת וָלֵב. אֵין דָּבָר נֶעְלָם מִמֶּךָּ, וְאֵין נִסְתָּר מִנֶּגֶד עֵינֶיךָ.\nיְהִי רָצוֹן מִלְּפָנֶיךָ, יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, שֶׁתִּמְחֹל לָנוּ אֶת כָּל חַטֹּאתֵינוּ, וּתְכַפֵּר לָנוּ אֶת כָּל עֲוׂנוֹתֵינוּ, וְתִמְחֹל וְתִסְלַח לְכָל פְּשָׁעֵינוּ.","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על חורבן בית המקדש, יישב על הארץ כאבל ויאמר:","cond":["rachel"]},{"kind":"text","text":"עַל נַהֲרוֹת בָּבֶל, שָׁם יָשַׁבְנוּ גַּם בָּכִינוּ בְּזָכְרֵנוּ אֶת צִיּוֹן: עַל עֲרָבִים בְּתוֹכָהּ תָּלִינוּ כִּנֹּרוֹתֵינוּ: כִּי שָׁם שְׁאֵלוּנוּ שׁוֹבֵינוּ דִּבְרֵי שִׁיר וְתוֹלָלֵינוּ שִׂמְחָה, שִׁירוּ לָנוּ מִשִּׁיר צִיּוֹן: אֵיךְ נָשִׁיר אֶת שִׁיר יהוה עַל אַדְמַת נֵכָר: אִם אֶשְׁכָּחֵךְ יְרוּשָׁלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָׁלַיִם עַל רֹאשׁ שִׂמְחָתִי: זְכֹר יהוה לִבְנֵי אֱדוֹם אֵת יוֹם יְרוּשָׁלָיִם, הָאֹמְרִים עָרוּ עָרוּ עַד הַיְסוֹד בָּהּ: בַּת בָּבֶל הַשְּׁדוּדָה, אַשְׁרֵי שֶׁיְשַׁלֶּם לָךְ אֶת גְּמוּלֵךְ שֶׁגָּמַלְתְּ לָנוּ: אַשְׁרֵי שֶׁיֹּאחֵז וְנִפֵּץ אֶת עֹלָלַיִךְ אֶל הַסָּלַע:","cond":["rachel"]},{"kind":"instruction","text":"יכוון לבכות על הרג צדיקים","cond":["rachel"]},{"kind":"text","text":"מִזְמוֹר לְאָסָף, אֱלֹהִים, בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ טִמְּאוּ אֶת הֵיכַל קָדְשֶׁךָ, שָׂמוּ אֶת יְרוּשָׁלַיִם לְעִיִּים: נָתְנוּ אֶת נִבְלַת עֲבָדֶיךָ מַאֲכָל לְעוֹף הַשָּׁמָיִם, בְּשַׂר חֲסִידֶיךָ לְחַיְתוֹ אָרֶץ: שָׁפְכוּ דָמָם כַּמַּיִם סְבִיבוֹת יְרוּשָׁלִָם וְאֵין קוֹבֵר: הָיִינוּ חֶרְפָּה לִשְׁכֵנֵינוּ, לַעַג וָקֶלֶס לִסְבִיבוֹתֵינוּ: עַד מָה יהוה תֶּאֱנַף לָנֶצַח, תִּבְעַר כְּמוֹ אֵשׁ קִנְאָתֶךָ: שְׁפֹךְ חֲמָתְךָ אֶל הַגּוֹיִם אֲשֶׁר לֹא יְדָעוּךָ, וְעַל מַמְלָכוֹת אֲשֶׁר בְּשִׁמְךָ לֹא קָרָאוּ: כִּי אָכַל אֶת יַעֲקֹב וְאֶת נָוֵהוּ הֵשַׁמּוּ: אַל תִּזְכָּר לָנוּ עֲוׂנֹת רִאשֹׁנִים, מַהֵר יְקַדְּמוּנוּ רַחֲמֶיךָ כִּי דַלּוֹנוּ מְאֹד: עָזְרֵנוּ אֱלֹהֵי יִשְׁעֵנוּ עַל דְּבַר כְּבוֹד שְׁמֶךָ, וְהַצִּילֵנוּ וְכַפֵּר עַל חַטֹּאתֵינוּ לְמַעַן שְׁמֶךָ: לָמָּה יֹאמְרוּ הַגּוֹיִם אַיֵּה אֱלֹהֵיהֶם, יִוָּדַע בַּגּוֹיִם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ: תָּבוֹא לְפָנֶיךָ אֶנְקַת אָסִיר כְּגֹדֶל זְרוֹעֲךָ הוֹתֵר בְּנֵי תְמוּתָה: וְהָשֵׁב לִשְׁכֵנֵינוּ שִׁבְעָתַיִם אֶל חֵיקָם חֶרְפָּתָם אֲשֶׁר חֵרְפוּךָ אֲדֹנָי: וַאֲנַחְנוּ עַמְּךָ וְצֹאן מַרְעִיתֶךָ נוֹדֶה לְּךָ לְעוֹלָם, לְדֹר וָדֹר נְסַפֵּר תְּהִלָּתֶךָ:","cond":["rachel"]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:\n\nהַבֵּט מִשָּׁמַיִם וּרְאֵה מִזְּבֻל קָדְשְׁךָ וְתִפְאַרְתֶּךָ, אַיֵּה קִנְאָתְךָ וּגְבוּרֹתֶךָ, הֲמוֹן מֵעֶיךָ וְרַחֲמֶיךָ אֵלַי הִתְאַפָּקוּ: כִּי אַתָּה אָבִינוּ, כִּי אַבְרָהָם לֹא יְדָעָנוּ וְיִשְׂרָאֵל לֹא יַכִּירָנוּ, אַתָּה יהוה אָבִינוּ, גֹּאֲלֵנוּ מֵעוֹלָם שְׁמֶךָ: לָמָּה תַתְעֵנוּ יהוה מִדְּרָכֶיךָ, תַּקְשִׁיחַ לִבֵּנוּ מִיִּרְאָתֶךָ, שׁוּב לְמַעַן עֲבָדֶיךָ שִׁבְטֵי נַחֲלָתֶךָ: לַמִּצְעָר יָרְשׁוּ עַם קָדְשֶׁךָ, צָרֵינוּ בּוֹסְסוּ מִקְדָּשֶׁךָ:\n\nוְעַתָּה יהוה אָבִינוּ אָתָּה, אֲנַחְנוּ הַחֹמֶר וְאַתָּה יֹצְרֵנוּ, וּמַעֲשֵׂה יָדְךָ כֻּלָּנוּ: אַל תִּקְצֹף יהוה עַד מְאֹד וְאַל לָעַד תִּזְכֹּר עָוׂן, הֵן הַבֶּט נָא עַמְּךָ כֻלָּנוּ: עָרֵי קָדְשְׁךָ הָיוּ מִדְבָּר, צִיּוֹן מִדְבָּר הָיָתָה, יְרוּשָׁלִַם שְׁמָמָה: בֵּית קָדְשֵׁנוּ וְתִפְאַרְתֵּנוּ אֲשֶׁר הִלְלוּךָ אֲבֹתֵינוּ הָיָה לִשְׂרֵפַת אֵשׁ, וְכָל מַחֲמַדֵּינוּ הָיָה לְחָרְבָּה: הַעַל אֵלֶּה תִתְאַפַּק יהוה, תֶּחֱשֶׁה וּתְעַנֵּנוּ עַד מְאֹד:","cond":["rachel"]},{"kind":"instruction","text":"בימי בין המצרים מוסיפים:","cond":["rachel","threeWeeks"]},{"kind":"text","text":"הֲמָאֹס מָאַסְתָּ אֶת יְהוּדָה, אִם בְּצִיּוֹן גָּעֲלָה נַפְשֶׁךָ, מַדּוּעַ הִכִּיתָנוּ וְאֵין לָנוּ מַרְפֵּא, קַוֵּה לְשָׁלוֹם וְאֵין טוֹב, וּלְעֵת מַרְפֵּא וְהִנֵּה בְעָתָה: יָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ, עֲוׂן אֲבוֹתֵינוּ, כִּי חָטָאנוּ לָךְ: אַל תִּנְאַץ לְמַעַן שִׁמְךָ, אַל תְּנַבֵּל כִּסֵּא כְבוֹדֶךָ, זְכֹר, אַל תָּפֵר בְּרִיתְךָ אִתָּנוּ:\n\nכֹּה אָמַר אֲדֹנָי, קוֹל בְּרָמָה נִשְׁמָע, נְהִי בְּכִי תַמְרוּרִים, רָחֵל מְבַכָּה עַל בָּנֶיהָ, מֵאֲנָה לְהִנָּחֵם עַל בָּנֶיהָ כִּי אֵינֶנּוּ: אֲדֹנָי מִמָּרוֹם יִשְׁאָג וּמִמְּעוֹן קָדְשׁוֹ יִתֵּן קוֹלוֹ, שָׁאֹג יִשְׁאַג עַל נָוֵהוּ: וַיִּקְרָא אֲדֹנָי אֱלֹהִים צְבָאוֹת בַּיּוֹם הַהוּא לִבְכִי וּלְמִסְפֵּד וּלְקָרְחָה וְלַחֲגֹר שָׂק: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: הֵן אֶרְאֶלָּם צָעֲקוּ חֻצָה, מַלְאֲכֵי שָׁלוֹם מַר יִבְכָּיוּן:\n\n\nהִקָּבְצוּ וְשִׁמְעוּ בְּנֵי יַעֲקֹב כֻּלְּכֶם, קִרְעוּ לְבַבְכֶם וְאַל בִּגְדֵיכֶם, כִּי בְפִשְׁעֵיכֶם שֻׁלְּחָה אִמְּכֶם, וּתְנוּ כָבוֹד לַאֲדֹנָי אֱלֹהֵיכֶם.\n\nמִי הָאִישׁ הֶחָפֵץ חַיִּים וְחֵךְ אֹכֶל יִטְעַם לוֹ, אוֹהֵב יָמִים לִרְאוֹת טוֹב וּלְבַקֵּר בְּהֵיכָלוֹ, וְהָאֱלֹהִים יִרְאֶה לוֹ לִשְׁכֹּן בְּאָהֳלוֹ מִבְּלִי לוֹ, אֲשֶׁר לֹא עָמַל בּוֹ וְלֹא גִדְּלוֹ.\n\nאָנָה הָלַךְ דּוֹדֵךְ תַּרְקִיעַ עִמּוֹ לִשְׁחָקִים, אָנֹכִי חָטָאתִי וְהוּא אָסוּר בָּזִקִּים, וְעַל זֹאת סִפְדוּ וְהֵילִילוּ בֹּאוּ וְלִינוּ בַשַּׂקִּים, בָּרְחוֹבוֹת וּבַשְּׁוָקִים.\n\nשְׁכִינָה מָה אוֹמֶרֶת קַלַּנִי מֵרֹאשִׁי, הַגְּדֻלָּה וְהַגְּבוּרָה וְהַתִּפְאֶרֶת עָבְרוּ רֹאשִׁי, וְהַנֵּצַח וְהַהוֹד אֵין דּוֹרֵשׁ לְנַפְשִׁי, וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי.\n\nעַל זֹאת אֶסְפְּדָה וְאֵילִילָה, אֲסַלְּדָה בְחִילָה, קוֹלִי כַּחוֹלָה, מֵעַי מֵעַי אוֹחִילָה, לְמַעַנְכֶם שֻׁלַּחְתִּי בָּבֶלָה, וַאֲנִי בְּתוֹךְ הַגּוֹלָה.\n\nעֲוׂנוֹתֵיכֶם הִטּוּ אֵלֶּה וְחַטֹּאתֵיכֶם, הִגְלֵיתִי אֶתְכֶם לְיַסְּרָה אֶתְכֶם, וַיִּתְעַבֵּר אֲדֹנָי בִּי לְמַעַנְכֶם, וַיִּשְׁלָחֵנִי אֱלֹהִים לִפְנֵיכֶם.\n\nבְּבֵית יִשְׂרָאֵל רָאִיתִי שַׁעֲרוּרִיָּה, אֵין אִישׁ שָׂם עַל לֵב שַׁלָּמָּה אֶהְיֶה כְּעוֹטְיָה, כְּקִיר נָטוּי וּכְגָדֵר הַדְּחוּיָה, הֲמִדְבָּר הָיִיתִי לְיִשְׂרָאֵל אִם אֶרֶץ מַאְפֵּלְיָה.\n\nיָדַעְנוּ אֲדֹנָי רִשְׁעֵנוּ וַעֲוׂן אֲבוֹתֵינוּ, הִנְנוּ אָתָאנוּ לְךָ אֲדֹנָי אֱלֹהֵינוּ, שׁוּב לְמַעַן עֲבָדֶיךָ וְסָלַחְתָּ לַעֲוׂנֵנוּ, תָּשׁוּב תְּרַחֲמֵנוּ וְתִכְבֹּשׁ עֲוׂנוֹתֵינוּ.\n\nוַיֹּאמֶר אֲדֹנָי אָהַבְתִּי אֶתְכֶם, כָּל יִשְׁעִי וְכָל חֶפְצִי אָשׁוּב לְרַחֶמְכֶם, שׁוּבוּ אֵלַי וְאָשׁוּבָה אֲלֵיכֶם, אָנֹכִי אָנֹכִי הוּא מְנַחֶמְכֶם.\n\nאִמְרוּ לְבַת צִיּוֹן כֹּה אָמַר אֲדוֹנָיִךְ, תַּחַת הֱיוֹתֵךְ עֲזוּבָה יִבְעָלוּךְ בָּנָיִךְ, וְכִמְשׂוֹשׂ חָתָן עַל כַּלָּה יָשִׂישׂ עָלַיִךְ אֱלֹהָיִךְ, וְהָיִית עֲטֶרֶת תִּפְאֶרֶת בְּיַד אֲדֹנָי, וּצְנִיף מְלוּכָה בְּכַף אֱלֹהָיִךְ.\n\n\nקוֹל בְּרָמָה נִשְׁמָע בִּילָלָה, קוֹל נְהִי מִצִּיּוֹן הַמְהֻלָּלָה.\n\nחִשַּׁבְתִּי יָמִים הָיִיתִי גְבֶרֶת, בְּיַד אֲדֹנָי עֲטֶרֶת תִּפְאֶרֶת, וְעַתָּה אֲנִי שְׁחַרְחֹרֶת, טָבַעְתִּי בַבּוֹר בִּיוֵן מְצוּלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיְחִידָה רַעְיָה אֲזַי הָיִיתִי, וּכְבוֹד עֶלְיוֹן אֲנִי נִקְרֵאתִי, וְעַתָּה לְתַחְתִּיּוֹת יָרַדְתִּי, וְדוֹדִי וְרֵעִי לָרוּם עָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nיַחַד יוֹדְעַי בְּתוּלוֹתַי וְרַעְיוֹתַי, בְּכוּ נָא עִמִּי כִּי רַבּוֹת אַנְחוֹתַי, אֵין נוֹטֶה עוֹד אָהֳלִי וּמֵקִים יְרִיעוֹתַי, כִּי דוֹדִי מֶנִּי נָסַע וְנִגְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nמִמָּרוֹם הֻשְׁלַכְתִּי בְּרֹב מְגִנָּה, שָׁלַח אֵשׁ בְּעַצְמוֹתַי וַיִּרְדֶּנָּה, וְיָצָאתִי בַגּוֹלָה בָּדָד כְּאַלְמָנָה, הָגְלָה יְהוּדָה הָגְלַת שְׁלוֹמִים כֻּלָּהּ. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהָיִיתִי כְכַלָּה בְּתוֹךְ אַפִּרְיוֹן, וַעֲנַן יוֹמָם עַל מְכוֹן הַר צִיּוֹן, הֻשְׁלַכְתִּי לַחוּץ כְּעָנִי וְאֶבְיוֹן, בְּגָדַי לָקַח צָר וַאֲנִי אֻמְלָלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nכֹּהֲנַי וּזְקֵנַי טָבְחוּ אוֹיְבַי, מַחֲזִיקִים בִּבְרִיתִי זֶרַע אוֹהֲבַי, בָּנַי הַיְקָרִים וּבַחוּרַי, הָלְכוּ בַשֶּׁבִי וְעוֹלָלַי בַּגּוֹלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nהֵן כָּל אֵלֶּה אֵין דּוֹרֵשׁ לְנַפְשִׁי, אִמָּלְאָה הָחֳרָבָה וְאֶל עַמִּים אָרִים רֹאשִׁי, וְאוֹיְבִי אָמַר לֹא תִקְרְאִי עוֹד אִישִׁי, כִּי נָפַלְתִּי לִפְנֵי בְנֵי עַוְלָה. קוֹל בְּרָמָה נִשְׁמָע בִּילָלָה.\n\nנָא אָב הָרַחֲמָן תָּשׁוּב לְצִיּוֹן, עַיִן בְּעַיִן נִרְאֶה בְּבִנְיַן אַפִּרְיוֹן, וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן, וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה. וְהַבַּיִת הַזֶּה יִהְיֶה עֶלְיוֹן. וְאָז גְּאוּלִים יִפְצְחוּ צָהֳלָה.\n\n\nעַד מָתַי אֲדֹנָי בְּיוֹם זֶה לְעֻמָּתֶךָ, בְּמַר תְּיַלֵּל עֲדָתֶךָ, עַל בֵּית תְּפִלָּתֶךָ, אֲשֶׁר שָׂרְפוּ צָרֶיךָ, וְהָרְגוּ בְּנֵי בְרִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי תִּשְׁכַּח שְׁאוֹן קָמֶיךָ, וְשׁוֹמְמוֹת הֵיכָלֶךָ, וּנְפוּצוֹת לְאֻמֶּךָ, הַלְּחוּצִים עָלֶיךָ.\nהַהֲרוּגִים עַל שְׁמֶךָ.\n\nעַד מָתַי עָשַׁנְתָּ בִּתְפִלַּת עַמֶּךָ, אֲשֶׁר יֶהֱגוּ לְפָנֶיךָ, עַל חֻרְבַּן בֵּיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי אֶשְׁכְּבָה בֵּין שְׁפַתָּיִם, וּבֵין תַּנּוּר וְכִירָיִם, יִכְהוּ לִי עֵינָיִם.\nלוֹהֲטִים לִי יִשְׁאֲפוּ עֶרֶב וָבֹקֶר וְצָהֳרָיִם.\n\nעַד מָתַי אֶשְׁתּוֹמֵם עַל חֻרְבַּן פַּעֲמַיִם, עַד מָתַי לֹא תְרַחֵם אֶת יְרוּשָׁלַיִם, עַד מָתַי יֶהֱגוּ בַּצַר שְׁאֵרִית צֹאן מַרְעִיתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\nעַד מָתַי אֲדֹנָי עַכּוּ\"ם יַעֲלֹזוּ, אֲשֶׁר אָכַל אֶת יַעֲקֹב וּבְכָל עֵת יָבוֹזּוּ, אֲנִי אֶדְרשׁ אֶת שְׁלוֹמָם וְהֵם יִמְרֹטוּ וְיָגֹזּוּ.\nבְּחֶרְפָּה הִכּוּ לְחָיַי וּבְשִׂפְתֵי שָׁוְא נָלוֹזוּ.\n\nעַד מָתַי אֲדֹנָי רְשָׁעִים יַעֲלֹזוּ, עַד אָן יִצְעַק בַּשְּׁבִי (פלוני בן פלונית) אֲמָתֶךָ.\nאֱלֹהִים בָּאוּ גוֹיִם בְּנַחֲלָתֶךָ.\n\n\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת. הִנֵּה זֹאת תּוֹרַת הַבָּיִת.\n\nאֵיכָה נֶחֱרַב הָאוּלָם, וְנֶהֱרַס יְסוֹד הָעוֹלָם, וְחִלּוּ כּוֹכָבִים וְהִלָּם, וּבָא אֲשֶׁר לוֹ הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nדִּירַת קֹדֶשׁ אֲשֶׁר בָּנִיתָ, לְהַנְחִיל לְעַם זוּ קָנִיתָ, אוֹי כִּי הָאוֹיְבִים צִוִּיתָ, יָבֹאוּ וּפִנּוּ אֶת הַבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nנֶחְשְׁכוּ כָּל מְאוֹרֶיהָ, סֻגָּרוּ כָּל שְׁעָרֶיהָ, עַד כִּי אָמְרוּ כָּל רוֹאֶיהָ, כְּנֶגַע נִרְאָה לִי בַּבָּיִת.\nבְּהֵיכָלָךְ שָׁמִיר וָשַׁיִת.\n\nאֲדֹנָי שׁוּב מֵחֲרוֹן אַפְּךָ וַחֲמָתֶךָ, וּזְכֹר דְּבַר נְבוּאָתֶךָ, לְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\nלְבַשֵּׂר נָא לַעֲדָתֶךָ, גָּדוֹל יִהְיֶה כְּבוֹד הַבַּיִת.\n\n\nאוֹי לִי עַל גָּלוּת הַשְּׁכִינָה.\nאוֹי לִי עַל חֻרְבָּן בֵּית הַמִּקְדָּשׁ.\nאוֹי לִי עַל שְׂרֵפַת הַתּוֹרָה.\nאוֹי לִי עַל הֲרִיגַת הַצַּדִּיקִים.\nאוֹי לִי עַל חִלּוּל שְׁמוֹ הַגָּדוֹל וְתוֹרָתוֹ הַקְּדוֹשָׁה.\nאוֹי לִי עַל כִּי גָבַר אוֹיֵב.\nאוֹי לִי עַל תִּנּוֹקוֹת שֶׁל בֵּית רַבָּן שֶׁבָּטֵלוּ.\nאוֹי לִי עַל צַעַר כָּל הָעוֹלָמוֹת.\nאוֹי לִי עַל צער הָאָבוֹת הַקְּדוֹשִׁים וְהָאִמָּהוֹת הַקְּדוֹשׁוֹת.\nאוֹי לִי עַל צער הַנְּבִיאִים וְהַחֲסִידִים וְהַצַּדִּיקִים אֲשֶׁר בְּגַן עֵדֶן.\nאוֹי לִי עַל צַעֲרוֹ שֶׁל מָשִיחַ.\nעֲוׂנוֹתֵינוּ הִטּוּ אֵלֶּה וּפְשָׁעֵינוּ הֶאֱרִיכוּ קִצֵּנוּ וְחַטֹּאתֵינוּ מָנְעוּ הַטּוֹב מִמֶּנּוּ.\nאוֹי לָהֶם לְבָנִים שֶׁגָּלוּ מֵעַל שֻׁלְחַן אֲבִיהֶם זֶה כַּמָּה אֹרֶך יָמִים וְשָׁנִים רַבִּים וְרָעִים.\nוְכָל דוֹר שֶׁלֹּא נִבְנָה בֵּית הַמִּקְדָּשׁ בְּיָמָיו כְּאִלּוּ נֶחְרַב בְּיָמָיו.\n\n\nעַל הֵיכָלִי אֶבְכֶּה יוֹמָם וָלָיְלָה. וּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\nבְּכִי תָמִיד עַל הַחֻרְבָּן פַּעֲמָיִם.\nאֶרֶץ צְבִי וִירוּשָׁלָיִם.\nוְעַל עַמָּהּ אֲשֶׁר הָלְכוּ בַגּוֹלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nבֵּית תִּפְאַרְתִּי שָׂם אוֹיֵב לְשַׁמָּה.\nהוֹשִׁיבַנִי בִּידֵי נְבָיוֹת וְשַׁמָּה.\nעַל זֹאת אֶבְכֶּה תָמִיד בְּקוֹל יְלָלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nסִפְדִי תּוֹרָה כִּי חֻלְלָה תִּפְאַרְתֵּךְ.\nנָפְלָה נִזְרֵךְ מִיּוֹם שֶׁחָרַב בֵּיתֵךְ.\nעַל זֹאת אֶשָּׂא קִינָה עַל אָהֳלִיבָה וְאָהֳלָה.\nוּלְתִפְאֶרֶת צִיּוֹן עִיר הַמְהֻלָּלָה.\n\nחִזְקִי עַמִּי מַהֵר אֶבְנֶה דְבִירְכֶם.\nנָקָם אַלְבִּישׁ וְאָשִׁיב אֶת שְׁבוּתְכֶם.\nתּוֹךְ הֵיכָלִי אֶשְׁכֹּן כְּבַתְּחִלָּה.\nכִּי מִצִּיּוֹן תֵּצֵא תוֹרָה וּתְהִלָּה.\nכְּדִכְתִיב: כִּי מִצִּיּוֹן תֵּצֵא תוֹרָה, וּדְבַר אֲדֹנָי מִירוּשָׁלָיִם:\n\n\nעוּרָה נָּא יְמִינְךָ רָמָה.\nוְלִזְעוּמָה קְרָא נֻחָמָה.\nוְיֵאָמֵר לְעַם דַּלָּה וַעֲגוּמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא חֲשׂוֹף זְרוֹעֲךָ.\nוְיִגָּלֶה קֵץ יִשְׁעֲךָ.\nוְיֵאָמֵר לְשֶׂה נֶאֱלָמָה.\nעֲנִיָּה סֹעֲרָה רֻחָמָה.\n\nעוּרָה נָּא יְמִינְךָ הָאֵל.\nוּפְדֵה בְּרַחֲמֶיךָ יִשְׂרָאֵל.\nוְיֵאָמֵר לְעַם דַּל הַשּׁוֹאֵל.\nוּבָא לְצִיּוֹן גּוֹאֵל.\n\nעוּרָה נָּא יְמִינְךָ עֶלְיוֹן.\nוּבְנֵה בְּרַחֲמֶיךָ אֶת צִיּוֹן.\nוְיֵאָמֵר לְעַם דַּל וְאֶבְיוֹן.\nכִּי נִחַם אֲדֹנָי צִיּוֹן.\nכְּדִכְתִיב: כִּי נִחַם אֲדֹנָי צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן אֲדֹנָי, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה.\n\n\nהִתְנַעֲרִי מֵעָפָר, קוּמִי שְּׁבִי יְרוּשָׁלִָם, הִתְפַּתְּחִי מוֹסְרֵי צַוָּארֵךְ שְׁבִיָּה בַּת צִיּוֹן:","cond":["rachel","threeWeeks"]},{"kind":"instruction","text":"עד כאן לימי בין המצרים","cond":["rachel","threeWeeks"]},{"kind":"text","text":"עַל חוֹמֹתַיִךְ יְרוּשָׁלִַם הִפְקַדְתִּי שֹׁמְרִים, כָּל הַיּוֹם וְכָל הַלַּיְלָה תָּמִיד לֹא יֶחֱשׁוּ, הַמַּזְכִּרִים אֶת יהוה אַל דֳּמִי לָכֶם: וְאַל תִּתְּנוּ דֳמִי לוֹ, עַד יְכוֹנֵן וְעַד יָשִׂים אֶת יְרוּשָׁלַיִם תְּהִלָּה בָּאָרֶץ: נִשְׁבַּע יהוה בִּימִינוֹ וּבִזְרוֹעַ עֻזּוֹ, אִם אֶתֵּן אֶת דְּגָנֵךְ עוֹד מַאֲכָל לְאֹיְבַיִךְ וְאִם יִשְׁתּוּ בְנֵי נֵכָר תִּירוֹשֵׁךְ אֲשֶׁר יָגַעַתְּ בּוֹ: כִּי מְאַסְפָיו יֹאכְלֻהוּ וְהִלְלוּ אֶת יהוה, וּמְקַבְּצָיו יִשְׁתֻּהוּ בְּחַצְרוֹת קָדְשִׁי:\n\nאַתָּה תָקוּם תְּרַחֵם צִיּוֹן, כִּי עֵת לְחֶנְנָהּ כִּי בָא מוֹעֵד: כִּי רָצוּ עֲבָדֶיךָ אֶת אֲבָנֶיהָ וְאֶת עֲפָרָהּ יְחֹנֵנוּ: בּוֹנֵה יְרוּשָׁלִַם יהוה, נִדְחֵי יִשְׂרָאֵל יְכַנֵּס:","cond":["rachel"]},{"kind":"header","text":"תיקון לאה","cond":[]},{"kind":"instruction","text":"תיקון לאה","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מַשְׂכִּיל לִבְנֵי-קֹרַח: כְּאַיָּל תַּעֲרֹג עַל-אֲפִיקֵי-מָיִם, כֵּן נַפְשִׁי תַעֲרֹג אֵלֶיךָ אֱלֹהִים: צָמְאָה נַפְשִׁי לֵאלֹהִים, לְאֵל חָי, מָתַי אָבוֹא וְאֵרָאֶה פְּנֵי אֱלֹהִים: הָיְתָה-לִּי דִמְעָתִי לֶחֶם יוֹמָם וָלָיְלָה, בֶּאֱמֹר אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: אֵלֶּה אֶזְכְּרָה וְאֶשְׁפְּכָה עָלַי נַפְשִׁי, כִּי אֶעֱבֹר בַּסָּךְ אֶדַּדֵּם עַד-בֵּית אֱלֹהִים, בְּקוֹל-רִנָּה וְתוֹדָה, הָמוֹן חוֹגֵג: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וַתֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעוֹת פָּנָיו: אֱלֹהַי, עָלַי נַפְשִׁי תִשְׁתּוֹחָח, עַל-כֵּן אֶזְכָּרְךָ מֵאֶרֶץ יַרְדֵּן, וְחֶרְמוֹנִים מֵהַר מִצְעָר: תְּהוֹם-אֶל-תְּהוֹם קוֹרֵא לְקוֹל צִנּוֹרֶיךָ, כָּל-מִשְׁבָּרֶיךָ וְגַלֶּיךָ עָלַי עָבָרוּ: יוֹמָם יְצַוֶּה יהוה חַסְדּוֹ, וּבַלַּיְלָה שִׁירֹה עִמִּי, תְּפִלָּה לְאֵל חַיָּי: אוֹמְרָה לְאֵל סַלְעִי, לָמָה שְׁכַחְתָּנִי, לָמָּה-קֹדֵר אֵלֵךְ, בְּלַחַץ אוֹיֵב: בְּרֶצַח בְּעַצְמוֹתַי, חֵרְפוּנִי צוֹרְרָי, בְּאָמְרָם אֵלַי כָּל-הַיּוֹם אַיֵּה אֱלֹהֶיךָ: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"שָׁפְטֵנִי אֱלֹהִים וְרִיבָה רִיבִי, מִגּוֹי לֹא חָסִיד, מֵאִישׁ מִרְמָה וְעַוְלָה תְפַלְּטֵנִי: כִּי-אַתָּה אֱלֹהֵי מָעוּזִּי, לָמָה זְנַחְתָּנִי, לָמָּה-קֹדֵר אֶתְהַלֵּךְ בְּלַחַץ אוֹיֵב: שְׁלַח-אוֹרְךָ וַאֲמִתְּךָ הֵמָּה יַנְחוּנִי, יְבִיאוּנִי אֶל-הַר-קָדְשְׁךָ וְאֶל-מִשְׁכְּנוֹתֶיךָ: וְאָבוֹאָה אֶל-מִזְבַּח אֱלֹהִים, אֶל-אֵל שִׂמְחַת גִּילִי, וְאוֹדְךָ בְכִנּוֹר, אֱלֹהִים אֱלֹהָי: מַה-תִּשְׁתּוֹחֲחִי נַפְשִׁי, וּמַה-תֶּהֱמִי עָלָי, הוֹחִילִי לֵאלֹהִים כִּי-עוֹד אוֹדֶנּוּ, יְשׁוּעֹת פָּנַי וֵאלֹהָי:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ מִזְמוֹר לְדָוִד: יַעַנְךָ יהוה בְּיוֹם צָרָה, יְשַׂגֶּבְךָ שֵׁם אֱלֹהֵי יַעֲקֹב: יִשְׁלַח עֶזְרְךָ מִקֹּדֶשׁ, וּמִצִּיּוֹן יִסְעָדֶךָּ: יִזְכֹּר כָּל מִנְחֹתֶךָ, וְעוֹלָתְךָ יְדַשְּׁנֶה סֶלָה: יִתֶּן לְךָ כִלְבָבֶךָ, וְכָל עֲצָתְךָ יְמַלֵּא: נְרַנְּנָה בִּישׁוּעָתֶךָ וּבְשֵׁם אֱלֹהֵינוּ נִדְגֹּל, יְמַלֵּא יהוה כָּל מִשְׁאֲלוֹתֶיךָ: עַתָּה יָדַעְתִּי כִּי הוֹשִׁיעַ יהוה מְשִׁיחוֹ, יַעֲנֵהוּ מִשְּׁמֵי קָדְשׁוֹ, בִּגְבֻרוֹת יֵשַׁע יְמִינוֹ: אֵלֶּה בָרֶכֶב וְאֵלֶּה בַסּוּסִים, וַאֲנַחְנוּ בְּשֵׁם יהוה אֱלֹהֵינוּ נַזְכִּיר: הֵמָּה כָּרְעוּ וְנָפָלוּ, וַאֲנַחְנוּ קַּמְנוּ וַנִּתְעוֹדָד: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ:","cond":["shacharitTachanun"]},{"kind":"text","text":"לְדָוִד מִזְמוֹר, לַיהוה הָאָרֶץ וּמְלוֹאָהּ, תֵּבֵל וְיֹשְׁבֵי בָהּ: כִּי הוּא עַל יַמִּים יְסָדָהּ, וְעַל נְהָרוֹת יְכוֹנְנֶהָ: מִי יַעֲלֶה בְהַר יהוה, וּמִי יָקוּם בִּמְקוֹם קָדְשׁוֹ: נְקִי כַפַּיִם וּבַר לֵבָב, אֲשֶׁר לֹא נָשָׂא לַשָּׁוְא נַפְשִׁי וְלֹא נִשְׁבַּע לְמִרְמָה: יִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: זֶה דּוֹר דֹּרְשָׁיו, מְבַקְשֵׁי פָנֶיךָ יַעֲקֹב סֶלָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וְהִנָּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבוֹא מֶלֶךְ הַכָּבוֹד: מִי זֶה מֶלֶךְ הַכָּבוֹד, יהוה עִזּוּז וְגִבּוֹר, יהוה גִּבּוֹר מִלְחָמָה: שְׂאוּ שְׁעָרִים רָאשֵׁיכֶם וּשְׂאוּ פִּתְחֵי עוֹלָם, וְיָבֹא מֶלֶךְ הַכָּבוֹד: מִי הוּא זֶה מֶלֶךְ הַכָּבוֹד, יהוה צְבָאוֹת הוּא מֶלֶךְ הַכָּבוֹד סֶלָה:","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"הַלְלוּיָהּ, אוֹדֶה יהוה בְּכָל לֵבָב, בְּסוֹד יְשָׁרִים וְעֵדָה: גְּדֹלִים מַעֲשֵׂי יהוה, דְּרוּשִׁים לְכָל חֶפְצֵיהֶם: הוֹד וְהָדָר פָּעֳלוֹ, וְצִדְקָתוֹ עֹמֶדֶת לָעַד: זֵכֶר עָשָׂה לְנִפְלְאֹתָיו, חַנּוּן וְרַחוּם יהוה: טֶרֶף נָתַן לִירֵאָיו, יִזְכֹּר לְעוֹלָם בְּרִיתוֹ: כֹּחַ מַעֲשָׂיו הִגִּיד לְעַמּוֹ, לָתֵת לָהֶם נַחֲלַת גּוֹיִם: מַעֲשֵׂי יָדָיו אֱמֶת וּמִשְׁפָּט, נֶאֱמָנִים כָּל פִּקּוּדָיו: סְמוּכִים לָעַד לְעוֹלָם, עֲשׂוּיִם בֶּאֱמֶת וְיָשָׁר: פְּדוּת שָׁלַח לְעַמּוֹ, צִוָּה לְעוֹלָם בְּרִיתוֹ, קָדוֹשׁ וְנוֹרָא שְׁמוֹ: רֵאשִׁית חָכְמָה יִרְאַת יהוה, שֵׂכֶל טוֹב לְכָל עֹשֵׂיהֶם, תְּהִלָּתוֹ עֹמֶדֶת לָעַד:\n\nלַמְנַצֵּחַ מִזְמוֹר לְדָוִד: בְּבוֹא אֵלָיו נָתָן הַנָּבִיא, כַּאֲשֶׁר-בָּא אֶל-בַּת-שָׁבַע: חָנֵּנִי אֱלֹהִים כְּחַסְדֶּךָ, כְּרֹב רַחֲמֶיךָ מְחֵה פְשָׁעָי: הֶרֶב כַּבְּסֵנִי מֵעֲוׂנִי, וּמֵחַטָּאתִי טַהֲרֵנִי: כִּי-פְשָׁעַי אֲנִי אֵדָע, וְחַטָּאתִי נֶגְדִּי תָמִיד: לְךָ לְבַדְּךָ חָטָאתִי, וְהָרַע בְּעֵינֶיךָ עָשִׂיתִי, לְמַעַן-תִּצְדַּק בְּדָבְרֶךָ, תִּזְכֶּה בְשָׁפְטֶךָ: הֵן-בְּעָווֹן חוֹלָלְתִּי, וּבְחֵטְא יֶחֱמַתְנִי אִמִּי: הֵן אֱמֶת חָפַצְתָּ בַטֻּחוֹת, וּבְסָתֻם חָכְמָה תוֹדִיעֵנִי: תְּחַטְּאֵנִי בְאֵזוֹב וְאֶטְהָר, תְּכַבְּסֵנִי וּמִשֶּׁלֶג אַלְבִּין: תַּשְׁמִיעֵנִי שָׂשׂוֹן וְשִׂמְחָה, תָּגֵלְנָה עֲצָמוֹת דִּכִּיתָ: הַסְתֵּר פָּנֶיךָ מֵחֲטָאָי, וְכָל-עֲוׂנתַי מְחֵה: לֵב טָהוֹר בְּרָא-לִי אֱלֹהִים, וְרוּחַ נָכוֹן חַדֵּשׁ בְּקִרְבִּי: אַל-תַּשְׁלִיכֵנִי מִלְּפָנֶיךָ, וְרוּחַ קָדְשְׁךָ אַל-תִּקַּח מִמֶּנִּי: הָשִׁיבָה לִּי שְׂשׂוֹן יִשְׁעֶךָ, וְרוּחַ נְדִיבָה תִסְמְכֵנִי: אֲלַמְּדָה פֹשְׁעִים דְּרָכֶיךָ, וְחַטָּאִים אֵלֶיךָ יָשׁוּבוּ: הַצִּילֵנִי מִדָּמִים אֱלֹהִים אֱלֹהֵי תְשׁוּעָתִי, תְּרַנֵּן לְשׁוֹנִי צִדְקָתֶךָ: אֲדֹנָי, שְׂפָתַי תִּפְתָּח, וּפִי יַגִּיד תְּהִלָּתֶךָ: כִּי לֹא-תַחְפֹּץ זֶבַח וְאֶתֵּנָה, עוֹלָה לֹא תִרְצֶה: זִבְחֵי אֱלֹהִים רוּחַ נִשְׁבָּרָה, לֵב-נִשְׁבָּר וְנִדְכֶּה אֱלֹהִים לֹא תִבְזֶה: הֵיטִיבָה בִרְצוֹנְךָ אֶת-צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם: אָז תַּחְפֹּץ זִבְחֵי-צֶדֶק, עוֹלָה וְכָלִיל, אָז יַעֲלוּ עַל-מִזְבַּחֲךָ פָרִים:","cond":[]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם.","cond":["rachel"]},{"kind":"text","text":"תָקוּם תְּרַחֵם צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר או\"א ומזמור בשוב ה' כדי לפסוק בנחמה (בא\"ח וישלח)","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, מֶלֶךְ רַחֲמָן רַחֵם עָלֵינוּ, טוֹב וּמֵטִיב הִדָּרֶשׁ לָנוּ, שׁוּבָה עָלֵינוּ בַּהֲמוֹן רַחֲמֶיךָ, בִּגְלַל אָבוֹת שֶׁעָשׂוּ רְצוֹנֶךָ, בְּנֵה בֵיתְךָ כּבַתְּחִלָּה, כּוֹנֵן בֵּית מִקְדָּשְׁךָ עַל מְכוֹנוֹ, הַרְאֵנוּ בְּבִנְיָנוֹ, שַׂמְּחֵנוּ בְּתִקּוּנוֹ, וְהָשֵׁב שְׁכִינָתְךָ לְתוֹכוֹ, וְהָשֵׁב כֹּהֲנִים לַעֲבוֹדָתָם, וּלְוִיִּים לְדוּכָנָם, לְשִׁירָם וּלְזִמְרָם, וְהָשֵׁב יִשְׂרָאֵל לִנְוֵיהֶם. וְשָׁם נַעֲלֶה וְנֵרָאֶה וְנִשְׁתַּחֲוֶה לְפָנֶיךָ. יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהֵינוּ וֵאלֹהֵי אֲבֹתֵינוּ, שֶׁתַּעֲלֵנוּ בְּשִׂמְחָה לְאַרְצֵנוּ, וְתִטָּעֵנוּ בִּגְבוּלֵנוּ, וְשֵׁם נַעֲשֶׂה לְפָנֶיךָ אֶת קָרְבְּנוֹת חֹבֹתֵינוּ, תְּמִידִים כְּסִדְרָם וּמוּסָפִים כְּהִלְכָתָם.\n\nשִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]}]}},{"id":"avinu_malkenu","title":"אבינו מלכנו","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"header","text":"אבינו מלכנו","cond":[]},{"kind":"instruction","text":"אבינו מלכנו","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":[]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם לְעֵינֵינוּ נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":[]}],"sfard":[{"kind":"header","text":"אבינו מלכנו","cond":[]},{"kind":"instruction","text":"אבינו מלכנו","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בָּרֵךְ עָלֵינוּ שָׁנָה טוֹבָה.","cond":["noGedalya"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרוֹת קָשׁוֹת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבוֹת שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, סְתֹם פִּיּוֹת מַשְׂטִינֵינוּ וּמְקַטְרְגֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָב וּשְׁבִי וּמַשְׁחִית וְעָוׂן וּשְׁמַד מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, סְלַח וּמְחַל לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ וְחַטֹּאתֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל שִׁטְרֵי חוֹבוֹתֵינוּ.","cond":[]},{"kind":"instruction","text":"מכאן אומרים בקול עם החזן","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִּתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְחוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רֹע גְּזַר דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב לְפָנֶיךָ.","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר זְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, כָָּתְבֵנוּ בְּסֵפֶר סְלִיחָה וּמְחִילָה.","cond":["ayt"]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְחַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִגְאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לְפַרְנָסָה וְכַלְכָּלָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִזְכֻיּוֹת.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ לִסְלִיחָה וּמְחִילָה.","cond":["noGedalya"]},{"kind":"instruction","text":"עד כאן עם החזן","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוֹב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא יָדֵינוּ מִבִּרְכוֹתֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, מַלֵּא אֲסָמֵינוּ שָׂבָע.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קוֹלֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצוֹן אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, פְּתַח שַׁעֲרֵי שָׁמַיִם לִתְפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנַחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, נָא אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, תְּהֵא הַשָּׁעָה הַזֹּאת שְׁעַת רַחֲמִים וְעֵת רָצוֹן מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, חֲמֹל עָלֵינוּ וְעַל עוֹלָלֵינוּ וְטַפֵּנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן הֲרוּגִים עַל שֶׁם קָדְשֶׁךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן טְבוּחִים עַל יִחוּדֶךָ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֶׂה לְמַעַן בָּאֵי בָאֵשׁ וּבַמָּיִּם עַל קִדּוּשׁ שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, נְקֹם נִקְמַת דַּם עֲבָדֶיךָ הַשָּׁפוּךְ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ אִם לֹא לְמַעַנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַנְךָ וְהוֹשִׁיעֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן רַחֲמֶיךָ הָרַבִּים.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעַן שִׁמְךָ הַגָּדוֹל הַגִּבּוֹר וְהַנּוֹרָא שֶׁנִּקְרָא עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ כִּי אֵין בָּנוּ מַעֲשִׂים, עֲשֵׂה עִמָּנוּ צְדָקָה וָחֶסֶד וְהוֹשִׁיעֵנוּ.","cond":[]}],"edot_mizrach":[{"kind":"header","text":"אבינו מלכנו","cond":[]},{"kind":"instruction","text":"אבינו מלכנו","cond":[]},{"kind":"special","text":"אָבִינוּ מַלְכֵּנוּ, חָטָאנוּ לְפָנֶיךָ רַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, אֵין לָנוּ מֶלֶךְ אֶלָּא אָתָּה.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה עִמָּנוּ לְמַעַן שְׁמֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חַדֵּשׁ עָלֵינוּ שָׁנָה טובָה וּמְבֹרֶכֶת.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מֵעָלֵינוּ כָּל גְּזֵרות קָשׁות וְרָעות.\nאָבִינוּ מַלְכֵּנוּ, בַּטֵּל מַחְשְׁבות שׂוֹנְאֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, הָפֵר עֲצַת אוֹיְבֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה כָּל צַר וּמַשְׂטִין מֵעָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, כַּלֵּה דֶבֶר וְחֶרֶב וְרָעָה וְרָעָב וּשְׁבִי וּבִזָּה וּמַשְׁחִית וּמַגֵּפָה וְשָׂטָן וְיֵצֶר הָרָע וָחֳלָאִים רָעִים מִבְּנֵי בְרִיתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁלַח רְפוּאָה שְׁלֵמָה לְכָל-חוֹלֵי עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, מְנַע מַגֵּפָה מִנַּחֲלָתֶךָ.\nאָבִינוּ מַלְכֵּנוּ, זְכֹר כִּי עָפָר אֲנָחְנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹל וּסְלַח לְכָל עֲוׂנוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, קְרַע רוֹעַ גְּזַר-דִּינֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֹק בְּרַחֲמֶיךָ הָרַבִּים כָּל-שִׁטְרֵי חוֹבוֹתֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, מְחֵה וְהַעֲבֵר פְּשָׁעֵינוּ מִנֶּגֶד עֵינֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר חַיִּים טוֹבִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר צַדִּיקִים וַחֲסִידִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר יְשָׁרִים וּתְמִימִים.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר פַּרְנָסָה וְכַלְכָּלָה טוֹבָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר מְחִילָה וּסְלִיחָה וְכַפָּרָה.\nאָבִינוּ מַלְכֵּנוּ, כָּתְבֵנוּ בְּסֵפֶר גְּאֻלָּה וִישׁוּעָה.\nאָבִינוּ מַלְכֵּנוּ, זָכְרֵנוּ בְּזִכְרוֹן טוֹב מִלְּפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, הַצְמַח לָנוּ יְשׁוּעָה בְּקָרוב.\nאָבִינוּ מַלְכֵּנוּ, הָרֵם קֶרֶן יִשְׂרָאֵל עַמֶּךָ.\nאָבִינוּ מַלְכֵּנוּ, וְהָרֵם קֶרֶן מְשִׁיחֶךָ.\nאָבִינוּ מַלְכֵּנוּ, חָנֵּנוּ וַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, הַחֲזִירֵנוּ בִתְשׁוּבָה שְׁלֵמָה לְפָנֶיךָ.\nאָבִינוּ מַלְכֵּנוּ, שְׁמַע קולֵנוּ, חוּס וְרַחֵם עָלֵינוּ.\nאָבִינוּ מַלְכֵּנוּ, עֲשֵׂה לְמַעֲנָךְ, אִם לא לְמַעֲנֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, קַבֵּל בְּרַחֲמִים וּבְרָצון אֶת תְּפִלָּתֵנוּ.\nאָבִינוּ מַלְכֵּנוּ, אַל תְּשִׁיבֵנוּ רֵיקָם מִלְּפָנֶיךָ.","cond":[]}]}},{"id":"havdala","title":"הבדלה","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"header","text":"הבדלה","cond":[]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":[]},{"kind":"text","text":"הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח וְלֹא אֶפְחָד: כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן, מִמַּעַיְנֵי הַיְשׁוּעָה: לַיהוה הַיְשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשׁוֹן וִיקָר: כֵּן תִּהְיֶה לָנוּ. כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:","cond":["sun"]},{"kind":"text","text":"סַבְרִי מָרָנָן וְרַבָּנָן וְרַבּוֹתַי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":[]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":[]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":[]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":[]}],"sfard":[{"kind":"header","text":"הבדלה","cond":[]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":[]},{"kind":"text","text":"הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח וְלֹא אֶפְחָד: כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן, מִמַּעַיְנֵי הַיְשׁוּעָה: לַיהוה הַיְשׁוּעָה, עַל עַמְּךָ בִרְכָתֶךָ סֶּלָה: יהוה צְבָאוֹת עִמָּנוּ, מִשְׂגָּב לָנוּ אֱלֹהֵי יַעֲקֹב סֶלָה: יהוה צְבָאוֹת, אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ: יהוה הוֹשִׁיעָה, הַמֶּלֶךְ יַעֲנֵנוּ בְיוֹם קָרְאֵנוּ: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשׁוֹן וִיקָר: כֵּן תִּהְיֶה לָנוּ. כּוֹס יְשׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:","cond":["sun"]},{"kind":"text","text":"סַבְרִי מָרָנָן וְרַבָּנָן וְרַבּוֹתַי.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":[]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":[]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל, בֵּין אוֹר לְחֹשֶׁךְ, בֵּין יִשְׂרָאֵל לָעַמִּים, בֵּין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":[]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":[]}],"edot_mizrach":[{"kind":"header","text":"הבדלה","cond":[]},{"kind":"instruction","text":"סדר הבדלה\n\nנוטל הכוס בידו ואומר:","cond":[]},{"kind":"text","text":"רִאשׁוֹן לְצִיּוֹן הִנֵּה הִנָּם, וְלִירוּשָׁלַיִם מְבַשֵּׂר אֶתֵּן: אַל תִּשְׂמְחִי אוֹיַבְתִּי לִי כִּי נָפַלְתִּי קַמְתִּי, כִּי אֵשֵׁב בַּחוֹשֶׁךְ יהוה אוֹר לִי: לַיּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל וַיהוה עִמּוֹ: וְנֹחַ מָצָא חֵן בְּעֵינֵי יהוה: כֵּן נִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.\n\nקוּמִי אוֹרִי כִּי בָא אוֹרֵךְ, וּכְבוֹד יהוה עָלַיִךְ זָרַח: כִּי הִנֵּה הַחֹשֶׁךְ יְכַסֶּה אֶרֶץ וַעֲרָפֶל לְאֻמִּים, וְעָלַיִךְ יִזְרַח יהוה וּכְבוֹדוֹ עָלַיִךְ יֵרָאֶה:","cond":[]},{"kind":"instruction","text":"יקח הכוס בידו ויאמר:","cond":[]},{"kind":"text","text":"כּוֹס ישׁוּעוֹת אֶשָּׂא, וּבְשֵׁם יהוה אֶקְרָא:\nאָנָּא יהוה הוֹשִׁיעָה נָּא,\nאָנָּא יהוה הוֹשִׁיעָה נָּא,\nאָנָּא יהוה הַצְלִיחָה נָא:\nאָנָּא יהוה הַצְלִיחָה נָא:\n\nהַצְלִיחֵנוּ, הַצְלַח דּרָכֵינוּ, הַצְלַח לִמּוּדֵינוּ, וּשְׁלַח בְּרָכָה רְוָחָה וְהַצְלָחָה בְּכָל מַעֲשֵׂה יָדֵינוּ, כְּדִכְתִיב: יִשָּׂא בְרָכָה מֵאֵת יהוה וּצְדָקָה מֵאֱלֹהֵי יִשְׁעוֹ: לַיּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר: וּכְתִיב: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל, וַיהוה עִמּוֹ: כֵּן יִהְיֶה עִמָּנוּ תָמִיד.\n\nסַבְרֵי מָרָנָן.","cond":[]},{"kind":"instruction","text":"ועונים:","cond":[]},{"kind":"text","text":"לחַיִּים.","cond":[]},{"kind":"instruction","text":"המבדיל ממשיך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.","cond":[]},{"kind":"instruction","text":"ואם מברך על משקה שאינו יין יברך שהכל.","cond":[]},{"kind":"instruction","text":"מוריד את הכוס ונוטל את הבשמים ומברך:","cond":["sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא (עֲצֵי או עִשְׂבֵּי או מִינֵי) בְשָׂמִים.","cond":["sun"]},{"kind":"instruction","text":"מברך לאור הנר:","cond":["fire"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["fire"]},{"kind":"instruction","text":"נוטל את הכוס בידו ומברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל וּבֵין אוֹר לְחֹשֶׁךְ וּבֵין יִשְׂרָאֵל לָעַמִּים וּבֵין יוֹם הַשְּׁבִיעִי לְשֵׁשֶׁת יְמֵי הַמַּעֲשֶׂה. בָּרוּךְ אַתָּה יהוה, הַמַּבְדִּיל בֵּין קֹדֶשׁ לְחוֹל.","cond":[]},{"kind":"instruction","text":"אם שתה רביעית יין יברך ברכת מעין שלש (מופיע בתפריט התפילות).","cond":[]}]}},{"id":"hadlakat_ner_chanukah","title":"הדלקת נרות חנוכה","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"instruction","text":"הנחת הנרות היא בצד הימני של החנוכיה, אבל מדליקים אותם בסדר הפוך - משמאל לימין.\nזמן ההדלקה לכתחילה הוא בשעת שקיעת החמה או בצאת הכוכבים (תלוי במנהגים השונים), והנרות צריכים לדלוק לפחות חצי שעה.\n\nלפני ההדלקה מברכים:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהַדְלִיק נֵר (שֶׁל) חֲנֻכָּה.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["chanuka1"]},{"kind":"instruction","text":"לאחר ההדלקה שרים:","cond":[]},{"kind":"text","text":"הַנֵּרוֹת הַלָּלוּ אָנוּ מַדְלִיקִין עַל הַנִּסִּים וְעַל הַנִּפְלָאוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה עַל יְדֵי כֹּהֲנֶיךָ הַקְּדוֹשִׁים, וְכָל שְׁמוֹנַת יְמֵי הָחֲנֻכָּה הַנֵּרוֹת הַלָּלוּ קֹדֶשׁ הֵם, וְאֵין לָנוּ רְשׁוּת לְהִשְׁתַּמֵּשׁ בָּהֶם אֶלָּא לִרְאוֹתָם בִּלְבָד, כְּדֵי לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל עַל נִסֶּיךָ וְעַל נִפְלְאוֹתֶיךָ וְעַל יְשׁוּעָתֶךָ.","cond":[]},{"kind":"text","text":"מָעוֹז צוּר יְשׁוּעָתִי, לְךָ נָאֶה לְשַׁבֵּחַ.\nתִּכּוֹן בֵּית תְּפִלָּתִי, וְשָׁם תּוֹדָה נְזַבֵּחַ.\nלְעֵת תָּכִין מַטְבֵּחַ, מִצָּר הַמְנַבֵּחַ.\nאָז אֶגְמוֹר בְּשִׁיר מִזְמוֹר חֲנֻכַּת הַמִּזְבֵּחַ.\n\nרָעוֹת שָׂבְעָה נַפְשִׁי, בְּיָגוֹן כֹּחִי כָּלָה.\nחַיַּי מֵרְרוּ בּקֹשִׁי, בְּשִׁעְבּוּד מַלְכוּת עֶגְלָה.\nוּבְיָדוֹ הַגְּדוֹלָה הוֹצִיא אֶת הַסְּגֻלָּה.\nחֵיל פַּרְעֹה וְכָל זַרְעוֹ יָרְדוּ כְאֶבֶן בִּמְצוּלָה.\n\nדְּבִיר קָדְשׁוֹ הֱבִיאַנִי, וְגַם שָׁם לֹא שָׁקַטְתִּי.\nוּבָא נוֹגֵשׂ וְהִגְלַנִי, כִּי זָרִים עָבַדְתִּי.\nוְיֵין רַעַל מָסַכְתִּי, כִּמְעַט שֶׁעָבַרְתִּי.\nקֵץ בָּבֵל, זְרֻבָּבֵל, לְקֵץ שִׁבְעִים נוֹשָׁעְתִּי.\n\nכְּרֹת קוֹמַת בְּרוֹשׁ, בִּקֵּשׁ אֲגָגִי בֶּן הַמְּדָתָא.\nוְנִהְיָתָה לוֹ לְפָח וּלְמוֹקֵשׁ, וְגַאֲוָתוֹ נִשְׁבָּתָה.\nרֹאשׁ יְמִינִי נִשֵּׂאתָ, וְאוֹיֵב שְׁמוֹ מָחִיתָ.\nרֹב בָּנָיו וְקִנְיָנָיו עַל הָעֵץ תָּלִיתָ.\n\nיְוָנִים נִקְבְּצוּ עָלַי, אֲזַי בִּימֵי חַשְׁמַנִּים.\nוּפָרְצוּ חוֹמוֹת מִגְדָּלַי, וְטִמְּאוּ כָּל הַשְּׁמָנִים.\nוּמִנּוֹתַר קַנְקַנִּים נַעֲשָׂה נֵס לַשּׁוֹשַׁנִּים.\nבְּנֵי בִינָה יְמֵי שְׁמוֹנָה קָבְעוּ שִׁיר וּרְנָנִים.\n\nחֲשׂוֹף זְרוֹעַ קָדְשֶׁךָ, וְקָרֵב קֵץ הַיְשׁוּעָה.\nנְקֹם נִקְמַת דַּם עֲבָדֶיךָ מֵאֻמָּה הָרְשָׁעָה.\nכִּי אָרְכָה לָנוּ הַשָּׁעָה, וְאֵין קֵץ לִימֵי הָרָעָה.\nדְּחֵה אַדְמוֹן בְּצֵל צַלְמוֹן, הָקֵם לָנוּ רוֹעִים שִׁבְעָה.","cond":[]}],"edot_mizrach":[{"kind":"text","text":"לְשֵׁם יִחוּד קֻדְשָׁא בְרִיךְ הוּא וּשְׁכִינְתֵּהּ, בִּדְחִילוּ וּרְחִימוּ, וּרְחִימוּ וּדְחִילוּ, לְיַחֲדָא שֵׁם אוֹת י' וְאוֹת ה' בְּשֵׁם אוֹת ו' וְאוֹת ה' בְּיִחוּדָא שְׁלִים בְּשֵׁם כָּל יִשְׂרָאֵל, לַאֲקָמָא שְׁכִינְתָּא מִעַפְרָא וּלְעִלּוּי שְׁכִינַת עֻזֵּנוּ, הִנֵּה אָנֹכִי בָּא לְקַיֵּם מִצְוַת עֲשֵׂה מִדִּבְרֵי סוֹפְרִים לְהַדְלִיק נֵר חֲנֻכָּה, לְתַקֵּן שֹׁרֶשׁ מִצְוָה זוֹ בְּמָקוֹם עֶלְיוֹן.","cond":[]},{"kind":"instruction","text":"הנחת הנרות היא בצד הימני של החנוכיה, אבל מדליקים אותם בסדר הפוך - משמאל לימין.\nזמן ההדלקה לכתחילה הוא בשעת שקיעת החמה או בצאת הכוכבים (תלוי במנהגים השונים), והנרות צריכים לדלוק לפחות חצי שעה.\n\nלפני ההדלקה מברכים:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהַדְלִיק נֵר (שֶׁל) חֲנֻכָּה.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":["chanuka1"]},{"kind":"instruction","text":"לאחר ההדלקה שרים:","cond":[]},{"kind":"text","text":"הַנֵּרוֹת הַלָּלוּ אֲנַחְנוּ מַדְלִיקִין, עַל הַנִּסִּים וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ עַל יְדֵי כֹהֲנֶיךָ הַקְּדוֹשִׁים, וְכָל שְׁמוֹנַת יְמֵי חֲנֻכָּה, הַנֵּרוֹת הַלָּלוּ קֹדֶשׁ, וְאֵין לָנוּ רְשׁוּת לְהִשְׁתַּמֵּשׁ בָּהֶם אֶלָּא לִרְאוֹתָם בִּלְבַד, כְּדֵי לְהוֹדוֹת לִשְׁמֶךָ עַל נִסֶּיךָ וְנִפְלְאוֹתֶיךָ וִישׁוּעוֹתֶיךָ.","cond":[]},{"kind":"text","text":"מִזְמוֹר שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד: אֲרוֹמִמְךָ יהוה כִּי דִלִּיתָנִי, וְלֹא שִׂמַּחְתָּ אֹיְבַי לִי: יהוה אֱלֹהָי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי: יהוה, הֶעֱלִיתָ מִן שְׁאוֹל נַפְשִׁי, חִיִּיתַנִי מִיָּרְדִי בוֹר: זַמְּרוּ לַיהוה חֲסִידָיו וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ: כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ, בָּעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה: וַאֲנִי אָמַרְתִּי בְשַׁלְוִי בַּל אֶמּוֹט לְעוֹלָם: יהוה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי עֹז, הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל: אֵלֶיךָ יהוה אֶקְרָא וְאֶל אֲדֹנָי אֶתְחַנָּן: מַה בֶּצַע בְּדָמִי בְּרִדְתִּי אֶל שָׁחַת, הֲיוֹדְךָ עָפָר הֲיַגִּיד אֲמִתֶּךָ: שְׁמַע יהוה וְחָנֵּנִי, יהוה הֱיֵה עֹזֵר לִי: הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם, יהוה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ:","cond":[]},{"kind":"text","text":"מָעוֹז צוּר יְשׁוּעָתִי, לְךָ נָאֶה לְשַׁבֵּחַ.\nתִּכּוֹן בֵּית תְּפִלָּתִי, וְשָׁם תּוֹדָה נְזַבֵּחַ.\nלְעֵת תָּכִין מַטְבֵּחַ, מִצָּר הַמְנַבֵּחַ.\nאָז אֶגְמוֹר בְּשִׁיר מִזְמוֹר חֲנֻכַּת הַמִּזְבֵּחַ.\n\nרָעוֹת שָׂבְעָה נַפְשִׁי, בְּיָגוֹן כֹּחִי כָּלָה.\nחַיַּי מֵרְרוּ בּקֹשִׁי, בְּשִׁעְבּוּד מַלְכוּת עֶגְלָה.\nוּבְיָדוֹ הַגְּדוֹלָה הוֹצִיא אֶת הַסְּגֻלָּה.\nחֵיל פַּרְעֹה וְכָל זַרְעוֹ יָרְדוּ כְאֶבֶן בִּמְצוּלָה.\n\nדְּבִיר קָדְשׁוֹ הֱבִיאַנִי, וְגַם שָׁם לֹא שָׁקַטְתִּי.\nוּבָא נוֹגֵשׂ וְהִגְלַנִי, כִּי זָרִים עָבַדְתִּי.\nוְיֵין רַעַל מָסַכְתִּי, כִּמְעַט שֶׁעָבַרְתִּי.\nקֵץ בָּבֵל, זְרֻבָּבֵל, לְקֵץ שִׁבְעִים נוֹשָׁעְתִּי.\n\nכְּרֹת קוֹמַת בְּרוֹשׁ, בִּקֵּשׁ אֲגָגִי בֶּן הַמְּדָתָא.\nוְנִהְיָתָה לוֹ לְפָח וּלְמוֹקֵשׁ, וְגַאֲוָתוֹ נִשְׁבָּתָה.\nרֹאשׁ יְמִינִי נִשֵּׂאתָ, וְאוֹיֵב שְׁמוֹ מָחִיתָ.\nרֹב בָּנָיו וְקִנְיָנָיו עַל הָעֵץ תָּלִיתָ.\n\nיְוָנִים נִקְבְּצוּ עָלַי, אֲזַי בִּימֵי חַשְׁמַנִּים.\nוּפָרְצוּ חוֹמוֹת מִגְדָּלַי, וְטִמְּאוּ כָּל הַשְּׁמָנִים.\nוּמִנּוֹתַר קַנְקַנִּים נַעֲשָׂה נֵס לַשּׁוֹשַׁנִּים.\nבְּנֵי בִינָה יְמֵי שְׁמוֹנָה קָבְעוּ שִׁיר וּרְנָנִים.\n\nחֲשׂוֹף זְרוֹעַ קָדְשֶׁךָ, וְקָרֵב קֵץ הַיְשׁוּעָה.\nנְקֹם נִקְמַת דַּם עֲבָדֶיךָ מֵאֻמָּה הָרְשָׁעָה.\nכִּי אָרְכָה לָנוּ הַשָּׁעָה, וְאֵין קֵץ לִימֵי הָרָעָה.\nדְּחֵה אַדְמוֹן בְּצֵל צַלְמוֹן, הָקֵם לָנוּ רוֹעִים שִׁבְעָה.","cond":[]}]}},{"id":"sheva_brachot","title":"שבע ברכות","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"header","text":"ברכת המזון לנישואין ושבעת ימי המשתה","cond":[]},{"kind":"instruction","text":"ברכת המזון לנישואין ושבעת ימי המשתה\n\nמברכים ברכת המזון על כוס יין ואחריה שבע ברכות על כוס שניה של יין.","cond":[]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"special","text":"המזמן: דְּוַי הָסֵר וְגַם חָרוֹן, וְאָז אִלֵּם בְּשִׁיר יָרוֹן. נְחֵנוּ בְמַעְגְּלֵי צֶדֶק, שְׁעֵה בִּרְכַּת בְּנֵי אַהֲרֹן.","cond":[]},{"kind":"text","text":"המזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ וְשֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ, שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ, שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ, בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל, וּמֵטִיב לַכֹּל, וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא. בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ, יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל, יהוה אֱלֹהֵינוּ, אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד, כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֶם (נָא) יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ, זוּנֵנוּ, פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ, יהוה אֱלֹהֵינוּ, לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]},{"kind":"header","text":"שבע ברכות","cond":[]},{"kind":"instruction","text":"שבע ברכות","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהַכֹּל בָּרָא לִכְבוֹדוֹ.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר הָאָדָם.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּצַלְמוֹ, בְּצֶלֶם דְּמוּת תַּבְנִיתוֹ, וְהִתְקִין לוֹ מִמֶּנּוּ בִּנְיַן עֲדֵי עַד. בָּרוּךְ אַתָּה יהוה, יוֹצֵר הָאָדָם.\n\nשׂוֹשׂ תָּשִׂישׂ וְתָגֵל הָעֲקָרָה, בְּקִבּוּץ בָּנֶיהָ לְתוֹכָהּ בְּשִׂמְחָה. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמֵּחַ תְּשַׂמַּח רֵעִים הָאֲהוּבִים, כְּשַׂמֵּחֲךָ יְצִירְךָ בְּגַן עֵדֶן מִקֶּדֶם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ חָתָן וְכַלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּרָא שָׂשׂוֹן וְשִׂמְחָה, חָתָן וְכַלָּה, גִּילָה, רִנָּה, דִּיצָה וְחֶדְוָה, אַהֲבָה וְאַחֲוָה וְשׁלוֹם וְרֵעוּת. מְהֵרָה יהוה אֱלֹהֵינוּ יִשָּׁמַע בְּעָרֵי יְהוּדָה וּבְחוּצוֹת יְרוּשָׁלַיִם קוֹל שָׂשׂוֹן וְקוֹל שִׂמְחָה, קוֹל חָתָן וְקוֹל כַּלָּה, קוֹל מִצְהֲלוֹת חֲתָנִים מֵחֻפָּתָם וּנְעָרִים מִמִּשְׁתֵּה נְגִינָתָם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ הֶחָתָן עִם הַכַּלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":[]}],"sfard":[{"kind":"header","text":"ברכת המזון לנישואין ושבעת ימי המשתה","cond":[]},{"kind":"instruction","text":"ברכת המזון לנישואין ושבעת ימי המשתה\n\nמברכין ברכת המזון על כוס יין ואחריה שבע ברכות על כוס שניה של יין.","cond":[]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"special","text":"המזמן: דְּוַי הָסֵר וְגַם חָרוֹן, וְאָז אִלֵּם בְּשִׁיר יָרוֹן. נְחֵנוּ בְמַעְגְּלֵי צֶדֶק, שְׁעֵה בִּרְכַּת בְּנֵי יְשׁוּרוּן בְּנֵי אַהֲרֹן.","cond":[]},{"kind":"text","text":"המזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ וְשֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ וְשֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ, שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ, בְּטוּבוֹ בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וּמֵטִיב לַכֹּל וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא, כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד. כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֶם נָא יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ זוּנֵנוּ פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]},{"kind":"header","text":"שבע ברכות","cond":[]},{"kind":"instruction","text":"שבע ברכות","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהַכֹּל בָּרָא לִכְבוֹדוֹ.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר הָאָדָם.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּצַלְמוֹ, בְּצֶלֶם דְּמוּת תַּבְנִיתוֹ, וְהִתְקִין לוֹ מִמֶּנּוּ בִּנְיַן עֲדֵי עַד. בָּרוּךְ אַתָּה יהוה, יוֹצֵר הָאָדָם.\n\nשׂוֹשׂ תָּשִׂישׂ וְתָגֵל הָעֲקָרָה, בְּקִבּוּץ בָּנֶיהָ לְתוֹכָהּ בְּשִׂמְחָה. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמֵּחַ תְּשַׂמַּח רֵעִים הָאֲהוּבִים, כְּשַׂמֵּחֲךָ יְצִירְךָ בְּגַן עֵדֶן מִקֶּדֶם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ חָתָן וְכַלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּרָא שָׂשׂוֹן וְשִׂמְחָה, חָתָן וְכַלָּה, גִּילָה, רִנָּה, דִּיצָה וְחֶדְוָה, אַהֲבָה וְאַחֲוָה וְשׁלוֹם וְרֵעוּת. מְהֵרָה יהוה אֱלֹהֵינוּ יִשָּׁמַע בְּעָרֵי יְהוּדָה וּבְחוּצוֹת יְרוּשָׁלַיִם קוֹל שָׂשׂוֹן וְקוֹל שִׂמְחָה, קוֹל חָתָן וְקוֹל כַּלָּה, קוֹל מִצְהֲלוֹת חֲתָנִים מֵחֻפָּתָם וּנְעָרִים מִמִּשְׁתֵּה נְגִינָתָם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ חָתָן עִם הַכַּלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגָּפֶן.","cond":[]}],"edot_mizrach":[{"kind":"header","text":"ברכת המזון לנישואין ושבעת ימי המשתה","cond":[]},{"kind":"instruction","text":"ברכת המזון לנישואין ושבעת ימי המשתה\n\nמברכין ברכת המזון על כוס יין ואחריה שבע ברכות על כוס שניה של יין.","cond":[]},{"kind":"header","text":"למנצח","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"אֲבָרְכָה אֶת-יהוה בְּכָל-עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: סוֹף דָּבָר הַכֹּל נִשְׁמָע, אֶת-הָאֱלֹהִים יְרָא וְאֶת-מִצְוׂתָיו שְׁמוֹר, כִּי-זֶה כָּל-הָאָדָם: תְּהִלַּת יהוה יְדַבֶּר פִּי, וִיבָרֵךְ כָּל-בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד-עוֹלָם הַלְלוּיָהּ:\n\nהמזמן אומר: הַב לָן וְנִבְרִיךְ לְמַלְכָּא עִלָּאָה קַדִּישָׁא.\nהמסובים עונים: שָמַיִם.\nהמברך אומר: בִּרְשׁוּת מַלְכָּא עִלָּאָה קַדִּישָׁא,","cond":[]},{"kind":"special","text":"וּבִרְשׁוּת שִׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין","cond":["sucot"]},{"kind":"text","text":"וּבִרְשׁוּת מוֹרַי וְרַבּוֹתַי, וּבִרְשׁוּתְכֶם, נְבָרֵךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ וְשֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ אֱלֹהֵינוּ שֶׁהַשִּׂמְחָה בִּמְעוֹנוֹ, שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל הַזָּן אוֹתָנוּ וְאֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ בְּחֵן בְּחֶסֶד בְּרֶוַח וּבְרַחֲמִים רַבִּים, נֹתֵן לֶחֶם לְכָל-בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן תָּמִיד לְעוֹלָם וָעֶד, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וְשֻׁלְחָנוֹ עָרוּךְ לַכֹּל וְהִתְקִין מִחְיָה וּמָזוֹן לְכָל-בְּרִיּוֹתָיו אֲשֶׁר בָּרָא בְרַחֲמָיו וּבְרוֹב חֲסָדָיו כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ, וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה בְּרִית וְתוֹרָה חַיִּים וּמָזוֹן, עַל שֶׁהוֹצֵאתָנוּ מֵאֶרֶץ מִצְרַיִם וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֵּי רְצוֹנָךְ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים וּמָזוֹן שֶׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אֶת שְׁמָךְ כָּאָמוּר: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת-יהוה אֱלֹהֶיךָ עַל-הָאָרֶץ הַטּוֹבָה אֲשֶׁר נָתַן-לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֵם יהוה אֱלֹהֵינוּ עָלֵינוּ וְעַל יִשְׂרָאֵל עַמָּךְ, וְעַל יְרוּשָׁלַיִם עִירָךְ, וְעַל הַר צִיּוֹן מִשְׁכַּן כְּבוֹדָךְ, וְעַל הֵיכָלָךְ, וְעַל מְעוֹנָךְ, וְעַל דְּבִירָךְ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, אָבִינוּ רְעֵנוּ זוּנֵנוּ, פַּרְנְסֵנוּ, כַּלְכְּלֵנוּ, הַרְוִיחֵנוּ הַרְוַח לָנוּ מְהֵרָה מִכָּל-צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לִידֵי מַתְּנוֹת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, אֶלָּא לְיָדְךָ הַמְּלֵאָה וְהָרְחָבָה, הָעֲשִׁירָה וְהַפְּתוּחָה. יְהִי רָצוֹן שֶׁלֹּא נֵבוֹשׁ בָּעוֹלָם הַזֶּה, וְלֹא נִכָּלֵם לְעוֹלָם הַבָּא, וּמַלְכוּת בֵּית דָּוִד מְשִׁיחָךְ תַּחֲזִירֶנָּה לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וְתִבְנֶה יְרוּשָׁלַיִם עִירָךְ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם. (ואומר בלחש: אָמֵן).","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, לָעַד הָאֵל אָבִינוּ מַלְכֵּנוּ אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, קְדוֹשֵׁנוּ, קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל-יוֹם וָיוֹם הוּא הֵטִיב לָנוּ, הוּא מֵטִיב לָנוּ, הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ, הוּא גוֹמְלֵנוּ, הוּא יִגְמְלֵנוּ לָעַד חֵן וָחֶסֶד וְרַחֲמִים וְרֵיוַח וְהַצָּלָה וְכָל-טוֹב.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִשְׁתַּבַּח עַל כִּסֵּא כְבוֹדוֹ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בָּנוּ לְדוֹר דּוֹרִים.\nהָרַחֲמָן הוּא קֶרֶן לְעַמּוֹ יָרִים.\nהָרַחֲמָן הוּא יִתְפָּאַר בָּנוּ לָנֶצַח נְצָחִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד וְלֹא בְבִזּוּי, בְּהֶתֵּר וְלֹא בְאִסּוּר, בְּנַחַת וְלֹא בְצָעַר.\nהָרַחֲמָן הוּא יִתֵּן שָׁלוֹם בֵּינֵינוּ.\nהָרַחֲמָן הוּא יִשְׁלַח בְּרָכָה רְוָחָה וְהַצְלָחָה בְּכָל-מַעֲשֵׂה יָדֵינוּ.\nהָרַחֲמָן הוּא יַצְלִיחַ אֶת דְּרָכֵינוּ.\nהָרַחֲמָן הוּא יִשְׁבּוֹר עוֹל גָּלוּת מְהֵרָה מֵעַל צַוָּארֵנוּ.\nהָרַחֲמָן הוּא יוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת בְּאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִרְפָּאֵנוּ רְפוּאָה שְׁלֵמָה רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף.\nהָרַחֲמָן הוּא יִפְתַּח לָנוּ אֶת יָדוֹ הָרְחָבָה.\nהָרַחֲמָן הוּא יְבָרֵךְ כָּל אֶחָד וְאֶחָד מִמֶּנּוּ בִּשְׁמוֹ הַגָּדוֹל כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ יַחַד בְּרָכָה שְׁלֵמָה, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן.\nהָרַחֲמָן הוּא יִפְרוֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמוֹ.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לֵישֵׁב בְּסֻכַּת עוֹרוֹ שֶׁל לִוְיָתָן.\nהָרַחֲמָן הוּא יַשְׁפִּיעַ עָלֵינוּ שֶׁפַע קְדֻשָּׁה וְטָהֳרָה מִשִּׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין, זְכוּתָם תְּהֵא מָגֵן וְצִנָּה עָלֵינוּ.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["pesach"]},{"kind":"text","text":"הָרַחֲמָן הוּא יִטַּע תּוֹרָתוֹ וְאַהֲבָתוֹ בְּלִבֵּנוּ וְתִהְיֶה יִרְאָתוֹ עַל פָּנֵינוּ לְבִלְתִּי נֶחֱטָא, וְיִהְיוּ כָל-מַעֲשֵׂינוּ לְשֵׁם שָׁמָיִם.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת הַשֻּׁלְחָן הַזֶּה שֶׁאָכַלְנוּ עָלָיו וִיסַדֵּר בּוֹ כָּל מַעֲדַנֵּי עוֹלָם וְיִהְיֶה כְּשֻׁלְחָנוֹ שֶׁל אַבְרָהָם אָבִינוּ (עָלָיו הַשָּׁלוֹם), כָּל רָעֵב מִמֶּנּוּ יֹאכַל, וְכָל צָמֵא מִמֶּנּוּ יִשְׁתֶּה, וְאַל יֶחְסַר מִמֶּנּוּ כָּל טוּב לָעַד וּלְעוֹלְמֵי עוֹלָמִים. הָרַחֲמָן הוּא יְבָרֵךְ אֶת בַּעַל הַבַּיִת הַזֶּה וּבַעַל הַסְּעֻדָּה הַזּאת, הוּא וּבָנָיו וְאִשְׁתּוֹ וְכָל אֲשֶׁר לוֹ, בְּבָנִים שֶׁיִּחְיוּ, וּבִנְכָסִים שֶׁיִּרְבּוּ, בָּרֵךְ יהוה חֵילוֹ וּפֹעַל יָדָיו תִּרְצֶה, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִזְדַּקֵּק לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר חֵטְא וְהִרְהוּר עָוׂן. שָׂשׂ וְשָׂמֵחַ כָּל הַיָּמִים בְּעֹשֶׁר וְכָבוֹד מֵעַתָּה וְעַד עוֹלָם, לֹא יֵבוֹשׁ בָּעוֹלָם הַזֶּה וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, אָמֵן כֵּן יְהִי רָצוֹן.","cond":[]},{"kind":"instruction","text":"הרחמן לסעודת שבע ברכות:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת הֶחָתָן וְהַכַּלָּה בְּבָנִים זְכָרִים שֶׁל קַיָּמָא לַעֲבוֹדָתוֹ יִתְבָּרָךְ.\nהָרַחֲמָן הוּא יְבָרֵךְ אֶת כָּל הַמְּסֻבִּין בַּשֻּלְחָן הַזֶּה, וְיִתֵּן לָנוּ הַקָּדוֹשׁ בָּרוּךְ הוּא כָּל מִשְׁאֲלוֹת לִבֵּנוּ לְטוֹבָה.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְחַיֵּינוּ וִיזַכֵּנוּ וִיקָרְבֵנוּ לִימוֹת הַמָּשִׁיחַ וּלְבִנְיַן בֵּית הַמִּקְדָּשׁ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדרְשֵׁי יהוה לֹא-יַחְסְרוּ כָל-טוֹב: נַעַר הָיִיתִי גַּם-זָקַנְתִּי וְלֹא-רָאִיתִי צַדִּיק נֶעֱזָב, וְזַרְעוֹ מְבַקֶּשׁ-לָחֶם: כָּל-הַיּוֹם חוֹנֵן וּמַלְוֶה, וְזַרְעוֹ לִבְרָכָה: מַה שֶּׁאָכַלְנוּ יִהְיֶה לְשָׂבְעָה, וּמַה שֶּׁשָּׁתִינוּ יִהְיֶה לִרְפוּאָה, וּמַה שֶּׁהוֹתַרְנוּ יִהְיֶה לִבְרָכָה, כְּדִכְתִיב: וַיִּתֵּן לִפְנֵיהֶם וַיֹּאכְלוּ וַיּוֹתִירוּ כִּדְבַר יהוה: בְּרוּכִים אַתֶּם לַיהוה, עוֹשֵׂה שָׁמַיִם וָאָרֶץ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטָחוֹ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת-עַמּוֹ בַשָּׁלוֹם:","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"header","text":"שבע ברכות","cond":[]},{"kind":"instruction","text":"שבע ברכות","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהַכֹּל בָּרָא לִכְבוֹדוֹ.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, יוֹצֵר הָאָדָם.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר יָצַר אֶת הָאָדָם בְּצַלְמוֹ, בְּצֶלֶם דְּמוּת תַּבְנִיתוֹ, וְהִתְקִין לוֹ מִמֶּנּוּ בִּנְיַן עֲדֵי עַד. בָּרוּךְ אַתָּה יהוה, יוֹצֵר הָאָדָם.\n\nשׂוֹשׂ תָּשִׂישׂ וְתָגֵל עֲקָרָה בְּקִבּוּץ בָּנֶיהָ לְתוֹכָהּ בִּמְהֵרָה בְּשִׂמְחָה. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ צִיּוֹן בְּבָנֶיהָ.\n\nשַׂמֵּחַ תְּשַׂמַּח רֵעִים אֲהוּבִים כְּשַׂמֵּחֲךָ יְצִירְךָ בְּגַן עֵדֶן מִקֶּדֶם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ חָתָן וְכַלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר בָּרָא שָׂשׂוֹן וְשִׂמְחָה, חָתָן וְכַלָּה, גִּילָה, רִנָּה, דִּיצָה וְחֶדְוָה, אַהֲבָה וְאַחֲוָה וְשׁלוֹם וְרֵעוּת. מְהֵרָה יהוה אֱלֹהֵינוּ יִשָּׁמַע בְּעָרֵי יְהוּדָה וּבְחוּצוֹת יְרוּשָׁלַיִם קוֹל שָׂשׂוֹן וְקוֹל שִׂמְחָה, קוֹל חָתָן וְקוֹל כַּלָּה, קוֹל מִצְהֲלוֹת חֲתָנִים מֵחֻפָּתָם וּנְעָרִים מִמִּשְׁתֵּה נְגִינָתָם. בָּרוּךְ אַתָּה יהוה, מְשַׂמֵּחַ הֶחָתָן עִם הַכַּלָּה.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.","cond":[]}]}},{"id":"brit_milah","title":"סדר ברית מילה","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"instruction","text":"כשמביאים התינוק לבית הכנסת למול אומרים הקהל:","cond":[]},{"kind":"header","text":"ברוך הבא","cond":[]},{"kind":"text","text":"בָּרוּךְ הַבָּא.","cond":[]},{"kind":"instruction","text":"המוהל אומר:","cond":[]},{"kind":"text","text":"אַשְׁרֵי תִּבְחַר וּתְקָרֵב יִשְׁכֹּן חֲצֵרֶיךָ,","cond":[]},{"kind":"instruction","text":"והעומדים שם אומרים:","cond":[]},{"kind":"text","text":"נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ, קְדֹשׁ הֵיכָלֶךָ:","cond":[]},{"kind":"instruction","text":"מוסרים את התינוק לאביו והאב אומר בלחש:","cond":["israel"]},{"kind":"text","text":"אִם אֶשְׁכָּחֵךְ יְרוּשָלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָלַיִם עַל רֹאשׁ שִׂמְחָתִי:","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.\nיהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָא. אָנָּא יהוה הוֹשִׁיעָה נָא.\nאָנָּא יהוה הַצְלִיחָה נָא: אָנָּא יהוה הַצְלִיחָה נָא:","cond":["israel"]},{"kind":"instruction","text":"ויניח התינוק על הכסא של אליהו, ויאמר המוהל:","cond":[]},{"kind":"header","text":"כסא אליהו","cond":[]},{"kind":"text","text":"זֶה הַכִּסֵּא שֶׁל אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: שִׂבַּרְתִּי לִישׁוּעָתְךָ יהוה וּמִצְוׂתֶיךָ עָשִׂיתִי: אֵלִיָּהוּ מַלְאַךְ הַבְּרִית, הִנֵּה שֶׁלְּךָ לְפָנֶיךָ, עֲמֹד עַל יְמִינִי וְסָמְכֵנִי. שִׂבַּרְתִּי לִישׁוּעָתְךָ יהוה: שָׂשׂ אָנֹכִי עַל אִמְרָתֶךָ, כְּמוֹצֵא שָׁלָל רָב: שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ וְאֵין לָמוֹ מִכְשׁוֹל: אַשְׁרֵי תִבְחַר וּתְקָרֵב יִשְׁכּוֹן חֲצֵרֶיךָ, נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ קְדֹשׁ הֵיכָלֶךָ:","cond":[]},{"kind":"instruction","text":"מניח את התינוק על ברכי הסנדק והמוהל מברך:","cond":[]},{"kind":"header","text":"ברכת המילה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל הַמִּילָה.","cond":[]},{"kind":"instruction","text":"ואחר כך יחתוך הערלה ואבי הבן מברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהַכְנִיסוֹ בִּבְרִיתוֹ שֶׁל אַבְרָהָם אָבִינוּ.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":[]},{"kind":"instruction","text":"והקהל אומר:","cond":[]},{"kind":"text","text":"אָמֵן. כְּשֵׁם שֶׁנִּכְנַס לַבְּרִית, כָּךְ יִכָּנֵס לְתוֹרָה וּלְחֻפָּה וּלְמַעֲשִׂים טוֹבִים.","cond":[]},{"kind":"instruction","text":"אחרי גמר המילה יברך המוהל:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדֵּשׁ יְדִיד מִבֶּטֶן, וְחֹק בִּשְׁאֵרוֹ שָׂם, וְצֶאֱצָאָיו חָתַם בְּאוֹת בְּרִית קֹדֶשׁ. עַל כֵּן בִּשְׂכַר זֹאת, אֵל חַי חֶלְקֵנוּ צוּרֵנוּ צַוֵּה לְהַצִּיל יְדִידוּת שְׁאֵרֵנוּ מִשַּׁחַת, לְמַעַן בְּרִיתוֹ אֲשֶׁר שָׂם בִּבְשָׂרֵנוּ. בָּרוּךְ אַתָּה יהוה, כּוֹרֵת הַבְּרִית.","cond":[]},{"kind":"instruction","text":"יטעם מעט מן היין ויאמר:","cond":[]},{"kind":"header","text":"מתן שם","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, קַיֵּם אֶת הַיֶּלֶד הַזֶּה לְאָבִיו וּלְאִמּוֹ, וְיִקָּרֵא שְׁמוֹ בְּיִשְׂרָאֵל [פלוני בן פלוני]. יִשְׂמַח הָאָב בְּיוֹצֵא חֲלָצָיו וְתָגֵל אִמּוֹ בִּפְרִי בִטְנָהּ, כַּכָּתוּב: יִשְׂמַח אָבִיךָ וְאִמֶּךָ, וְתָגֵל יוֹלַדְתֶּךָ: וְנֶאֱמַר: וָאֶעֱבֹר עָלַיִךְ וָאֶרְאֵךְ מִתְבּוֹסֶסֶת בְּדָמָיִךְ, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי: וְנֶאֱמַר: זָכַר לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִשְׂחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: וְנֶאֱמַר: וַיָּמָל אַבְרָהָם אֶת יִצְחָק בְּנוֹ בֶּן שְׁמוֹנַת יָמִים, כַּאֲשֶׁר צִוָּה אֹתוֹ אֱלֹהִים: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:","cond":[]},{"kind":"instruction","text":"והקהל עונה:","cond":[]},{"kind":"text","text":"הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\n\n[פלוני בן פלוני] זֶה הַקָּטֹן גָּדוֹל יִהְיֶה, כְּשֵׁם שֶׁנִּכְנַס לַבְּרִית, כֵּן יִכָּנֵס לְתוֹרָה וּלְחֻפָּה וּלְמַעֲשִׂים טוֹבִים. אָמֵן.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ, כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"עַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד, כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ בְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשְׂרָאֵל בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"יש נוהגים לומר פיוט זה לאחר המילה או בזמן הסעודה:","cond":[]},{"kind":"text","text":"יוֹם לְיַבָּשָׁה נֶהֶפְכוּ מְצוּלִים, שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים.\nיוֹם בְּצַר נִכְבַּדְתָּ וְאֵלַי נֶחְמַדְתָּ, וְלָךְ עֹז יִסַּדְתָּ מִפִּי עוֹלְלִים.\nהִטְבַּעְתָּ בְתַרְמִית רַגְלֵי בַת עֲנָמִית, וַּפַעֲמֵי שׁוּלַמִּית יָפוּ בַנְּעָלִים.\nוְכָל רֹאַי יְשִׁירוּן בְּעֵת הוֹדִי יְשׁוּרוּן, אֵין כָּאֵל יְשֻׁרוּן וְאֹיְבֵינוּ פְּלִילִים.\nדְּגָלַי כֵּן תָּרִים עַל הַנִּשְׁאָרִים, וּתְלַקֵּט פְּזוּרִים כִּמְלַקֵּט שִׁבֳּלִים.\nהַבָּאִים עִמְּךָ בִּבְרִית חֹתָמְךָ, וּמִבֶּטֶן לְשִׁמְךָ הֵם נִמֹּלִים.\nהֶרְאוּ אֹתֹתָם לְכָל רֹאֶה אוֹתָם, וְעַל כַּנְפֵי כְסוּתָם יַעֲשׂוּ גְדִלִים.\nלְמִי זֹאת נִרְשֶׁמֶת הַכֶּר נָא דְּבַר אֱמֶת, לְמִי הַחֹתֶמֶת וְהַפְּתִילִים.\nוְשׁוּב שֵׁנִית לְקַדְּשָׁהּ וְאַל תּוֹסֶף לְגָרְשָׁהּ, וְהַעֲלֵה אוֹר שִׁמְשָׁהּ וְנָסוּ הַצְּלָלִים.\nיְדִידִים רוֹמְמוּךָ בְּשִׁירָה קִדְּמוּךָ, מִי כָמֹכָה אֲדֹנָי בָּאֵלִים.","cond":[]},{"kind":"header","text":"ברכת המזון לברית מילה","cond":[]},{"kind":"instruction","text":"ברכת המזון לסעודת ברית מילה","cond":[]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"special","text":"המזמן: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת אֵל אָיוֹם וְנוֹרָא מִשְׂגָּב לְעִתּוֹת בַּצָּרָה, אֵל נֶאְזָר בִּגְבוּרָה, אַדִּיר בַּמָּרוֹם אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת הַתּוֹרָה הַקְּדוֹשָׁה, טְהוֹרָה הִיא וְגַם פְּרוּשָׁה, צִוָּה לָנוּ מוֹרָשָׁה, מֹשֶׁה עֶבֶד אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת הַכֹּהֲנִים וְהַלְוִיִּם, אֶקְרָא לֵאלֹהֵי הָעִבְרִיִּים, אֲהוֹדֶנּוּ בְּכָל אִיִּים, אֲבָרְכָה אֶת אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי, אֶפְתְּחָה בְּשִׁיר פִּי וּשְׂפָתַי, וְתֹאמַרְנָה עַצְמוֹתַי, בָּרוּךְ הַבָּא בְּשֵׁם אֲדֹנָי.","cond":[]},{"kind":"text","text":"המזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nומי שלא אכל עונה: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) וּמְבֹרָךְ שְׁמוֹ תָּמֵיד לְעוֹלָם וָעֵד.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ, בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל, וּמֵטִיב לַכֹּל, וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא. בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ, יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"עַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל.","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל, יהוה אֱלֹהֵינוּ, אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד, כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֶם (נָא) יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ, זוּנֵנוּ, פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ, יהוה אֱלֹהֵינוּ, לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וּפִקְדוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךָ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים, לְחַיִּים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן, הוּא יְבָרֵךְ אֲבִי הַיֶלֶד וְאִמּוֹ, וְיִזְכּוּ לְגַדְּלוֹ וּלְחַנְּכוֹ וּלְחַכְּמוֹ, מִיּוֹם הַשְּׁמִינִי וָהָלְאָה יֵרָצֶה דָמוֹ, וִיהִי אֲדֹנָי אֱלֹהָיו עִמּוֹ. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ בַּעַל בְּרִית הַמִּילָה, אֲשֶׁר שָׂשׂ לַעֲשׂוֹת צֶדֶק בְּגִילָה, וִישַׁלֵּם פָּעֳלוֹ וּמַשְׂכֻּרְתּוֹ כְּפוּלָה, וְיִתְּנֵהוּ לְמַעְלָה לְמַעְלָה. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ רַךְ הַנִמּוֹל לִשְׁמוֹנָה, וְיִהְיוּ יָדָיו וְלִבּוֹ לָאֵל אֱמוּנָה, וְיִזְכֶּה לִרְאוֹת פְּנֵי הַשְּׁכִינָה, שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ הַמָּל בְּשַׂר הָעָרְלָה, וּפָרַע וּמָצַץ דְּמֵי הַמִּילָה, אִישׁ הַיָּרֵא וְרַךְ הַלֵּבָב עֲבוֹדָתוֹ פְּסוּלָה, אִם שְׁלָשׁ אֵלֶּה לֹא יַעֲשֶׂה לָהּ. אָמֵן.\n\nהָרַחֲמָן, הוּא יִשְׁלַח לָנוּ מְשִׁיחוֹ הוֹלֵךְ תָּמִים, בִּזְכוּת חֲתַן לַמּוּלוֹת דָּמִים, לְבַשֵּׂר בְּשׂוֹרוֹת טוֹבוֹת וְנִחוּמִים, לְעַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים. אָמֵן.\n\nהָרַחֲמָן, הוּא יִשְׁלַח לָנוּ כֹּהֵן צֶדֶק אֲשֶׁר לֻקַּח לְעֵילֹם, עַד הוּכַן כִּסְאוֹ כַּשֶּׁמֶשׁ וְיָהֲלֹם, וַיָּלֶט פָּנָיו בְּאַדַּרְתּוֹ וַיִּגְלוֹם, בְּרִיתִי הָיְתָה אִתּוֹ הַחַיִּים וְהַשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]}],"sfard":[{"kind":"instruction","text":"כשמביאים התינוק לבית הכנסת למול אומרים הקהל:","cond":[]},{"kind":"header","text":"ברוך הבא","cond":[]},{"kind":"text","text":"בָּרוּךְ הַבָּא.","cond":[]},{"kind":"instruction","text":"המוהל אומר:","cond":[]},{"kind":"text","text":"אַשְׁרֵי תִּבְחַר וּתְקָרֵב יִשְׁכֹּן חֲצֵרֶיךָ,","cond":[]},{"kind":"instruction","text":"והעומדים שם אומרים:","cond":[]},{"kind":"text","text":"נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ, קְדֹשׁ הֵיכָלֶךָ:","cond":[]},{"kind":"instruction","text":"מוסרים את התינוק לאביו והאב אומר בלחש:","cond":["israel"]},{"kind":"text","text":"אִם אֶשְׁכָּחֵךְ יְרוּשָלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָלַיִם עַל רֹאשׁ שִׂמְחָתִי:","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.\nיהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.","cond":["israel"]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":["israel"]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָא. אָנָּא יהוה הוֹשִׁיעָה נָא.\nאָנָּא יהוה הַצְלִיחָה נָא: אָנָּא יהוה הַצְלִיחָה נָא:","cond":["israel"]},{"kind":"instruction","text":"ויניח התינוק על הכסא של אליהו, ויאמר המוהל:","cond":[]},{"kind":"header","text":"כסא אליהו","cond":[]},{"kind":"text","text":"זֶה הַכִּסֵּא שֶׁל אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב.\nלִישׁוּעָתְךָ קִוִּיתִי יהוה: שִׂבַּרְתִּי לִישׁוּעָתְךָ יהוה וּמִצְוׂתֶיךָ עָשִׂיתִי: אֵלִיָּהוּ מַלְאַךְ הַבְּרִית, הִנֵּה שֶׁלְּךָ לְפָנֶיךָ, עֲמֹד עַל יְמִינִי וְסָמְכֵנִי. שִׂבַּרְתִּי לִישׁוּעָתְךָ יהוה: שָׂשׂ אָנֹכִי עַל אִמְרָתֶךָ, כְּמוֹצֵא שָׁלָל רָב: שָׁלוֹם רָב לְאֹהֲבֵי תוֹרָתֶךָ וְאֵין לָמוֹ מִכְשׁוֹל: אַשְׁרֵי תִבְחַר וּתְקָרֵב יִשְׁכּוֹן חֲצֵרֶיךָ, נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ קְדֹשׁ הֵיכָלֶךָ:","cond":[]},{"kind":"instruction","text":"מניח את התינוק על ברכי הסנדק והמוהל מברך:","cond":[]},{"kind":"header","text":"ברכת המילה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל הַמִּילָה.","cond":[]},{"kind":"instruction","text":"ואחר כך יחתוך הערלה ואבי הבן מברך:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהַכְנִיסוֹ בִּבְרִיתוֹ שֶׁל אַבְרָהָם אָבִינוּ.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":[]},{"kind":"instruction","text":"והקהל אומר:","cond":[]},{"kind":"text","text":"אָמֵן. כְּשֵׁם שֶׁנִּכְנַס לַבְּרִית, כָּךְ יִכָּנֵס לְתוֹרָה וּלְחֻפָּה וּלְמַעֲשִׂים טוֹבִים.","cond":[]},{"kind":"instruction","text":"אחרי גמר המילה יברך המוהל:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדֵּשׁ יְדִיד מִבֶּטֶן, וְחֹק בִּשְׁאֵרוֹ שָׂם, וְצֶאֱצָאָיו חָתַם בְּאוֹת בְּרִית קֹדֶשׁ. עַל כֵּן בִּשְׂכַר זֹאת, אֵל חַי חֶלְקֵנוּ צוּרֵנוּ צַוֵּה לְהַצִּיל יְדִידוּת שְׁאֵרֵנוּ מִשַּׁחַת, לְמַעַן בְּרִיתוֹ אֲשֶׁר שָׂם בִּבְשָׂרֵנוּ. בָּרוּךְ אַתָּה יהוה, כּוֹרֵת הַבְּרִית.","cond":[]},{"kind":"instruction","text":"יטעם מעט מן היין ויאמר:","cond":[]},{"kind":"header","text":"מתן שם","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ קַיֵּם אֶת הַיֶּלֶד הַזֶּה לְאָבִיו וּלְאִמּוֹ, וְיִקָּרֵא שְׁמוֹ בְּיִשְׂרָאֵל [פלוני בן פלוני]. יִשְׂמַח הָאָב בְּיוֹצֵא חֲלָצָיו וְתָגֵל אִמּוֹ בִּפְרִי בִטְנָהּ, כַּכָּתוּב: יִשְׂמַח אָבִיךָ וְאִמֶּךָ, וְתָגֵל יוֹלַדְתֶּךָ: וְנֶאֱמַר: וָאֶעֱבֹר עָלַיִךְ וָאֶרְאֵךְ מִתְבּוֹסֶסֶת בְּדָמָיִךְ, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי: וְנֶאֱמַר: זָכַר לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִשְׂחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: וְנֶאֱמַר: וַיָּמָל אַבְרָהָם אֶת יִצְחָק בְּנוֹ בֶּן שְׁמוֹנַת יָמִים, כַּאֲשֶׁר צִוָּה אֹתוֹ אֱלֹהִים: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:","cond":[]},{"kind":"instruction","text":"והקהל עונה:","cond":[]},{"kind":"text","text":"הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ:\n\n[פלוני בן פלוני] זֶה הַקָּטֹן גָּדוֹל יִהְיֶה, כְּשֵׁם שֶׁנִּכְנַס לַבְּרִית, כֵּן יִכָּנֵס לְתוֹרָה וּלְחֻפָּה וּלְמַעֲשִׂים טוֹבִים. אָמֵן.","cond":[]},{"kind":"header","text":"עלינו לשבח","cond":[]},{"kind":"text","text":"עָלֵינוּ לְשַׁבֵּחַ לַאֲדוֹן הַכֹּל, לָתֵת גְּדֻלָּה לְיוֹצֵר בְּרֵאשִׁית, שֶׁלֹּא עָשָׂנוּ כְּגוֹיֵי הָאֲרָצוֹת, וְלֹא שָׂמָנוּ כְּמִשְׁפְּחוֹת הָאֲדָמָה. שֶׁלֹּא שָׂם חֶלְקֵנוּ כָּהֶם, וְגוֹרָלֵנוּ כְּכָל-הֲמוֹנָם[, שֶׁהֵם מִשְׁתַּחֲוִים לְהֶבֶל וָרִיק, וּמִתְפַּלְּלִים אֶל אֵל לֹא יוֹשִׁיעַ]. וַאֲנַחְנוּ כּוֹרְעִים וּמִשְׁתַּחֲוִים וּמוֹדִים לִפְנֵי מֶלֶךְ מַלְכֵי הַמְּלָכִים הַקָּדוֹשׁ בָּרוּךְ הוּא, שֶׁהוּא נוֹטֶה שָׁמַיִם וְיוֹסֵד אָרֶץ, וּמוֹשַׁב יְקָרוֹ בַּשָּׁמַיִם מִמַּעַל, וּשְׁכִינַת עֻזּוֹ בְּגָבְהֵי מְרוֹמִים. הוּא אֱלֹהֵינוּ, אֵין עוֹד, אֱמֶת מַלְכֵּנוּ, אֶפֶס זוּלָתוֹ. כַּכָּתוּב בְּתוֹרָתוֹ: וְיָדַעְתָּ הַיּוֹם וַהֲשֵׁבֹתָ אֶל לְבָבֶךָ כִּי יהוה הוּא הָאֱלֹהִים בַּשָּׁמַיִם מִמַּעַל וְעַל הָאָרֶץ מִתָּחַת אֵין עוֹד:","cond":[]},{"kind":"text","text":"וְעַל כֵּן נְקַוֶּה לְךָ יהוה אֱלֹהֵינוּ, לִרְאוֹת מְהֵרָה בְּתִפְאֶרֶת עֻזֶּךָ, לְהַעֲבִיר גִּלּוּלִים מִן הָאָרֶץ, וְהָאֱלִילִים כָּרוֹת יִכָּרֵתוּן, לְתַקֵּן עוֹלָם בְּמַלְכוּת שַׁדַּי, וְכָל בְּנֵי בָשָׂר יִקְרְאוּ בִשְׁמֶךָ, לְהַפְנוֹת אֵלֶיךָ כָּל רִשְׁעֵי אָרֶץ. יַכִּירוּ וְיֵדְעוּ כָּל יוֹשְׁבֵי תֵבֵל, כִּי לְךָ תִכְרַע כָּל בֶּרֶךְ, תִּשָּׁבַע כָּל לָשׁוֹן. לְפָנֶיךָ יהוה אֱלֹהֵינוּ יִכְרְעוּ וְיִפֹּלוּ, וְלִכְבוֹד שִׁמְךָ יְקָר יִתֵּנוּ, וִיקַבְּלוּ כֻלָּם אֶת עֹל מַלְכוּתֶךָ, וְתִמְלֹךְ עֲלֵיהֶם מְהֵרָה לְעוֹלָם וָעֶד. כִּי הַמַּלְכוּת שֶׁלְּךָ הִיא, וּלְעוֹלְמֵי עַד תִּמְלֹךְ בְּכָבוֹד. כַּכָּתוּב בְּתוֹרָתֶךָ: יהוה יִמְלֹךְ לְעֹלָם וָעֶד: וְנֶאֱמַר: וְהָיָה יהוה לְמֶלֶךְ עַל כָּל הָאָרֶץ, בַּיּוֹם הַהוּא יִהְיֶה יהוה אֶחָד וּשְׁמוֹ אֶחָד:","cond":[]},{"kind":"instruction","text":"קדיש יתום","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכוֹן וּבְיוֹמֵיכוֹן וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא.\nיִתְבָּרַךְ וְיִשְׁתַּבַּח וְיִתְפָּאַר וְיִתְרוֹמַם וְיִתְנַשֵּׂא וְיִתְהַדָּר וְיִתְעַלֶּה וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא בְּרִיךְ הוּא.","cond":[]},{"kind":"text","text":"לְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["noAyt"]},{"kind":"special","text":"לְעֵלָּא לְעֵלָּא מִכָּל בִּרְכָתָא וְשִׁירָתָא, תֻּשְׁבְּחָתָא וְנֶחֱמָתָא, דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"text","text":"יְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא וְחַיִּים טוֹבִים עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["noayt"]},{"kind":"special","text":"עוֹשֶׂה הַשָּׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":["ayt"]},{"kind":"instruction","text":"יש נוהגים לומר פיוט זה לאחר המילה או בזמן הסעודה:","cond":[]},{"kind":"text","text":"יוֹם לְיַבָּשָׁה נֶהֶפְכוּ מְצוּלִים, שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים.\nיוֹם בְּצַר נִכְבַּדְתָּ וְאֵלַי נֶחְמַדְתָּ, וְלָךְ עֹז יִסַּדְתָּ מִפִּי עוֹלְלִים.\nהִטְבַּעְתָּ בְתַרְמִית רַגְלֵי בַת עֲנָמִית, וַּפַעֲמֵי שׁוּלַמִּית יָפוּ בַנְּעָלִים.\nוְכָל רֹאַי יְשִׁירוּן בְּעֵת הוֹדִי יְשׁוּרוּן, אֵין כָּאֵל יְשֻׁרוּן וְאֹיְבֵינוּ פְּלִילִים.\nדְּגָלַי כֵּן תָּרִים עַל הַנִּשְׁאָרִים, וּתְלַקֵּט פְּזוּרִים כִּמְלַקֵּט שִׁבֳּלִים.\nהַבָּאִים עִמְּךָ בִּבְרִית חֹתָמְךָ, וּמִבֶּטֶן לְשִׁמְךָ הֵם נִמֹּלִים.\nהֶרְאוּ אֹתֹתָם לְכָל רֹאֶה אוֹתָם, וְעַל כַּנְפֵי כְסוּתָם יַעֲשׂוּ גְדִלִים.\nלְמִי זֹאת נִרְשֶׁמֶת הַכֶּר נָא דְּבַר אֱמֶת, לְמִי הַחֹתֶמֶת וְהַפְּתִילִים.\nוְשׁוּב שֵׁנִית לְקַדְּשָׁהּ וְאַל תּוֹסֶף לְגָרְשָׁהּ, וְהַעֲלֵה אוֹר שִׁמְשָׁהּ וְנָסוּ הַצְּלָלִים.\nיְדִידִים רוֹמְמוּךָ בְּשִׁירָה קִדְּמוּךָ, מִי כָמֹכָה אֲדֹנָי בָּאֵלִים.","cond":[]},{"kind":"header","text":"ברכת המזון לברית מילה","cond":[]},{"kind":"instruction","text":"ברכת המזון לסעודת ברית מילה","cond":[]},{"kind":"special","text":"שִׁיר הַמַּעֲלוֹת בְּשׁוּב יהוה אֶת שִׁיבַת צִיּוֹן, הָיִינוּ כְּחֹלְמִים: אָז יִמָּלֵא שְׂחוֹק פִּינוּ וּלְשׁוֹנֵנוּ רִנָּה, אָז יֹאמְרוּ בַגּוֹיִם הִגְדִּיל יהוה לַעֲשׂוֹת עִם אֵלֶּה: הִגְדִּיל יהוה לַעֲשׂוֹת עִמָּנוּ, הָיִינוּ שְׂמֵחִים: שׁוּבָה יהוה אֶת שְׁבִיתֵנוּ כַּאֲפִיקִים בַּנֶּגֶב: הַזֹּרְעִים בְּדִמְעָה בְּרִנָּה יִקְצֹרוּ: הָלוֹךְ יֵלֵךְ וּבָכֹה נֹשֵׂא מֶשֶׁךְ הַזָּרַע, בֹּא יָבוֹא בְרִנָּה נֹשֵׂא אֲלֻמֹּתָיו:","cond":[]},{"kind":"text","text":"המזמן אומר: רַבּוֹתַי, נְבָרֵךְ.\nהמסובים עונים: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:\nהמזמן אומר: יְהִי שֵׁם יהוה מְבֹרָךְ מִעַתָּה וְעַד עוֹלָם:","cond":[]},{"kind":"special","text":"המזמן: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת אֵל אָיוֹם וְנוֹרָא מִשְׂגָּב לְעִתּוֹת בַּצָּרָה, אֵל נֶאְזָר בִּגְבוּרָה, אַדִּיר בַּמָּרוֹם אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת הַתּוֹרָה הַקְּדוֹשָׁה, טְהוֹרָה הִיא וְגַם פְּרוּשָׁה, צִוָּה לָנוּ מוֹרָשָׁה, מֹשֶׁה עֶבֶד אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת הַכֹּהֲנִים וְהַלְוִיִּם, אֶקְרָא לֵאלֹהֵי הָעִבְרִיִּים, אֲהוֹדֶנּוּ בְּכָל אִיִּים, אֲבָרְכָה אֶת אֲדֹנָי.","cond":[]},{"kind":"instruction","text":"המסובים עונים: נוֹדֶה לְשִׁמְךָ בְּתוֹךְ אֱמוּנַי, בְּרוּכִים אַתֶּם לַאדֹנָי.","cond":[]},{"kind":"special","text":"המזמן: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי, אֶפְתְּחָה בְּשִׁיר פִּי וּשְׂפָתַי, וְתֹאמַרְנָה עַצְמוֹתַי, בָּרוּךְ הַבָּא בְּשֵׁם אֲדֹנָי.","cond":[]},{"kind":"text","text":"המזמן אומר: בִּרְשׁוּת מָרָנָן וְרַבָּנָן וְרַבּוֹתַי נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nהמזמן אומר: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.\nומי שלא אכל עונה: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) וּמְבֹרָךְ שְׁמוֹ תָּמֵיד לְעוֹלָם וָעֵד.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הַזָּן אֶת הָעוֹלָם כֻּלּוֹ, בְּטוּבוֹ בְּחֵן בְּחֶסֶד וּבְרַחֲמִים. הוּא נוֹתֵן לֶחֶם לְכָל בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן לְעוֹלָם וָעֶד, בַּעֲבוּר שְׁמוֹ הַגָּדוֹל, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וּמֵטִיב לַכֹּל וּמֵכִין מָזוֹן לְכָל בְּרִיּוֹתָיו אֲשֶׁר בָּרָא, כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ, עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָה טוֹבָה וּרְחָבָה, וְעַל שֶׁהוֹצֵאתָנוּ יהוה אֱלֹהֵינוּ מֵאֶרֶץ מִצְרַיִם, וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֶּיךָ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים חֵן וָחֶסֶד שֶׁחוֹנַנְתָּנוּ, וְעַל אֲכִילַת מָזוֹן שָׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ תָּמִיד, בְּכָל יוֹם וּבְכָל עֵת וּבְכָל שָׁעָה.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים, מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ, וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ, וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְּרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ (, וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה).","cond":["purim"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת וְעַל הַמִּלְחָמוֹת שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיּמָים הַהֵם בַּזְּמַן הַזֶּה. בִּימֵי מַתִּתְיָהוּ בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְהַשְׁכִּיחָם תּוֹרָתֶךָ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנֶךָ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּטְמֵאִים בְּיַד טְהוֹרִים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, וּלְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמֶךָ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כֵּן בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ לְהוֹדוֹת וּלְהַלֵּל לְשִׁמְךָ הַגָּדוֹל. (נ\"א: וְקָבְעוּ שְׁמוֹנַת יָמִים אֵלּוּ בְּהַלֵּל וּבְהוֹדָאָה וְעָשִׂיתָ עִמָּהֶם נֵס וָפֶלֶא וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל סֶלָה.)","cond":["chanuka"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אוֹתָךְ, יִתְבָּרַךְ שִׁמְךָ בְּפִי כָּל חַי תָּמִיד לְעוֹלָם וָעֶד. כַּכָּתוּב: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת יהוה אֱלֹהֶיךָ עַל הָאָרֶץ הַטֹּבָה אֲשֶׁר נָתַן לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֶם נָא יהוה אֱלֹהֵינוּ עַל יִשְׂרָאֵל עַמֶּךָ, וְעַל יְרוּשָׁלַיִם עִירֶךָ, וְעַל צִיּוֹן מִשְׁכַּן כְּבוֹדֶךָ, וְעַל מַלְכוּת בֵּית דָּוִד מְשִׁיחֶךָ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו. אֱלֹהֵינוּ, אָבִינוּ, רְעֵנוּ זוּנֵנוּ פַּרְנְסֵנוּ וְכַלְכְּלֵנוּ וְהַרְוִיחֵנוּ, וְהַרְוַח לָנוּ יהוה אֱלֹהֵינוּ מְהֵרָה מִכָּל צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לֹא לִידֵי מַתְּנַת בָּשָׂר וָדָם וְלֹא לִידֵי הַלְוָאָתָם, כִּי אִם לְיָדְךָ הַמְּלֵאָה, הַפְּתוּחָה, הַקְּדוֹשָׁה וְהָרְחָבָה, שֶׁלֹּא נֵבוֹשׁ וְלֹא נִכָּלֵם לְעוֹלָם וָעֶד.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה.","cond":["rh"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה.","cond":["pesach"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבֹא, וְיַגִּיעַ וְיֵרָאֶה וְיֵרָצֶה, וְיִשָּׁמַע וְיִפָּקֵד וְיִזָּכֵר, זִכְרוֹנֵנוּ וּפִקְדוֹנֵנו וְזִכְרוֹן אֲבוֹתֵינוּ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדֶּךְ, וְזִכְרוֹן יְרוּשָׁלַיִם עִיר קָדְשֶׁךָ, וְזִכְרוֹן כָָל עַמְּךָ בֵּית יִשְׂרָאֵל לְפָנֶיךָ, לִפְלֵטָה, לְטוֹבָה, לְחֵן וּלְחֶסֶד וּלְרַחֲמִים לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה.","cond":["sucot"]},{"kind":"special","text":"זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. וּבִדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ, וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וּבְנֵה יְרוּשָׁלַיִם עִיר הַקֹּדֶשׁ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה בְרַחֲמָיו יְרוּשָׁלָיִם. אָמֵן.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל, אָבִינוּ, מַלְכֵּנוּ, אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, יוֹצְרֵנוּ, קְדוֹשֵׁנוּ קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל יוֹם וָיוֹם הוּא הֵטִיב הוּא מֵטִיב הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ הוּא גוֹמְלֵנוּ הוּא יִגְמְלֵנוּ לָעַד לְחֵן וּלְחֶסֶד וּלְרַחֲמִים וּלְרֶוַח, הַצָּלָה וְהַצְלָחָה, בְּרָכָה וִישׁוּעָה, נֶחָמָה, פַּרְנָסָה וְכַלְכָּלָה, וְרַחֲמִים וְחַיִּים וְשָׁלוֹם וְכָל טוֹב, וּמִכָּל טוּב לְעוֹלָם אַל יְחַסְּרֵנוּ.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִמְלֹךְ עָלֵינוּ לְעוֹלָם וָעֶד.\nהָרַחֲמָן הוּא יִתְבָּרַךְ בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח לְדוֹר דּוֹרִים, וְיִתְפָּאַר בָּנוּ (לָעַד וּ)לְנֵצַח נְצָחִים, וְיִתְהַדַּר בָּנוּ לָעַד וּלְעוֹלְמֵי עוֹלָמִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד.\nהָרַחֲמָן הוּא יִשְׁבֹּר עֻלֵּנוּ מֵעַל צַוָּארֵנוּ וְהוּא יוֹלִיכֵנוּ קוֹמְמִיּוּת לְאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ בְּרָכָה מְרֻבָּה בַּבַּיִת הַזֶּה וְעַל שֻׁלְחָן זֶה שֶׁאָכַלְנוּ עָלָיו.\nהָרַחֲמָן הוּא יִשְׁלַח לָנוּ אֶת אֵלִיָּהוּ הַנָּבִיא זָכוּר לַטּוֹב, וִיבַשֶּׂר לָנוּ בְּשׂוֹרוֹת טוֹבוֹת יְשׁוּעוֹת וְנֶחָמוֹת.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"יְהִי רָצוֹן שֶׁלֹּא יֵבוֹשׁ בַּעַל הַבַּיִת בָּעוֹלָם הַזֶּה, וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, וְיִצְלַח מְאֹד בְּכָל נְכָסָיו, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִשְׁלוֹט שָׂטָן לֹא בְּמַעֲשֶׂה יָדָיו וְלֹא בְּמַעֲשֶׂה יָדֵינוּ. וְאַל יִזְדַּקֵּק לֹא לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר הִרְהוּר חֵטְא, עֲבֵירָה וְעָוׂן, מֵעַתָּה וְעַד עוֹלָם.","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן עצמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אוֹתִי וְאֶת אִשְׁתִּי (אשה אומרת: בַּעֲלִי) וְאֶת זַרְעִי וְאֶת כָּל אֲשֶׁר לִי,","cond":[]},{"kind":"instruction","text":"אם סמוך על שולחן אחרים או על שולחן אביו ואמו אומר:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת (אָבִי מוֹרִי) בַּעַל הַבַּיִת הַזֶּה וְאֶת (אִמִּי מוֹרָתִי) בַּעֲלַת הַבַּיִת הַזֶּה, אוֹתָם וְאֶת בֵּיתָם וְאֶת זַרְעָם וְאֶת כָּל אֲשֶׁר לָהֶם,\n\nאוֹתָנוּ וְאֶת כָּל אֲשֶׁר לָנוּ, כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקֹב, בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ כֻּלָּנוּ יַחַד בִּבְרָכָה שְׁלֵמָה, וְנֹאמַר אָמֵן.","cond":[]},{"kind":"text","text":"בַּמָּרוֹם יְלַמְּדוּ עֲלֵיהֶם וְעָלֵינוּ זְכוּת שֶׁתְּהֵא לְמִשְׁמֶרֶת שָׁלוֹם, וְנִשָּׂא בְרָכָה מֵאֵת יהוה, וּצְדָקָה מֵאֱלֹהֵי יִשְׁעֵנוּ, וְנִמְצָא חֵן וְשֵׂכֶל טוֹב בְּעֵינֵי אֱלֹהִים וְאָדָם.","cond":[]},{"kind":"special","text":"הָרַחֲמָן, הוּא יְבָרֵךְ אֲבִי הַיֶלֶד וְאִמּוֹ, וְיִזְכּוּ לְגַדְּלוֹ וּלְחַנְּכוֹ וּלְחַכְּמוֹ, מִיּוֹם הַשְּׁמִינִי וָהָלְאָה יֵרָצֶה דָמוֹ, וִיהִי אֲדֹנָי אֱלֹהָיו עִמּוֹ. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ בַּעַל בְּרִית הַמִּילָה, אֲשֶׁר שָׂשׂ לַעֲשׂוֹת צֶדֶק בְּגִילָה, וִישַׁלֵּם פָּעֳלוֹ וּמַשְׂכֻּרְתּוֹ כְּפוּלָה, וְיִתְּנֵהוּ לְמַעְלָה לְמַעְלָה. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ רַךְ הַנִמּוֹל לִשְׁמוֹנָה, וְיִהְיוּ יָדָיו וְלִבּוֹ לָאֵל אֱמוּנָה, וְיִזְכֶּה לִרְאוֹת פְּנֵי הַשְּׁכִינָה, שָׁלֹשׁ פְּעָמִים בַּשָּׁנָה. אָמֵן.\n\nהָרַחֲמָן, הוּא יְבָרֵךְ הַמָּל בְּשַׂר הָעָרְלָה, וּפָרַע וּמָצַץ דְּמֵי הַמִּילָה, אִישׁ הַיָּרֵא וְרַךְ הַלֵּבָב עֲבוֹדָתוֹ פְּסוּלָה, אִם שְׁלָשׁ אֵלֶּה לֹא יַעֲשֶׂה לָהּ. אָמֵן.\n\nהָרַחֲמָן, הוּא יִשְׁלַח לָנוּ מְשִׁיחוֹ הוֹלֵךְ תָּמִים, בִּזְכוּת חֲתַן לַמּוּלוֹת דָּמִים, לְבַשֵּׂר בְּשׂוֹרוֹת טוֹבוֹת וְנִחוּמִים, לְעַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים. אָמֵן.\n\nהָרַחֲמָן, הוּא יִשְׁלַח לָנוּ כֹּהֵן צֶדֶק אֲשֶׁר לֻקַּח לְעֵילֹם, עַד הוּכַן כִּסְאוֹ כַּשֶּׁמֶשׁ וְיָהֲלֹם, וַיָּלֶט פָּנָיו בְּאַדַּרְתּוֹ וַיִּגְלוֹם, בְּרִיתִי הָיְתָה אִתּוֹ הַחַיִּים וְהַשָּׁלוֹם. אָמֵן.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"text","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לִימוֹת הַמָשִׁיחַ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"עוֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"יְראוּ אֶת יהוה קְדוֹשָׁיו, כִּי אֵין מַחְסוֹר לִירֵאָיו: כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדוֹרְשֵׁי יהוה לֹא יַחְסְרוּ כָל טוֹב: הוֹדוּ לַיהוה כִּי טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: פּוֹתֵחַ אֶת יָדֶךָ, וּמַשְׂבִּיעַ לְכָל חַי רָצוֹן: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטַחוֹ: נַעַר הָיִיתִי גַם זָקַנְתִּי, וְלֹא רָאִיתִי צַדִּיק נֶעֱזָב וְזַרְעוֹ מְבַקֶּשׁ לָחֶם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:","cond":[]}],"edot_mizrach":[{"kind":"instruction","text":"כשמביאים התינוק לבית-הכנסת עומדים כל הקהל ואומרים:","cond":[]},{"kind":"header","text":"ברוך הבא","cond":[]},{"kind":"text","text":"בָּרוּךְ הַבָּא בְּשֵׁם יהוה.","cond":[]},{"kind":"instruction","text":"וכשלוקח אבי הבן את התינוק בידיו אומר:","cond":[]},{"kind":"text","text":"שָׂשׂ אָנֹכִי עַל-אִמְרָתֶךָ, כְּמוֹצֵא שָׁלָל רָב: זִבְחֵי אֱלֹהִים רוּחַ נִשְׁבָּרָה, לֵב-נִשְׁבָּר וְנִדְכֶּה, אֱלֹהִים לֹא תִבְזֶה: הֵיטִיבָה בִרְצוֹנְךָ אֶת-צִיּוֹן, תִּבְנֶה חוֹמוֹת יְרוּשָׁלָיִם: אָז תַּחְפּוֹץ זִבְחֵי-צֶדֶק עוֹלָה וְכָלִיל, אָז יַעֲלוּ עַל-מִזְבַּחֲךָ פָרִים:","cond":[]},{"kind":"instruction","text":"ואחר-כך יאמר אבי הבן:","cond":[]},{"kind":"text","text":"אַשְׁרֵי תִּבְחַר וּתְקָרֵב יִשְׁכֹּן חֲצֵרֶיךָ,","cond":[]},{"kind":"instruction","text":"ועונים העומדים:","cond":[]},{"kind":"text","text":"נִשְׂבְּעָה בְּטוּב בֵּיתֶךָ, קְדֹשׁ הֵיכָלֶךָ:","cond":[]},{"kind":"instruction","text":"מוסרים את התינוק לאביו והאב אומר בלחש:","cond":[]},{"kind":"text","text":"אִם אֶשְׁכָּחֵךְ יְרוּשָלָיִם תִּשְׁכַּח יְמִינִי: תִּדְבַּק לְשׁוֹנִי לְחִכִּי אִם לֹא אֶזְכְּרֵכִי, אִם לֹא אַעֲלֶה אֶת יְרוּשָלַיִם עַל רֹאשׁ שִׂמְחָתִי:","cond":[]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":[]},{"kind":"text","text":"שְׁמַע יִשְׂרָאֵל, יהוה אֱלֹהֵינוּ, יהוה אֶחָד:","cond":[]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":[]},{"kind":"text","text":"יהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.\nיהוה מֶלֶךְ, יהוה מָלָךְ, יהוה יִמְלֹךְ לְעוֹלָם וָעֶד.","cond":[]},{"kind":"instruction","text":"ואומר האב בקול רם והקהל חוזר אחריו:","cond":[]},{"kind":"text","text":"אָנָּא יהוה הוֹשִׁיעָה נָא. אָנָּא יהוה הוֹשִׁיעָה נָא.\nאָנָּא יהוה הַצְלִיחָה נָא: אָנָּא יהוה הַצְלִיחָה נָא:","cond":[]},{"kind":"instruction","text":"אומר אבי הבן:","cond":[]},{"kind":"text","text":"בִּרְשׁוּת מוֹרַי ורַבּוֹתַי.","cond":[]},{"kind":"instruction","text":"הקהל עונים:","cond":[]},{"kind":"text","text":"שָׁמָיִם.","cond":[]},{"kind":"instruction","text":"ומברך בעמידה:","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ לְהַכְנִיסוֹ בִּבְרִיתוֹ שֶׁל אַבְרָהָם אָבִינוּ.","cond":[]},{"kind":"instruction","text":"והקהל והמוהל אומרים:","cond":[]},{"kind":"text","text":"כְּשֵׁם שֶׁהִכְנַסְתּוֹ לַבְּרִית, כָּךְ תִּזְכֶּה לְהַכְנִיסוֹ לַתּוֹרָה וְלַמִּצְוׂת וְלַחֻפָּה וּלְמַעֲשִׂים טוֹבִים.","cond":[]},{"kind":"instruction","text":"וישב הסנדק על הכסא ומניח התינוק על ברכיו, ואומר המוהל:","cond":[]},{"kind":"header","text":"כסא אליהו","cond":[]},{"kind":"text","text":"זֶה הַכִּסֵּא שֶׁל אֵלִיָּהוּ הַנָּבִיא מַלְאַךְ הַבְּרִית זָכוּר לַטּוֹב.","cond":[]},{"kind":"instruction","text":"האב אומר למוהל:","cond":[]},{"kind":"text","text":"הִנְנִי מְמַנֶּה אוֹתְךָ שְׁלִיחַ מִצְוָה בִּמְקוֹמִי לָמוּל אֶת בְּנִי.","cond":[]},{"kind":"instruction","text":"המוהל מברך:","cond":[]},{"kind":"header","text":"ברכת המילה","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל הַמִּילָה.","cond":[]},{"kind":"instruction","text":"ואחרי שימול יברך אבי הבן ברכה זו","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":[]},{"kind":"instruction","text":"ולוקח המוהל או אָדָם אחר כוס יין ומברך","cond":[]},{"kind":"text","text":"סַבְרֵי מָרָנָן. (עונים: לְחַיִּים.)\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא פְּרִי הַגֶּפֶן.","cond":[]},{"kind":"instruction","text":"ואחר-כך לוקח הדס ומברך","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא עֲצֵי בְשָׂמִים.\n\nבָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדֵּשׁ יְדִיד מִבֶּטֶן וְחֹק בִּשְׁאֵרוֹ שָׂם וְצֶאֱצָאָיו חָתַם בְּאוֹת בְּרִית קֹדֶשׁ. עַל כֵּן בִּשְׂכַר זוֹ אֵל חַי חֶלְקֵנוּ צוּרֵנוּ צַוֵּה לְהַצִּיל יְדִידוּת זֶרַע קֹדֶשׁ שְׁאֵרֵנוּ מִשַּׁחַת, לְמַעַן בְּרִיתוֹ אֲשֶׁר שָׂם בִּבְשָׂרֵנוּ. בָּרוּךְ אַתָּה יהוה, כּוֹרֵת הַבְּרִית.","cond":[]},{"kind":"instruction","text":"יטעם מעט מן היין ויאמר:","cond":[]},{"kind":"header","text":"מתן שם","cond":[]},{"kind":"text","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ קַיֵּם אֶת-הַיֶּלֶד הַזֶּה לְאָבִיו וּלְאִמּוֹ וְיִקָּרֵא שְׁמוֹ בְּיִשְׂרָאֵל [פלוני]. יִשְׂמַח הָאִישׁ בְּיוֹצֵא חֲלָצָיו, וְתָגֵל הָאִשָּׁה בִּפְרִי בִטְנָהּ, כָּאָמוּר: יִשְׂמַח-אָבִיךָ וְאִמֶּךָ, וְתָגֵל יוֹלַדְתֶּךָ: וְנֶאֱמַר: וָאֶעֱבֹר עָלַיִךְ וָאֶרְאֵךְ מִתְבּוֹסֶסֶת בְּדָמָיִךְ, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי, וָאֹמַר לָךְ בְּדָמַיִךְ חֲיִי: וְנֶאֱמַר: זָכַר לְעוֹלָם בְּרִיתוֹ, דָּבָר צִוָּה לְאֶלֶף דּוֹר: אֲשֶׁר כָּרַת אֶת-אַבְרָהָם, וּשְׁבוּעָתוֹ לְיִשְׂחָק: וַיַּעֲמִידֶהָ לְיַעֲקֹב לְחֹק, לְיִשְׂרָאֵל בְּרִית עוֹלָם: הוֹדוּ לַיהוה כִּי-טוֹב, כִּי לְעוֹלָם חַסְדּוֹ: [פלוני] זֶה הַקָּטָן, אֱלֹהִים יְגַדְּלֵהוּ, כְּשֵׁם שֶׁנִּכְנַס לַבְּרִית, כָּךְ יִכָּנֵס לַתּוֹרָה וְלַמִּצְוׂת וְלָחֻפָּה וּלְמַעֲשִׂים טוֹבִים, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן.\n\nשִׁיר הַמַּעֲלוֹת אַשְׁרֵי כָּל-יְרֵא יהוה, הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פֹּרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִילֵי זֵיתִים, סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִי-כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן וּרְאֵה בְּטוּב יְרוּשָׁלָיִם, כָּל יְמֵי חַיֶּיךָ: וּרְאֵה-בָנִים לְבָנֶיךָ שָׁלוֹם עַל-יִשְׂרָאֵל:","cond":[]},{"kind":"instruction","text":"קדיש יהא שלמא","cond":[]},{"kind":"text","text":"יִתְגַּדַּל וְיִתְקַדַּשׁ שְׁמֵהּ רַבָּא.\nבְּעָלְמָא דִּי בְרָא כִרְעוּתֵהּ וְיַמְלִיךְ מַלְכוּתֵהּ וְיַצְמַח פֻּרְקָנֵהּ וִיקָרֵב מְשִׁיחֵהּ.\nבְּחַיֵּיכון וּבְיומֵיכון וּבְחַיֵּי דְכָל בֵּית יִשרָאֵל, בַּעֲגָלָא וּבִזְמַן קָרִיב, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁמֵהּ רַבָּא מְבָרַךְ לְעָלַם וּלְעָלְמֵי עָלְמַיָּא יִתְבָּרַךְ. וְיִשְׁתַּבַּח. וְיִתְפָּאַר. וְיִתְרוֹמַם. וְיִתְנַשֵּׂא. וְיִתְהַדָּר. וְיִתְעַלֶּה. וְיִתְהַלָּל שְׁמֵהּ דְּקֻדְשָׁא. בְּרִיךְ הוּא.\nלְעֵלָּא מִן כָּל בִּרְכָתָא וְשִׁירָתָא, תִּשְׁבְּחָתָא וְנֶחֱמָתָא דַּאֲמִירָן בְּעָלְמָא, וְאִמְרוּ אָמֵן.\nיְהֵא שְׁלָמָא רַבָּא מִן שְׁמַיָּא, חַיִּים וְשָׂבָע וִישׁוּעָה וְנֶחָמָה וְשֵיזָבָא וּרְפוּאָה וּגְאֻלָּה וּסְלִיחָה וְכַפָּרָה וְרֶוַח וְהַצָּלָה, לָנוּ וּלְכָל עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]},{"kind":"instruction","text":"יש נוהגים לומר פיוט זה לאחר המילה או בזמן הסעודה:","cond":[]},{"kind":"text","text":"יוֹם לְיַבָּשָׁה נֶהֶפְכוּ מְצוּלִים, שִׁירָה חֲדָשָׁה שִׁבְּחוּ גְאוּלִים.\nיוֹם בְּצַר נִכְבַּדְתָּ וְאֵלַי נֶחְמַדְתָּ, וְלָךְ עֹז יִסַּדְתָּ מִפִּי עוֹלְלִים.\nהִטְבַּעְתָּ בְתַרְמִית רַגְלֵי בַת עֲנָמִית, וַּפַעֲמֵי שׁוּלַמִּית יָפוּ בַנְּעָלִים.\nוְכָל רֹאַי יְשִׁירוּן בְּעֵת הוֹדִי יְשׁוּרוּן, אֵין כָּאֵל יְשֻׁרוּן וְאֹיְבֵינוּ פְּלִילִים.\nדְּגָלַי כֵּן תָּרִים עַל הַנִּשְׁאָרִים, וּתְלַקֵּט פְּזוּרִים כִּמְלַקֵּט שִׁבֳּלִים.\nהַבָּאִים עִמְּךָ בִּבְרִית חֹתָמְךָ, וּמִבֶּטֶן לְשִׁמְךָ הֵם נִמֹּלִים.\nהֶרְאוּ אֹתֹתָם לְכָל רֹאֶה אוֹתָם, וְעַל כַּנְפֵי כְסוּתָם יַעֲשׂוּ גְדִלִים.\nלְמִי זֹאת נִרְשֶׁמֶת הַכֶּר נָא דְּבַר אֱמֶת, לְמִי הַחֹתֶמֶת וְהַפְּתִילִים.\nוְשׁוּב שֵׁנִית לְקַדְּשָׁהּ וְאַל תּוֹסֶף לְגָרְשָׁהּ, וְהַעֲלֵה אוֹר שִׁמְשָׁהּ וְנָסוּ הַצְּלָלִים.\nיְדִידִים רוֹמְמוּךָ בְּשִׁירָה קִדְּמוּךָ, מִי כָמֹכָה אֲדֹנָי בָּאֵלִים.","cond":[]},{"kind":"header","text":"ברכת המזון","cond":[]},{"kind":"instruction","text":"ברכת המזון לסעודת ברית מילה","cond":[]},{"kind":"header","text":"למנצח","cond":[]},{"kind":"text","text":"לַמְנַצֵּחַ בִּנְגִינֹת מִזְמוֹר שִׁיר: אֱלֹהִים יְחָנֵּנוּ וִיבָרְכֵנוּ, יָאֵר פָּנָיו אִתָּנוּ סֶלָה: לָדַעַת בָּאָרֶץ דַּרְכֶּךָ, בְּכָל-גּוֹיִם יְשׁוּעָתֶךָ: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: יִשְׂמְחוּ וִירַנְּנוּ לְאֻמִּים כִּי-תִשְׁפֹּט עַמִּים מִישֹׁר, וּלְאֻמִּים בָּאָרֶץ תַּנְחֵם סֶלָה: יוֹדוּךָ עַמִּים אֱלֹהִים, יוֹדוּךָ עַמִּים כֻּלָּם: אֶרֶץ נָתְנָה יְבוּלָהּ, יְבָרְכֵנוּ אֱלֹהִים אֱלֹהֵינוּ: יְבָרְכֵנוּ אֱלֹהִים, וְיִירְאוּ אוֹתוֹ כָּל-אַפְסֵי-אָרֶץ:","cond":[]},{"kind":"text","text":"אֲבָרְכָה אֶת-יהוה בְּכָל-עֵת, תָּמִיד תְּהִלָּתוֹ בְּפִי: סוֹף דָּבָר הַכֹּל נִשְׁמָע, אֶת-הָאֱלֹהִים יְרָא וְאֶת-מִצְוׂתָיו שְׁמוֹר, כִּי-זֶה כָּל-הָאָדָם: תְּהִלַּת יהוה יְדַבֶּר פִּי, וִיבָרֵךְ כָּל-בָּשָׂר שֵׁם קָדְשׁוֹ לְעוֹלָם וָעֶד: וַאֲנַחְנוּ נְבָרֵךְ יָהּ מֵעַתָּה וְעַד-עוֹלָם הַלְלוּיָהּ:","cond":[]},{"kind":"instruction","text":"שלשה שאכלו יחדיו חייבים בזימון:","cond":[]},{"kind":"text","text":"המזמן אומר: הַב לָן וְנִבְרִיךְ לְמַלְכָּא עִלָּאָה קַדִּישָׁא.\nהמסובים עונים: שָמַיִם.\nהמברך אומר: בִּרְשׁוּת מַלְכָּא עִלָּאָה קַדִּישָׁא,","cond":[]},{"kind":"special","text":"וּבִרְשׁוּת שִׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין","cond":["sucot"]},{"kind":"text","text":"וּבִרְשׁוּת מוֹרַי וְרַבּוֹתַי, וּבִרְשׁוּתְכֶם, נְבָרֵךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ.\nהמסובים עונים: בָּרוּךְ (בעשרה: אֱלֹהֵינוּ) שֶׁאָכַלְנוּ מִשּׁלּוֹ וּבְטוּבוֹ חָיִינוּ.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָאֵל הַזָּן אוֹתָנוּ וְאֶת הָעוֹלָם כֻּלּוֹ בְּטוּבוֹ בְּחֵן בְּחֶסֶד בְּרֶוַח וּבְרַחֲמִים רַבִּים, נֹתֵן לֶחֶם לְכָל-בָּשָׂר, כִּי לְעוֹלָם חַסְדּוֹ. וּבְטוּבוֹ הַגָּדוֹל תָּמִיד לֹא חָסַר לָנוּ וְאַל יֶחְסַר לָנוּ מָזוֹן תָּמִיד לְעוֹלָם וָעֶד, כִּי הוּא אֵל זָן וּמְפַרְנֵס לַכֹּל וְשֻׁלְחָנוֹ עָרוּךְ לַכֹּל וְהִתְקִין מִחְיָה וּמָזוֹן לְכָל-בְּרִיּוֹתָיו אֲשֶׁר בָּרָא בְרַחֲמָיו וּבְרוֹב חֲסָדָיו כָּאָמוּר: פּוֹתֵחַ אֶת-יָדֶךָ, וּמַשְׂבִּיעַ לְכָל-חַי רָצוֹן: בָּרוּךְ אַתָּה יהוה, הַזָּן אֶת הַכֹּל.","cond":[]},{"kind":"text","text":"נוֹדֶה לְּךָ יהוה אֱלֹהֵינוּ עַל שֶׁהִנְחַלְתָּ לַאֲבוֹתֵינוּ אֶרֶץ חֶמְדָּה טוֹבָה וּרְחָבָה בְּרִית וְתוֹרָה חַיִּים וּמָזוֹן, עַל שֶׁהוֹצֵאתָנוּ מֵאֶרֶץ מִצְרַיִם וּפְדִיתָנוּ מִבֵּית עֲבָדִים, וְעַל בְּרִיתְךָ שֶׁחָתַמְתָּ בִּבְשָׂרֵנוּ, וְעַל תּוֹרָתְךָ שֶׁלִּמַּדְתָּנוּ, וְעַל חֻקֵּי רְצוֹנָךְ שֶׁהוֹדַעְתָּנוּ, וְעַל חַיִּים וּמָזוֹן שֶׁאַתָּה זָן וּמְפַרְנֵס אוֹתָנוּ.","cond":[]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מַתִּתְיָה בֶן יוֹחָנָן כֹּהֵן גָּדוֹל חַשְׁמוֹנָאי וּבָנָיו, כְּשֶׁעָמְדָה מַלְכוּת יָוָן הָרְשָׁעָה עַל עַמְּךָ יִשְׂרָאֵל לְשַׁכְּחָם תּוֹרָתָךְ וּלְהַעֲבִירָם מֵחֻקֵּי רְצוֹנָךְ, וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים עָמַדְתָּ לָהֶם בְּעֵת צָרָתָם, רַבְתָּ אֶת רִיבָם, דַּנְתָּ אֶת דִּינָם, נָקַמְתָּ אֶת נִקְמָתָם, מָסַרְתָּ גִבּוֹרִים בְּיַד חַלָּשִׁים, וְרַבִּים בְּיַד מְעַטִּים, וּרְשָׁעִים בְּיַד צַדִּיקִים, וּטְמֵאִים בְּיַד טְהוֹרִים, וְזֵדִים בְּיַד עוֹסְקֵי תוֹרָתֶךָ, לְךָ עָשִׂיתָ שֵׁם גָּדוֹל וְקָדוֹשׁ בְּעוֹלָמָךְ, וּלְעַמְּךָ יִשְׂרָאֵל עָשִׂיתָ תְּשׁוּעָה גְדוֹלָה וּפֻרְקָן כְּהַיּוֹם הַזֶּה. וְאַחַר כָּךְ בָּאוּ בָנֶיךָ לִדְבִיר בֵּיתֶךָ, וּפִנּוּ אֶת הֵיכָלֶךָ, וְטִהֲרוּ אֶת מִקְדָּשֶׁךָ, וְהִדְלִיקוּ נֵרוֹת בְּחַצְרוֹת קָדְשֶׁךָ, וְקָבְעוּ שְׁמוֹנַת יְמֵי חֲנֻכָּה אֵלּוּ בְּהַלֵּל גָּמוּר וּבְהוֹדָאָה, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["chanuka"]},{"kind":"special","text":"וְעַל הַנִּסִּים וְעַל הַפֻּרְקָן וְעַל הַגְּבוּרוֹת וְעַל הַתְּשׁוּעוֹת וְעַל הַנִּפְלָאוֹת וְעַל הַנֶּחָמוֹת, שֶׁעָשִׂיתָ לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה, בִּימֵי מָרְדְּכַי וְאֶסְתֵּר בְּשׁוּשַׁן הַבִּירָה, כְּשֶׁעָמַד עֲלֵיהֶם הָמָן הָרָשָׁע, בִּקֵּשׁ לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים, בְּיוֹם אֶחָד, בִּשְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: וְאַתָּה בְּרַחֲמֶיךָ הָרַבִּים הֵפַרְתָּ אֶת עֲצָתוֹ וְקִלְקַלְתָּ אֶת מַחֲשַׁבְתּוֹ וַהֲשֵׁבוֹתָ לוֹ גְמוּלוֹ בְרֹאשׁוֹ, וְתָלוּ אוֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ, וְעָשִׂיתָ עִמָּהֶם נִסִּים וְנִפְלָאוֹת, וְנוֹדֶה לְשִׁמְךָ הַגָּדוֹל, סֶלָה.","cond":["purim"]},{"kind":"text","text":"וְעַל הַכֹּל יהוה אֱלֹהֵינוּ אֲנַחְנוּ מוֹדִים לָךְ וּמְבָרְכִים אֶת שְׁמָךְ כָּאָמוּר: וְאָכַלְתָּ וְשָׂבָעְתָּ, וּבֵרַכְתָּ אֶת-יהוה אֱלֹהֶיךָ עַל-הָאָרֶץ הַטּוֹבָה אֲשֶׁר נָתַן-לָךְ: בָּרוּךְ אַתָּה יהוה, עַל הָאָרֶץ וְעַל הַמָּזוֹן.","cond":[]},{"kind":"text","text":"רַחֵם יהוה אֱלֹהֵינוּ עָלֵינוּ וְעַל יִשְׂרָאֵל עַמָּךְ, וְעַל יְרוּשָׁלַיִם עִירָךְ, וְעַל הַר צִיּוֹן מִשְׁכַּן כְּבוֹדָךְ, וְעַל הֵיכָלָךְ, וְעַל מְעוֹנָךְ, וְעַל דְּבִירָךְ, וְעַל הַבַּיִת הַגָּדוֹל וְהַקָּדוֹשׁ שֶׁנִּקְרָא שִׁמְךָ עָלָיו, אָבִינוּ רְעֵנוּ זוּנֵנוּ, פַּרְנְסֵנוּ, כַּלְכְּלֵנוּ, הַרְוִיחֵנוּ הַרְוַח לָנוּ מְהֵרָה מִכָּל-צָרוֹתֵינוּ, וְנָא אַל תַּצְרִיכֵנוּ יהוה אֱלֹהֵינוּ לִידֵי מַתְּנוֹת בָּשָׂר וָדָם, וְלֹא לִידֵי הַלְוָאָתָם, אֶלָּא לְיָדְךָ הַמְּלֵאָה וְהָרְחָבָה, הָעֲשִׁירָה וְהַפְּתוּחָה. יְהִי רָצוֹן שֶׁלֹּא נֵבוֹשׁ בָּעוֹלָם הַזֶּה, וְלֹא נִכָּלֵם לְעוֹלָם הַבָּא, וּמַלְכוּת בֵּית דָּוִד מְשִׁיחָךְ תַּחֲזִירֶנָּה לִמְקוֹמָהּ בִּמְהֵרָה בְיָמֵינוּ.","cond":[]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["rh"]},{"kind":"special","text":"רֹאשׁ הַחֹדֶשׁ הַזֶּה,","cond":["rh"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["rh"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["pesach"]},{"kind":"special","text":"חַג הַמַּצּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["pesach"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["pesach"]},{"kind":"special","text":"אֱלֹהֵינוּ וֵאלֹהֵי אֲבוֹתֵינוּ, יַעֲלֶה וְיָבוֹא וְיַגִּיעַ, וְיֵרָאֶה וְיֵרָצֶה וְיִשָּׁמַע, וְיִפָּקֵד וְיִזָּכֵר זִכְרוֹנֵנוּ וְזִכְרוֹן אֲבוֹתֵינוּ, זִכְרוֹן יְרוּשָׁלַיִם עִירָךְ, וְזִכְרוֹן מָשִׁיחַ בֶּן דָּוִד עַבְדָּךְ, וְזִכְרוֹן כָּל עַמְּךָ בֵּית יִשְׂרָאֵל, לְפָנֶיךָ, לִפְלֵיטָה לְטוֹבָה, לְחֵן לְחֶסֶד וּלְרַחֲמִים, לְחַיִּים טוֹבִים וּלְשָׁלוֹם בְּיוֹם","cond":["sucot"]},{"kind":"special","text":"חַג הַסֻּכּוֹת הַזֶּה, בְּיוֹם מִקְרָא קֹדֶשׁ הַזֶּה,","cond":["sucot"]},{"kind":"special","text":"לְרַחֵם בּוֹ עָלֵינוּ וּלְהוֹשִׁיעֵנוּ. זָכְרֵנוּ יהוה אֱלֹהֵינוּ בּוֹ לְטוֹבָה, וּפָקְדֵנוּ בוֹ לִבְרָכָה, וְהוֹשִׁיעֵנוּ בוֹ לְחַיִּים טוֹבִים. בִּדְבַר יְשׁוּעָה וְרַחֲמִים חוּס וְחָנֵּנוּ וַחֲמוֹל וְרַחֵם עָלֵינוּ וְהוֹשִׁיעֵנוּ, כִּי אֵלֶיךָ עֵינֵינוּ, כִּי אֵל מֶלֶךְ חַנּוּן וְרַחוּם אָתָּה.","cond":["sucot"]},{"kind":"text","text":"וְתִבְנֶה יְרוּשָׁלַיִם עִירָךְ בִּמְהֵרָה בְיָמֵינוּ. בָּרוּךְ אַתָּה יהוה, בּוֹנֵה יְרוּשָׁלָיִם. (ואומר בלחש: אָמֵן).","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, לָעַד הָאֵל אָבִינוּ מַלְכֵּנוּ אַדִּירֵנוּ, בּוֹרְאֵנוּ, גּוֹאֲלֵנוּ, קְדוֹשֵׁנוּ, קְדוֹשׁ יַעֲקב, רוֹעֵנוּ רוֹעֵה יִשְׂרָאֵל, הַמֶּלֶךְ הַטּוֹב וְהַמֵּטִיב לַכֹּל, שֶׁבְּכָל-יוֹם וָיוֹם הוּא הֵטִיב לָנוּ, הוּא מֵטִיב לָנוּ, הוּא יֵיטִיב לָנוּ, הוּא גְמָלָנוּ, הוּא גוֹמְלֵנוּ, הוּא יִגְמְלֵנוּ לָעַד חֵן וָחֶסֶד וְרַחֲמִים וְרֵיוַח וְהַצָּלָה וְכָל-טוֹב.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יִשְׁתַּבַּח עַל כִּסֵּא כְבוֹדוֹ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בַּשָּׁמַיִם וּבָאָרֶץ.\nהָרַחֲמָן הוּא יִשְׁתַּבַּח בָּנוּ לְדוֹר דּוֹרִים.\nהָרַחֲמָן הוּא קֶרֶן לְעַמּוֹ יָרִים.\nהָרַחֲמָן הוּא יִתְפָּאַר בָּנוּ לָנֶצַח נְצָחִים.\nהָרַחֲמָן הוּא יְפַרְנְסֵנוּ בְּכָבוֹד וְלֹא בְבִזּוּי, בְּהֶתֵּר וְלֹא בְאִסּוּר, בְּנַחַת וְלֹא בְצָעַר.\nהָרַחֲמָן הוּא יִתֵּן שָׁלוֹם בֵּינֵינוּ.\nהָרַחֲמָן הוּא יִשְׁלַח בְּרָכָה רְוָחָה וְהַצְלָחָה בְּכָל-מַעֲשֵׂה יָדֵינוּ.\nהָרַחֲמָן הוּא יַצְלִיחַ אֶת דְּרָכֵינוּ.\nהָרַחֲמָן הוּא יִשְׁבּוֹר עוֹל גָּלוּת מְהֵרָה מֵעַל צַוָּארֵנוּ.\nהָרַחֲמָן הוּא יוֹלִיכֵנוּ מְהֵרָה קוֹמְמִיּוּת בְּאַרְצֵנוּ.\nהָרַחֲמָן הוּא יִרְפָּאֵנוּ רְפוּאָה שְׁלֵמָה רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף.\nהָרַחֲמָן הוּא יִפְתַּח לָנוּ אֶת יָדוֹ הָרְחָבָה.\nהָרַחֲמָן הוּא יְבָרֵךְ כָּל אֶחָד וְאֶחָד מִמֶּנּוּ בִּשְׁמוֹ הַגָּדוֹל כְּמוֹ שֶׁנִּתְבָּרְכוּ אֲבוֹתֵינוּ אַבְרָהָם יִצְחָק וְיַעֲקב בַּכֹּל, מִכֹּל, כֹּל, כֵּן יְבָרֵךְ אוֹתָנוּ יַחַד בְּרָכָה שְׁלֵמָה, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן.\nהָרַחֲמָן הוּא יִפְרוֹשׂ עָלֵינוּ סֻכַּת שְׁלוֹמוֹ.","cond":[]},{"kind":"special","text":"הָרַחֲמָן הוּא יְחַדֵּשׁ עָלֵינוּ אֶת הַחֹדֶשׁ הַזֶּה לְטוֹבָה וְלִבְרָכָה.","cond":["rh"]},{"kind":"special","text":"הָרַחֲמָן הוּא יְזַכֵּנוּ לֵישֵׁב בְּסֻכַּת עוֹרוֹ שֶׁל לִוְיָתָן.\nהָרַחֲמָן הוּא יַשְׁפִּיעַ עָלֵינוּ שֶׁפַע קְדֻשָּׁה וְטָהֳרָה מִשִּׁבְעָה אֻשְׁפִּיזִין עִלָּאִין קַדִּישִׁין, זְכוּתָם תְּהֵא מָגֵן וְצִנָּה עָלֵינוּ.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יָקִים לָנוּ אֶת סֻכַּת דָוִיד הַנּוֹפֶלֶת.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["sucot"]},{"kind":"special","text":"הָרַחֲמָן הוּא יַגִּיעֵנוּ לְמוֹעֲדִים אֲחֵרִים הַבָּאִים לִקְרָאתֵנוּ לְשָׁלוֹם.","cond":["pesach"]},{"kind":"text","text":"הָרַחֲמָן הוּא יִטַּע תּוֹרָתוֹ וְאַהֲבָתוֹ בְּלִבֵּנוּ וְתִהְיֶה יִרְאָתוֹ עַל פָּנֵינוּ לְבִלְתִּי נֶחֱטָא, וְיִהְיוּ כָל-מַעֲשֵׂינוּ לְשֵׁם שָׁמָיִם.","cond":[]},{"kind":"instruction","text":"ברכת האורח:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת הַשֻּׁלְחָן הַזֶּה שֶׁאָכַלְנוּ עָלָיו וִיסַדֵּר בּוֹ כָּל מַעֲדַנֵּי עוֹלָם וְיִהְיֶה כְּשֻׁלְחָנוֹ שֶׁל אַבְרָהָם אָבִינוּ (עָלָיו הַשָּׁלוֹם), כָּל רָעֵב מִמֶּנּוּ יֹאכַל, וְכָל צָמֵא מִמֶּנּוּ יִשְׁתֶּה, וְאַל יֶחְסַר מִמֶּנּוּ כָּל טוּב לָעַד וּלְעוֹלְמֵי עוֹלָמִים. הָרַחֲמָן הוּא יְבָרֵךְ אֶת בַּעַל הַבַּיִת הַזֶּה וּבַעַל הַסְּעֻדָּה הַזּאת, הוּא וּבָנָיו וְאִשְׁתּוֹ וְכָל אֲשֶׁר לוֹ, בְּבָנִים שֶׁיִּחְיוּ, וּבִנְכָסִים שֶׁיִּרְבּוּ, בָּרֵךְ יהוה חֵילוֹ וּפֹעַל יָדָיו תִּרְצֶה, וְיִהְיוּ נְכָסָיו וּנְכָסֵינוּ מֻצְלָחִים וּקְרוֹבִים לָעִיר, וְאַל יִזְדַּקֵּק לְפָנָיו וְלֹא לְפָנֵינוּ שׁוּם דְּבַר חֵטְא וְהִרְהוּר עָוׂן. שָׂשׂ וְשָׂמֵחַ כָּל הַיָּמִים בְּעֹשֶׁר וְכָבוֹד מֵעַתָּה וְעַד עוֹלָם, לֹא יֵבוֹשׁ בָּעוֹלָם הַזֶּה וְלֹא יִכָּלֵם לָעוֹלָם הַבָּא, אָמֵן כֵּן יְהִי רָצוֹן.","cond":[]},{"kind":"instruction","text":"הרחמן לסעודת ברית מילה:","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְבָרֵךְ אֶת בַּעַל הַבַּיִת הַזֶּה אֲבִי הַבֵּן, הוּא וְאִשְׁתּוֹ הַיּוֹלֶדֶת, מֵעַתָּה וְעַד עוֹלָם.\nהָרַחֲמָן הוּא יְבָרֵךְ אֶת הַיֶּלֶד הַנּוֹלָד, וּכְשֵׁם שֶׁזִּכָּהוּ הַקָּדוֹשׁ בָּרוּךְ הוּא לְמִילָה, כָּךְ יְזַכֵּהוּ לְהִכָּנֵס לַתּוֹרָה וּלְחֻפָּה, וּלְמִצְוׂת וּלְמַעֲשִׂים טוֹבִים, וְכֵן יְהִי רָצוֹן וְנֹאמַר אָמֵן.\nהָרַחֲמָן הוּא יְבָרֵךְ אֶת מַעֲלַת הַסַּנְדָּק וְהַמּוֹהֵל וּשְׁאָר הַמִּשְׁתַּדְּלִים בַּמִּצְוָה, הֵם וְכָל-אֲשֶׁר-לָהֶם.","cond":[]},{"kind":"text","text":"הָרַחֲמָן הוּא יְחַיֵּינוּ וִיזַכֵּנוּ וִיקָרְבֵנוּ לִימוֹת הַמָּשִׁיחַ וּלְבִנְיַן בֵּית הַמִּקְדָּשׁ וּלְחַיֵּי הָעוֹלָם הַבָּא.","cond":[]},{"kind":"text","text":"מַגְדִּל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["magdil"]},{"kind":"special","text":"מִגְדּוֹל יְשׁוּעוֹת מַלְכּוֹ וְעֹשֶׂה חֶסֶד לִמְשִׁיחוֹ, לְדָוִד וּלְזַרְעוֹ עַד עוֹלָם:","cond":["migdol"]},{"kind":"text","text":"כְּפִירִים רָשׁוּ וְרָעֵבוּ, וְדרְשֵׁי יהוה לֹא-יַחְסְרוּ כָל-טוֹב: נַעַר הָיִיתִי גַּם-זָקַנְתִּי וְלֹא-רָאִיתִי צַדִּיק נֶעֱזָב, וְזַרְעוֹ מְבַקֶּשׁ-לָחֶם: כָּל-הַיּוֹם חוֹנֵן וּמַלְוֶה, וְזַרְעוֹ לִבְרָכָה: מַה שֶּׁאָכַלְנוּ יִהְיֶה לְשָׂבְעָה, וּמַה שֶּׁשָּׁתִינוּ יִהְיֶה לִרְפוּאָה, וּמַה שֶּׁהוֹתַרְנוּ יִהְיֶה לִבְרָכָה, כְּדִכְתִיב: וַיִּתֵּן לִפְנֵיהֶם וַיֹּאכְלוּ וַיּוֹתִירוּ כִּדְבַר יהוה: בְּרוּכִים אַתֶּם לַיהוה, עוֹשֵׂה שָׁמַיִם וָאָרֶץ: בָּרוּךְ הַגֶּבֶר אֲשֶׁר יִבְטַח בַּיהוה, וְהָיָה יהוה מִבְטָחוֹ: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת-עַמּוֹ בַשָּׁלוֹם:","cond":[]},{"kind":"text","text":"עֹשֶׂה שָׁלוֹם בִּמְרוֹמָיו, הוּא בְרַחֲמָיו יַעֲשֶׂה שָׁלוֹם עָלֵינוּ וְעַל כָּל-עַמּוֹ יִשְׂרָאֵל, וְאִמְרוּ אָמֵן.","cond":[]}]}},{"id":"megillat_esther","title":"מגילת אסתר","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"header","text":"מגילת אסתר","cond":[]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה שלוש ברכות גם בלילה וגם ביום. לדעת השו\"ע מברכים שהחיינו רק בלילה (ואם לא קרא בלילה יברך ביום). בברכת שהחיינו ביום יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה. הנוהגים כדעת השו\"ע יכוונו על זה בלילה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":[]},{"kind":"header","text":"פרק א'","cond":[]},{"kind":"instruction","text":"פרק א'","cond":[]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":[]},{"kind":"header","text":"פרק ב'","cond":[]},{"kind":"instruction","text":"פרק ב'","cond":[]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":[]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":[]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":[]},{"kind":"header","text":"פרק ג'","cond":[]},{"kind":"instruction","text":"פרק ג'","cond":[]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":[]},{"kind":"header","text":"פרק ד'","cond":[]},{"kind":"instruction","text":"פרק ד'","cond":[]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":[]},{"kind":"header","text":"פרק ה'","cond":[]},{"kind":"instruction","text":"פרק ה'","cond":[]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":[]},{"kind":"header","text":"פרק ו'","cond":[]},{"kind":"instruction","text":"פרק ו'","cond":[]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":[]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":[]},{"kind":"header","text":"פרק ז'","cond":[]},{"kind":"instruction","text":"פרק ז'","cond":[]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":[]},{"kind":"header","text":"פרק ח'","cond":[]},{"kind":"instruction","text":"פרק ח'","cond":[]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":[]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":[]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":[]},{"kind":"header","text":"פרק ט'","cond":[]},{"kind":"instruction","text":"פרק ט'","cond":[]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":[]},{"kind":"header","text":"פרק י'","cond":[]},{"kind":"instruction","text":"פרק י'","cond":[]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":[]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":[]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":[]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.","cond":[]},{"kind":"header","text":"אשר הניא","cond":[]},{"kind":"instruction","text":"אשר הניא\n\nבשחרית מתחילים משושנת יעקב. ויש נוהגים לומר \"אשר הניא\" אף בשחרית, אם אין אומרים פיוטים בחזרת הש\"ץ.","cond":[]},{"kind":"text","text":"אֲשֶׁר הֵנִיא עֲצַת גּוֹיִם, וַיָּפֶר מַחְשְׁבוֹת עֲרוּמִים.\nבְּקוּם עָלֵינוּ אָדָם רָשָׁע, נֵצֶר זָדוֹן מִזֶּרַע עֲמָלֵק.\nגָּאָה בְעָשְׁרוֹ וְכָרָה לוֹ בּוֹר, וּגְדֻלָּתוֹ יָקְשָׁה לּוֹ לָכֶד.\nדִּמָּה בְנַפְשׁוֹ לִלְכֹּד וְנִלְכַּד, בִּקֵּשׁ לְהַשְׁמִיד וְנִשְׁמַד מְהֵרָה.\nהָמָן הוֹדִיעַ אֵיבַת אֲבוֹתָיו, וְעוֹרֵר שִׂנְאַת אַחִים לַבָּנִים.\nוְלֹא זָכַר רַחֲמֵי שָׁאוּל, כִּי בְחֶמְלָתוֹ עַל אֲגָג נוֹלַד אוֹיֵב.\nזָמַם רָשָׁע לְהַכְרִית צַדִּיק, וְנִלְכַּד טָמֵא בִּידֵי טָהוֹר.\nחֶסֶד גָּבַר עַל שִׁגְגַת אָב, וְרָשָׁע הוֹסִיף חֵטְא עַל חֲטָאָיו.\nטָמַן בְּלִבּוֹ מַחְשְׁבוֹת עֲרוּמָיו, וַיִּתְמַכֵּר לַעֲשׂוֹת רָעָה.\nיָדוֹ שָׁלַח בִּקְדוֹשֵׁי אֵל, כַּסְפּוֹ נָתַן לְהַכְרִית זִכְרָם.\nכִּרְאוֹת מָרְדֳּכַי כִּי יָצָא קֶצֶף, וְדָתֵי הָמָן נִתְּנוּ בְשׁוּשָׁן.\nלָבַשׁ שַׂק וְקָשַׁר מִסְפֵּד, וְגָזַר צוֹם וַיֵּשֶׁב עַל הָאֵפֶר.\nמִי זֶה יַעֲמֹד לְכַפֵּר שְׁגָגָה, וְלִמְחֹל חַטַּאת עֲוׂן אֲבוֹתֵינוּ.\nנֵץ פָּרַח מִלּוּלָב, הֵן הֲדַסָּה עָמְדָה לְעוֹרֵר יְשֵׁנִים.\nסָרִיסֶיהָ הִבְהִילוּ לְהָמָן, לְהַשְׁקוֹתוֹ יֵין חֲמַת תַּנִּינִים.\nעָמַד בְּעָשְׁרוֹ וְנָפַל בְּרִשְׁעוֹ, עָשָׂה לוֹ עֵץ וְנִתְלָה עָלָיו.\nפִּיהֶם פָּתְחוּ כָָּל יוֹשְׁבֵי תֵבֵל, כִּי פוּר הָמָן נֶהְפַּךְ לְפוּרֵנוּ.\nצַדִּיק נֶחֱלַץ מִיַּד רָשָׁע, אוֹיֵב נִתַּן תַּחַת נַפְשׁוֹ.\nקִיְּמוּ עֲלֵיהֶם לַעֲשׂוֹת פּוּרִים, וְלִשְׂמֹחַ בְּכָל שָׁנָה וְשָׁנָה.\nרָאִיתָ אֶת תְּפִלַּת מָרְדֳּכַי וְאֶסְתֵּר, הָמָן וּבָנָיו עַל הָעֵץ תָּלִיתָ.","cond":[]},{"kind":"header","text":"שושנת יעקב","cond":[]},{"kind":"text","text":"שׁוֹשַׁנַּת יַעֲקֹב צָהֲלָה וְשָׂמֵחָה, בִּרְאוֹתָם יַחַד תְּכֵלֶת מָרְדֳּכָי.\nתְּשׁוּעָתָם הָיִיתָ לָנֶצַח, וְתִקְוָתָם בְּכָל דּוֹר וָדוֹר.\nלְהוֹדִיעַ שֶׁכָּל קֹוֶיךָ לֹא יֵבֹשׁוּ, וְלֹא יִכָּלְמוּ לָנֶצַח כָּל הַחוֹסִים בָּךְ.\nאָרוּר הָמָן אֲשֶׁר בִּקֵשׁ לְאַבְּדִי. בָּרוּךְ מָרְדֳּכַי הַיְּהוּדִי.\nאֲרוּרָה זֶרֶשׁ אֵשֶׁת מַפְחִידִי. בְּרוּכָה אֶסְתֵּר [מְגִנָּה] בַּעֲדִי.\nאֲרוּרִים כָּל הָרְשָׁעִים. בְּרוּכִים כָּל הַצַּדִּיקִים.\nוְגַם חַרְבוֹנָה זָכוּר לַטּוֹב.","cond":[]}],"edot_mizrach":[{"kind":"header","text":"מגילת אסתר","cond":[]},{"kind":"instruction","text":"הקורא את המגילה מברך לפניה. בברכת שהחיינו יכוון גם על שאר מצוות היום: מתנות לאביונים, משלוח מנות ומשתה ושמחה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, אֲשֶׁר קִדְּשָׁנוּ בְּמִצְוׂתָיו, וְצִוָּנוּ עַל מִקְרָא מְגִלָּה.\nבָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁעָשָׂה נִסִּים לַאֲבוֹתֵינוּ בַּיָּמִים הָהֵם בַּזְּמַן הַזֶּה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַָתָּה יהוה אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, שֶׁהֶחֱיָנוּ וְקִיְּמָנוּ וְהִגִּיעָנוּ לַזְּמַן הַזֶּה.","cond":[]},{"kind":"header","text":"פרק א'","cond":[]},{"kind":"instruction","text":"פרק א'","cond":[]},{"kind":"text","text":"וַיְהִי בִּימֵי אֲחַשְׁוֵרוֹשׁ, הוּא אֲחַשְׁוֵרוֹשׁ הַמֹּלֵךְ מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה: בַּיָּמִים הָהֵם, כְּשֶׁבֶת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ עַל כִּסֵּא מַלְכוּתוֹ אֲשֶׁר בְּשׁוּשַׁן הַבִּירָה: בִּשְׁנַת שָׁלוֹשׁ לְמָלְכוֹ עָשָׂה מִשְׁתֶּה לְכָל שָׂרָיו וַעֲבָדָיו, חֵיל פָּרַס וּמָדַי הַפַּרְתְּמִים וְשָׂרֵי הַמְּדִינוֹת לְפָנָיו: בְּהַרְאֹתוֹ אֶת עֹשֶׁר כְּבוֹד מַלְכוּתוֹ וְאֶת יְקָר תִּפְאֶרֶת גְּדוּלָּתוֹ, יָמִים רַבִּים שְׁמוֹנִים וּמְאַת יוֹם: וּבִמְלוֹאת הַיָּמִים הָאֵלֶּה עָשָׂה הַמֶּלֶךְ לְכָל הָעָם הַנִּמְצְאִים בְּשׁוּשַׁן הַבִּירָה לְמִגָּדוֹל וְעַד קָטָן מִשְׁתֶּה שִׁבְעַת יָמִים, בַּחֲצַר גִּנַּת בִּיתַן הַמֶּלֶךְ: חוּר כַּרְפַּס וּתְכֵלֶת אָחוּז בְּחַבְלֵי בוּץ וְאַרְגָּמָן עַל גְּלִילֵי כֶסֶף וְעַמּוּדֵי שֵׁשׁ, מִטּוֹת זָהָב וָכֶסֶף עַל רִצְפַת בַּהַט וָשֵׁשׁ וְדַר וְסֹחָרֶת: וְהַשְׁקוֹת בִּכְלֵי זָהָב וְכֵלִים מִכֵּלִים שׁוֹנִים, וְיֵין מַלְכוּת רָב כְּיַד הַמֶּלֶךְ: וְהַשְּׁתִיָּה כַדָּת אֵין אֹנֵס, כִּי כֵן יִסַּד הַמֶּלֶךְ עַל כָּל רַב בֵּיתוֹ לַעֲשׂוֹת כִּרְצוֹן אִישׁ וָאִישׁ: גַּם וַשְׁתִּי הַמַּלְכָּה עָשְׂתָה מִשְׁתֵּה נָשִׁים, בֵּית הַמַּלְכוּת אֲשֶׁר לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: בַּיּוֹם הַשְּׁבִיעִי כְּטוֹב לֵב הַמֶּלֶךְ בַּיָּיִן, אָמַר לִמְהוּמָן בִּזְּתָא חַרְבוֹנָא בִּגְתָא וַאֲבַגְתָא זֵתַר וְכַרְכַּס שִׁבְעַת הַסָּרִיסִים הַמְשָׁרְתִים אֶת פְּנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לִפְנֵי הַמֶּלֶךְ בְּכֶתֶר מַלְכוּת, לְהַרְאוֹת הָעַמִּים וְהַשָּׂרִים אֶת יָפְיָהּ, כִּי טוֹבַת מַרְאֶה הִיא: וַתְּמָאֵן הַמַּלְכָּה וַשְׁתִּי לָבוֹא בִּדְבַר הַמֶּלֶךְ אֲשֶׁר בְּיַד הַסָּרִיסִים, וַיִּקְצֹף הַמֶּלֶךְ מְאֹד וַחֲמָתוֹ בָּעֲרָה בוֹ: וַיֹּאמֶר הַמֶּלֶךְ לַחֲכָמִים יֹדְעֵי הָעִתִּים, כִּי כֵן דְּבַר הַמֶּלֶךְ לִפְנֵי כָּל יֹדְעֵי דָּת וָדִין: וְהַקָּרֹב אֵלָיו כַּרְשְׁנָא שֵׁתָר אַדְמָתָא תַרְשִׁישׁ מֶרֶס מַרְסְנָא מְמוּכָן, שִׁבְעַת שָׂרֵי פָּרַס וּמָדַי רֹאֵי פְּנֵי הַמֶּלֶךְ הַיֹּשְׁבִים רִאשֹׁנָה בַּמַּלְכוּת: כְּדָת מַה לַּעֲשׂוֹת בַּמַּלְכָּה וַשְׁתִּי, עַל אֲשֶׁר לֹא עָשְׂתָה אֶת מַאֲמַר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ בְּיַד הַסָּרִיסִים: וַיֹּאמֶר מְמוּכָן לִפְנֵי הַמֶּלֶךְ וְהַשָּׂרִים, לֹא עַל הַמֶּלֶךְ לְבַדּוֹ עָוְתָה וַשְׁתִּי הַמַּלְכָּה, כִּי עַל כָּל הַשָּׂרִים וְעַל כָּל הָעַמִּים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: כִּי יֵצֵא דְבַר הַמַּלְכָּה עַל כָּל הַנָּשִׁים לְהַבְזוֹת בַּעְלֵיהֶן בְּעֵינֵיהֶן, בְּאָמְרָם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אָמַר לְהָבִיא אֶת וַשְׁתִּי הַמַּלְכָּה לְפָנָיו וְלֹא בָאָה: וְהַיּוֹם הַזֶּה תֹּאמַרְנָה שָׂרוֹת פָּרַס וּמָדַי אֲשֶׁר שָׁמְעוּ אֶת דְּבַר הַמַּלְכָּה לְכֹל שָׂרֵי הַמֶּלֶךְ, וּכְדַי בִּזָּיוֹן וָקָצֶף: אִם עַל הַמֶּלֶךְ טוֹב יֵצֵא דְבַר מַלְכוּת מִלְּפָנָיו וְיִכָּתֵב בְּדָתֵי פָרַס וּמָדַי וְלֹא יַעֲבוֹר, אֲשֶׁר לֹא תָבוֹא וַשְׁתִּי לִפְנֵי הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וּמַלְכוּתָהּ יִתֵּן הַמֶּלֶךְ לִרְעוּתָהּ הַטּוֹבָה מִמֶּנָּה: וְנִשְׁמַע פִּתְגָם הַמֶּלֶךְ אֲשֶׁר יַעֲשֶׂה בְּכָל מַלְכוּתוֹ כִּי רַבָּה הִיא, וְכָל הַנָּשִׁים יִתְּנוּ יְקָר לְבַעְלֵיהֶן לְמִגָּדוֹל וְעַד קָטָן: וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וְהַשָּׂרִים, וַיַּעַשׂ הַמֶּלֶךְ כִּדְבַר מְמוּכָן: וַיִּשְׁלַח סְפָרִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, אֶל מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְאֶל עַם וָעָם כִּלְשׁוֹנוֹ, לִהְיוֹת כָּל אִישׁ שֹׂרֵר בְּבֵיתוֹ וּמְדַבֵּר כִּלְשׁוֹן עַמּוֹ:","cond":[]},{"kind":"header","text":"פרק ב'","cond":[]},{"kind":"instruction","text":"פרק ב'","cond":[]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה כְּשֹׁךְ חֲמַת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, זָכַר אֶת וַשְׁתִּי וְאֵת אֲשֶׁר עָשָׂתָה וְאֵת אֲשֶׁר נִגְזַר עָלֶיהָ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו, יְבַקְשׁוּ לַמֶּלֶךְ נְעָרוֹת בְּתוּלוֹת טוֹבוֹת מַרְאֶה: וְיַפְקֵד הַמֶּלֶךְ פְּקִידִים בְּכָל מְדִינוֹת מַלְכוּתוֹ, וְיִקְבְּצוּ אֶת כָּל נַעֲרָה בְתוּלָה טוֹבַת מַרְאֶה אֶל שׁוּשַׁן הַבִּירָה אֶל בֵּית הַנָּשִׁים אֶל יַד הֵגֶא סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וְנָתוֹן תַּמְרוּקֵיהֶן: וְהַנַּעֲרָה אֲשֶׁר תִּיטַב בְּעֵינֵי הַמֶּלֶךְ תִּמְלֹךְ תַּחַת וַשְׁתִּי, וַיִּיטַב הַדָּבָר בְּעֵינֵי הַמֶּלֶךְ וַיַּעַשׂ כֵּן:","cond":[]},{"kind":"special","text":"אִישׁ יְהוּדִי הָיָה בְּשׁוּשַׁן הַבִּירָה, וּשְׁמוֹ מָרְדֳּכַי בֶּן יָאִיר בֶּן שִׁמְעִי בֶּן קִישׁ אִישׁ יְמִינִי:","cond":[]},{"kind":"text","text":"אֲשֶׁר הָגְלָה מִירוּשָׁלַיִם עִם הַגֹּלָה אֲשֶׁר הָגְלְתָה עִם יְכָנְיָה מֶלֶךְ יְהוּדָה, אֲשֶׁר הֶגְלָה נְבוּכַדְנֶאצַּר מֶלֶךְ בָּבֶל: וַיְהִי אֹמֵן אֶת הֲדַסָּה הִיא אֶסְתֵּר בַּת דֹּדוֹ כִּי אֵין לָהּ אָב וָאֵם, וְהַנַּעֲרָה יְפַת תֹּאַר וְטוֹבַת מַרְאֶה וּבְמוֹת אָבִיהָ וְאִמָּהּ לְקָחָהּ מָרְדֳּכַי לוֹ לְבַת: וַיְהִי בְּהִשָּׁמַע דְּבַר הַמֶּלֶךְ וְדָתוֹ, וּבְהִקָּבֵץ נְעָרוֹת רַבּוֹת אֶל שׁוּשַׁן הַבִּירָה אֶל יַד הֵגָי, וַתִּלָּקַח אֶסְתֵּר אֶל בֵּית הַמֶּלֶךְ אֶל יַד הֵגַי שֹׁמֵר הַנָּשִׁים: וַתִּיטַב הַנַּעֲרָה בְעֵינָיו וַתִּשָּׂא חֶסֶד לְפָנָיו, וַיְבַהֵל אֶת תַּמְרוּקֶיהָ וְאֶת מָנוֹתֶהָ לָתֵת לָהּ, וְאֵת שֶׁבַע הַנְּעָרוֹת הָרְאֻיוֹת לָתֶת לָהּ מִבֵּית הַמֶּלֶךְ, וַיְשַׁנֶּהָ וְאֶת נַעֲרוֹתֶיהָ לְטוֹב בֵּית הַנָּשִׁים: לֹא הִגִּידָה אֶסְתֵּר אֶת עַמָּהּ וְאֶת מוֹלַדְתָּהּ, כִּי מָרְדֳּכַי צִוָּה עָלֶיהָ אֲשֶׁר לֹא תַגִּיד: וּבְכָל יוֹם וָיוֹם מָרְדֳּכַי מִתְהַלֵּךְ לִפְנֵי חֲצַר בֵּית הַנָּשִׁים, לָדַעַת אֶת שְׁלוֹם אֶסְתֵּר וּמַה יֵּעָשֶׂה בָּהּ: וּבְהַגִּיעַ תֹּר נַעֲרָה וְנַעֲרָה לָבוֹא אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, מִקֵּץ הֱיוֹת לָהּ כְּדָת הַנָּשִׁים שְׁנֵים עָשָׂר חֹדֶשׁ כִּי כֵּן יִמְלְאוּ יְמֵי מְרוּקֵיהֶן, שִׁשָּׁה חֳדָשִׁים בְּשֶׁמֶן הַמֹּר וְשִׁשָּׁה חֳדָשִׁים בַּבְּשָׂמִים וּבְתַמְרוּקֵי הַנָּשִׁים: וּבָזֶה הַנַּעֲרָה בָּאָה אֶל הַמֶּלֶךְ, אֵת כָּל אֲשֶׁר תֹּאמַר יִנָּתֵן לָהּ לָבוֹא עִמָּהּ מִבֵּית הַנָּשִׁים עַד בֵּית הַמֶּלֶךְ: בָּעֶרֶב הִיא בָאָה וּבַבֹּקֶר הִיא שָׁבָה אֶל בֵּית הַנָּשִׁים שֵׁנִי, אֶל יַד שַׁעֲשְׁגַז סְרִיס הַמֶּלֶךְ שֹׁמֵר הַפִּילַגְשִׁים, לֹא תָבוֹא עוֹד אֶל הַמֶּלֶךְ כִּי אִם חָפֵץ בָּהּ הַמֶּלֶךְ וְנִקְרְאָה בְשֵׁם: וּבְהַגִּיעַ תֹּר אֶסְתֵּר בַּת אֲבִיחַיִל דֹּד מָרְדֳּכַי אֲשֶׁר לָקַח לוֹ לְבַת לָבוֹא אֶל הַמֶּלֶךְ, לֹא בִקְשָׁה דָּבָר כִּי אִם אֶת אֲשֶׁר יֹאמַר הֵגַי סְרִיס הַמֶּלֶךְ שֹׁמֵר הַנָּשִׁים, וַתְּהִי אֶסְתֵּר נֹשֵׂאת חֵן בְּעֵינֵי כָּל רֹאֶיהָ: וַתִּלָּקַח אֶסְתֵּר אֶל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶל בֵּית מַלְכוּתוֹ בַּחֹדֶשׁ הָעֲשִׂירִי הוּא חֹדֶשׁ טֵבֵת, בִּשְׁנַת שֶׁבַע לְמַלְכוּתוֹ: וַיֶּאֱהַב הַמֶּלֶךְ אֶת אֶסְתֵּר מִכָּל הַנָּשִׁים וַתִּשָּׂא חֵן וָחֶסֶד לְפָנָיו מִכָּל הַבְּתוּלֹת, וַיָּשֶׂם כֶּתֶר מַלְכוּת בְּרֹאשָׁהּ וַיַּמְלִיכֶהָ תַּחַת וַשְׁתִּי: וַיַּעַשׂ הַמֶּלֶךְ מִשְׁתֶּה גָדוֹל לְכָל שָׂרָיו וַעֲבָדָיו, אֵת מִשְׁתֵּה אֶסְתֵּר, וַהֲנָחָה לַמְּדִינוֹת עָשָׂה וַיִּתֵּן מַשְׂאֵת כְּיַד הַמֶּלֶךְ: וּבְהִקָּבֵץ בְּתוּלוֹת שֵׁנִית, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: אֵין אֶסְתֵּר מַגֶּדֶת מוֹלַדְתָּהּ וְאֶת עַמָּהּ כַּאֲשֶׁר צִוָּה עָלֶיהָ מָרְדֳּכַי, וְאֶת מַאֲמַר מָרְדֳּכַי אֶסְתֵּר עֹשָׂה כַּאֲשֶׁר הָיְתָה בְאָמְנָה אִתּוֹ: בַּיָּמִים הָהֵם, וּמָרְדֳּכַי יֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, קָצַף בִּגְתָן וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף וַיְבַקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרֹשׁ: וַיִּוָּדַע הַדָּבָר לְמָרְדֳּכַי וַיַּגֵּד לְאֶסְתֵּר הַמַּלְכָּה, וַתֹּאמֶר אֶסְתֵּר לַמֶּלֶךְ בְּשֵׁם מָרְדֳּכַי: וַיְבֻקַּשׁ הַדָּבָר וַיִּמָּצֵא וַיִּתָּלוּ שְׁנֵיהֶם עַל עֵץ, וַיִּכָּתֵב בְּסֵפֶר דִּבְרֵי הַיָּמִים לִפְנֵי הַמֶּלֶךְ:","cond":[]},{"kind":"header","text":"פרק ג'","cond":[]},{"kind":"instruction","text":"פרק ג'","cond":[]},{"kind":"text","text":"אַחַר הַדְּבָרִים הָאֵלֶּה גִּדַּל הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ אֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי וַיְנַשְּׂאֵהוּ, וַיָּשֶׂם אֶת כִּסְאוֹ מֵעַל כָּל הַשָּׂרִים אֲשֶׁר אִתּוֹ: וְכָל עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ כֹּרְעִים וּמִשְׁתַּחֲוִים לְהָמָן, כִּי כֵן צִוָּה לוֹ הַמֶּלֶךְ, וּמָרְדֳּכַי לֹא יִכְרַע וְלֹא יִשְׁתַּחֲוֶה: וַיֹּאמְרוּ עַבְדֵי הַמֶּלֶךְ אֲשֶׁר בְּשַׁעַר הַמֶּלֶךְ לְמָרְדֳּכַי, מַדּוּעַ אַתָּה עוֹבֵר אֵת מִצְוַת הַמֶּלֶךְ: וַיְהִי כְּאָמְרָם אֵלָיו יוֹם וָיוֹם וְלֹא שָׁמַע אֲלֵיהֶם, וַיַּגִּידוּ לְהָמָן לִרְאוֹת הֲיַעַמְדוּ דִּבְרֵי מָרְדֳּכַי כִּי הִגִּיד לָהֶם אֲשֶׁר הוּא יְהוּדִי: וַיַּרְא הָמָן כִּי אֵין מָרְדֳּכַי כֹּרֵעַ וּמִשְׁתַּחֲוֶה לוֹ, וַיִּמָּלֵא הָמָן חֵמָה: וַיִּבֶז בְּעֵינָיו לִשְׁלֹח יָד בְּמָרְדֳּכַי לְבַדּוֹ כִּי הִגִּידוּ לוֹ אֶת עַם מָרְדֳּכַי, וַיְבַקֵּשׁ הָמָן לְהַשְׁמִיד אֶת כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מַלְכוּת אֲחַשְׁוֵרוֹשׁ עַם מָרְדֳּכַי: בַּחֹדֶשׁ הָרִאשׁוֹן הוּא חֹדֶשׁ נִיסָן בִּשְׁנַת שְׁתֵּים עֶשְׂרֵה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, הִפִּיל פּוּר הוּא הַגּוֹרָל לִפְנֵי הָמָן מִיּוֹם לְיוֹם וּמֵחֹדֶשׁ לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: וַיֹּאמֶר הָמָן לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ יֶשְׁנוֹ עַם אֶחָד מְפֻזָּר וּמְפֹרָד בֵּין הָעַמִּים בְּכֹל מְדִינוֹת מַלְכוּתֶךָ, וְדָתֵיהֶם שֹׁנוֹת מִכָּל עָם וְאֶת דָּתֵי הַמֶּלֶךְ אֵינָם עֹשִׂים וְלַמֶּלֶךְ אֵין שֹׁוֶה לְהַנִּיחָם: אִם עַל הַמֶּלֶךְ טוֹב יִכָּתֵב לְאַבְּדָם, וַעֲשֶׂרֶת אֲלָפִים כִּכַּר כֶּסֶף אֶשְׁקוֹל עַל יְדֵי עֹשֵׂי הַמְּלָאכָה לְהָבִיא אֶל גִּנְזֵי הַמֶּלֶךְ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ מֵעַל יָדוֹ, וַיִּתְּנָהּ לְהָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר הַיְּהוּדִים: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן הַכֶּסֶף נָתוּן לָךְ, וְהָעָם לַעֲשׂוֹת בּוֹ כַּטּוֹב בְּעֵינֶיךָ: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בַּחֹדֶשׁ הָרִאשׁוֹן בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה הָמָן אֶל אֲחַשְׁדַּרְפְּנֵי הַמֶּלֶךְ וְאֶל הַפַּחוֹת אֲשֶׁר עַל מְדִינָה וּמְדִינָה וְאֶל שָׂרֵי עַם וָעָם, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשׁוֹנוֹ, בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ נִכְתָּב וְנֶחְתָּם בְּטַבַּעַת הַמֶּלֶךְ: וְנִשְׁלוֹחַ סְפָרִים בְּיַד הָרָצִים אֶל כָּל מְדִינוֹת הַמֶּלֶךְ, לְהַשְׁמִיד לַהֲרֹג וּלְאַבֵּד אֶת כָּל הַיְּהוּדִים מִנַּעַר וְעַד זָקֵן טַף וְנָשִׁים בְּיוֹם אֶחָד, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר, וּשְׁלָלָם לָבוֹז: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, לִהְיוֹת עֲתִדִים לַיּוֹם הַזֶּה: הָרָצִים יָצְאוּ דְחוּפִים בִּדְבַר הַמֶּלֶךְ וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה, וְהַמֶּלֶךְ וְהָמָן יָשְׁבוּ לִשְׁתּוֹת וְהָעִיר שׁוּשָׁן נָבוֹכָה:","cond":[]},{"kind":"header","text":"פרק ד'","cond":[]},{"kind":"instruction","text":"פרק ד'","cond":[]},{"kind":"text","text":"וּמָרְדֳּכַי יָדַע אֶת כָּל אֲשֶׁר נַעֲשָׂה וַיִּקְרַע מָרְדֳּכַי אֶת בְּגָדָיו וַיִּלְבַּשׁ שַׂק וָאֵפֶר, וַיֵּצֵא בְּתוֹךְ הָעִיר וַיִּזְעַק זְעָקָה גְדֹלָה וּמָרָה: וַיָּבוֹא עַד לִפְנֵי שַׁעַר הַמֶּלֶךְ, כִּי אֵין לָבוֹא אֶל שַׁעַר הַמֶּלֶךְ בִּלְבוּשׁ שָׂק: וּבְכָל מְדִינָה וּמְדִינָה מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, אֵבֶל גָּדוֹל לַיְּהוּדִים וְצוֹם וּבְכִי וּמִסְפֵּד, שַׂק וָאֵפֶר יֻצַּע לָרַבִּים: וַתָּבוֹאנָה נַעֲרוֹת אֶסְתֵּר וְסָרִיסֶיהָ וַיַּגִּידוּ לָהּ וַתִּתְחַלְחַל הַמַּלְכָּה מְאֹד, וַתִּשְׁלַח בְּגָדִים לְהַלְבִּישׁ אֶת מָרְדֳּכַי וּלְהָסִיר שַׂקּוֹ מֵעָלָיו וְלֹא קִבֵּל: וַתִּקְרָא אֶסְתֵּר לַהֲתָךְ מִסָּרִיסֵי הַמֶּלֶךְ אֲשֶׁר הֶעֱמִיד לְפָנֶיהָ וַתְּצַוֵּהוּ עַל מָרְדֳּכַי, לָדַעַת מַה זֶּה וְעַל מַה זֶּה: וַיֵּצֵא הֲתָךְ אֶל מָרְדֳּכַי, אֶל רְחוֹב הָעִיר אֲשֶׁר לִפְנֵי שַׁעַר הַמֶּלֶךְ: וַיַּגֶּד לוֹ מָרְדֳּכַי אֵת כָּל אֲשֶׁר קָרָהוּ, וְאֵת פָּרָשַׁת הַכֶּסֶף אֲשֶׁר אָמַר הָמָן לִשְׁקוֹל עַל גִּנְזֵי הַמֶּלֶךְ בַּיְּהוּדִים לְאַבְּדָם: וְאֶת פַּתְשֶׁגֶן כְּתָב הַדָּת אֲשֶׁר נִתַּן בְּשׁוּשָׁן לְהַשְׁמִידָם נָתַן לוֹ לְהַרְאוֹת אֶת אֶסְתֵּר וּלְהַגִּיד לָהּ, וּלְצַוּוֹת עָלֶיהָ לָבוֹא אֶל הַמֶּלֶךְ לְהִתְחַנֶּן לוֹ וּלְבַקֵּשׁ מִלְּפָנָיו עַל עַמָּהּ: וַיָּבוֹא הֲתָךְ, וַיַּגֵּד לְאֶסְתֵּר אֵת דִּבְרֵי מָרְדֳּכַי: וַתֹּאמֶר אֶסְתֵּר לַהֲתָךְ, וַתְּצַוֵּהוּ אֶל מָרְדֳּכַי: כָּל עַבְדֵי הַמֶּלֶךְ וְעַם מְדִינוֹת הַמֶּלֶךְ יוֹדְעִים אֲשֶׁר כָּל אִישׁ וְאִשָּׁה אֲשֶׁר יָבוֹא אֶל הַמֶּלֶךְ אֶל הֶחָצֵר הַפְּנִימִית אֲשֶׁר לֹא יִקָּרֵא אַחַת דָּתוֹ לְהָמִית, לְבַד מֵאֲשֶׁר יוֹשִׁיט לוֹ הַמֶּלֶךְ אֶת שַׁרְבִיט הַזָּהָב וְחָיָה, וַאֲנִי לֹא נִקְרֵאתִי לָבוֹא אֶל הַמֶּלֶךְ זֶה שְׁלוֹשִׁים יוֹם: וַיַּגִּידוּ לְמָרְדֳּכַי אֵת דִּבְרֵי אֶסְתֵּר: וַיֹּאמֶר מָרְדֳּכַי לְהָשִׁיב אֶל אֶסְתֵּר, אַל תְּדַמִּי בְנַפְשֵׁךְ לְהִמָּלֵט בֵּית הַמֶּלֶךְ מִכָּל הַיְּהוּדִים: כִּי אִם הַחֲרֵשׁ תַּחֲרִישִׁי בָּעֵת הַזֹּאת, רֶוַח וְהַצָּלָה יַעֲמוֹד לַיְּהוּדִים מִמָּקוֹם אַחֵר וְאַתְּ וּבֵית אָבִיךְ תֹּאבֵדוּ, וּמִי יוֹדֵעַ אִם לְעֵת כָּזֹאת הִגַּעַתְּ לַמַּלְכוּת: וַתֹּאמֶר אֶסְתֵּר לְהָשִׁיב אֶל מָרְדֳּכַי: לֵךְ כְּנוֹס אֶת כָּל הַיְּהוּדִים הַנִּמְצְאִים בְּשׁוּשָׁן וְצוּמוּ עָלַי וְאַל תֹּאכְלוּ וְאַל תִּשְׁתּוּ שְׁלֹשֶׁת יָמִים לַיְלָה וָיוֹם, גַּם אֲנִי וְנַעֲרֹתַי אָצוּם כֵּן, וּבְכֵן אָבוֹא אֶל הַמֶּלֶךְ אֲשֶׁר לֹא כַדָּת וְכַאֲשֶׁר אָבַדְתִּי אָבָדְתִּי: וַיַּעֲבֹר מָרְדֳּכַי, וַיַּעַשׂ כְּכֹל אֲשֶׁר צִוְּתָה עָלָיו אֶסְתֵּר:","cond":[]},{"kind":"header","text":"פרק ה'","cond":[]},{"kind":"instruction","text":"פרק ה'","cond":[]},{"kind":"text","text":"וַיְהִי בַּיּוֹם הַשְּׁלִישִׁי וַתִּלְבַּשׁ אֶסְתֵּר מַלְכוּת, וַתַּעֲמֹד בַּחֲצַר בֵּית הַמֶּלֶךְ הַפְּנִימִית נֹכַח בֵּית הַמֶּלֶךְ, וְהַמֶּלֶךְ יוֹשֵׁב עַל כִּסֵּא מַלְכוּתוֹ בְּבֵית הַמַּלְכוּת נֹכַח פֶּתַח הַבָּיִת: וַיְהִי כִרְאוֹת הַמֶּלֶךְ אֶת אֶסְתֵּר הַמַּלְכָּה עֹמֶדֶת בֶּחָצֵר נָשְׂאָה חֵן בְּעֵינָיו, וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֶת שַׁרְבִיט הַזָּהָב אֲשֶׁר בְּיָדוֹ, וַתִּקְרַב אֶסְתֵּר וַתִּגַּע בְּרֹאשׁ הַשַּׁרְבִיט: וַיֹּאמֶר לָהּ הַמֶּלֶךְ מַה לָּךְ אֶסְתֵּר הַמַּלְכָּה, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְיִנָּתֵן לָךְ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יָבוֹא הַמֶּלֶךְ וְהָמָן הַיּוֹם אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשִׂיתִי לוֹ: וַיֹּאמֶר הַמֶּלֶךְ מַהֲרוּ אֶת הָמָן לַעֲשׂוֹת אֶת דְּבַר אֶסְתֵּר, וַיָּבֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר וַתֹּאמַר, שְׁאֵלָתִי וּבַקָּשָׁתִי: אִם מָצָאתִי חֵן בְּעֵינֵי הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב לָתֵת אֶת שְׁאֵלָתִי וְלַעֲשׂוֹת אֶת בַּקָּשָׁתִי, יָבוֹא הַמֶּלֶךְ וְהָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר אֶעֱשֶׂה לָהֶם וּמָחָר אֶעֱשֶׂה כִּדְבַר הַמֶּלֶךְ: וַיֵּצֵא הָמָן בַּיּוֹם הַהוּא שָׂמֵחַ וְטוֹב לֵב, וְכִרְאוֹת הָמָן אֶת מָרְדֳּכַי בְּשַׁעַר הַמֶּלֶךְ וְלֹא קָם וְלֹא זָע מִמֶּנּוּ וַיִּמָּלֵא הָמָן עַל מָרְדֳּכַי חֵמָה: וַיִּתְאַפַּק הָמָן וַיָּבוֹא אֶל בֵּיתוֹ, וַיִּשְׁלַח וַיָּבֵא אֶת אֹהֲבָיו וְאֶת זֶרֶשׁ אִשְׁתּוֹ: וַיְסַפֵּר לָהֶם הָמָן אֶת כְּבוֹד עָשְׁרוֹ וְרֹב בָּנָיו, וְאֵת כָּל אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ וְאֵת אֲשֶׁר נִשְּׂאוֹ עַל הַשָּׂרִים וְעַבְדֵי הַמֶּלֶךְ: וַיֹּאמֶר הָמָן, אַף לֹא הֵבִיאָה אֶסְתֵּר הַמַּלְכָּה עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשָׂתָה כִּי אִם אוֹתִי, וְגַם לְמָחָר אֲנִי קָרוּא לָהּ עִם הַמֶּלֶךְ: וְכָל זֶה אֵינֶנּוּ שֹׁוֶה לִי, בְּכָל עֵת אֲשֶׁר אֲנִי רֹאֶה אֶת מָרְדֳּכַי הַיְּהוּדִי יוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ: וַתֹּאמֶר לוֹ זֶרֶשׁ אִשְׁתּוֹ וְכָל אֹהֲבָיו יַעֲשׂוּ עֵץ גָּבֹהַּ חֲמִשִּׁים אַמָּה, וּבַבֹּקֶר אֱמֹר לַמֶּלֶךְ וְיִתְלוּ אֶת מָרְדֳּכַי עָלָיו וּבֹא עִם הַמֶּלֶךְ אֶל הַמִּשְׁתֶּה שָׂמֵחַ, וַיִּיטַב הַדָּבָר לִפְנֵי הָמָן וַיַּעַשׂ הָעֵץ:","cond":[]},{"kind":"header","text":"פרק ו'","cond":[]},{"kind":"instruction","text":"פרק ו'","cond":[]},{"kind":"special","text":"בַּלַּיְלָה הַהוּא נָדְדָה שְׁנַת הַמֶּלֶךְ, וַיֹּאמֶר לְהָבִיא אֶת סֵפֶר הַזִּכְרֹנוֹת דִּבְרֵי הַיָּמִים, וַיִּהְיוּ נִקְרָאִים לִפְנֵי הַמֶּלֶךְ:","cond":[]},{"kind":"text","text":"וַיִּמָּצֵא כָתוּב אֲשֶׁר הִגִּיד מָרְדֳּכַי עַל בִּגְתָנָא וָתֶרֶשׁ שְׁנֵי סָרִיסֵי הַמֶּלֶךְ מִשֹּׁמְרֵי הַסַּף אֲשֶׁר בִּקְשׁוּ לִשְׁלֹחַ יָד בַּמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ: וַיֹּאמֶר הַמֶּלֶךְ מַה נַּעֲשָׂה יְקָר וּגְדוּלָּה לְמָרְדֳּכַי עַל זֶה, וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ מְשָׁרְתָיו לֹא נַעֲשָׂה עִמּוֹ דָּבָר: וַיֹּאמֶר הַמֶּלֶךְ מִי בֶחָצֵר, וְהָמָן בָּא לַחֲצַר בֵּית הַמֶּלֶךְ הַחִיצוֹנָה לֵאמֹר לַמֶּלֶךְ לִתְלוֹת אֶת מָרְדֳּכַי עַל הָעֵץ אֲשֶׁר הֵכִין לוֹ: וַיֹּאמְרוּ נַעֲרֵי הַמֶּלֶךְ אֵלָיו הִנֵּה הָמָן עֹמֵד בֶּחָצֵר, וַיֹּאמֶר הַמֶּלֶךְ יָבוֹא: וַיָּבוֹא הָמָן, וַיֹּאמֶר לוֹ הַמֶּלֶךְ מַה לַעֲשׂוֹת בָּאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וַיֹּאמֶר הָמָן בְּלִבּוֹ לְמִי יַחְפֹּץ הַמֶּלֶךְ לַעֲשׂוֹת יְקָר יוֹתֵר מִמֶּנִּי: וַיֹּאמֶר הָמָן אֶל הַמֶּלֶךְ, אִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: יָבִיאוּ לְבוּשׁ מַלְכוּת אֲשֶׁר לָבַשׁ בּוֹ הַמֶּלֶךְ, וְסוּס אֲשֶׁר רָכַב עָלָיו הַמֶּלֶךְ וַאֲשֶׁר נִתַּן כֶּתֶר מַלְכוּת בְּרֹאשׁוֹ: וְנָתוֹן הַלְּבוּשׁ וְהַסּוּס עַל יַד אִישׁ מִשָּׂרֵי הַמֶּלֶךְ הַפַּרְתְּמִים וְהִלְבִּישׁוּ אֶת הָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ, וְהִרְכִּיבֻהוּ עַל הַסּוּס בִּרְחוֹב הָעִיר וְקָרְאוּ לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיֹּאמֶר הַמֶּלֶךְ לְהָמָן מַהֵר קַח אֶת הַלְּבוּשׁ וְאֶת הַסּוּס כַּאֲשֶׁר דִּבַּרְתָּ וַעֲשֵׂה כֵן לְמָרְדֳּכַי הַיְּהוּדִי הַיּוֹשֵׁב בְּשַׁעַר הַמֶּלֶךְ, אַל תַּפֵּל דָּבָר מִכֹּל אֲשֶׁר דִּבַּרְתָּ: וַיִּקַּח הָמָן אֶת הַלְּבוּשׁ וְאֶת הַסּוּס וַיַּלְבֵּשׁ אֶת מָרְדֳּכַי, וַיַּרְכִּיבֵהוּ בִּרְחוֹב הָעִיר וַיִּקְרָא לְפָנָיו כָּכָה יֵעָשֶׂה לָאִישׁ אֲשֶׁר הַמֶּלֶךְ חָפֵץ בִּיקָרוֹ: וַיָּשָָב מָרְדֳּכַי אֶל שַׁעַר הַמֶּלֶךְ, וְהָמָן נִדְחַף אֶל בֵּיתוֹ אָבֵל וַחֲפוּי רֹאשׁ: וַיְסַפֵּר הָמָן לְזֶרֶשׁ אִשְׁתּוֹ וּלְכָל אֹהֲבָיו אֵת כָּל אֲשֶׁר קָרָהוּ, וַיֹּאמְרוּ לּוֹ חֲכָמָיו וְזֶרֶשׁ אִשְׁתּוֹ אִם מִזֶּרַע הַיְּהוּדִים מָרְדֳּכַי אֲשֶׁר הַחִלּוֹתָ לִנְפֹּל לְפָנָיו לֹא תוּכַל לוֹ, כִּי נָפוֹל תִּפּוֹל לְפָנָיו: עוֹדָם מְדַבְּרִים עִמּוֹ וְסָרִיסֵי הַמֶּלֶךְ הִגִּיעוּ, וַיַּבְהִלוּ לְהָבִיא אֶת הָמָן אֶל הַמִּשְׁתֶּה אֲשֶׁר עָשְׂתָה אֶסְתֵּר:","cond":[]},{"kind":"header","text":"פרק ז'","cond":[]},{"kind":"instruction","text":"פרק ז'","cond":[]},{"kind":"text","text":"וַיָּבֹא הַמֶּלֶךְ וְהָמָן לִשְׁתּוֹת עִם אֶסְתֵּר הַמַּלְכָּה: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר גַּם בַּיּוֹם הַשֵּׁנִי בְּמִשְׁתֵּה הַיַּיִן מַה שְּׁאֵלָתֵךְ אֶסְתֵּר הַמַּלְכָּה וְתִנָּתֵן לָךְ, וּמַה בַּקָּשָׁתֵךְ עַד חֲצִי הַמַּלְכוּת וְתֵעָשׂ: וַתַּעַן אֶסְתֵּר הַמַּלְכָּה וַתֹּאמַר אִם מָצָאתִי חֵן בְּעֵינֶיךָ הַמֶּלֶךְ וְאִם עַל הַמֶּלֶךְ טוֹב, תִּנָּתֶן לִי נַפְשִׁי בִּשְׁאֵלָתִי וְעַמִּי בְּבַקָּשָׁתִי: כִּי נִמְכַּרְנוּ אֲנִי וְעַמִּי לְהַשְׁמִיד לַהֲרוֹג וּלְאַבֵּד, וְאִלּוּ לַעֲבָדִים וְלִשְׁפָחוֹת נִמְכַּרְנוּ הֶחֱרַשְׁתִּי כִּי אֵין הַצָּר שֹׁוֶה בְּנֵזֶק הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וַיֹּאמֶר לְאֶסְתֵּר הַמַּלְכָּה, מִי הוּא זֶה וְאֵי זֶה הוּא אֲשֶׁר מְלָאוֹ לִבּוֹ לַעֲשׂוֹת כֵּן: וַתֹּאמֶר אֶסְתֵּר אִישׁ צַר וְאוֹיֵב הָמָן הָרָע הַזֶּה, וְהָמָן נִבְעַת מִלִּפְנֵי הַמֶּלֶךְ וְהַמַּלְכָּה: וְהַמֶּלֶךְ קָם בַּחֲמָתוֹ מִמִּשְׁתֵּה הַיַּיִן אֶל גִּנַּת הַבִּיתָן, וְהָמָן עָמַד לְבַקֵּשׁ עַל נַפְשׁוֹ מֵאֶסְתֵּר הַמַּלְכָּה כִּי רָאָה כִּי כָלְתָה אֵלָיו הָרָעָה מֵאֵת הַמֶּלֶךְ: וְהַמֶּלֶךְ שָׁב מִגִּנַּת הַבִּיתָן אֶל בֵּית מִשְׁתֵּה הַיַּיִן וְהָמָן נֹפֵל עַל הַמִּטָּה אֲשֶׁר אֶסְתֵּר עָלֶיהָ, וַיֹּאמֶר הַמֶּלֶךְ הֲגַם לִכְבּוֹשׁ אֶת הַמַּלְכָּה עִמִּי בַּבָּיִת, הַדָּבָר יָצָא מִפִּי הַמֶּלֶךְ וּפְנֵי הָמָן חָפוּ: וַיֹּאמֶר חַרְבוֹנָה אֶחָד מִן הַסָּרִיסִים לִפְנֵי הַמֶּלֶךְ גַּם הִנֵּה הָעֵץ אֲשֶׁר עָשָׂה הָמָן לְמָרְדֳּכַי אֲשֶׁר דִּבֶּר טוֹב עַל הַמֶּלֶךְ עֹמֵד בְּבֵית הָמָן גָּבֹהַּ חֲמִשִּׁים אַמָּה, וַיֹּאמֶר הַמֶּלֶךְ תְּלֻהוּ עָלָיו: וַיִּתְלוּ אֶת הָמָן עַל הָעֵץ אֲשֶׁר הֵכִין לְמָרְדֳּכַי, וַחֲמַת הַמֶּלֶךְ שָׁכָכָה:","cond":[]},{"kind":"header","text":"פרק ח'","cond":[]},{"kind":"instruction","text":"פרק ח'","cond":[]},{"kind":"text","text":"בַּיּוֹם הַהוּא נָתַן הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ לְאֶסְתֵּר הַמַּלְכָּה אֶת בֵּית הָמָן צֹרֵר הַיְּהוּדִים, וּמָרְדֳּכַי בָּא לִפְנֵי הַמֶּלֶךְ כִּי הִגִּידָה אֶסְתֵּר מַה הוּא לָהּ: וַיָּסַר הַמֶּלֶךְ אֶת טַבַּעְתּוֹ אֲשֶׁר הֶעֱבִיר מֵהָמָן וַיִּתְּנָהּ לְמָרְדֳּכַי, וַתָּשֶׂם אֶסְתֵּר אֶת מָרְדֳּכַי עַל בֵּית הָמָן: וַתּוֹסֶף אֶסְתֵּר וַתְּדַבֵּר לִפְנֵי הַמֶּלֶךְ וַתִּפֹּל לִפְנֵי רַגְלָיו, וַתֵּבְךְּ וַתִּתְחַנֶּן לוֹ לְהַעֲבִיר אֶת רָעַת הָמָן הָאֲגָגִי וְאֵת מַחֲשַׁבְתּוֹ אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים: וַיּוֹשֶׁט הַמֶּלֶךְ לְאֶסְתֵּר אֵת שַׁרְבִט הַזָּהָב, וַתָּקָם אֶסְתֵּר וַתַּעֲמֹד לִפְנֵי הַמֶּלֶךְ: וַתֹּאמֶר אִם עַל הַמֶּלֶךְ טוֹב וְאִם מָצָאתִי חֵן לְפָנָיו וְכָשֵׁר הַדָּבָר לִפְנֵי הַמֶּלֶךְ וְטוֹבָה אֲנִי בְּעֵינָיו, יִכָּתֵב לְהָשִׁיב אֶת הַסְּפָרִים מַחֲשֶׁבֶת הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי אֲשֶׁר כָּתַב לְאַבֵּד אֶת הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ: כִּי אֵיכָכָה אוּכַל וְרָאִיתִי בָּרָעָה אֲשֶׁר יִמְצָא אֶת עַמִּי, וְאֵיכָכָה אוּכַל וְרָאִיתִי בְּאָבְדַן מוֹלַדְתִּי: וַיֹּאמֶר הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ לְאֶסְתֵּר הַמַּלְכָּה וּלְמָרְדֳּכַי הַיְּהוּדִי, הִנֵּה בֵית הָמָן נָתַתִּי לְאֶסְתֵּר וְאֹתוֹ תָּלוּ עַל הָעֵץ עַל אֲשֶׁר שָׁלַח יָדוֹ בַּיְּהוּדִים: וְאַתֶּם כִּתְבוּ עַל הַיְּהוּדִים כַּטּוֹב בְּעֵינֵיכֶם בְּשֵׁם הַמֶּלֶךְ וְחִתְמוּ בְּטַבַּעַת הַמֶּלֶךְ, כִּי כְתָב אֲשֶׁר נִכְתָּב בְּשֵׁם הַמֶּלֶךְ וְנַחְתּוֹם בְּטַבַּעַת הַמֶּלֶךְ אֵין לְהָשִׁיב: וַיִּקָּרְאוּ סֹפְרֵי הַמֶּלֶךְ בָּעֵת הַהִיא בַּחֹדֶשׁ הַשְּׁלִישִׁי הוּא חֹדֶשׁ סִיוָן בִּשְׁלוֹשָׁה וְעֶשְׂרִים בּוֹ, וַיִּכָּתֵב כְּכָל אֲשֶׁר צִוָּה מָרְדֳּכַי אֶל הַיְּהוּדִים וְאֶל הָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְשָׂרֵי הַמְּדִינוֹת אֲשֶׁר מֵהֹדּוּ וְעַד כּוּשׁ, שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה, מְדִינָה וּמְדִינָה כִּכְתָבָהּ וְעַם וָעָם כִּלְשֹׁנוֹ, וְאֶל הַיְּהוּדִים כִּכְתָבָם וְכִלְשׁוֹנָם: וַיִּכְתֹּב בְּשֵׁם הַמֶּלֶךְ אֲחַשְׁוֵרֹשׁ וַיַּחְתֹּם בְּטַבַּעַת הַמֶּלֶךְ, וַיִּשְׁלַח סְפָרִים בְּיַד הָרָצִים בַּסּוּסִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים בְּנֵי הָרַמָּכִים: אֲשֶׁר נָתַן הַמֶּלֶךְ לַיְּהוּדִים אֲשֶׁר בְּכָל עִיר וָעִיר לְהִקָּהֵל וְלַעֲמֹד עַל נַפְשָׁם, לְהַשְׁמִיד וְלַהֲרֹג וּלְאַבֵּד אֶת כָּל חֵיל עַם וּמְדִינָה הַצָּרִים אֹתָם טַף וְנָשִׁים, וּשְׁלָלָם לָבוֹז: בְּיוֹם אֶחָד בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ, בִּשְׁלוֹשָׁה עָשָׂר לְחֹדֶשׁ שְׁנֵים עָשָׂר הוּא חֹדֶשׁ אֲדָר: פַּתְשֶׁגֶן הַכְּתָב לְהִנָּתֵן דָּת בְּכָל מְדִינָה וּמְדִינָה גָּלוּי לְכָל הָעַמִּים, וְלִהְיוֹת הַיְּהוּדִים עֲתִידִים לַיּוֹם הַזֶּה לְהִנָּקֵם מֵאֹיְבֵיהֶם: הָרָצִים רֹכְבֵי הָרֶכֶשׁ הָאֲחַשְׁתְּרָנִים יָצְאוּ מְבֹהָלִים וּדְחוּפִים בִּדְבַר הַמֶּלֶךְ, וְהַדָּת נִתְּנָה בְּשׁוּשַׁן הַבִּירָה:","cond":[]},{"kind":"special","text":"וּמָרְדֳּכַי יָצָא מִלִּפְנֵי הַמֶּלֶךְ בִּלְבוּשׁ מַלְכוּת תְּכֵלֶת וָחוּר וַעֲטֶרֶת זָהָב גְּדוֹלָה וְתַכְרִיךְ בּוּץ וְאַרְגָּמָן, וְהָעִיר שׁוּשָׁן צָהֲלָה וְשָׂמֵחָה: לַיְּהוּדִים הָיְתָה אוֹרָה וְשִׂמְחָה, וְשָׂשֹׂן וִיקָר:","cond":[]},{"kind":"text","text":"וּבְכָל מְדִינָה וּמְדִינָה וּבְכָל עִיר וָעִיר, מְקוֹם אֲשֶׁר דְּבַר הַמֶּלֶךְ וְדָתוֹ מַגִּיעַ, שִׂמְחָה וְשָׂשׂוֹן לַיְּהוּדִים מִשְׁתֶּה וְיוֹם טוֹב, וְרַבִּים מֵעַמֵּי הָאָרֶץ מִתְיַהֲדִים כִּי נָפַל פַּחַד הַיְּהוּדִים עֲלֵיהֶם:","cond":[]},{"kind":"header","text":"פרק ט'","cond":[]},{"kind":"instruction","text":"פרק ט'","cond":[]},{"kind":"text","text":"וּבִשְׁנֵים עָשָׂר חֹדֶשׁ הוּא חֹדֶשׁ אֲדָר בִּשְׁלוֹשָׁה עָשָׂר יוֹם בּוֹ אֲשֶׁר הִגִּיעַ דְּבַר הַמֶּלֶךְ וְדָתוֹ לְהֵעָשׂוֹת, בַּיּוֹם אֲשֶׁר שִׂבְּרוּ אֹיְבֵי הַיְּהוּדִים לִשְׁלוֹט בָּהֶם וְנַהֲפוֹךְ הוּא אֲשֶׁר יִשְׁלְטוּ הַיְּהוּדִים הֵמָּה בְּשֹׂנְאֵיהֶם: נִקְהֲלוּ הַיְּהוּדִים בְּעָרֵיהֶם בְּכָל מְדִינוֹת הַמֶּלֶךְ אֳחַשְׁוֵרוֹשׁ לִשְׁלֹחַ יָד בִּמְבַקְשֵׁי רָעָתָם, וְאִישׁ לֹא עָמַד לִפְנֵיהֶם כִּי נָפַל פַּחְדָּם עַל כָּל הָעַמִּים: וְכָל שָׂרֵי הַמְּדִינוֹת וְהָאֲחַשְׁדַּרְפְּנִים וְהַפַּחוֹת וְעֹשֵׂי הַמְּלָאכָה אֲשֶׁר לַמֶּלֶךְ מְנַשְּׂאִים אֶת הַיְּהוּדִים, כִּי נָפַל פַּחַד מָרְדֳּכַי עֲלֵיהֶם: כִּי גָדוֹל מָרְדֳּכַי בְּבֵית הַמֶּלֶךְ וְשָׁמְעוֹ הוֹלֵךְ בְּכָל הַמְּדִינוֹת, כִּי הָאִישׁ מָרְדֳּכַי הוֹלֵךְ וְגָדוֹל: וַיַּכּוּ הַיְּהוּדִים בְּכָל אֹיְבֵיהֶם מַכַּת חֶרֶב וְהֶרֶג וְאַבְדָן, וַיַּעֲשׂוּ בְשֹׂנְאֵיהֶם כִּרְצוֹנָם: וּבְשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ: וְאֵת פַּרְשַׁנְדָּתָא וְאֵת דַּלְפוֹן וְאֵת אַסְפָּתָא: וְאֵת פּוֹרָתָא וְאֵת אֲדַלְיָא וְאֵת אֲרִידָתָא: וְאֵת פַּרְמַשְׁתָּא וְאֵת אֲרִיסַי וְאֵת אֲרִדַי וְאֵת וַיְזָתָא: עֲשֶׂרֶת בְּנֵי הָמָן בֶּן הַמְּדָתָא צֹרֵר הַיְּהוּדִים הָרָגוּ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בַּיּוֹם הַהוּא בָּא מִסְפַּר הַהֲרוּגִים בְּשׁוּשַׁן הַבִּירָה לִפְנֵי הַמֶּלֶךְ: וַיֹּאמֶר הַמֶּלֶךְ לְאֶסְתֵּר הַמַּלְכָּה בְּשׁוּשַׁן הַבִּירָה הָרְגוּ הַיְּהוּדִים וְאַבֵּד חֲמֵשׁ מֵאוֹת אִישׁ וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן, בִּשְׁאָר מְדִינוֹת הַמֶּלֶךְ מֶה עָשׂוּ, וּמַה שְּׁאֵלָתֵךְ וְיִנָּתֵן לָךְ וּמַה בַּקָּשָׁתֵךְ עוֹד וְתֵעָשׂ: וַתֹּאמֶר אֶסְתֵּר אִם עַל הַמֶּלֶךְ טוֹב, יִנָּתֵן גַּם מָחָר לַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן לַעֲשׂוֹת כְּדָת הַיּוֹם, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן יִתְלוּ עַל הָעֵץ: וַיֹּאמֶר הַמֶּלֶךְ לְהֵעָשׂוֹת כֵּן וַתִּנָּתֵן דָּת בְּשׁוּשָׁן, וְאֵת עֲשֶׂרֶת בְּנֵי הָמָן תָּלוּ: וַיִּקָּהֲלוּ הַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן גַּם בְּיוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וַיַּהַרְגוּ בְשׁוּשָׁן שְׁלֹשׁ מֵאוֹת אִישׁ, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: וּשְׁאָר הַיְּהוּדִים אֲשֶׁר בִּמְדִינוֹת הַמֶּלֶךְ נִקְהֲלוּ וְעָמֹד עַל נַפְשָׁם וְנוֹחַ מֵאֹיְבֵיהֶם וְהָרֹג בְּשֹׂנְאֵיהֶם חֲמִשָּׁה וְשִׁבְעִים אָלֶף, וּבַבִּזָּה לֹא שָׁלְחוּ אֶת יָדָם: בְּיוֹם שְׁלֹשָׁה עָשָׂר לְחֹדֶשׁ אֲדָר, וְנוֹחַ בְּאַרְבָּעָה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: וְהַיְּהוּדִים אֲשֶׁר בְּשׁוּשָׁן נִקְהֲלוּ בִּשְׁלֹשָׁה עָשָׂר בּוֹ וּבְאַרְבָּעָה עָשָׂר בּוֹ, וְנוֹחַ בַּחֲמִשָּׁה עָשָׂר בּוֹ וְעָשֹׂה אֹתוֹ יוֹם מִשְׁתֶּה וְשִׂמְחָה: עַל כֵּן הַיְּהוּדִים הַפְּרָזִים הַיֹּשְׁבִים בְּעָרֵי הַפְּרָזוֹת, עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר שִׂמְחָה וּמִשְׁתֶּה וְיוֹם טוֹב, וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ: וַיִּכְתֹּב מָרְדֳּכַי אֶת הַדְּבָרִים הָאֵלֶּה, וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים אֲשֶׁר בְּכָל מְדִינוֹת הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ הַקְּרוֹבִים וְהָרְחוֹקִים: לְקַיֵּם עֲלֵיהֶם, לִהְיוֹת עֹשִׂים אֵת יוֹם אַרְבָּעָה עָשָׂר לְחֹדֶשׁ אֲדָר וְאֵת יוֹם חֲמִשָּׁה עָשָׂר בּוֹ, בְּכָל שָׁנָה וְשָׁנָה: כַּיָּמִים אֲשֶׁר נָחוּ בָהֶם הַיְּהוּדִים מֵאוֹיְבֵיהֶם, וְהַחֹדֶשׁ אֲשֶׁר נֶהְפַּךְ לָהֶם מִיָּגוֹן לְשִׂמְחָה וּמֵאֵבֶל לְיוֹם טוֹב, לַעֲשׂוֹת אוֹתָם יְמֵי מִשְׁתֶּה וְשִׂמְחָה וּמִשְׁלוֹחַ מָנוֹת אִישׁ לְרֵעֵהוּ וּמַתָּנוֹת לָאֶבְיוֹנִים: וְקִבֵּל הַיְּהוּדִים אֵת אֲשֶׁר הֵחֵלּוּ לַעֲשׂוֹת, וְאֵת אֲשֶׁר כָּתַב מָרְדֳּכַי אֲלֵיהֶם: כִּי הָמָן בֶּן הַמְּדָתָא הָאֲגָגִי צֹרֵר כָּל הַיְּהוּדִים חָשַׁב עַל הַיְּהוּדִים לְאַבְּדָם, וְהִפִּיל פּוּר הוּא הַגּוֹרָל לְהֻמָּם וּלְאַבְּדָם: וּבְבֹאָהּ לִפְנֵי הַמֶּלֶךְ, אָמַר עִם הַסֵּפֶר יָשׁוּב מַחֲשַׁבְתּוֹ הָרָעָה אֲשֶׁר חָשַׁב עַל הַיְּהוּדִים עַל רֹאשׁוֹ, וְתָלוּ אֹתוֹ וְאֶת בָּנָיו עַל הָעֵץ: עַל כֵּן קָרְאוּ לַיָּמִים הָאֵלֶּה פוּרִים עַל שֵׁם הַפּוּר, עַל כֵּן עַל כָּל דִּבְרֵי הָאִגֶּרֶת הַזֹּאת, וּמָה רָאוּ עַל כָּכָה וּמָה הִגִּיעַ אֲלֵיהֶם: קִיְּמוּ וְקִבְּלוּ הַיְּהוּדִים עֲלֵיהֶם וְעַל זַרְעָם וְעַל כָּל הַנִּלְוִים עֲלֵיהֶם וְלֹא יַעֲבוֹר, לִהְיוֹת עֹשִׂים אֵת שְׁנֵי הַיָּמִים הָאֵלֶּה כִּכְתָבָם וְכִזְמַנָּם, בְּכָל שָׁנָה וְשָׁנָה: וְהַיָּמִים הָאֵלֶּה נִזְכָּרִים וְנַעֲשִׂים בְּכָל דּוֹר וָדוֹר מִשְׁפָּחָה וּמִשְׁפָּחָה מְדִינָה וּמְדִינָה וְעִיר וָעִיר, וִימֵי הַפּוּרִים הָאֵלֶּה לֹא יַעַבְרוּ מִתּוֹךְ הַיְּהוּדִים וְזִכְרָם לֹא יָסוּף מִזַּרְעָם: וַתִּכְתֹּב אֶסְתֵּר הַמַּלְכָּה בַת אֲבִיחַיִל וּמָרְדֳּכַי הַיְּהוּדִי אֶת כָּל תֹּקֶף, לְקַיֵּם אֵת אִגֶּרֶת הַפּוּרִים הַזֹּאת הַשֵּׁנִית: וַיִּשְׁלַח סְפָרִים אֶל כָּל הַיְּהוּדִים, אֶל שֶׁבַע וְעֶשְׂרִים וּמֵאָה מְדִינָה מַלְכוּת אֲחַשְׁוֵרוֹשׁ, דִּבְרֵי שָׁלוֹם וֶאֱמֶת: לְקַיֵּם אֵת יְמֵי הַפֻּרִים הָאֵלֶּה בִּזְמַנֵּיהֶם כַּאֲשֶׁר קִיַּם עֲלֵיהֶם מָרְדֳּכַי הַיְּהוּדִי וְאֶסְתֵּר הַמַּלְכָּה וְכַאֲשֶׁר קִיְּמוּ עַל נַפְשָׁם וְעַל זַרְעָם, דִּבְרֵי הַצֹּמוֹת וְזַעֲקָתָם: וּמַאֲמַר אֶסְתֵּר קִיַּם דִּבְרֵי הַפֻּרִים הָאֵלֶּה, וְנִכְתָּב בַּסֵּפֶר:","cond":[]},{"kind":"header","text":"פרק י'","cond":[]},{"kind":"instruction","text":"פרק י'","cond":[]},{"kind":"text","text":"וַיָּשֶׂם הַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ מַס עַל הָאָרֶץ וְאִיֵּי הַיָּם: וְכָל מַעֲשֵׂה תָקְפּוֹ וּגְבוּרָתוֹ, וּפָרָשַׁת גְּדֻלַּת מָרְדֳּכַי אֲשֶׁר גִּדְּלוֹ הַמֶּלֶךְ, הֲלוֹא הֵם כְּתוּבִים עַל סֵפֶר דִּבְרֵי הַיָּמִים לְמַלְכֵי מָדַי וּפָרָס:","cond":[]},{"kind":"special","text":"כִּי מָרְדֳּכַי הַיְּהוּדִי מִשְׁנֶה לַמֶּלֶךְ אֲחַשְׁוֵרוֹשׁ וְגָדוֹל לַיְּהוּדִים וְרָצוּי לְרֹב אֶחָיו, דֹּרֵשׁ טוֹב לְעַמּוֹ וְדֹבֵר שָׁלוֹם לְכָל זַרְעוֹ:","cond":[]},{"kind":"header","text":"ברכת הרב את ריבנו","cond":[]},{"kind":"instruction","text":"ברכת הרב את ריבנו מברכים גם ביום וגם בלילה, ומברכים אותה רק בציבור של עשרה. ברכה זו מברך רק החזן הקורא את המגילה לאחר שכרך את כל המגילה.","cond":[]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, הָרָב אֶת רִיבֵנוּ, וְהַדָּן אֶת דִּינֵנוּ, וְהַנּוֹקֵם אֶת נִקְמָתֵנוּ, וְהַמְשַׁלֵּם גְּמוּל לְכָל אוֹיְבֵי נַפְשֵׁנוּ, וְהַנִּפְרָע לָנוּ מִצָּרֵינוּ. בָּרוּךְ אַתָּה יהוה, הַנִּפְרָע לְעַמּוֹ יִשְׂרָאֵל מִכָּל צָרֵיהֶם, הָאֵל הַמּוֹשִׁיעַ.\n\nבָּרוּךְ יהוה אֱלֹהֵי יִשְׂרָאֵל. אָרוּר הָמָן. בָּרוּךְ מָרְדֳּכִי. אֲרוּרָה זֶרֶשׁ וּוַשְׁתִּי. בְּרוּכָה אֶסְתֵּר. אֲרוּרִים עוֹבְדֵי אֱלִילִים. בְּרוּכִים כָּל יִשְׂרָאֵל. וְגַם חַרְבוֹנָה זָכוּר לְטוֹב.","cond":[]}]}},{"id":"megillat_eicha","title":"מגילת איכה","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"instruction","text":"מברך לאור הנר:","cond":["sun"]},{"kind":"text","text":"בָּרוּךְ אַתָּה יהוה, אֱלֹהֵינוּ מֶלֶךְ הָעוֹלָם, בּוֹרֵא מְאוֹרֵי הָאֵשׁ.","cond":["sun"]},{"kind":"header","text":"מגילת איכה","cond":[]},{"kind":"instruction","text":"מגילת איכה\n\n\nפרק א'","cond":[]},{"kind":"text","text":"אֵיכָה יָשְׁבָה בָדָד הָעִיר רַבָּתִי עָם הָיְתָה כְּאַלְמָנָה, רַבָּתִי בַגּוֹיִם, שָׂרָתִי בַּמְּדִינוֹת, הָיְתָה לָמַס: בָּכוֹ תִבְכֶּה בַּלַּיְלָה וְדִמְעָתָהּ עַל לֶחֱיָהּ, אֵין לָהּ מְנַחֵם מִכָּל אֹהֲבֶיהָ, כָּל רֵעֶיהָ בָּגְדוּ בָהּ, הָיוּ לָהּ לְאֹיְבִים: גָּלְתָה יְהוּדָה מֵעֹנִי וּמֵרֹב עֲבֹדָה, הִיא יָשְׁבָה בַגּוֹיִם, לֹא מָצְאָה מָנוֹחַ, כָּל רֹדְפֶיהָ הִשִּׂיגוּהָ בֵּין הַמְּצָרִים: דַּרְכֵי צִיּוֹן אֲבֵלוֹת מִבְּלִי בָּאֵי מוֹעֵד, כָּל שְׁעָרֶיהָ שׁוֹמֵמִין, כֹּהֲנֶיהָ נֶאֱנָחִים, בְּתוּלֹתֶיהָ נּוּגוֹת וְהִיא מַר לָהּ: הָיוּ צָרֶיהָ לְרֹאשׁ אֹיְבֶיהָ שָׁלוּ, כִּי יהוה הוֹגָהּ עַל רֹב פְּשָׁעֶיהָ, עוֹלָלֶיהָ הָלְכוּ שְׁבִי לִפְנֵי צָר: וַיֵּצֵא מִבַּת צִיּוֹן כָּל הֲדָרָהּ, הָיוּ שָׂרֶיהָ כְּאַיָּלִים לֹא מָצְאוּ מִרְעֶה, וַיֵּלְכוּ בְלֹא כֹחַ לִפְנֵי רוֹדֵף: זָכְרָה יְרוּשָׁלַיִם יְמֵי עָנְיָהּ וּמְרוּדֶיהָ, כֹּל מַחֲמֻדֶיהָ אֲשֶׁר הָיוּ מִימֵי קֶדֶם, בִּנְפֹל עַמָּהּ בְּיַד צָר וְאֵין עוֹזֵר לָהּ, רָאוּהָ צָרִים, שָׂחֲקוּ עַל מִשְׁבַּתֶּהָ: חֵטְא חָטְאָה יְרוּשָׁלַיִם, עַל כֵּן לְנִידָה הָיָתָה, כָּל מְכַבְּדֶיהָ הִזִּילוּהָ כִּי רָאוּ עֶרְוָתָהּ, גַּם הִיא נֶאֶנְחָה וַתָּשָׁב אָחוֹר: טֻמְאָתָהּ בְּשׁוּלֶיהָ, לֹא זָכְרָה אַחֲרִיתָהּ, וַתֵּרֶד פְּלָאִים, אֵין מְנַחֵם לָהּ, רְאֵה יהוה אֶת עָנְיִי כִּי הִגְדִּיל אוֹיֵב: יָדוֹ פָּרַשׂ צָר עַל כָּל מַחֲמַדֶּיהָ, כִּי רָאֲתָה גוֹיִם בָּאוּ מִקְדָּשָׁהּ, אֲשֶׁר צִוִּיתָה לֹא יָבֹאוּ בַקָּהָל לָךְ: כָּל עַמָּהּ נֶאֱנָחִים מְבַקְשִׁים לֶחֶם, נָתְנוּ מַחֲמַדֵּיהֶם בְּאֹכֶל לְהָשִׁיב נָפֶשׁ, רְאֵה יהוה וְהַבִּיטָה כִּי הָיִיתִי זוֹלֵלָה: לוֹא אֲלֵיכֶם כָּל עֹבְרֵי דֶרֶךְ, הַבִּיטוּ וּרְאוּ אִם יֵשׁ מַכְאוֹב כְּמַכְאֹבִי אֲשֶׁר עוֹלַל לִי, אֲשֶׁר הוֹגָה יהוה בְּיוֹם חֲרוֹן אַפּוֹ: מִמָּרוֹם שָׁלַח אֵשׁ בְּעַצְמֹתַי וַיִּרְדֶּנָּה, פָּרַשׂ רֶשֶׁת לְרַגְלַי הֱשִׁיבַנִי אָחוֹר, נְתָנַנִי שֹׁמֵמָה כָּל הַיּוֹם דָּוָה: נִשְׂקַד עֹל פְּשָׁעַי בְּיָדוֹ, יִשְׂתָּרְגוּ, עָלוּ עַל צַוָּארִי הִכְשִׁיל כֹּחִי, נְתָנַנִי אֲדֹנָי בִּידֵי לֹא אוּכַל קוּם: סִלָּה כָל אַבִּירַי אֲדֹנָי בְּקִרְבִּי, קָרָא עָלַי מוֹעֵד לִשְׁבֹּר בַּחוּרָי, גַּת דָּרַךְ אֲדֹנָי לִבְתוּלַת בַּת יְהוּדָה: עַל אֵלֶּה אֲנִי בוֹכִיָּה, עֵינִי עֵינִי יֹרְדָה מַּיִם, כִּי רָחַק מִמֶּנִּי מְנַחֵם מֵשִׁיב נַפְשִׁי, הָיוּ בָנַי שׁוֹמֵמִים כִּי גָבַר אוֹיֵב: פֵּרְשָׂה צִיּוֹן בְּיָדֶיהָ, אֵין מְנַחֵם לָהּ, צִוָּה יהוה לְיַעֲקֹב סְבִיבָיו צָרָיו, הָיְתָה יְרוּשָׁלַיִם לְנִדָּה בֵּינֵיהֶם: צַדִּיק הוּא יהוה כִּי פִיהוּ מָרִיתִי, שִׁמְעוּ נָא כָל הָעַמִּים וּרְאוּ מַכְאֹבִי, בְּתוּלֹתַי וּבַחוּרַי הָלְכוּ בַשֶּׁבִי: קָרָאתִי לַמְאַהֲבַי הֵמָּה רִמּוּנִי, כֹּהֲנַי וּזְקֵנַי בָּעִיר גָּוָעוּ, כִּי בִקְשׁוּ אֹכֶל לָמוֹ וְיָשִׁיבוּ אֶת נַפְשָׁם: רְאֵה יהוה כִּי צַר לִי מֵעַי חֳמַרְמָרוּ, נֶהְפַּךְ לִבִּי בְּקִרְבִּי כִּי מָרוֹ מָרִיתִי, מִחוּץ שִׁכְּלָה חֶרֶב, בַּבַּיִת כַּמָּוֶת: שָׁמְעוּ כִּי נֶאֱנָחָה אָנִי, אֵין מְנַחֵם לִי, כָּל אֹיְבַי שָׁמְעוּ רָעָתִי שָׂשׂוּ כִּי אַתָּה עָשִׂיתָ, הֵבֵאתָ יוֹם קָרָאתָ וְיִהְיוּ כָמוֹנִי: תָּבֹא כָל רָעָתָם לְפָנֶיךָ וְעוֹלֵל לָמוֹ, כַּאֲשֶׁר עוֹלַלְתָּ לִי עַל כָּל פְּשָׁעָי, כִּי רַבּוֹת אַנְחֹתַי וְלִבִּי דַוָּי:","cond":[]},{"kind":"instruction","text":"פרק ב'","cond":[]},{"kind":"text","text":"אֵיכָה יָעִיב בְּאַפּוֹ אֲדֹנָי אֶת בַּת צִיּוֹן, הִשְׁלִיךְ מִשָּׁמַיִם אֶרֶץ, תִּפְאֶרֶת יִשְׂרָאֵל, וְלֹא זָכַר הֲדֹם רַגְלָיו בְּיוֹם אַפּוֹ: בִּלַּע אֲדֹנָי וְלֹא חָמַל אֵת כָּל נְאוֹת יַעֲקֹב, הָרַס בְּעֶבְרָתוֹ מִבְצְרֵי בַת יְהוּדָה הִגִּיעַ לָאָרֶץ, חִלֵּל מַמְלָכָה וְשָׂרֶיהָ: גָּדַע בָּחֳרִי אַף כֹּל קֶרֶן יִשְׂרָאֵל, הֵשִׁיב אָחוֹר יְמִינוֹ מִפְּנֵי אוֹיֵב, וַיִּבְעַר בְּיַעֲקֹב כְּאֵשׁ לֶהָבָה, אָכְלָה סָבִיב: דָּרַךְ קַשְׁתּוֹ כְּאוֹיֵב, נִצָּב יְמִינוֹ כְּצָר, וַיַּהֲרֹג כֹּל מַחֲמַדֵּי עָיִן, בְּאֹהֶל בַּת צִיּוֹן שָׁפַךְ כָּאֵשׁ חֲמָתוֹ: הָיָה אֲדֹנָי כְּאוֹיֵב, בִּלַּע יִשְׂרָאֵל, בִּלַּע כָּל אַרְמְנוֹתֶיהָ שִׁחֵת מִבְצָרָיו, וַיֶּרֶב בְּבַת יְהוּדָה תַּאֲנִיָּה וַאֲנִיָּה: וַיַּחְמֹס כַּגַּן שֻׂכּוֹ שִׁחֵת מוֹעֲדוֹ, שִׁכַּח יהוה בְּצִיּוֹן מוֹעֵד וְשַׁבָּת, וַיִּנְאַץ בְּזַעַם אַפּוֹ מֶלֶךְ וְכֹהֵן: זָנַח אֲדֹנָי מִזְבְּחוֹ, נִאֵר מִקְדָּשׁוֹ, הִסְגִּיר בְּיַד אוֹיֵב חוֹמֹת אַרְמְנוֹתֶיהָ, קוֹל נָתְנוּ בְּבֵית יהוה כְּיוֹם מוֹעֵד: חָשַׁב יהוה לְהַשְׁחִית חוֹמַת בַּת צִיּוֹן, נָטָה קָו לֹא הֵשִׁיב יָדוֹ מִבַּלֵּעַ, וַיַּאֲבֶל חֵל וְחוֹמָה יַחְדָּו אֻמְלָלוּ: טָבְעוּ בָאָרֶץ שְׁעָרֶיהָ, אִבַּד וְשִׁבַּר בְּרִיחֶיהָ, מַלְכָּהּ וְשָׂרֶיהָ בַגּוֹיִם אֵין תּוֹרָה, גַּם נְבִיאֶיהָ לֹא מָצְאוּ חָזוֹן מֵיהוה: יֵשְׁבוּ לָאָרֶץ יִדְּמוּ זִקְנֵי בַת צִיּוֹן, הֶעֱלוּ עָפָר עַל רֹאשָׁם, חָגְרוּ שַׂקִּים, הוֹרִידוּ לָאָרֶץ רֹאשָׁן בְּתוּלֹת יְרוּשָׁלַיִם: כָּלוּ בַדְּמָעוֹת עֵינַי חֳמַרְמְרוּ מֵעַי, נִשְׁפַּךְ לָאָרֶץ כְּבֵדִי עַל שֶׁבֶר בַּת עַמִּי, בֵּעָטֵף עוֹלֵל וְיוֹנֵק בִּרְחֹבוֹת קִרְיָה: לְאִמֹּתָם יֹאמְרוּ אַיֵּה דָּגָן וָיָיִן, בְּהִתְעַטְּפָם כֶּחָלָל בִּרְחֹבוֹת עִיר, בְּהִשְׁתַּפֵּךְ נַפְשָׁם אֶל חֵיק אִמֹּתָם: מָה אֲעִידֵךְ מָה אֲדַמֶּה לָּךְ, הַבַּת יְרוּשָׁלַיִם, מָה אַשְׁוֶה לָּךְ וַאֲנַחֲמֵךְ בְּתוּלַת בַּת צִיּוֹן, כִּי גָדוֹל כַּיָּם שִׁבְרֵךְ מִי יִרְפָּא לָךְ: נְבִיאַיִךְ חָזוּ לָךְ שָׁוְא וְתָפֵל, וְלֹא גִלּוּ עַל עֲוׂנֵךְ לְהָשִׁיב שְׁבוּתֵךְ, וַיֶּחֱזוּ לָךְ מַשְׂאוֹת שָׁוְא וּמַדּוּחִים: סָפְקוּ עָלַיִךְ כַּפַּיִם כָּל עֹבְרֵי דֶרֶךְ, שָׁרְקוּ וַיָּנִעוּ רֹאשָׁם עַל בַּת יְרוּשָׁלָיִם, הֲזֹאת הָעִיר שֶׁיֹּאמְרוּ כְּלִילַת יֹפִי, מָשׂוֹשׂ לְכָל הָאָרֶץ: פָּצוּ עָלַיִךְ פִּיהֶם כָּל אוֹיְבַיִךְ, שָׁרְקוּ וַיַּחַרְקוּ שֵׁן, אָמְרוּ בִּלָּעְנוּ, אַךְ זֶה הַיּוֹם שֶׁקִּוִּינֻהוּ מָצָאנוּ רָאִינוּ: עָשָׂה יהוה אֲשֶׁר זָמָם, בִּצַּע אֶמְרָתוֹ אֲשֶׁר צִוָּה מִימֵי קֶדֶם, הָרַס וְלֹא חָמָל, וַיְשַׂמַּח עָלַיִךְ אוֹיֵב, הֵרִים קֶרֶן צָרָיִךְ: צָעַק לִבָּם אֶל אֲדֹנָי, חוֹמַת בַּת צִיּוֹן הוֹרִידִי כַנַּחַל דִּמְעָה יוֹמָם וָלַיְלָה, אַל תִּתְּנִי פוּגַת לָךְ, אַל תִּדֹּם בַּת עֵינֵךְ: קוּמִי רֹנִּי בַלַּיְלָה לְרֹאשׁ אַשְׁמֻרוֹת, שִׁפְכִי כַמַּיִם לִבֵּךְ נֹכַח פְּנֵי אֲדֹנָי, שְׂאִי אֵלָיו כַּפַּיִךְ עַל נֶפֶשׁ עוֹלָלַיִךְ הָעֲטוּפִים בְּרָעָב בְּרֹאשׁ כָּל חוּצוֹת: רְאֵה יהוה וְהַבִּיטָה לְמִי עוֹלַלְתָּ כֹּה, אִם תֹּאכַלְנָה נָשִׁים פִּרְיָם עֹלְלֵי טִפֻּחִים, אִם יֵהָרֵג בְּמִקְדַּשׁ אֲדֹנָי כֹּהֵן וְנָבִיא: שָׁכְבוּ לָאָרֶץ חוּצוֹת נַעַר וְזָקֵן, בְּתוּלֹתַי וּבַחוּרַי נָפְלוּ בֶחָרֶב, הָרַגְתָּ בְּיוֹם אַפֶּךָ, טָבַחְתָּ לֹא חָמָלְתָּ: תִּקְרָא כְיוֹם מוֹעֵד מְגוּרַי מִסָּבִיב וְלֹא הָיָה בְּיוֹם אַף יהוה פָּלִיט וְשָׂרִיד, אֲשֶׁר טִפַּחְתִּי וְרִבִּיתִי אֹיְבִי כִלָּם:","cond":[]},{"kind":"instruction","text":"פרק ג'","cond":[]},{"kind":"text","text":"אֲנִי הַגֶּבֶר רָאָה עֳנִי בְּשֵׁבֶט עֶבְרָתוֹ: אוֹתִי נָהַג וַיֹּלַךְ חֹשֶׁךְ וְלֹא אוֹר: אַךְ בִּי יָשֻׁב יַהֲפֹךְ יָדוֹ כָּל הַיּוֹם: בִּלָּה בְשָׂרִי וְעוֹרִי, שִׁבַּר עַצְמוֹתָי: בָּנָה עָלַי, וַיַּקַּף רֹאשׁ וּתְלָאָה: בְּמַחֲשַׁכִּים הוֹשִׁיבַנִי כְּמֵתֵי עוֹלָם: גָּדַר בַּעֲדִי וְלֹא אֵצֵא, הִכְבִּיד נְחָשְׁתִּי: גַּם כִּי אֶזְעַק וַאֲשַׁוֵּעַ שָׂתַם תְּפִלָּתִי: גָּדַר דְּרָכַי בְּגָזִית, נְתִיבֹתַי עִוָּה: דֹּב אֹרֵב הוּא לִי, אֲרִי בְּמִסְתָּרִים: דְּרָכַי סוֹרֵר וַיְפַשְּׁחֵנִי, שָׂמַנִי שֹׁמֵם: דָּרַךְ קַשְׁתּוֹ וַיַּצִּיבֵנִי כַּמַּטָּרָא לַחֵץ: הֵבִיא בְּכִלְיוֹתָי בְּנֵי אַשְׁפָּתוֹ: הָיִיתִי שְּׂחֹק לְכָל עַמִּי, נְגִינָתָם כָּל הַיּוֹם: הִשְׂבִּיעַנִי בַמְּרוֹרִים הִרְוַנִי לַעֲנָה: וַיַּגְרֵס בֶּחָצָץ שִׁנָּי, הִכְפִּישַׁנִי בָּאֵפֶר: וַתִּזְנַח מִשָּׁלוֹם נַפְשִׁי, נָשִׁיתִי טוֹבָה: וָאֹמַר אָבַד נִצְחִי וְתוֹחַלְתִּי מֵיהוה: זְכָר עָנְיִי וּמְרוּדִי, לַעֲנָה וָרֹאשׁ: זָכוֹר תִּזְכּוֹר וְתָשׁוֹחַ עָלַי נַפְשִׁי: זֹאת אָשִׁיב אֶל לִבִּי, עַל כֵּן אוֹחִיל: חַסְדֵי יהוה כִּי לֹא תָמְנוּ, כִּי לֹא כָלוּ רַחֲמָיו: חֲדָשִׁים לַבְּקָרִים רַבָּה אֱמוּנָתֶךָ: חֶלְקִי יהוה אָמְרָה נַפְשִׁי, עַל כֵּן אוֹחִיל לוֹ: טוֹב יהוה לְקֹוָו, לְנֶפֶשׁ תִּדְרְשֶׁנּוּ: טוֹב וְיָחִיל וְדוּמָם לִתְשׁוּעַת יהוה: טוֹב לַגֶּבֶר כִּי יִשָּׂא עֹל בִּנְעוּרָיו: יֵשֵׁב בָּדָד וְיִדֹּם כִּי נָטַל עָלָיו: יִתֵּן בֶּעָפָר פִּיהוּ, אוּלַי יֵשׁ תִּקְוָה: יִתֵּן לְמַכֵּהוּ לֶחִי, יִשְׂבַּע בְּחֶרְפָּה: כִּי לֹא יִזְנַח לְעוֹלָם אֲדֹנָי: כִּי אִם הוֹגָה וְרִחַם כְּרֹב חֲסָדָיו: כִּי לֹא עִנָּה מִלִּבּוֹ, וַיַּגֶּה בְּנֵי אִישׁ: לְדַכֵּא תַּחַת רַגְלָיו כֹּל אֲסִירֵי אָרֶץ: לְהַטּוֹת מִשְׁפַּט גָּבֶר נֶגֶד פְּנֵי עֶלְיוֹן: לְעַוֵּת אָדָם בְּרִיבוֹ אֲדֹנָי לֹא רָאָה: מִי זֶה אָמַר וַתֶּהִי, אֲדֹנָי לֹא צִוָּה: מִפִּי עֶלְיוֹן לֹא תֵצֵא הָרָעוֹת וְהַטּוֹב: מַה יִּתְאוֹנֵן אָדָם חָי, גֶּבֶר עַל חֲטָאָיו: נַחְפְּשָׂה דְרָכֵינוּ וְנַחְקֹרָה, וְנָשׁוּבָה עַד יהוה: נִשָּׂא לְבָבֵנוּ אֶל כַּפָּיִם, אֶל אֵל בַּשָּׁמָיִם: נַחְנוּ פָשַׁעְנוּ וּמָרִינוּ, אַתָּה לֹא סָלָחְתָּ: סַכֹּתָה בָאַף וַתִּרְדְּפֵנוּ, הָרַגְתָּ לֹא חָמָלְתָּ: סַכּוֹתָה בֶעָנָן לָךְ מֵעֲבוֹר תְּפִלָּה: סְחִי וּמָאוֹס תְּשִׂימֵנוּ בְּקֶרֶב הָעַמִּים: פָּצוּ עָלֵינוּ פִּיהֶם כָּל אֹיְבֵינוּ: פַּחַד וָפַחַת הָיָה לָנוּ, הַשֵּׁאת וְהַשָּׁבֶר: פַּלְגֵי מַיִם תֵּרַד עֵינִי עַל שֶׁבֶר בַּת עַמִּי: עֵינִי נִגְּרָה וְלֹא תִדְמֶה מֵאֵין הֲפֻגוֹת: עַד יַשְׁקִיף וְיֵרֶא יהוה מִשָּׁמָיִם: עֵינִי עוֹלְלָה לְנַפְשִׁי מִכֹּל בְּנוֹת עִירִי: צוֹד צָדוּנִי כַּצִּפּוֹר אֹיְבַי חִנָּם: צָמְתוּ בַבּוֹר חַיָּי וַיַּדּוּ אֶבֶן בִּי: צָפוּ מַיִם עַל רֹאשִׁי, אָמַרְתִּי נִגְזָרְתִּי: קָרָאתִי שִׁמְךָ יהוה מִבּוֹר תַּחְתִּיּוֹת: קוֹלִי שָׁמָעְתָּ, אַל תַּעְלֵם אָזְנְךָ לְרַוְחָתִי לְשַׁוְעָתִי: קָרַבְתָּ בְּיוֹם אֶקְרָאֶךָּ, אָמַרְתָּ אַל תִּירָא: רַבְתָּ אֲדֹנָי רִיבֵי נַפְשִׁי, גָּאַלְתָּ חַיָּי: רָאִיתָה יהוה עַוָּתָתִי, שָׁפְטָה מִשְׁפָּטִי: רָאִיתָה כָּל נִקְמָתָם, כָּל מַחְשְׁבֹתָם לִי: שָׁמַעְתָּ חֶרְפָּתָם יהוה, כָּל מַחְשְׁבֹתָם עָלָי: שִׂפְתֵי קָמַי וְהֶגְיוֹנָם עָלַי כָּל הַיּוֹם: שִׁבְתָּם וְקִימָתָם הַבִּיטָה, אֲנִי מַנְגִּינָתָם: תָּשִׁיב לָהֶם גְּמוּל, יהוה, כְּמַעֲשֵׂה יְדֵיהֶם: תִּתֵּן לָהֶם מְגִנַּת לֵב, תַּאֲלָתְךָ לָהֶם: תִּרְדֹּף בְּאַף וְתַשְׁמִידֵם מִתַּחַת שְׁמֵי יהוה:","cond":[]},{"kind":"instruction","text":"פרק ד'","cond":[]},{"kind":"text","text":"אֵיכָה יוּעַם זָהָב יִשְׁנֶא הַכֶּתֶם הַטּוֹב, תִּשְׁתַּפֵּכְנָה אַבְנֵי קֹדֶשׁ בְּרֹאשׁ כָּל חוּצוֹת: בְּנֵי צִיּוֹן הַיְקָרִים הַמְסֻלָּאִים בַּפָּז, אֵיכָה נֶחְשְׁבוּ לְנִבְלֵי חֶרֶשׂ מַעֲשֵׂה יְדֵי יוֹצֵר: גַּם תַּנִּים חָלְצוּ שַׁד, הֵינִיקוּ גּוּרֵיהֶן, בַּת עַמִּי לְאַכְזָר כַּיְעֵנִים בַּמִּדְבָּר: דָּבַק לְשׁוֹן יוֹנֵק אֶל חִכּוֹ בַּצָּמָא, עוֹלָלִים שָׁאֲלוּ לֶחֶם, פֹּרֵשׂ אֵין לָהֶם: הָאֹכְלִים לְמַעֲדַנִּים נָשַׁמּוּ בַּחוּצוֹת, הָאֱמֻנִים עֲלֵי תוֹלָע חִבְּקוּ אַשְׁפַּתּוֹת: וַיִּגְדַּל עֲוׂן בַּת עַמִּי מֵחַטַּאת סְדֹם הַהֲפוּכָה כְמוֹ רָגַע, וְלֹא חָלוּ בָהּ יָדָיִם: זַכּוּ נְזִירֶיהָ מִשֶּׁלֶג, צַחוּ מֵחָלָב, אָדְמוּ עֶצֶם מִפְּנִינִים, סַפִּיר גִּזְרָתָם: חָשַׁךְ מִשְּׁחוֹר תָּאֳרָם, לֹא נִכְּרוּ בַּחוּצוֹת, צָפַד עוֹרָם עַל עַצְמָם, יָבֵשׁ הָיָה כָעֵץ: טוֹבִים הָיוּ חַלְלֵי חֶרֶב מֵחַלְלֵי רָעָב, שֶׁהֵם יָזוּבוּ מְדֻקָּרִים מִתְּנוּבֹת שָׂדָי: יְדֵי נָשִׁים רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵיהֶן, הָיוּ לְבָרוֹת לָמוֹ בְּשֶׁבֶר בַּת עַמִּי: כִּלָּה יהוה אֶת חֲמָתוֹ, שָׁפַךְ חֲרוֹן אַפּוֹ, וַיַּצֶּת אֵשׁ בְּצִיּוֹן וַתֹּאכַל יְסוֹדֹתֶיהָ: לֹא הֶאֱמִינוּ מַלְכֵי אֶרֶץ כֹּל יֹשְׁבֵי תֵבֵל, כִּי יָבֹא צַר וְאוֹיֵב בְּשַׁעֲרֵי יְרוּשָׁלָיִם: מֵחַטֹּאת נְבִיאֶיהָ, עֲוׂנוֹת כֹּהֲנֶיהָ, הַשֹּׁפְכִים בְּקִרְבָּהּ דַּם צַדִּיקִים: נָעוּ עִוְרִים בַּחוּצוֹת נְגֹאֲלוּ בַּדָּם, בְּלֹא יוּכְלוּ יִגְּעוּ בִּלְבֻשֵׁיהֶם: סוּרוּ טָמֵא, קָרְאוּ לָמוֹ, סוּרוּ סוּרוּ אַל תִּגָּעוּ, כִּי נָצוּ גַּם נָעוּ, אָמְרוּ בַּגּוֹיִם לֹא יוֹסִיפוּ לָגוּר: פְּנֵי יהוה חִלְּקָם לֹא יוֹסִיף לְהַבִּיטָם, פְּנֵי כֹהֲנִים לֹא נָשָׂאוּ וּזְקֵנִים לֹא חָנָנוּ: עוֹדֵינוּ תִּכְלֶינָה עֵינֵינוּ אֶל עֶזְרָתֵנוּ הָבֶל, בְּצִפִּיָּתֵנוּ צִפִּינוּ אֶל גּוֹי לֹא יוֹשִׁעַ: צָדוּ צְעָדֵינוּ מִלֶּכֶת בִּרְחֹבֹתֵינוּ, קָרַב קִצֵּינוּ מָלְאוּ יָמֵינוּ כִּי בָא קִצֵּינוּ: קַלִּים הָיוּ רֹדְפֵינוּ מִנִּשְׁרֵי שָׁמָיִם, עַל הֶהָרִים דְּלָקֻנוּ, בַּמִּדְבָּר אָרְבוּ לָנוּ: רוּחַ אַפֵּינוּ מְשִׁיחַ יהוה נִלְכַּד בִּשְׁחִיתוֹתָם, אֲשֶׁר אָמַרְנוּ בְּצִלּוֹ נִחְיֶה בַגּוֹיִם: שִׂישִׂי וְשִׂמְחִי בַּת אֱדוֹם יוֹשֶׁבֶת בְּאֶרֶץ עוּץ, גַּם עָלַיִךְ תַּעֲבָר כּוֹס, תִּשְׁכְּרִי וְתִתְעָרִי: תַּם עֲוׂנֵךְ בַּת צִיּוֹן, לֹא יוֹסִיף לְהַגְלוֹתֵךְ, פָּקַד עֲוׂנֵךְ בַּת אֱדוֹם, גִּלָּה עַל חַטֹּאתָיִךְ:","cond":[]},{"kind":"instruction","text":"פרק ה'","cond":[]},{"kind":"text","text":"זְכֹר יהוה מֶה הָיָה לָנוּ, הַבִּיטָה וּרְאֵה אֶת חֶרְפָּתֵנוּ: נַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים, בָּתֵּינוּ לְנָכְרִים: יְתוֹמִים הָיִינוּ וְאֵין אָב, אִמֹּתֵינוּ כְּאַלְמָנוֹת: מֵימֵינוּ בְּכֶסֶף שָׁתִינוּ, עֵצֵינוּ בִּמְחִיר יָבֹאוּ: עַל צַוָּארֵנוּ נִרְדָּפְנוּ, יָגַעְנוּ וְלֹא הוּנַח לָנוּ: מִצְרַיִם נָתַנּוּ יָד, אַשּׁוּר לִשְׂבֹּעַ לָחֶם: אֲבֹתֵינוּ חָטְאוּ וְאֵינָם, וַאֲנַחְנוּ עֲוׂנֹתֵיהֶם סָבָלְנוּ: עֲבָדִים מָשְׁלוּ בָנוּ, פֹּרֵק אֵין מִיָּדָם: בְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ מִפְּנֵי חֶרֶב הַמִּדְבָּר: עוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ מִפְּנֵי זַלְעֲפוֹת רָעָב: נָשִׁים בְּצִיּוֹן עִנּוּ, בְּתֻלֹת בְּעָרֵי יְהוּדָה: שָׂרִים בְּיָדָם נִתְלוּ, פְּנֵי זְקֵנִים לֹא נֶהְדָּרוּ: בַּחוּרִים טְחוֹן נָשָׂאוּ, וּנְעָרִים בָּעֵץ כָּשָׁלוּ: זְקֵנִים מִשַּׁעַר שָׁבָתוּ, בַּחוּרִים מִנְּגִינָתָם: שָׁבַת מְשׂוֹשׂ לִבֵּנוּ, נֶהְפַּךְ לְאֵבֶל מְחֹלֵנוּ: נָפְלָה עֲטֶרֶת רֹאשֵׁנוּ, אוֹי נָא לָנוּ כִּי חָטָאנוּ: עַל זֶה הָיָה דָוֶה לִבֵּנוּ, עַל אֵלֶּה חָשְׁכוּ עֵינֵינוּ: עַל הַר צִיּוֹן שֶׁשָּׁמֵם, שׁוּעָלִים הִלְּכוּ בוֹ: אַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:","cond":[]},{"kind":"special","text":"הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":[]}]}},{"id":"kinot_tisha_beav","title":"קינות לליל תשעה באב","category":"מועדים ואירועים","nusachim":{"ashkenaz":[{"kind":"header","text":"קינות לליל תשעה באב","cond":[]},{"kind":"instruction","text":"קינות לליל תשעה באב\n\nקינה א'","cond":[]},{"kind":"text","text":"זְכֹר יהוה מֶה-הָיָה לָנוּ אוֹי. הַבִּיטָה וּרְאֵה אֶת-חֶרְפָּתֵנוּ: אוֹי מֶה הָיָה לָנוּ.\nנַחֲלָתֵנוּ נֶהֶפְכָה לְזָרִים אוֹי. בָּתֵּינוּ לְנָכְרִים: אוֹי מֶה הָיָה לָנוּ.\nיְתוֹמִים הָיִינוּ וְאֵין אָב אוֹי. אִמּוֹתֵינוּ מְקוֹנְנוֹת בְּחֹדֶשׁ אָב. אוֹי מֶה הָיָה לָנוּ.\nמֵימֵינוּ בְּכֶסֶף שָׁתִינוּ אוֹי. כִּי נִסּוּךְ הַמַּיִם בָּזִינוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל צַוָּארֵנוּ נִרְדָּפְנוּ אוֹי. כִּי שִׂנְאַת חִנָּם רָדָפְנוּ. אוֹי מֶה הָיָה לָנוּ.\nמִצְרַיִם נָתַנּוּ יָד אוֹי. וְאַשּׁוּר צָדוּנוּ כְּצַיָּד. אוֹי מֶה הָיָה לָנוּ.\nאֲבֹתֵינוּ חָטְאוּ וְאֵינָם אוֹי. וַאֲנַחְנוּ סוֹבְלִים אֶת עֲוׂנָם. אוֹי מֶה הָיָה לָנוּ.\nעֲבָדִים מָשְׁלוּ בָנוּ אוֹי. כִּי שִׁלּוּחַ עֲבָדִים בִּטַּלְנוּ. אוֹי מֶה הָיָה לָנוּ.\nבְּנַפְשֵׁנוּ נָבִיא לַחְמֵנוּ אוֹי. כִּי קָפַצְנוּ מֵעָנִי יָדֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעוֹרֵנוּ כְּתַנּוּר נִכְמָרוּ אוֹי. כִּי כְבוֹדָם בְּקָלוֹן הֵמִירוּ. אוֹי מֶה הָיָה לָנוּ.\nנָשִׁים בְּצִיּוֹן עִנּוּ אוֹי. כִּי אִישׁ אֶת אֵשֶׁת רֵעֵהוּ טִמְּאוּ וְזִנּוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׂרִים בְּיָדָם נִתְלוּ אוֹי. כִּי גְּזֵלַת הֶעָנִי חָמְסוּ וְגָזְלוּ. אוֹי מֶה הָיָה לָנוּ.\nבַּחוּרִים טְחוֹן נָשָׂאוּ אוֹי. כִּי בְּבֵית זוֹנָה נִמְצָאוּ. אוֹי מֶה הָיָה לָנוּ.\nזְקֵנִים מִשַּׁעַר שָׁבָתוּ אוֹי. כִּי מִשְׁפַּט יָתוֹם וְאַלְמָנָה עִוְּתוּ. אוֹי מֶה הָיָה לָנוּ.\nשָׁבַת מְשׂוֹשׂ לִבֵּנוּ אוֹי. כִּי נִבְטְלוּ עוֹלֵי רְגָלֵינוּ. אוֹי מֶה הָיָה לָנוּ.\nנָפְלָה עֲטֶרֶת רֹאשֵׁנוּ אוֹי. כִּי נִשְׂרַף בֵּית מִקְדָּשֵׁנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל זֶה הָיָה דָוֶה לִבֵּנוּ אוֹי. כִּי נֻטַּל כְּבוֹד בֵּית מַאֲוָיֵנוּ. אוֹי מֶה הָיָה לָנוּ.\nעַל הַר צִיּוֹן שֶׁשָּׁמֵם אוֹי. כִּי נִתַּן עָלָיו שִׁקּוּץ מְשׁוֹמֵם. אוֹי מֶה הָיָה לָנוּ.\nאַתָּה יהוה לְעוֹלָם תֵּשֵׁב, כִּסְאֲךָ לְדוֹר וָדוֹר: לָמָּה לָנֶצַח תִּשְׁכָּחֵנוּ, תַּעַזְבֵנוּ לְאֹרֶךְ יָמִים: הֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה, חַדֵּשׁ יָמֵינוּ כְּקֶדֶם: כִּי אִם מָאֹס מְאַסְתָּנוּ, קָצַפְתָּ עָלֵינוּ עַד מְאֹד:\nהֲשִׁיבֵנוּ יהוה אֵלֶיךָ וְנָשׁוּבָה חַדֵּשׁ יָמֵינוּ כְּקֶדֶם:","cond":[]},{"kind":"instruction","text":"קינה ב'\nקינה לליל תשעה באב שחל במוצאי שבת:","cond":["sun"]},{"kind":"text","text":"אֵיךְ מִפִּי בֵּן וּבַת, הֲגוֹת קִינִים רַבַּת, תְּמוּר שִׁירִים וְחֶדְוַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נִגְזְרָה גְּזֵרָה, בָּחֳרִי אַף וְגַם עֶבְרָה, וְאַפּוֹ בָּנוּ חָרָה, וּבָעֲרָה חֲמָתוֹ כְּלַבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי בָתֵּינוּ שִׁנּוּ, וּבְתוּלוֹתֵינוּ עִנּוּ, וּפָנֵינוּ נִשְׁתַּנּוּ, וְגַם הֻשְׁחֲרוּ כְּמַחֲבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי שַׁדּוּנוּ, וְגַם הִפִּילוּ בָנוּ פְּגָרִים, בְּנֵי צִיּוֹן הַיְקָרִים, הָיוּ נְצוּרִים כְּבָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נָפְלָה עֲטֶרֶת, וְגָבְרָה כָּתֵף סוֹרֶרֶת, וְחָדַל הוֹד תִּפְאֶרֶת, צִמְצוּם שֶׁכֶן חִבַּת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.\n\nאוֹי כִּי נֻטְּלָה מְנוֹרָה, וּקְטֹרֶת לְבֹנָה הַטְּהוֹרָה, וְנִבְזָה גָּזִית מְיֻקָּרָה, אָכְלָה אֶרֶץ זָבַת.\nוִיהִי נֹעַם נִשְׁבַּת בְּמוֹצָאֵי שַׁבָּת.","cond":["sun"]},{"kind":"instruction","text":"קינה ג'","cond":[]},{"kind":"text","text":"בְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי. וְכָל בֵּית יִשְׂרָאֵל יֶהְגּוּ בִיגוֹנַי. וְיִבְכּוּ אֶת הַשְּׂרֵפָה אֲשֶׁר שָׂרַף יהוה:\n\nבְּלֵיל זֶה תְּיַלֵּל מַר עֲנִיָּה נֶחְדֶּלֶת, וּמִבֵּית אָבִיהָ בַּחַיִּים מֻבְדֶּלֶת. וְיָצְאָה מִבֵּיתוֹ וְנִסְגַּר הַדֶּלֶת, וְהָלְכָה בַּשִּׁבְיָה בְּכָל פֶּה נֶאֱכֶלֶת. בְּיוֹם שֻׁלְּחָה בְּאֵשׁ בּוֹעֶרֶת וְאוֹכֶלֶת, וְאֵשׁ עִם גַּחֶלֶת יָצְאָה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה הַגַּלְגַּל סִבֵּב הַחוֹבָה, רִאשׁוֹן גַּם שֵׁנִי בֵּיתִי נֶחְרְבָה. וְעוֹד לֹא רֻחָמָה בַּת הַשּׁוֹבָבָה, הֻשְׁקְתָה מֵי רוֹשׁ וְאֶת בִּטְנָהּ צָבָה. וְשֻׁלְּחָה מִבֵּיתוֹ וְגַם נָשְׁתָה טוֹבָה, גְּדוֹלָה הַשִּׂנְאָה מֵאֵת אֲשֶׁר אֲהֵבָהּ, וּכְאַלְמְנוּת חַיּוּת כְּאִשָּׁה נֶעֱזָבָה. וַתֹּאמֶר צִיּוֹן עֲזָבַנִי יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה קָדַרְתִּי וְחָשְׁכוּ הַמְּאוֹרוֹת, לְחֻרְבַּן בֵּית קָדְשִׁי וּבִטּוּל מִשְׁמָרוֹת. בְּלֵיל זֶה סַבּוּנִי אֲפָפוּנִי צָרוֹת, וְגַם קָרָא מוֹעֵד בְּדִין חָמֵשׁ גְּזֵרוֹת. בְּכִי חִנָּם בָּכוּ וְנִקְבַּע לְדוֹרוֹת, יַעַן כִּי הָיְתָה סִבָּה מֵאֵת יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.\n\nבְּלֵיל זֶה אֵרְעוּ בוֹ חָמֵשׁ מְאוֹרָעוֹת, גָּזַר עַל אָבוֹת בִּפְרֹעַ פְּרָעוֹת. וְדָבְקוּ בוֹ צָרוֹת מְצֵרוֹת וְגַם רָעוֹת, יוֹם מוּכָן הָיָה בִּפְגֹּעַ פְּגָעוֹת. וְהֶעֱמִיד הָאוֹיֵב וְהֵרִים קוֹל זְוָעוֹת, קוּם כִּי זֶה הַיּוֹם אֲשֶׁר אָמַר יהוה.\nבְּלֵיל זֶה יִבְכָּיוּן וְיֵילִילוּ בָּנַי, בְּלֵיל זֶה חָרַב בֵּית קָדְשִׁי וְנִשְׂרְפוּ אַרְמוֹנַי.","cond":[]},{"kind":"instruction","text":"קינה ד'","cond":[]},{"kind":"text","text":"שֹׁמְרוֹן קוֹל תִּתֵּן: מְצָאוּנִי עֲוׂנַי, לְאֶרֶץ אַחֶרֶת יְצָאוּנִי בָנַי.\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nלֹא לָךְ, אָהֳלִיבָה, חֲשֹׁב עָנְיֵךְ כְּעָנְיִי, הֲתַמְשִׁילִי חָלְיֵךְ לְשִׁבְרִי וּלְחָלְיִי? אֲנִי אָהֳלָה סוּרָה בָּגַדְתִּי בְקָשְׁיִי, וְקָם עָלַי כַּחֲשִׁי וְעָנָה בִי מֶרְיִי, וּלְמִקְצָת הַיָּמִים שִׁלַּמְתִּי נִשְׁיִי, וְתִגְלַת פִּלְאֶסֶר אָכַל אֶת פִּרְיִי, חֶמְדָּתִי פָּשַׁט וְהִצִּיל אֶת עֶדְיִי, וְלַחֲלַח וְחָבוֹר נָשָׂא אֶת שִׁבְיִי. דֹּמִי, אָהֳלִיבָה, וְאַל תִּבְכִּי כְּבִכְיִי, שְׁנָתַיִךְ אָרְכוּ, וְלֹא אָרְכוּ שָׁנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nמְשִׁיבָה אָהֳלִיבָה: אֲנִי כֵן נֶעֱקַשְׁתִּי, וּבְאַלּוּף נְעוּרַי כְּאָהֳלָה בָּגַדְתִּי. דֹּמִי, אַהֳלָה, כִּי יְגוֹנִי זָכַרְתִּי. נָדַדְתְּ אַתְּ אַחַת, וְרַבּוֹת נָדַדְתִּי. הִנֵּה, בְּיַד הַכַּשְׂדִּים פַּעֲמַיִם נִלְכַּדְתִּי, וּשְׁבִיָּה עֲנִיָּה לְבָבֶל יָרַדְתִּי, וְנִשְׂרַף הַהֵיכָל אֲשֶׁר בּוֹ נִכְבַּדְתִּי, וּלְשִׁבְעִים שָׁנָה בְּבָבֶל נִפְקַדְתִּי, וְשַׁבְתִּי לְצִיּוֹן עוֹד וְהֵיכָל יָסַדְתִּי, גַּם זֹאת הַפַּעַם מְעַט לֹא עָמַדְתִּי, עַד לְקָחַנִי אֱדוֹם וְכִמְעַט אָבַדְתִּי, וְעַל כָּל הָאֲרָצוֹת נָפְצוּ הֲמוֹנַי.\n\nוְאָהֳלִיבָה תִּזְעַק: נִשְׂרְפוּ אַרְמוֹנַי.\nוַתֹּאמֶר צִיּוֹן: עֲזָבַנִי יהוה.\n\nהַחוֹמֵל עַל דַּל, חֲמֹל עַל דַּלּוּתָם, וּרְאֵה שׁוֹמְמוּתָם וְאֹרֶךְ גָּלוּתָם. אַל תִּקְצֹף עַד מְאֹד, וּרְאֵה שִׁפְלוּתָם, וְאַל לָעַד תִּזְכֹּר עֲוֹנָם וְסִכְלוּתָם. רְפָא נָא אֶת שִׁבְרָם, וְנַחֵם אֲבֵלוּתָם, כִּי אַתָּה שִׂבְרָם וְאַתָּה אֱיָלוּתָם.\nחַדֵּשׁ יָמֵינוּ כִּימֵי קַדְמוֹנַי, כְּנָאֳמֶךָ: \"בּוֹנֵה יְרוּשָׁלַיִם יהוה\".","cond":[]},{"kind":"instruction","text":"קינה ה'","cond":[]},{"kind":"text","text":"עַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nאָז בַּחֲטָאֵינוּ חָרַב מִקְדָּשׁ וּבַעֲוׂנוֹתֵינוּ נִשְׂרַף הֵיכָל. בְּאֶרֶץ חֻבְּרָה לָהּ קָשְׁרָה מִסְפֵּד, וּצְבָא הַשָּׁמַיִם נָשְׂאוּ קִינָה.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nגַּם בָּכוּ בְּמֶרֶר שִׁבְטֵי יַעֲקֹב, וְאַף מַזָּלוֹת יִזְּלוּ דִּמְעָה. דִּגְלֵי יְשֻׁרוּן חָפוּ רֹאשָׁם, וְכִימָה וּכְסִיל קָדְרוּ פְּנֵיהֶם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nהֶעְתִּירוּ אָבוֹת וְלֹא שָׁמַע אֵל, צָעֲקוּ בָנִים וְלֹא עָנָה אָב. וְקוֹל הַתֹּר נִשְׁמַע בַּמָּרוֹם, וְרוֹעֶה נֶאֱמָן לֹא הִטָּה אֹזֶן.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nזֶרַע קֹדֶשׁ לָבְשׁוּ שַׂקִּים, וּצְבָא הַשָּׁמַיִם גַּם הֵם שַׂק הוּשַׂם כְּסוּתָם. חָשַׁךְ הַשֶּׁמֶשׁ וְיָרֵחַ קָדַר, וְכוֹכָבִים וּמַזָּלוֹת אָסְפוּ נָגְהָם.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nטָלֶה רִאשׁוֹן בָּכָה בְּמַר נֶפֶשׁ, עַל כִּי כְבָשָׂיו לָטֶבַח הוּבָלוּ. יְלָלָה הִשְׁמִיעַ שׁוֹר בַּמְּרוֹמִים, כִּי עַל צַוָּארֵנוּ נִרְדַּפְנוּ כֻּלָּנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nכּוֹכַב תְּאוֹמִים נִרְאָה חָלוּק, כִּי דַּם אַחִים נִשְׁפַּךְ כַּמַּיִם. לָאָרֶץ בִּקֵּשׁ לִפֹּל סַרְטָן, כִּי נִתְעַלַּפְנוּ מִפְּנֵי צָמָא.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nמָרוֹם נִבְעַת מִפְּנֵי אַרְיֵה, כִּי שַׁאֲגָתֵנוּ לֹא עָלְתָה לַמָּרוֹם. נֶהֶרְגוּ בְתוּלוֹת וְגַם בַּחוּרִים, כִּי עַל כֵּן בְּתוּלָה קָדְרָה פָנֶיהָ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nסִבֵּב מֹאזְנַיִם וּבִקֵּשׁ תְּחִנָּה, כִּי נִבְחַר לָנוּ מָוֶת מֵחַיִּים. עַקְרָב לָבַשׁ פַּחַד וּרְעָדָה, כִּי בְּחֶרֶב וּבְרָעָב שְׁפָטָנוּ צוּרֵנוּ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nפַּלְגֵי מַיִם הוֹרִידוּ דִּמְעָה כַּנַּחַל, כִּי אוֹת בַּקֶּשֶׁת לֹא נִתַּן לָנוּ. צָפוּ מַיִם עַל רֹאשֵׁנוּ, וּבִדְלִי מָלֵא חִכֵּנוּ יָבֵשׁ.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nקֵרַבְנוּ קָרְבָּן וְלֹא נִתְקַבֵּל, וּגְדִי פָּסַק שְׂעִיר חַטֹּאתֵינוּ. רַחֲמָנִיּוֹת בִּשְּׁלוּ יַלְדֵּיהֶן, וּמַזַּל דָּגִים הֶעֱלִים עֵינָיו.\nעַד אָנָה בִּכְיָה בְצִיּוֹן וּמִסְפֵּד בִּירוּשָׁלָיִם? תְּרַחֵם צִיּוֹן וְתִבְנֶה חוֹמוֹת יְרוּשָׁלָיִם.\n\nשָׁכַחְנוּ שַׁבָּת בְּלִבּוֹת שׁוֹבָבִים, שַׁדַּי שִׁכַּח כָּל צִדְקוֹתֵינוּ. תְּקַנֵּא לְצִיּוֹן קִנְאָה גְּדוֹלָה, וְתָאִיר לְרַבָּתִי עָם מֵאוֹר נָגְהֶךָ.\n\nתְּרַחֵם צִיּוֹן כַּאֲשֶׁר אָמַרְתָּ, וּתְכוֹנְנֶהָ כַּאֲשֶׁר דִּבַּרְתָּ. תְּמַהֵר יְשׁוּעָה וְתָחִישׁ גְּאֻלָּה וְתָשׁוּב לִירוּשָׁלַיִם בְּרַחֲמִים רַבִּים, כַּכָּתוּב עַל יַד נְבִיאֶךָ: לָכֵן כֹּה אָמַר יהוה: שַׁבְתִּי לִירוּשָׁלַיִם בְּרַחֲמִים, בֵּיתִי יִבָּנֶה בָּהּ נְאֻם יהוה צְבָאוֹת, וְקָו יִנָּטֶה עַל יְרוּשָׁלָיִם: וְנֶאֱמַר עוֹד קְרָא לֵאמֹר: כֹּה אָמַר יהוה צְבָאוֹת: עוֹד תְּפוּצֶנָה עָרַי מִטּוֹב, וְנִחַם יהוה עוֹד אֶת צִיּוֹן וּבָחַר עוֹד בִּירוּשָׁלָיִם: וְנֶאֱמַר: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ תּוֹדָה וְקוֹל זִמְרָה:","cond":[]}]}},{"id":"vayiten_lecha","title":"ויתן לך (מוצאי שבת)","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"header","text":"ויתן לך","cond":[]},{"kind":"instruction","text":"פסוקים הנהוגים לומר במוצאי שבת לסימן ברכה:","cond":[]},{"kind":"text","text":"וְיִתֶּן לְךָ הָאֱלהִים מִטַּל הַשָּׁמַיִם וּמִשְׁמַנֵּי הָאָרֶץ, וְרֹב דָגָן וְתִירֹשׁ: יַעַבְדּוּךָ עַמִּים וְיִשְׁתַּחֲווּ לְךָ לְאֻמִּים, הֱוֵה גְבִיר לְאַחֶיךָ וְיִשְׁתַּחֲווּ לְךָ בְּנֵי אִמֶּךָ, אֹרְרֶיךָ אָרוּר וּמְבָרְכֶיךָ בָּרוּךְ:\n\nוְאֵל שַׁדַּי יְבָרֵךְ אֹתְךָ וְיַפְרְךָ וְיַרְבֶּךָ, וְהָיִיתָ לִקְהַל עַמִּים: וְיִתֵּן לְךָ אֶת בִּרְכַּת אַבְרָהָם לְךָ וּלְזַרְעֲךָ אִתָּךְ, לְרִשְׁתְּךָ אֶת אֶרֶץ מְגֻרֶיךָ, אֲשֶׁר נָתַן אֱלֹהִים לְאַבְרָהָם: מֵאֵל אָבִיךָ וְיַעְזְרֶךָּ, וְאֵת שַׁדַּי וִיבָרְכֶךָּ, בִּרְכֹת שָׁמַיִם מֵעָל, בִּרְכֹת תְּהוֹם רֹבֶצֶת תָּחַת, בִּרְכֹת שָׁדַיִם וָרָחַם: בִּרְכֹת אָבִיךָ גָּבְרוּ עַל בִּרְכֹת הוֹרַי עַד תַּאֲוַת גִּבְעֹת עוֹלָם, תִּהְיֶיןָ לְרֹאשׁ יוסֵף וּלְקָדְקֹד נְזִיר אֶחָיו: וַאֲהֵבְךָ וּבֵרַכְךָ וְהִרְבֶּךָ, וּבֵרַךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתֶךָ, דְּגָנְךָ וְתִירֹשְׁךָ וְיִצְהָרֶךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרֹת צֹאנֶךָ, עַל הָאֲדָמָה אֲשֶׁר נִשְׁבַּע לַאֲבֹתֶיךָ לָתֶת לָךְ: בָּרוּךְ תִּהְיֶה מִכָּל הָעַמִּים, לֹא יִהְיֶה בְךָ עָקָר וַעֲקָרָה וּבִבְהֶמְתֶּךָ: וְהֵסִיר יהוה מִמְּךָ כָּל חֹלִי, וְכָל מַדְוֵי מִצְרַיִם הָרָעִים אֲשֶׁר יָדַעְתָּ לֹא יְשִׂימָם בָּךְ, וּנְתָנָם בְּכָל שֹׂנְאֶיךָ:\n\nהַמַּלְאָךְ הַגֹּאֵל אֹתִי מִכָּל רָע יְבָרֵךְ אֶת הַנְּעָרִים, וְיִקָּרֵא בָהֶם שְׁמִי, וְשֵׁם אֲבֹתַי אַבְרָהָם וְיִצְחָק, וְיִדְגּוּ לָרֹב בְּקֶרֶב הָאָרֶץ: יהוה אֱלֹהֵיכֶם הִרְבָּה אֶתְכֶם, וְהִנְּכֶם הַיּוֹם כְּכוֹכְבֵי הַשָּׁמַיִם לָרֹב: יהוה אֱלֹהֵי אֲבוֹתֵכֶם יֹסֵף עֲלֵיכֶם כָּכֶם אֶלֶף פְּעָמִים, וִיבָרֵךְ אֶתְכֶם כַּאֲשֶׁר דִּבֶּר לָכֶם:\n\nבָּרוּךְ אַתָּה בָּעִיר, וּבָרוּךְ אַתָּה בַּשָּׂדֶה: בָּרוּךְ אַתָּה בְּבֹאֶךָ, וּבָרוּךְ אַתָּה בְּצֵאתֶךָ: בָּרוּךְ טַנְאֲךָ וּמִשְׁאַרְתֶּךָ: בָּרוּךְ פְּרִי בִטְנְךָ וּפְרִי אַדְמָתְךָ וּפְרִי בְהֶמְתֶּךָ, שְׁגַר אֲלָפֶיךָ וְעַשְׁתְּרוֹת צֹאנֶךָ: יְצַו יהוה אִתְּךָ אֶת הַבְּרָכָה, בַּאֲסָמֶיךָ וּבְכֹל מִשְׁלַח יָדֶךָ, וּבֵרַכְךָ בָּאָרֶץ אֲשֶׁר יהוה אֱלהֶיךָ נֹתֵן לָךְ: יִפְתַּח יהוה לְךָ אֶת אוֹצָרוֹ הַטּוֹב אֶת הַשָּׁמַיִם לָתֵת מְטַר אַרְצְךָ בְּעִתּוֹ וּלְבָרֵךְ אֵת כָּל מַעֲשֵׂה יָדֶךָ, וְהִלְוִיתָ גּוֹיִם רַבִּים וְאַתָּה לֹא תִלְוֶה: כִּי יהוה אֱלֹהֶיךָ בֵּרַכְךָ כַּאֲשֶׁר דִּבֶּר לָךְ, וְהַעֲבַטְתָּ גּוֹיִם רַבִּים וְאַתָּה לֹא תַעֲבֹט, וּמָשַׁלְתָּ בְּגוֹיִם רַבִּים וּבְךָ לֹא יִמְשֹׁלוּ: אַשְׁרֶיךָ יִשְׂרָאֵל, מִי כָמוֹךָ, עַם נושַׁע בַּיהוה, מָגֵן עֶזְרֶךָ, וַאֲשֶׁר חֶרֶב גַּאֲוָתֶךָ, וְיִכָּחֲשׁוּ אוֹיְבֶיךָ לָךְ, וְאַתָּה עַל בָּמוֹתֵימוֹ תִדְרֹךְ:\n\nמָחִיתִי כָעָב פְּשָׁעֶיךָ וְכֶעָנָן חַטֹּאותֶיךָ, שׁוּבָה אֵלַי כִּי גְאַלְתִּיךָ: רָנּוּ שָׁמַיִם כִּי עָשָׂה יהוה, הָרִיעוּ תַּחְתִּיּוֹת אָרֶץ, פִּצְחוּ הָרִים רִנָּה, יַעַר וְכָל עֵץ בּוֹ, כִּי גָאַל יהוה יַעֲקֹב וּבְיִשְׂרָאֵל יִתְפָּאָר: גֹּאֲלֵנוּ יהוה צְבָאוֹת שְׁמוֹ, קְדוֹשׁ יִשְׂרָאֵל:\n\nיִשְׂרָאֵל נוֹשַׁע בַּיהוה תְּשׁוּעַת עוֹלָמִים, לֹא תֵבשׁוּ וְלֹא תִכָּלְמוּ עַד עוֹלְמֵי עַד: וַאֲכַלְתֶּם אָכוֹל וְשָׂבוֹעַ, וְהִלַּלְתֶּם אֶת שֵׁם יהוה אֱלֹהֵיכֶם אֲשֶׁר עָשָׂה עִמָּכֶם לְהַפְלִיא, וְלֹא יֵבֹשׁוּ עַמִּי לְעוֹלָם: וִידַעְתֶּם כִּי בְקֶרֶב יִשְׂרָאֵל אָנִי, וַאֲנִי יהוה אֱלֹהֵיכֶם וְאֵין עוֹד, וְלֹא יֵבשׁוּ עַמִּי לְעוֹלָם: כִּי בְשִׂמְחָה תֵצֵאוּ וּבְשָׁלוֹם תּוּבָלוּן, הֶהָרִים וְהַגְּבָעוֹת יִפְצְחוּ לִפְנֵיכֶם רִנָּה, וְכָל עֲצֵי הַשָּׂדֶה יִמְחֲאוּ כָף: הִנֵּה אֵל יְשׁוּעָתִי אֶבְטַח, וְלֹא אֶפְחָד, כִּי עָזִּי וְזִמְרָת יָהּ יהוה, וַיְהִי לִי לִישׁוּעָה: וּשְׁאַבְתֶּם מַיִם בְּשָׂשׂוֹן מִמַּעַיְנֵי הַיְשׁוּעָה: וַאֲמַרְתֶּם בַּיּוֹם הַהוּא, הוֹדוּ לַיהוה קִרְאוּ בִשְׁמוֹ, הוֹדִיעוּ בָעַמִּים עֲלִילֹתָיו, הַזְכִּירוּ כִּי נִשְׂגָּב שְׁמוֹ: זַמְּרוּ יהוה כִּי גֵאוּת עָשָׂה, מוּדַעַת זֹאת בְּכָל הָאָרֶץ: צַהֲלִי וָרֹנִּי יוֹשֶׁבֶת צִיּוֹן, כִּי גָדוֹל בְּקִרְבֵּךְ קְדוֹשׁ יִשְׂרָאֵל: וְאָמַר בַּיּוֹם הַהוּא, הִנֵּה אֱלֹהֵינוּ זֶה קִוִּינוּ לוֹ, וְיוֹשִׁיעֵנוּ, זֶה יהוה קִוִּינוּ לוֹ, נָגִילָה וְנִשְׂמְחָה בִּישׁוּעָתוֹ: בֵּית יַעֲקֹב, לְכוּ וְנֵלְכָה בְּאוֹר יהוה: וְהָיָה אֱמוּנַת עִתֶּיךָ, חֹסֶן יְשׁוּעֹת, חָכְמַת וָדָעַת, יִרְאַת יהוה הִיא אוֹצָרוֹ: וַיְהִי דָוִד לְכָל דְּרָכָיו מַשְׂכִּיל, וַיהוה עִמּוֹ:\n\nפָּדָה בְשָׁלוֹם נַפְשִׁי מִקְּרָב לִי, כִּי בְרַבִּים הָיוּ עִמָּדִי: וַיֹּאמֶר הָעָם אֶל שָׁאוּל, הֲיוֹנָתָן יָמוּת, אֲשֶׁר עָשָׂה הַיְשׁוּעָה הַגְּדוֹלָה הַזֹּאת בְּיִשְׂרָאֵל, חָלִילָה, חַי יהוה אִם יִפֹּל מִשַּׂעֲרַת רֹאשׁוֹ אַרְצָה, כִּי עִם אֱלֹהִים עָשָׂה הַיּוֹם הַזֶּה, וַיִּפְדּוּ הָעָם אֶת יוֹנָתָן וְלֹא מֵת: וּפְדוּיֵי יהוה יְשֻׁבוּן וּבָאוּ צִיּוֹן בְּרִנָּה וְשִׂמְחַת עוֹלָם עַל רֹאשָׁם, שָׂשׂוֹן וְשִׂמְחָה יַשִּׂיגוּ, וְנָסוּ יָגוֹן וַאֲנָחָה:\n\nהָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי, פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה: וְלֹא אָבָה יהוה אֱלֹהֶיךָ לִשְׁמֹעַ אֶל בִּלְעָם, וַיַּהֲפֹךְ יהוה אֱלֹהֶיךָ לְּךָ אֶת הַקְּלָלָה לִבְרָכָה, כִּי אֲהֵבְךָ יהוה אֱלֹהֶיךָ: אָז תִּשְׂמַח בְּתוּלָה בְּמָחוֹל וּבַחֻרִים וּזְקֵנִים יַחְדָּו, וְהָפַכְתִּי אֶבְלָם לְשָׂשׂוֹן וְנִחַמְתִּים, וְשִׂמַּחְתִּים מִיגוֹנָם:\n\nבּוֹרֵא נִיב שְׂפָתָיִם, שָׁלוֹם שָׁלוֹם לָרָחוֹק וְלַקָּרוֹב אָמַר יהוה, וּרְפָאתִיו: וְרוּחַ לָבְשָׁה אֶת עֲמָשַׂי רֹאשׁ הַשָּׁלִישִׁים, לְךָ דָוִיד וְעִמְּךָ בֶן יִשַׁי שָׁלוֹם, שָׁלוֹם לְךָ וְשָׁלוֹם לְעֹזְרֶךָ כִּי עֲזָרְךָ אֱלֹהֶיךָ, וַיְקַבְּלֵם דָּוִיד וַיִּתְּנֵם בְּרָאשֵׁי הַגְּדוּד: וַאֲמַרְתֶּם כֹּה לֶחָי, וְאַתָּה שָׁלוֹם, וּבֵיתְךָ שָׁלוֹם וְכֹל אֲשֶׁר לְךָ שָׁלוֹם: יהוה עֹז לְעַמּוֹ יִתֵּן, יהוה יְבָרֵךְ אֶת עַמּוֹ בַשָּׁלוֹם:\n\nאָמַר רַבִּי יוֹחָנָן: בְּכָל מָקוֹם שֶׁאַתָּה מוֹצֵא גְּדֻלָּתוֹ שֶׁל הַקָּדוֹשׁ בָּרוּךְ הוּא, שָׁם אַתָּה מוֹצֵא עַנְוְתָנוּתוֹ. דָּבָר זֶה כָּתוּב בַּתּוֹרָה, וְשָׁנוּי בַּנְּבִיאִים, וּמְשֻׁלָּשׁ בַּכְּתוּבִים. כָּתוּב בַּתּוֹרָה: כִּי יהוה אֱלֹהֵיכֶם הוּא אֱלֹהֵי הָאֱלֹהִים וַאֲדֹנֵי הָאֲדֹנִים, הָאֵל הַגָּדֹל, הַגִּבֹּר וְהַנּוֹרָא, אֲשֶׁר לֹא יִשָּׂא פָנִים וְלֹא יִקַּח שֹׁחַד: וּכְתִיב בָּתְרֵיהּ: עֹשֶׂה מִשְׁפַּט יָתוֹם וְאַלְמָנָה, וְאֹהֵב גֵּר לָתֶת לוֹ לֶחֶם וְשִׂמְלָה: שָׁנוּי בַּנְּבִיאִים, דִּכְתִיב: כִּי כֹה אָמַר רָם וְנִשָּׂא, שֹׁכֵן עַד וְקָדוֹשׁ שְׁמוֹ, מָרוֹם וְקָדוֹשׁ אֶשְׁכּוֹן, וְאֶת דַּכָּא וּשְׁפַל רוּחַ, לְהַחֲיוֹת רוּחַ שְׁפָלִים וּלְהַחֲיוֹת לֵב נִדְכָּאִים: מְשֻׁלָּשׁ בַּכְּתוּבִים, דִּכְתִיב: שִׁירוּ לֵאלֹהִים זַמְּרוּ שְׁמוֹ, סֹלּוּ לָרֹכֵב בָּעֲרָבוֹת בְּיָהּ שְׁמוֹ, וְעִלְזוּ לְפָנָיו: וּכְתִיב בָּתְרֵיהּ: אֲבִי יְתוֹמִים וְדַיַּן אַלְמָנוֹת, אֱלֹהִים בִּמְעוֹן קָדְשׁוֹ:\n\nיְהִי יהוה אֱלֹהֵינוּ עִמָּנוּ כַּאֲשֶׁר הָיָה עִם אֲבֹתֵינוּ, אַל יַעַזְבֵנוּ וְאַל יִטְּשֵׁנוּ: וְאַתֶּם הַדְּבֵקִים בַּיהוה אֱלֹהֵיכֶם, חַיִּים כֻּלְּכֶם הַיּוֹם: כִּי נִחַם יהוה צִיּוֹן, נִחַם כָּל חָרְבֹתֶיהָ, וַיָּשֶׂם מִדְבָּרָהּ כְּעֵדֶן וְעַרְבָתָהּ כְּגַן יהוה, שָׂשׂוֹן וְשִׂמְחָה יִמָּצֵא בָהּ, תּוֹדָה וְקוֹל זִמְרָה: יהוה חָפֵץ לְמַעַן צִדְקוֹ, יַגְדִּיל תּוֹרָה וְיַאְדִּיר:\n\nשִׁיר הַמַּעֲלוֹת, אַשְׁרֵי כָּל יְרֵא יהוה הַהֹלֵךְ בִּדְרָכָיו: יְגִיעַ כַּפֶּיךָ כִּי תֹאכֵל, אַשְׁרֶיךָ וְטוֹב לָךְ: אֶשְׁתְּךָ כְּגֶפֶן פֹּרִיָּה בְּיַרְכְּתֵי בֵיתֶךָ, בָּנֶיךָ כִּשְׁתִלֵי זֵיתִים סָבִיב לְשֻׁלְחָנֶךָ: הִנֵּה כִי כֵן יְבֹרַךְ גָּבֶר יְרֵא יהוה: יְבָרֶכְךָ יהוה מִצִּיּוֹן וּרְאֵה בְּטוּב יְרוּשָׁלָיִם, כֹּל יְמֵי חַיֶּיךָ: וּרְאֵה בָנִים לְבָנֶיךָ, שָׁלוֹם עַל יִשְׂרָאֵל:","cond":[]}]}},{"id":"tefila_lecholeh","title":"תפילה לרפואת חולה","category":"תפילות","nusachim":{"ashkenaz":[{"kind":"special","text":"יְהִי רָצוֹן מִלְּפָנֶיךָ יהוה אֱלֹהַי וֵאלֹהֵי אֲבוֹתַי, שֶׁתִּשְׁלַח מְהֵרָה רְפוּאָה שְׁלֵמָה מִן הַשָּׁמַיִם, רְפוּאַת הַנֶּפֶשׁ וּרְפוּאַת הַגּוּף לַחוֹלֶה (לנקבה: לַחוֹלָה, לרבים: לַחוֹלִים, לרבות: לַחוֹלוֹת):\n:=:=\nבְּתוֹךְ שְׁאָר חוֹלֵי יִשְׂרָאֵל.","cond":[]}]}}]};
